/* ============================================================
   Module 3, The Grown-Ups' Table  ("After Bedtime")
   A parent-facing, fine-dining meal planner. Pick a kitchen
   (Italian, Japanese, and more), follow a craving, and get
   tonight's three ideas, each with the chef's thinking, the
   method, the ingredients and a ready shopping list.

   Recipes were developed and adversarially cross-checked by a
   culinary panel (one author + one stern editor per cuisine) for
   authenticity, sound quantities and correct method.

   Plugs into the same platform core as Animals and Meals:
   { id, title, renderHome }. Its whole look is the dark
   "After Bedtime" theme, scoped behind body.gm-active so it
   never touches Chloe's light rose world.
   ============================================================ */
(function(){
  "use strict";
  var P = window.ChloePlatform, el = P.el;

  /* ---------------- recipe database (built + verified offline) ---------------- */
  var GM = {"cuisines":[{"key":"mediterranean","short":"Mediterranean","name":"Mediterranean & Middle Eastern","cats":["Mezze","Grills & Mains","Bowls & Salads"],"hue":"#5cc0ad"},{"key":"italian","short":"Italian","name":"Italian","cats":["Pizza","Pasta","Risotto","Secondi"],"hue":"#d06a4e"},{"key":"japanese","short":"Japanese","name":"Japanese","cats":["Sushi & Rice bowls","Ramen & Noodles","Yakimono (grilled)","Small plates"],"hue":"#9bb0c9"},{"key":"american","short":"American","name":"American","cats":["Burgers","BBQ & Grill","Comfort classics"],"hue":"#d9a45a"},{"key":"mexican","short":"Mexican","name":"Mexican","cats":["Tacos","Bowls & Enchiladas","Sides & Salsas"],"hue":"#df7d3f"},{"key":"indian","short":"Indian","name":"Indian","cats":["Curries","Tandoori & Grills","Rice & Breads"],"hue":"#e0ab44"},{"key":"thai","short":"Thai","name":"Thai & Southeast Asian","cats":["Curries & Stir-fry","Noodles","Salads & Small plates"],"hue":"#88bd76"},{"key":"french","short":"French","name":"French","cats":["Bistro mains","Brasserie classics","Desserts"],"hue":"#c79ad0"}],"types":["Pizza","Pasta","Burgers","Curry","Noodles & Ramen","Tacos","Grills & BBQ","Rice & Bowls","Mains","Starters","Salads","Desserts"],"dishes":[{"id":"me-hummus-tahini","name":"Hummus bi Tahini","category":"Mezze","course":"Starter","meal":"both","tier":"easy","inspiration":"","minutes":15,"serves":4,"level":"Weeknight","idea":"Silky, lemony hummus from a tin, ready in the time it takes to toast pita. A spoon of bicarb in a quick simmer slips the chickpea skins so the blend turns creamy instead of grainy. No overnight soak, no fuss.","ingredients":[{"item":"2 x 400 g tins chickpeas, drained","note":"also sold as garbanzo beans; tinned is fine"},{"item":"1/2 tsp bicarbonate of soda","note":"baking soda; helps the skins soften for smoother hummus"},{"item":"150 g light tahini, well stirred","note":"smooth sesame-seed paste; in the world-foods or hummus aisle. Choose a runny pale one"},{"item":"60 ml fresh lemon juice (about 2 lemons)","note":""},{"item":"1 small garlic clove","note":""},{"item":"1 tsp fine salt","note":""},{"item":"60 ml ice-cold water, plus more as needed","note":""},{"item":"2 tbsp extra virgin olive oil, to finish","note":""},{"item":"1 tsp paprika or Aleppo pepper, to finish","note":"Aleppo pepper is a mild, fruity Syrian chilli flake; sweet paprika with a pinch of chilli works instead"}],"steps":["Tip the chickpeas into a pan with the bicarb and water to cover, bring to a brisk simmer for 8 to 10 minutes until soft and the skins float, then drain.","Blend the warm chickpeas, tahini, lemon juice, garlic and salt for a full 2 minutes, scraping down once.","With the motor running, trickle in the ice water until the hummus turns pale and loose. Taste and adjust salt and lemon.","Spread on a plate, swirl a well in the middle, pool in the olive oil and dust with paprika. Serve with warm pita."],"pairing":"Warm pita and a glass of mint tea","tags":["Vegetarian","Vegan","Make-ahead","Gluten-free option","Quick","Crowd-pleaser"],"vegetarian":true,"spicy":false,"calories":290,"protein":10,"carbs":24,"fat":18,"allergens":["Sesame"],"role":"appetizer","cuisineKey":"mediterranean","type":"Starters"},{"id":"me-baba-ganoush","name":"Baba Ganoush","category":"Mezze","course":"Starter","meal":"both","tier":"easy","inspiration":"","minutes":35,"serves":4,"level":"Weeknight","idea":"Smoky charred aubergine whipped with tahini and lemon into a loose, savoury dip. Burning the skins over a flame or under the grill gives that bitter smoke that is the whole point.","ingredients":[{"item":"3 large aubergines (about 1.2 kg total)","note":"also called eggplant"},{"item":"60 g light tahini, well stirred","note":"smooth sesame-seed paste; world-foods or hummus aisle"},{"item":"2 tbsp fresh lemon juice","note":""},{"item":"1 small garlic clove, crushed","note":""},{"item":"3/4 tsp fine salt","note":""},{"item":"2 tbsp extra virgin olive oil, plus more to finish","note":""},{"item":"1 tbsp chopped flat-leaf parsley","note":"flat-leaf (Italian) parsley; curly parsley is fine"}],"steps":["Char the whole aubergines over a gas flame or under a hot grill, turning often, for 15 to 20 minutes until the skin is blackened and the flesh collapses.","Cool in a colander, then peel off all the skin and let the flesh drain 10 minutes.","Mash the flesh with a fork to keep some texture, then stir in the tahini, lemon juice, garlic, salt and olive oil. Taste and adjust.","Spread on a plate, drizzle with more oil and scatter parsley. Serve with flatbread."],"pairing":"A crisp dry white or sparkling water with lemon","tags":["Vegetarian","Vegan","Make-ahead","Gluten-free option","Light"],"vegetarian":true,"spicy":false,"calories":175,"protein":4,"carbs":12,"fat":13,"allergens":["Sesame"],"role":"appetizer","cuisineKey":"mediterranean","type":"Starters"},{"id":"me-falafel","name":"Crispy Falafel","category":"Mezze","course":"Starter","meal":"both","tier":"signature","inspiration":"Tawlet (Kamal Mouzawak, Beirut)","minutes":35,"serves":4,"level":"Weekend","idea":"Shatteringly crisp, green-centred falafel made the proper way from soaked raw chickpeas, never tinned. The ground-not-blended texture and a herb-packed crumb are what separate the real thing from a dense pub fritter. Soak the night before and the active work is quick.","ingredients":[{"item":"250 g dried chickpeas, soaked overnight (do not cook)","note":"must be dried and raw-soaked, not tinned, or the falafel falls apart"},{"item":"1 small onion, roughly chopped","note":""},{"item":"4 garlic cloves","note":""},{"item":"30 g flat-leaf parsley","note":"flat-leaf (Italian) parsley"},{"item":"20 g fresh coriander","note":"fresh cilantro leaves"},{"item":"1.5 tsp ground cumin","note":""},{"item":"1 tsp ground coriander","note":"the dried ground seed, warm and citrusy; different from the fresh leaf above"},{"item":"1 tsp fine salt","note":""},{"item":"1/2 tsp bicarbonate of soda","note":"baking soda; lightens the texture"},{"item":"1 litre neutral oil, for frying","note":"flavourless oil such as sunflower, vegetable or rapeseed"}],"steps":["Drain the soaked chickpeas well and pat dry; they stay raw, never cooked.","Pulse the chickpeas, onion, garlic and herbs to a coarse, couscous-like crumb that just holds when pressed. Do not blend to a paste.","Mix in the cumin, ground coriander and salt. Chill 30 minutes, then stir through the bicarb just before frying.","Shape into walnut-sized balls with wet hands.","Fry at 175C in batches for 3 to 4 minutes until deep golden with a green, steamy centre. Drain on paper.","Serve hot with tahini sauce and pickles."],"pairing":"Tahini-lemon sauce, pickled turnips and a cold lager","tags":["Vegetarian","Vegan","Make-ahead","Crowd-pleaser"],"vegetarian":true,"spicy":false,"calories":330,"protein":12,"carbs":30,"fat":18,"allergens":[],"role":"appetizer","cuisineKey":"mediterranean","type":"Starters"},{"id":"me-whipped-feta","name":"Whipped Feta with Honey","category":"Mezze","course":"Starter","meal":"both","tier":"easy","inspiration":"","minutes":10,"serves":4,"level":"Weeknight","idea":"Feta and yoghurt blitzed into a cloud, finished with a drizzle of honey and a crack of black pepper. Five minutes in a food processor and you have a mezze that tastes like much more effort than it took.","ingredients":[{"item":"200 g Greek feta (block, in brine)","note":"salty, tangy sheep/goat cheese; buy the block not pre-crumbled for a creamier whip"},{"item":"100 g Greek yoghurt","note":"thick strained yoghurt; plain full-fat yoghurt works"},{"item":"1 tbsp extra virgin olive oil, plus more to finish","note":""},{"item":"1 tsp lemon juice","note":""},{"item":"1 tbsp runny honey","note":""},{"item":"1/2 tsp black pepper","note":""},{"item":"1 tsp toasted sesame seeds or chilli flakes, to finish","note":""}],"steps":["Blitz the feta, yoghurt, olive oil and lemon juice in a food processor for 2 minutes until smooth and fluffy.","Spread thickly onto a plate with the back of a spoon.","Drizzle with honey and a little more olive oil, then crack over the black pepper.","Scatter sesame seeds or chilli flakes and serve with warm pita or crudites."],"pairing":"Warm pita, sliced cucumber and a chilled rosé","tags":["Vegetarian","Quick","Gluten-free option","Crowd-pleaser"],"vegetarian":true,"spicy":false,"calories":220,"protein":10,"carbs":7,"fat":17,"allergens":["Milk","Sesame"],"role":"appetizer","cuisineKey":"mediterranean","type":"Starters"},{"id":"me-muhammara","name":"Muhammara (Roasted Pepper & Walnut Dip)","category":"Mezze","course":"Starter","meal":"both","tier":"signature","inspiration":"Orfali Bros (Mohamad Orfali, Dubai)","minutes":20,"serves":6,"level":"Weekend","idea":"A jewel-red Aleppan dip of roasted red peppers and toasted walnuts, sharpened with pomegranate molasses and warmed by cumin. A Syrian classic that Ottolenghi has championed in print; the balance of sweet, smoky and sour against the slight grit of hand-pounded walnuts is its whole identity.","ingredients":[{"item":"3 large red peppers (or 250 g jarred roasted red peppers, drained)","note":"red bell/capsicum peppers; jarred roasted ones save time"},{"item":"120 g walnuts, toasted","note":""},{"item":"40 g fine dried breadcrumbs","note":"plain dried breadcrumbs; panko or even crushed crackers work"},{"item":"2 tbsp pomegranate molasses, plus extra to finish","note":"thick tangy-sweet reduced pomegranate syrup; world-foods aisle. Substitute 2 tbsp balsamic with a little honey"},{"item":"1 tbsp tomato paste","note":"concentrated tomato puree (the thick kind in a tube or small tin)"},{"item":"1 garlic clove","note":""},{"item":"1 tsp ground cumin","note":""},{"item":"1/2 tsp Aleppo pepper or chilli flakes","note":"Aleppo pepper is a mild fruity Syrian chilli flake; ordinary chilli flakes are fine"},{"item":"2 tbsp extra virgin olive oil","note":""},{"item":"1 tbsp lemon juice","note":""},{"item":"3/4 tsp salt","note":""},{"item":"1 tbsp pomegranate seeds and chopped parsley, to finish","note":"the jewel-like seeds from inside a fresh pomegranate; sold loose in tubs too"}],"steps":["If using fresh peppers, char them whole under a hot grill, turning, for 12 to 15 minutes until blackened, then steam in a covered bowl 10 minutes, peel and deseed.","Toast the walnuts in a dry pan until fragrant, then set a few aside for the top.","Pulse the peppers, walnuts, breadcrumbs, pomegranate molasses, tomato paste, garlic, cumin, Aleppo pepper, olive oil, lemon juice and salt to a coarse, spoonable paste; keep some texture.","Taste and balance the sweet-sour with more molasses or lemon.","Spread on a plate, drizzle with molasses and oil, and scatter the reserved walnuts, pomegranate seeds and parsley."],"pairing":"Warm flatbread, grilled halloumi and a glass of Lebanese red","tags":["Vegetarian","Vegan","Make-ahead","Spicy","Crowd-pleaser"],"vegetarian":true,"spicy":true,"calories":230,"protein":4,"carbs":13,"fat":18,"allergens":["Gluten","Tree nuts"],"role":"appetizer","cuisineKey":"mediterranean","type":"Starters"},{"id":"me-chicken-shawarma","name":"Chicken Shawarma","category":"Grills & Mains","course":"Main","meal":"both","tier":"easy","inspiration":"","minutes":35,"serves":4,"level":"Weeknight","idea":"All the spit-roast flavour of street shawarma from a home oven: thigh meat in warm spices and yoghurt, roasted hot then crisped under the grill. A quick weeknight version once the marinade is on.","ingredients":[{"item":"800 g boneless skinless chicken thighs","note":"thighs stay juicier than breast for this"},{"item":"3 tbsp Greek yoghurt","note":"thick strained yoghurt; plain yoghurt works"},{"item":"3 tbsp olive oil","note":""},{"item":"2 tbsp fresh lemon juice","note":""},{"item":"4 garlic cloves, crushed","note":""},{"item":"2 tsp ground cumin","note":""},{"item":"2 tsp ground coriander","note":"ground dried coriander seed, warm and citrusy"},{"item":"1 tsp smoked paprika","note":""},{"item":"1/2 tsp ground cinnamon","note":""},{"item":"1 tsp salt","note":""},{"item":"1/2 tsp black pepper","note":""}],"steps":["Whisk the yoghurt, oil, lemon, garlic, spices, salt and pepper into a marinade and coat the thighs. Rest at least 30 minutes, ideally overnight.","Heat the oven to 220C. Stack the thighs snugly in a small dish and roast 30 to 35 minutes to an internal 75C.","Flash under a hot grill for 3 to 5 minutes until the edges char.","Rest 5 minutes, slice thinly, then pile into warm flatbread with garlic sauce, pickles and tomato, or serve over rice."],"pairing":"Garlic toum, pickled cucumber and a chilled Côtes du Rhône","tags":["Make-ahead","Gluten-free option","Crowd-pleaser","Batch-cook"],"vegetarian":false,"spicy":false,"calories":350,"protein":40,"carbs":4,"fat":19,"allergens":["Milk"],"role":"main","cuisineKey":"mediterranean","type":"Grills & BBQ"},{"id":"me-lamb-kofta","name":"Lamb Kofta Kebab","category":"Grills & Mains","course":"Main","meal":"dinner","tier":"easy","inspiration":"","minutes":30,"serves":4,"level":"Weeknight","idea":"Juicy spiced minced lamb skewers, kneaded with grated onion and parsley so they stay tender. Fattier lamb and a firm knead give the springy bite of a proper kofta.","ingredients":[{"item":"600 g minced lamb (around 20% fat)","note":"ground lamb; some fat keeps the kebabs moist"},{"item":"1 small onion, coarsely grated and squeezed dry","note":""},{"item":"20 g flat-leaf parsley, finely chopped","note":"flat-leaf (Italian) parsley"},{"item":"2 garlic cloves, crushed","note":""},{"item":"1.5 tsp ground cumin","note":""},{"item":"1 tsp ground coriander","note":"ground dried coriander seed"},{"item":"1 tsp sweet paprika","note":""},{"item":"1/2 tsp ground cinnamon","note":""},{"item":"1 tsp salt","note":""},{"item":"1/2 tsp black pepper","note":""},{"item":"1 tbsp olive oil, for grilling","note":""}],"steps":["Combine the lamb, grated onion, parsley, garlic, spices, salt and pepper in a bowl.","Knead firmly for 3 to 4 minutes until sticky and cohesive, then chill 15 minutes.","With wet hands, mould around metal skewers into long sausage shapes, pressing firmly.","Grill on a hot griddle or barbecue, brushed with oil, for 8 to 10 minutes, turning, until charred and just cooked.","Rest briefly and serve with flatbread, sumac onions and yoghurt."],"pairing":"Sumac onions, garlicky yoghurt and a robust Syrah","tags":["Quick","Gluten-free option","Crowd-pleaser"],"vegetarian":false,"spicy":false,"calories":380,"protein":26,"carbs":3,"fat":30,"allergens":[],"role":"main","cuisineKey":"mediterranean","type":"Grills & BBQ"},{"id":"me-shakshuka","name":"Shakshuka","category":"Grills & Mains","course":"All-day","meal":"both","tier":"easy","inspiration":"","minutes":35,"serves":4,"level":"Weeknight","idea":"Eggs poached in a spiced tomato and pepper sauce, all in one pan. Cumin, caraway and a pinch of chilli build a deep brunch sauce; the aim is just-set whites over a still-runny yolk.","ingredients":[{"item":"3 tbsp olive oil","note":""},{"item":"1 onion, finely sliced","note":""},{"item":"2 red peppers, sliced","note":"red bell/capsicum peppers"},{"item":"4 garlic cloves, sliced","note":""},{"item":"1.5 tsp ground cumin","note":""},{"item":"1 tsp sweet paprika","note":""},{"item":"1/2 tsp caraway seeds","note":"small ridged seeds with an aniseed-pepper flavour; or use a pinch more cumin"},{"item":"1/2 tsp chilli flakes","note":""},{"item":"2 x 400 g tins chopped tomatoes","note":""},{"item":"1 tsp sugar","note":""},{"item":"1 tsp salt","note":""},{"item":"6 large eggs","note":""},{"item":"60 g feta, crumbled","note":"salty tangy Greek cheese"},{"item":"2 tbsp chopped coriander","note":"fresh cilantro leaves; flat-leaf parsley works if you dislike coriander"}],"steps":["Soften the onion and peppers in the oil over medium heat for 10 minutes in a wide pan.","Add the garlic, cumin, paprika, caraway and chilli and fry 1 minute until fragrant.","Pour in the tomatoes with sugar and salt and simmer 12 to 15 minutes until thick and jammy.","Make six wells, crack in the eggs, cover and cook gently 6 to 8 minutes until the whites just set.","Scatter feta and coriander and serve from the pan with crusty bread."],"pairing":"Crusty sourdough and a glass of fresh orange juice","tags":["Vegetarian","One-pan","Spicy","Comfort","Gluten-free option"],"vegetarian":true,"spicy":true,"calories":280,"protein":14,"carbs":17,"fat":18,"allergens":["Egg","Milk"],"role":"main","cuisineKey":"mediterranean","type":"Grills & BBQ"},{"id":"me-sheet-pan-harissa-chicken","name":"Sheet-Pan Harissa Chicken & Chickpeas","category":"Grills & Mains","course":"Main","meal":"dinner","tier":"easy","inspiration":"","minutes":35,"serves":4,"level":"Weeknight","idea":"One tray, almost no washing up: chicken thighs and chickpeas roasted in harissa and lemon until the edges crisp and the chickpeas turn nutty. A weeknight rescue dish that still tastes North African.","ingredients":[{"item":"8 bone-in skin-on chicken thighs (about 1 kg)","note":""},{"item":"1 x 400 g tin chickpeas, drained","note":""},{"item":"2 tbsp rose harissa (or regular harissa)","note":"North African chilli paste; rose harissa is milder and floral. Substitute any chilli paste, easing back on the quantity if it is hot"},{"item":"3 tbsp olive oil","note":""},{"item":"1 lemon (half juiced, half sliced)","note":""},{"item":"1 tsp ground cumin","note":""},{"item":"1 red onion, cut into wedges","note":""},{"item":"1 tsp salt","note":""},{"item":"2 tbsp chopped coriander, to finish","note":"fresh cilantro leaves"},{"item":"100 g Greek yoghurt, to serve","note":"thick strained yoghurt"}],"steps":["Heat the oven to 220C. Toss the chickpeas, onion wedges and lemon slices in a large roasting tray with 1 tbsp oil and a pinch of salt.","Mix the harissa, remaining oil, lemon juice, cumin and salt, then rub all over the chicken thighs.","Nestle the thighs skin-up among the chickpeas and roast 30 to 35 minutes until the skin is crisp and the juices run clear.","Scatter with coriander and serve with the yoghurt and warm flatbread."],"pairing":"Flatbread, cooling yoghurt and a chilled Grenache rosé","tags":["One-pan","Spicy","Gluten-free option","Batch-cook","Comfort"],"vegetarian":false,"spicy":true,"calories":560,"protein":42,"carbs":16,"fat":36,"allergens":["Milk"],"role":"main","cuisineKey":"mediterranean","type":"Grills & BBQ"},{"id":"me-musakhan","name":"Musakhan (Sumac Chicken & Caramelised Onion)","category":"Grills & Mains","course":"Main","meal":"dinner","tier":"signature","inspiration":"EM SHERIF (Mireille Hayek, Beirut)","minutes":70,"serves":4,"level":"Project","idea":"Palestine's national dish: roast chicken over flatbread soaked in olive oil, sumac and a mountain of slow-cooked onions, scattered with toasted pine nuts. Sami Tamimi calls it the taste of home in Falastin; the tart hit of sumac against sweet onions and crisp-skinned chicken is unforgettable.","ingredients":[{"item":"8 bone-in skin-on chicken thighs (about 1 kg)","note":""},{"item":"5 large onions, thinly sliced (about 1 kg)","note":""},{"item":"90 ml extra virgin olive oil, plus more for the bread","note":""},{"item":"4 tbsp sumac, plus extra to finish","note":"tangy deep-red ground berry, lemony in flavour; world-foods aisle. Substitute lemon zest mixed with a little salt"},{"item":"1 tsp ground allspice","note":"warm spice tasting of cinnamon, clove and nutmeg combined; a mix of those works"},{"item":"1 tsp ground cumin","note":""},{"item":"1/2 tsp ground cinnamon","note":""},{"item":"1.5 tsp salt","note":""},{"item":"4 large flatbreads or taboon bread","note":"taboon is a soft Middle Eastern flatbread; large naan or thick pitta works"},{"item":"60 g pine nuts, toasted","note":"small soft cream-coloured nuts; flaked almonds are a cheaper stand-in"},{"item":"20 g flat-leaf parsley, chopped","note":"flat-leaf (Italian) parsley"},{"item":"1 lemon, in wedges","note":""}],"steps":["Heat the oven to 200C. Rub the chicken with 2 tbsp oil, 1 tbsp sumac, half the allspice, cumin, cinnamon and 1 tsp salt. Roast in a tray 35 to 40 minutes until cooked through and the skin is golden.","Meanwhile, cook the onions slowly in the remaining oil over medium-low heat for 25 to 30 minutes until soft, sweet and pale gold, stirring often.","Stir 3 tbsp sumac, the rest of the spices and 1/2 tsp salt through the onions and cook 2 minutes more.","Brush the flatbreads with oil, lay them on a tray and spread the onions over. Sit the roasted chicken on top and spoon over the pan juices.","Return to the oven for 8 to 10 minutes until the bread crisps at the edges.","Scatter with toasted pine nuts, parsley and more sumac. Serve with lemon wedges."],"pairing":"Cucumber-yoghurt salad and a glass of Lebanese Cinsault","tags":["Make-ahead","Comfort","Crowd-pleaser","Date night"],"vegetarian":false,"spicy":false,"calories":680,"protein":38,"carbs":42,"fat":40,"allergens":["Gluten","Tree nuts"],"role":"main","cuisineKey":"mediterranean","type":"Grills & BBQ"},{"id":"me-tabbouleh","name":"Tabbouleh","category":"Bowls & Salads","course":"Starter","meal":"both","tier":"easy","inspiration":"","minutes":25,"serves":4,"level":"Weeknight","idea":"The Levantine herb salad as it should be: overwhelmingly parsley and mint, with bulgur as a supporting whisper, not a bed. Hand-chopping keeps the herbs lively and green.","ingredients":[{"item":"40 g fine bulgur wheat","note":"fine-ground cracked wheat that just needs soaking; world-foods or grains aisle. Couscous can stand in"},{"item":"150 g flat-leaf parsley, very finely chopped","note":"flat-leaf (Italian) parsley; the salad is mostly parsley, so buy plenty"},{"item":"30 g fresh mint, finely chopped","note":""},{"item":"4 spring onions, finely sliced","note":"also called scallions or green onions"},{"item":"3 ripe tomatoes, finely diced","note":""},{"item":"60 ml fresh lemon juice","note":""},{"item":"60 ml extra virgin olive oil","note":""},{"item":"3/4 tsp salt","note":""},{"item":"1/4 tsp ground allspice","note":"warm spice tasting of cinnamon, clove and nutmeg; a pinch of mixed spice works"}],"steps":["Rinse the bulgur and soak in cold water 15 minutes until just tender, then drain and squeeze dry.","Soak the diced tomatoes briefly in their own juice, then drain off the excess.","Chop the parsley and mint by hand into fine ribbons; skip the food processor, which turns them to paste.","Combine the bulgur, herbs, spring onions and tomatoes.","Whisk the lemon, oil, salt and allspice and toss through just before serving."],"pairing":"Serve alongside grills, or with romaine leaves as scoops","tags":["Vegetarian","Vegan","Light","Quick","Make-ahead","Lunchbox"],"vegetarian":true,"spicy":false,"calories":210,"protein":3,"carbs":14,"fat":15,"allergens":["Gluten"],"role":"salad","cuisineKey":"mediterranean","type":"Salads"},{"id":"me-fattoush","name":"Fattoush","category":"Bowls & Salads","course":"Starter","meal":"both","tier":"easy","inspiration":"","minutes":25,"serves":4,"level":"Weeknight","idea":"A crunchy Levantine bread salad of crisp toasted pita, cucumber and tomato in a tangy sumac dressing. Toasting the pita and dressing late keeps every shard shatteringly crisp.","ingredients":[{"item":"2 pita breads, torn","note":"pocket flatbread; sold as pita or pitta"},{"item":"3 tbsp olive oil, for the pita","note":""},{"item":"3 baby cucumbers, sliced","note":"small thin-skinned Lebanese/Persian cucumbers; use half a regular cucumber instead"},{"item":"4 ripe tomatoes, cut into wedges","note":""},{"item":"1 baby gem lettuce, chopped","note":"small crisp lettuce; romaine/cos hearts work"},{"item":"4 radishes, thinly sliced","note":""},{"item":"4 spring onions, sliced","note":"scallions/green onions"},{"item":"20 g flat-leaf parsley, chopped","note":"flat-leaf (Italian) parsley"},{"item":"10 g fresh mint, chopped","note":""},{"item":"2 tbsp fresh lemon juice","note":""},{"item":"60 ml extra virgin olive oil","note":""},{"item":"1 tbsp sumac, plus extra to finish","note":"tangy lemony deep-red ground berry; world-foods aisle. Substitute extra lemon juice"},{"item":"1 small garlic clove, crushed","note":""},{"item":"1/2 tsp salt","note":""}],"steps":["Toss the torn pita with the 3 tbsp oil and bake at 200C for 8 to 10 minutes until deep golden, then cool.","Combine the cucumbers, tomatoes, lettuce, radishes, spring onions and herbs in a large bowl.","Whisk the lemon, oil, sumac, garlic and salt into a sharp dressing.","Add the crisp pita, pour over the dressing, toss, dust with more sumac and serve at once."],"pairing":"A natural partner to grilled meats; pair with a chilled dry rosé","tags":["Vegetarian","Vegan","Light","Quick","Crowd-pleaser"],"vegetarian":true,"spicy":false,"calories":280,"protein":4,"carbs":21,"fat":20,"allergens":["Gluten"],"role":"salad","cuisineKey":"mediterranean","type":"Salads"},{"id":"me-greek-salad","name":"Horiatiki (Greek Village Salad)","category":"Bowls & Salads","course":"Starter","meal":"both","tier":"easy","inspiration":"","minutes":15,"serves":4,"level":"Weeknight","idea":"The honest Greek village salad: chunky tomato, cucumber and pepper with a whole slab of feta on top, no lettuce in sight. Great olive oil and dried oregano are all it needs.","ingredients":[{"item":"500 g ripe tomatoes, cut into wedges","note":""},{"item":"1 cucumber, peeled in stripes and sliced thick","note":""},{"item":"1 green pepper, sliced into rings","note":"green bell/capsicum pepper"},{"item":"1 small red onion, thinly sliced","note":""},{"item":"100 g Kalamata olives","note":"large purple-black Greek olives; any good black olive works"},{"item":"200 g block Greek feta (do not crumble)","note":"salty tangy sheep/goat cheese; traditionally laid on top in a slab"},{"item":"60 ml extra virgin olive oil","note":""},{"item":"1 tbsp red wine vinegar","note":""},{"item":"1.5 tsp dried Greek oregano","note":"dried oregano, ideally the Greek kind sold on the branch; any dried oregano is fine"},{"item":"1/2 tsp salt","note":""}],"steps":["Pile the tomato, cucumber, pepper rings and red onion into a wide shallow bowl.","Scatter over the olives and season with the salt.","Lay the whole slab of feta on top rather than crumbling it.","Drizzle generously with oil and the vinegar, dust heavily with oregano and serve at once with bread."],"pairing":"Crusty bread for the juices and a chilled glass of Assyrtiko","tags":["Vegetarian","Gluten-free option","Light","Quick","Crowd-pleaser"],"vegetarian":true,"spicy":false,"calories":340,"protein":10,"carbs":11,"fat":29,"allergens":["Milk","Sulphites"],"role":"salad","cuisineKey":"mediterranean","type":"Salads"},{"id":"me-halloumi-grain-bowl","name":"Halloumi & Freekeh Bowl with Lemon-Herb Dressing","category":"Bowls & Salads","course":"Main","meal":"both","tier":"easy","inspiration":"","minutes":25,"serves":4,"level":"Weeknight","idea":"A filling lunch bowl of nutty grains, crisp pan-fried halloumi and a bright herb dressing. Uses a pouch of pre-cooked grains so it comes together fast, and it travels well for a lunchbox the next day.","ingredients":[{"item":"2 x 250 g pouches cooked freekeh or bulgur (or 300 g cooked from dry)","note":"freekeh is smoky roasted young wheat; cooked grain pouches are by the rice. Cooked bulgur or even brown rice works"},{"item":"2 x 225 g blocks halloumi, sliced","note":"firm salty cheese that holds its shape when fried; a squeaky grilling cheese"},{"item":"1 tbsp olive oil, for frying","note":""},{"item":"200 g cherry tomatoes, halved","note":""},{"item":"1 cucumber, diced","note":""},{"item":"60 g rocket","note":"peppery salad leaf, also called arugula"},{"item":"20 g mint, chopped","note":""},{"item":"20 g parsley, chopped","note":"flat-leaf (Italian) parsley"},{"item":"60 ml extra virgin olive oil","note":""},{"item":"2 tbsp lemon juice","note":""},{"item":"1 tsp honey","note":""},{"item":"1/2 tsp salt","note":""},{"item":"2 tbsp pomegranate seeds, to finish","note":"jewel-like seeds from a fresh pomegranate; sold in tubs too"}],"steps":["Warm the grains through and tip into a big bowl with the tomatoes, cucumber, rocket and herbs.","Fry the halloumi in the olive oil over medium-high heat 2 minutes a side until golden and crisp.","Whisk the extra virgin oil, lemon, honey and salt into a dressing and toss most of it through the grains.","Top with the hot halloumi, drizzle the rest of the dressing and scatter pomegranate seeds."],"pairing":"A chilled Assyrtiko or sparkling water with lemon","tags":["Vegetarian","Quick","Lunchbox","Make-ahead","Light"],"vegetarian":true,"spicy":false,"calories":620,"protein":28,"carbs":35,"fat":41,"allergens":["Gluten","Milk"],"role":"salad","cuisineKey":"mediterranean","type":"Salads"},{"id":"me-ottolenghi-roast-aubergine","name":"Roasted Aubergine with Saffron Yoghurt & Pomegranate","category":"Bowls & Salads","course":"Starter","meal":"both","tier":"signature","inspiration":"Ottolenghi (Yotam Ottolenghi, London)","minutes":50,"serves":4,"level":"Weekend","idea":"The dish from the cover of Ottolenghi's Plenty: aubergine halves roasted until collapsing, draped in saffron-stained yoghurt and showered with pomegranate seeds and za'atar. A study in contrast, soft and silky against jewel-bright tart seeds, that defined a generation of vegetable cooking.","ingredients":[{"item":"4 medium aubergines, halved lengthways","note":"also called eggplant"},{"item":"90 ml olive oil","note":""},{"item":"1 tsp salt","note":""},{"item":"1/2 tsp black pepper","note":""},{"item":"1 large pinch saffron threads","note":"dried crocus stigmas that add colour and aroma; a pinch of turmeric gives colour but not the same flavour"},{"item":"3 tbsp hot water","note":""},{"item":"250 g Greek yoghurt","note":"thick strained yoghurt"},{"item":"1 small garlic clove, crushed","note":""},{"item":"2 tbsp lemon juice","note":""},{"item":"1 tbsp extra virgin olive oil","note":""},{"item":"seeds of 1 pomegranate (about 120 g)","note":"the jewel-like seeds from a fresh pomegranate"},{"item":"2 tsp za'atar","note":"herb-and-sesame spice blend with thyme and sumac; world-foods aisle. Substitute dried thyme with a little sesame and a pinch of sumac"},{"item":"10 g mint leaves, torn","note":""}],"steps":["Heat the oven to 220C. Score the cut faces of the aubergines in a criss-cross, brush generously with the olive oil and season with salt and pepper.","Roast cut-side up for 35 to 40 minutes until deeply golden and completely soft. Cool to warm.","Steep the saffron in the hot water for 5 minutes, then whisk into the yoghurt with the garlic, lemon juice, extra virgin oil and a pinch of salt to a pourable cream.","Arrange the aubergines on a platter and spoon the saffron yoghurt generously over the cut faces.","Shower with pomegranate seeds, dust with za'atar and scatter the mint. Serve warm or at room temperature."],"pairing":"Warm flatbread and a glass of dry Provençal rosé","tags":["Vegetarian","Gluten-free option","Make-ahead","Light","Crowd-pleaser"],"vegetarian":true,"spicy":false,"calories":340,"protein":7,"carbs":20,"fat":27,"allergens":["Milk","Sesame"],"role":"salad","cuisineKey":"mediterranean","type":"Salads"},{"id":"me-shish-taouk","name":"Shish Taouk (Lebanese Garlic Chicken Skewers)","cuisineKey":"mediterranean","category":"Grills & Mains","role":"main","course":"Main","meal":"both","tier":"easy","inspiration":"","minutes":40,"serves":4,"level":"Weeknight","idea":"Yoghurt-and-garlic marinated chicken skewers, charred and served with toum and warm flatbread for a light, satisfying lunch or dinner main.","ingredients":[{"item":"800 g boneless skinless chicken thighs, cut into 3 cm pieces","note":""},{"item":"4 tbsp Greek yoghurt","note":"thick strained yoghurt"},{"item":"3 tbsp olive oil","note":""},{"item":"3 tbsp lemon juice","note":""},{"item":"5 garlic cloves, crushed","note":""},{"item":"1 tbsp tomato paste","note":"concentrated tomato puree (thick, from a tube or small tin)"},{"item":"1 tsp sweet paprika","note":""},{"item":"1 tsp dried oregano","note":""},{"item":"1/2 tsp ground allspice","note":"warm spice tasting of cinnamon, clove and nutmeg; mixed spice works"},{"item":"1 tsp salt","note":""},{"item":"1/2 tsp black pepper","note":""},{"item":"4 flatbreads, to serve","note":"pita or other flatbread"}],"steps":["Whisk yoghurt, olive oil, lemon juice, garlic, tomato paste, paprika, oregano, allspice, salt and pepper in a bowl.","Add the chicken and toss to coat. Cover and marinate at least 30 minutes, ideally 2 hours.","Thread the chicken onto skewers, leaving a little space between pieces.","Grill over high heat or under a hot grill for 10 to 12 minutes, turning, until charred and cooked through.","Rest 3 minutes, then serve on warm flatbread with toum and pickles."],"pairing":"Toum garlic sauce and warm flatbread","tags":["chicken","grilled","skewers","high-protein"],"vegetarian":false,"spicy":false,"calories":420,"protein":44,"carbs":22,"fat":17,"allergens":["Gluten","Milk"],"type":"Grills & BBQ"},{"id":"me-samke-harra","name":"Samke Harra (Spiced Tahini Baked Fish)","cuisineKey":"mediterranean","category":"Grills & Mains","role":"main","course":"Main","meal":"both","tier":"signature","inspiration":"EM SHERIF (Mireille Hayek, Beirut)","minutes":55,"serves":4,"level":"Weekend","idea":"A Tripoli classic of whole white fish baked under a fiery coriander, chilli and walnut tahini sauce, finished with toasted pine nuts in the refined Em Sherif style.","ingredients":[{"item":"4 sea bass or sea bream fillets (about 600 g)","note":"mild white fish fillets; cod, haddock or hake fillets also work"},{"item":"3 tbsp olive oil","note":""},{"item":"1 tsp salt","note":""},{"item":"1/2 tsp black pepper","note":""},{"item":"150 g light tahini, well stirred","note":"smooth sesame-seed paste; world-foods or hummus aisle"},{"item":"90 ml lemon juice","note":""},{"item":"120 ml water","note":""},{"item":"6 garlic cloves, crushed","note":""},{"item":"30 g fresh coriander, chopped","note":"fresh cilantro leaves"},{"item":"1 red chilli, finely chopped","note":""},{"item":"1 tsp ground cumin","note":""},{"item":"1/2 tsp Aleppo pepper","note":"mild fruity Syrian chilli flake; ordinary chilli flakes are fine"},{"item":"40 g pine nuts, toasted","note":"small soft cream-coloured nuts; flaked almonds substitute"},{"item":"20 g walnuts, chopped","note":""}],"steps":["Heat oven to 200 C. Pat the fish dry, rub with olive oil, salt and pepper and set in a baking dish.","Whisk tahini with lemon juice and water until smooth and pourable, loosening with more water if needed.","Soften the garlic, coriander, chilli, cumin and Aleppo pepper in a little oil for 2 minutes, then stir into the tahini.","Spoon the sauce over the fish to coat generously.","Bake 18 to 22 minutes until the fish flakes and the sauce is bubbling and just golden.","Scatter with toasted pine nuts and walnuts and serve with rice or flatbread."],"pairing":"Vermicelli rice and a squeeze of lemon","tags":["fish","baked","tahini","levantine"],"vegetarian":false,"spicy":true,"calories":510,"protein":40,"carbs":14,"fat":34,"allergens":["Fish","Sesame","Tree nuts"],"type":"Grills & BBQ"},{"id":"me-makloubeh","name":"Makloubeh (Upside-Down Spiced Chicken & Rice)","cuisineKey":"mediterranean","category":"Grills & Mains","role":"main","course":"Main","meal":"dinner","tier":"signature","inspiration":"Tawlet (Kamal Mouzawak, Beirut)","minutes":80,"serves":6,"level":"Project","idea":"The celebrated upside-down Levantine rice pot, layered with fried aubergine, spiced chicken and saffron rice, dramatically flipped at the table and showered with toasted nuts.","ingredients":[{"item":"8 bone-in skin-on chicken thighs (about 1 kg)","note":""},{"item":"2 large aubergines, sliced into rounds","note":"also called eggplant"},{"item":"1 large cauliflower, cut into florets","note":""},{"item":"400 g basmati rice, rinsed and soaked 20 minutes","note":"long-grain aromatic rice"},{"item":"2 tsp ground allspice","note":"warm spice tasting of cinnamon, clove and nutmeg; mixed spice works"},{"item":"1 tsp ground cinnamon","note":""},{"item":"1 tsp ground cumin","note":""},{"item":"1/2 tsp ground turmeric","note":"earthy yellow spice that adds colour"},{"item":"1 large pinch saffron","note":"dried crocus threads for colour and aroma; optional, or use a little extra turmeric"},{"item":"2 tsp salt","note":""},{"item":"90 ml olive oil","note":""},{"item":"1 litre chicken stock","note":"a stock cube in 1 litre water is fine"},{"item":"60 g pine nuts, toasted","note":"small soft cream-coloured nuts; flaked almonds substitute"},{"item":"60 g flaked almonds, toasted","note":""},{"item":"20 g parsley, chopped","note":"flat-leaf (Italian) parsley"}],"steps":["Simmer the chicken in the stock with half the spices and 1 tsp salt for 25 minutes, then reserve chicken and stock.","Fry or roast the aubergine and cauliflower in olive oil until deeply golden; drain.","In a heavy pot, layer the chicken skin-side down, then aubergine and cauliflower, then the drained spiced rice.","Pour over the reserved stock to just cover the rice, season, cover and cook gently 30 to 35 minutes until rice is tender.","Rest 10 minutes off the heat, place a large platter over the pot and confidently flip.","Scatter with pine nuts, almonds and parsley and serve with cucumber yoghurt."],"pairing":"Cucumber and mint yoghurt","tags":["chicken","rice","one-pot","celebration"],"vegetarian":false,"spicy":false,"calories":680,"protein":38,"carbs":62,"fat":32,"allergens":["Tree nuts"],"type":"Grills & BBQ"},{"id":"me-freekeh-roast-veg","name":"Smoky Freekeh with Roasted Vegetables & Tahini","cuisineKey":"mediterranean","category":"Grills & Mains","role":"main","course":"Main","meal":"both","tier":"easy","inspiration":"","minutes":45,"serves":4,"level":"Weeknight","idea":"Nutty smoked freekeh tossed with roasted squash, courgette and chickpeas under a lemon tahini drizzle, a hearty vegetarian main that holds up for lunch the next day.","ingredients":[{"item":"300 g freekeh, rinsed","note":"smoky roasted young green wheat with a nutty, firm bite; world-foods or grains aisle. Bulgur or pearl barley substitute"},{"item":"700 ml vegetable stock","note":"a stock cube in water is fine"},{"item":"500 g butternut squash, diced","note":""},{"item":"2 courgettes, sliced","note":"also called zucchini"},{"item":"1 x 400 g tin chickpeas, drained","note":""},{"item":"4 tbsp olive oil","note":""},{"item":"1 tsp ground cumin","note":""},{"item":"1 tsp sweet paprika","note":""},{"item":"1 tsp salt","note":""},{"item":"90 g light tahini, well stirred","note":"smooth sesame-seed paste; world-foods or hummus aisle"},{"item":"2 tbsp lemon juice","note":""},{"item":"60 ml water","note":""},{"item":"20 g parsley, chopped","note":"flat-leaf (Italian) parsley"},{"item":"2 tbsp pomegranate seeds","note":"jewel-like seeds from a fresh pomegranate"}],"steps":["Heat oven to 210 C. Toss squash, courgette and chickpeas with 3 tbsp oil, cumin, paprika and salt; roast 25 to 30 minutes until caramelised.","Meanwhile simmer freekeh in the stock for 20 to 25 minutes until tender, then drain any excess and fluff.","Whisk tahini with lemon juice and water to a pourable sauce.","Fold the roasted vegetables through the warm freekeh with the remaining oil.","Plate, drizzle generously with tahini and scatter parsley and pomegranate seeds."],"pairing":"A dollop of garlic yoghurt","tags":["grains","meal-prep","tahini"],"vegetarian":true,"spicy":false,"calories":540,"protein":18,"carbs":68,"fat":24,"allergens":["Gluten","Sesame"],"type":"Grills & BBQ"},{"id":"me-kibbeh-trio","name":"Baked Kibbeh with Pine Nuts","cuisineKey":"mediterranean","category":"Mezze","role":"appetizer","course":"Starter","meal":"both","tier":"signature","inspiration":"EM SHERIF (Mireille Hayek, Beirut)","minutes":70,"serves":6,"level":"Project","idea":"A burnished tray of bulgur and lamb kibbeh layered around a spiced pine-nut filling, cut into the classic diamonds, an Em Sherif table essential.","ingredients":[{"item":"300 g fine bulgur wheat","note":"fine-ground cracked wheat; world-foods or grains aisle. Use the fine grade so it binds"},{"item":"500 g lean minced lamb","note":"lean ground lamb, for the outer shell"},{"item":"1 onion, grated","note":""},{"item":"1.5 tsp ground allspice","note":"warm spice tasting of cinnamon, clove and nutmeg; mixed spice works"},{"item":"1 tsp ground cinnamon","note":""},{"item":"1 tsp salt","note":""},{"item":"1/2 tsp black pepper","note":""},{"item":"300 g minced lamb, for filling","note":"ground lamb, slightly fattier is fine here"},{"item":"1 onion, finely chopped, for filling","note":""},{"item":"60 g pine nuts, toasted","note":"small soft cream-coloured nuts; flaked almonds substitute"},{"item":"1 tbsp pomegranate molasses","note":"thick tangy-sweet pomegranate syrup; world-foods aisle. Substitute balsamic with a little honey"},{"item":"60 ml olive oil","note":""}],"steps":["Soak the bulgur in cold water 15 minutes, then squeeze dry.","Blend the bulgur, 500 g lamb, grated onion, allspice, cinnamon, salt and pepper to a smooth paste, adding a little iced water.","For the filling, fry the chopped onion and remaining lamb until browned, stir in pine nuts and pomegranate molasses, season and cool.","Press half the kibbeh paste into an oiled tray, spread the filling, then top with the remaining paste, smoothing the surface.","Score into diamonds, brush with olive oil and bake at 200 C for 30 to 35 minutes until deep golden.","Rest briefly and serve warm with yoghurt."],"pairing":"Cool labneh or garlic yoghurt","tags":["lamb","kibbeh","mezze","baked"],"vegetarian":false,"spicy":false,"calories":380,"protein":22,"carbs":26,"fat":21,"allergens":["Gluten","Tree nuts"],"type":"Starters"},{"id":"me-sambousek-cheese","name":"Sambousek (Cheese & Herb Pastries)","cuisineKey":"mediterranean","category":"Mezze","role":"appetizer","course":"Starter","meal":"both","tier":"easy","inspiration":"","minutes":45,"serves":6,"level":"Weekend","idea":"Crisp little half-moon pastries filled with melting akkawi and halloumi and fresh mint, a beloved Levantine mezze for sharing.","ingredients":[{"item":"12 sheets shortcrust or sambousek pastry rounds","note":"small savoury pastry discs; cut rounds from shortcrust pastry, or use spring-roll/samosa wrappers"},{"item":"200 g akkawi or low-moisture mozzarella, grated","note":"akkawi is a mild semi-soft Levantine cheese, often sold salted in brine; low-moisture mozzarella is the easy substitute"},{"item":"100 g halloumi, grated","note":"firm salty grilling cheese"},{"item":"20 g mint, chopped","note":""},{"item":"20 g parsley, chopped","note":"flat-leaf (Italian) parsley"},{"item":"1 spring onion, finely sliced","note":"scallion/green onion"},{"item":"1/2 tsp black pepper","note":""},{"item":"1 egg, beaten, for sealing","note":""},{"item":"1 litre neutral oil, for frying","note":"flavourless oil such as sunflower or vegetable"}],"steps":["Mix the cheeses, mint, parsley, spring onion and pepper into a filling.","Place a spoonful on each pastry round, brush the edge with egg and fold into a half-moon, crimping firmly.","Heat the oil to 175 C.","Fry the sambousek in batches for 2 to 3 minutes until golden and crisp.","Drain on paper and serve hot with a lemon wedge."],"pairing":"Lemon wedges and a tomato dip","tags":["pastry","cheese","fried","mezze"],"vegetarian":true,"spicy":false,"calories":300,"protein":11,"carbs":24,"fat":18,"allergens":["Gluten","Milk","Egg"],"type":"Starters"},{"id":"me-warak-enab","name":"Warak Enab (Stuffed Vine Leaves)","cuisineKey":"mediterranean","category":"Mezze","role":"appetizer","course":"Starter","meal":"both","tier":"easy","inspiration":"","minutes":75,"serves":6,"level":"Project","idea":"Vine leaves rolled tight around lemony herbed rice and slow-simmered until silky, the cold mezze that anchors every Levantine spread.","ingredients":[{"item":"250 g vine leaves in brine, rinsed","note":"preserved grape leaves in a jar; world-foods aisle. Rinse well to remove the salty brine"},{"item":"200 g short-grain rice, rinsed","note":"plump short-grain rice such as pudding or risotto rice"},{"item":"3 ripe tomatoes, finely diced","note":""},{"item":"1 onion, finely chopped","note":""},{"item":"30 g parsley, chopped","note":"flat-leaf (Italian) parsley"},{"item":"20 g mint, chopped","note":""},{"item":"90 ml extra virgin olive oil","note":""},{"item":"90 ml lemon juice","note":""},{"item":"1 tsp ground allspice","note":"warm spice tasting of cinnamon, clove and nutmeg; mixed spice works"},{"item":"1 tsp salt","note":""},{"item":"1/2 tsp black pepper","note":""},{"item":"400 ml water","note":""}],"steps":["Mix the rice, tomatoes, onion, herbs, half the olive oil, half the lemon juice, allspice, salt and pepper.","Lay a vine leaf vein-side up, place a little filling near the stem, fold the sides and roll tightly.","Line a pot with a few leaves, then pack the rolls in snug layers.","Pour over the water, remaining oil and lemon juice, weigh down with a plate and simmer gently 45 minutes until the rice is tender.","Cool in the pot, then serve at room temperature with lemon."],"pairing":"Thick labneh and lemon","tags":["vine-leaves","mezze","make-ahead"],"vegetarian":true,"spicy":false,"calories":240,"protein":4,"carbs":34,"fat":11,"allergens":[],"type":"Starters"},{"id":"me-batata-harra","name":"Batata Harra (Spicy Coriander Potatoes)","cuisineKey":"mediterranean","category":"Mezze","role":"appetizer","course":"Starter","meal":"both","tier":"easy","inspiration":"","minutes":35,"serves":4,"level":"Weeknight","idea":"Crisp cubes of potato tossed in garlic, coriander, chilli and lemon, a punchy hot mezze that disappears fast.","ingredients":[{"item":"800 g potatoes, cut into 2 cm cubes","note":"a floury/roasting variety such as Maris Piper or Russet"},{"item":"4 tbsp olive oil","note":""},{"item":"6 garlic cloves, crushed","note":""},{"item":"30 g fresh coriander, chopped","note":"fresh cilantro leaves; flat-leaf parsley works if you dislike coriander"},{"item":"1 red chilli, finely chopped","note":""},{"item":"1/2 tsp Aleppo pepper","note":"mild fruity Syrian chilli flake; ordinary chilli flakes are fine"},{"item":"1 tsp salt","note":""},{"item":"2 tbsp lemon juice","note":""}],"steps":["Heat oven to 220 C. Toss the potatoes with 3 tbsp oil and salt and roast 25 minutes until crisp and golden.","In a pan, warm the remaining oil and gently fry the garlic, chilli and Aleppo pepper for 1 minute.","Add the roasted potatoes and most of the coriander and toss to coat.","Finish with lemon juice and the remaining coriander and serve hot."],"pairing":"Garlic toum or labneh","tags":["potatoes","mezze"],"vegetarian":true,"spicy":true,"calories":260,"protein":4,"carbs":36,"fat":12,"allergens":[],"type":"Starters"},{"id":"me-salatet-rocca","name":"Salatet Rocca (Rocket, Tomato & Sumac Salad)","cuisineKey":"mediterranean","category":"Bowls & Salads","role":"salad","course":"Starter","meal":"both","tier":"easy","inspiration":"","minutes":15,"serves":4,"level":"Weeknight","idea":"Peppery rocket with sweet tomatoes, thin red onion and walnuts in a sumac and pomegranate dressing, the bright Levantine answer to a green salad.","ingredients":[{"item":"100 g rocket","note":"peppery salad leaf, also called arugula"},{"item":"250 g cherry tomatoes, halved","note":""},{"item":"1 small red onion, thinly sliced","note":""},{"item":"60 g walnuts, toasted","note":""},{"item":"2 tbsp extra virgin olive oil","note":""},{"item":"1 tbsp pomegranate molasses","note":"thick tangy-sweet pomegranate syrup; world-foods aisle. Substitute balsamic with a little honey"},{"item":"1 tbsp lemon juice","note":""},{"item":"1 tsp sumac","note":"tangy lemony deep-red ground berry; substitute a little extra lemon juice"},{"item":"1/2 tsp salt","note":""},{"item":"2 tbsp pomegranate seeds","note":"jewel-like seeds from a fresh pomegranate"}],"steps":["Whisk the olive oil, pomegranate molasses, lemon juice, sumac and salt into a dressing.","Combine the rocket, tomatoes and red onion in a bowl.","Toss with the dressing just before serving.","Scatter with walnuts and pomegranate seeds."],"pairing":"Grilled halloumi or any kebab","tags":["salad","sumac","quick"],"vegetarian":true,"spicy":false,"calories":210,"protein":4,"carbs":12,"fat":17,"allergens":["Tree nuts"],"type":"Salads"},{"id":"me-jajik-cucumber","name":"Khyar bi Laban (Cucumber Mint Yoghurt Salad)","cuisineKey":"mediterranean","category":"Bowls & Salads","role":"salad","course":"Starter","meal":"both","tier":"easy","inspiration":"","minutes":10,"serves":4,"level":"Weeknight","idea":"Cool strained yoghurt with crisp cucumber, garlic and dried mint, the calming foil to every grill and spice on the table.","ingredients":[{"item":"400 g Greek yoghurt","note":"thick strained yoghurt"},{"item":"2 baby cucumbers, finely diced","note":"small thin-skinned Lebanese/Persian cucumbers; use half a regular cucumber instead"},{"item":"1 small garlic clove, crushed","note":""},{"item":"2 tsp dried mint","note":"dried mint gives the classic flavour; or use 1 tbsp extra fresh mint"},{"item":"1 tbsp extra virgin olive oil","note":""},{"item":"1/2 tsp salt","note":""},{"item":"1 tbsp fresh mint, chopped","note":""}],"steps":["Stir the yoghurt with the garlic, dried mint and salt until smooth.","Fold in the diced cucumber.","Spoon into a bowl and drizzle with olive oil.","Finish with fresh mint and serve chilled."],"pairing":"Any kebab, kibbeh or rice dish","tags":["yoghurt","cooling","quick"],"vegetarian":true,"spicy":false,"calories":120,"protein":7,"carbs":7,"fat":7,"allergens":["Milk"],"type":"Salads"},{"id":"me-loubieh-salad","name":"Loubieh b'Zeit (Braised Green Beans in Olive Oil)","cuisineKey":"mediterranean","category":"Bowls & Salads","role":"salad","course":"Starter","meal":"both","tier":"easy","inspiration":"","minutes":40,"serves":4,"level":"Weeknight","idea":"Green beans slow-braised with tomato, onion and garlic in good olive oil, served at room temperature as a classic Levantine cold dish.","ingredients":[{"item":"500 g green beans, trimmed","note":"also sold as French or fine beans"},{"item":"1 onion, sliced","note":""},{"item":"4 garlic cloves, sliced","note":""},{"item":"400 g ripe tomatoes, chopped","note":"or a 400 g tin of chopped tomatoes"},{"item":"60 ml extra virgin olive oil","note":""},{"item":"1 tsp ground allspice","note":"warm spice tasting of cinnamon, clove and nutmeg; mixed spice works"},{"item":"1 tsp salt","note":""},{"item":"1/2 tsp black pepper","note":""},{"item":"1 tbsp lemon juice","note":""}],"steps":["Soften the onion and garlic in the olive oil over medium heat for 5 minutes.","Add the tomatoes, allspice, salt and pepper and cook down for 5 minutes.","Stir in the green beans, cover and braise gently 25 minutes until very tender and glossy.","Finish with lemon juice, cool to room temperature and serve."],"pairing":"Warm flatbread to mop the oil","tags":["beans","braised","make-ahead"],"vegetarian":true,"spicy":false,"calories":190,"protein":4,"carbs":16,"fat":13,"allergens":[],"type":"Salads"},{"id":"it-pizza-margherita","name":"Pizza Margherita","category":"Pizza","course":"Main","meal":"both","tier":"easy","inspiration":"","minutes":30,"serves":2,"level":"Weeknight","idea":"The benchmark pie made approachable: shop-bought dough, raw crushed tomato, milky mozzarella and fresh basil. Three or four good ingredients doing all the work in a hot home oven.","ingredients":[{"item":"2 ready-made pizza dough balls (about 250g each)","note":"sold chilled near the fresh pasta, or use a pizza base kit"},{"item":"200g tinned chopped tomatoes, drained slightly","note":""},{"item":"180g fresh mozzarella (fior di latte), torn and patted dry","note":"soft white Italian cheese sold in balls in water; the firmer block 'pizza mozzarella' also works and melts well"},{"item":"8 fresh basil leaves","note":""},{"item":"2 tbsp olive oil","note":""},{"item":"plain flour for dusting","note":""},{"item":"pinch of salt","note":""}],"steps":["Heat the oven as hot as it goes (250C or higher) with a baking tray or stone inside for at least 20 minutes.","Season the tomatoes with a pinch of salt and a little oil. Do not cook them.","Stretch each dough ball by hand on a floured surface into a round, leaving a thicker rim.","Spread a thin layer of tomato, scatter the mozzarella and drizzle with oil.","Slide onto the hot tray and bake 8 to 10 minutes until the crust is golden and the cheese bubbles.","Finish with fresh basil and a thread of oil. Repeat with the second pizza."],"pairing":"A chilled light red or sparkling water with lemon","tags":["Vegetarian","Crowd-pleaser","Comfort","Quick"],"vegetarian":true,"spicy":false,"calories":620,"protein":24,"carbs":78,"fat":24,"allergens":["Gluten","Milk"],"role":"main","cuisineKey":"italian","type":"Pizza"},{"id":"it-pizza-marinara","name":"Pizza Marinara","category":"Pizza","course":"Main","meal":"both","tier":"easy","inspiration":"","minutes":30,"serves":2,"level":"Weeknight","idea":"The oldest Neapolitan pizza, dressed only with tomato, garlic, oregano and oil. No cheese at all, proof that a good crust needs almost nothing to sing. Naturally vegan and pantry-friendly.","ingredients":[{"item":"2 ready-made pizza dough balls (about 250g each)","note":"sold chilled near the fresh pasta, or use a pizza base kit"},{"item":"220g tinned chopped tomatoes","note":""},{"item":"3 garlic cloves, thinly sliced","note":""},{"item":"1 tsp dried oregano","note":""},{"item":"3 tbsp olive oil","note":""},{"item":"plain flour for dusting","note":""},{"item":"pinch of salt","note":""}],"steps":["Heat the oven as hot as it goes with a tray or stone inside for at least 20 minutes.","Season the tomatoes with a pinch of salt.","Stretch each dough ball by hand into a round with a raised rim.","Spread the tomato thinly, scatter the sliced garlic and oregano, and drizzle generously with oil.","Bake 8 to 10 minutes until the rim is golden and puffed.","Finish with a last drizzle of oil and serve at once."],"pairing":"A crisp dry white or chilled lager","tags":["Vegan","Crowd-pleaser","Comfort","Quick"],"vegetarian":true,"spicy":false,"calories":570,"protein":13,"carbs":80,"fat":23,"allergens":["Gluten"],"role":"main","cuisineKey":"italian","type":"Pizza"},{"id":"it-pizza-prosciutto-rucola","name":"Pizza with Mozzarella, Rocket and Tomato","category":"Pizza","course":"Main","meal":"both","tier":"easy","inspiration":"","minutes":25,"serves":2,"level":"Weeknight","idea":"A bistro-style pizza finished cold: melted mozzarella under a tangle of peppery rocket, sweet cherry tomatoes and shaved Parmesan. Fresh, fast and a guaranteed crowd-pleaser with kids and adults alike.","ingredients":[{"item":"2 ready-made pizza dough balls (about 250g each)","note":"sold chilled near the fresh pasta, or use a pizza base kit"},{"item":"200g fresh mozzarella (fior di latte), torn and patted dry","note":"soft white Italian cheese sold in balls in water; the firmer block 'pizza mozzarella' also works"},{"item":"150g cherry tomatoes, halved","note":""},{"item":"60g rocket","note":"peppery salad leaf, also labelled arugula"},{"item":"30g Parmesan, shaved","note":"hard Italian cheese; Grana Padano is a cheaper swap"},{"item":"3 tbsp olive oil","note":""},{"item":"plain flour for dusting","note":""},{"item":"salt and pepper","note":""}],"steps":["Heat the oven as hot as it goes with a tray inside for 20 minutes.","Stretch each dough ball into a round, brush lightly with oil and scatter over the mozzarella.","Bake 8 to 10 minutes until golden and bubbling.","Toss the rocket and cherry tomatoes with a little oil, salt and pepper.","Pile the salad onto the hot pizzas, shave over the Parmesan and finish with a drizzle of oil.","Slice and serve right away while the base is crisp."],"pairing":"A light Pinot Grigio or sparkling water","tags":["Vegetarian","Quick","Light","Crowd-pleaser"],"vegetarian":true,"spicy":false,"calories":640,"protein":28,"carbs":75,"fat":26,"allergens":["Gluten","Milk"],"role":"main","cuisineKey":"italian","type":"Pizza"},{"id":"it-pizza-margherita-sbagliata","name":"Margherita Sbagliata","category":"Pizza","course":"Main","meal":"dinner","tier":"signature","inspiration":"Osteria Francescana (Massimo Bottura)","minutes":120,"serves":2,"level":"Project","idea":"Franco Pepe's deconstructed Margherita from Caiazzo, repeatedly crowned among the world's best pizzas. The cheese cream and basil go on the airy, just-baked crust, then tomato is piped on raw in concentric drops so each element reads on its own.","ingredients":[{"item":"300g tipo 00 flour","note":"extra-fine Italian wheat flour; strong white bread flour or plain flour works"},{"item":"210ml cold water","note":""},{"item":"6g fine sea salt","note":""},{"item":"1g instant dry yeast","note":"fast-action dried yeast, sold in sachets in the baking aisle"},{"item":"250g tinned San Marzano tomatoes, blended and lightly seasoned","note":"sweet, low-acid Italian plum tomatoes; any tinned whole plum tomatoes work"},{"item":"200g fior di latte mozzarella","note":"soft cow's-milk mozzarella sold in balls in water; standard fresh mozzarella is fine"},{"item":"60ml double cream","note":"heavy cream; whipping cream works"},{"item":"large handful fresh basil, blitzed with a little oil into a bright sauce","note":""},{"item":"extra virgin olive oil","note":""},{"item":"semolina for dusting","note":"coarse golden wheat flour that stops dough sticking; fine flour works"}],"steps":["Mix flour, water and yeast to a shaggy dough, add salt and knead 10 minutes until smooth. Cover and prove 1 hour, then ball up and rest 4 to 6 hours, or overnight in the fridge.","Blend the mozzarella with the cream into a smooth, spoonable cheese cream and chill. Season the blended tomato lightly and keep it raw.","Heat the oven to its absolute maximum with a steel or stone for at least 45 minutes.","Stretch one dough ball by hand into a 28cm round with a pronounced rim and bake plain, or with just a film of oil, 6 to 8 minutes until blistered and puffed.","On the hot base spread the cold cheese cream, then dot the basil sauce over it.","Pipe the raw tomato in small concentric drops across the top so it stays vivid and uncooked.","Finish with a thread of olive oil and serve immediately, repeating for the second pizza."],"pairing":"A grower Champagne or a dry Falanghina","tags":["Vegetarian","Date night","Comfort"],"vegetarian":true,"spicy":false,"calories":600,"protein":22,"carbs":72,"fat":24,"allergens":["Gluten","Milk"],"role":"main","cuisineKey":"italian","type":"Pizza"},{"id":"it-spaghetti-aglio-olio","name":"Spaghetti Aglio e Olio","category":"Pasta","course":"Main","meal":"both","tier":"easy","inspiration":"","minutes":15,"serves":2,"level":"Weeknight","idea":"The midnight classic from four pantry staples: garlic and chilli warmed gently in good oil, tossed through spaghetti with parsley. The fastest real dinner in the Italian repertoire.","ingredients":[{"item":"200g spaghetti","note":""},{"item":"4 garlic cloves, thinly sliced","note":""},{"item":"0.5 tsp chilli flakes","note":"dried crushed red chilli, also sold as crushed red pepper"},{"item":"5 tbsp olive oil","note":""},{"item":"small handful flat-leaf parsley, chopped","note":"flat-leaf is milder than curly; curly parsley works"},{"item":"salt for the pasta water","note":""}],"steps":["Boil the spaghetti in well-salted water until al dente, reserving a mugful of water before draining.","Meanwhile gently warm the oil with the garlic and chilli until the garlic is pale gold, never browned.","Add the drained pasta and a splash of pasta water, tossing hard to bind into a light, glossy sauce.","Stir through the parsley, season and serve at once."],"pairing":"A crisp dry white or sparkling water","tags":["Vegan","Quick","Comfort","One-pan"],"vegetarian":true,"spicy":false,"calories":560,"protein":11,"carbs":70,"fat":27,"allergens":["Gluten"],"role":"main","cuisineKey":"italian","type":"Pasta"},{"id":"it-penne-pomodoro-basilico","name":"Penne al Pomodoro e Basilico","category":"Pasta","course":"Main","meal":"both","tier":"easy","inspiration":"","minutes":25,"serves":4,"level":"Weeknight","idea":"The everyday red sauce done properly: tinned tomatoes simmered with garlic and a knob of butter until sweet and silky, tossed with penne and torn basil. A reliable family workhorse that batch-cooks beautifully.","ingredients":[{"item":"400g penne","note":""},{"item":"800g tinned chopped tomatoes (2 tins)","note":""},{"item":"3 garlic cloves, sliced","note":""},{"item":"30g butter","note":""},{"item":"3 tbsp olive oil","note":""},{"item":"large handful fresh basil","note":""},{"item":"40g Parmesan, grated, to serve","note":"hard Italian cheese; Grana Padano is a cheaper swap"},{"item":"salt and a pinch of sugar","note":""}],"steps":["Soften the garlic in the oil over low heat until fragrant, do not colour.","Add the tomatoes, a pinch of salt and sugar, and simmer 15 to 18 minutes until thick and sweet.","Stir in the butter and torn basil for gloss and roundness.","Cook the penne in well-salted water until al dente and drain, saving a splash of water.","Toss the pasta through the sauce with a little reserved water to coat.","Serve with grated Parmesan."],"pairing":"A young Sangiovese or red grape juice for the kids","tags":["Vegetarian","Batch-cook","Comfort","Crowd-pleaser"],"vegetarian":true,"spicy":false,"calories":480,"protein":15,"carbs":78,"fat":12,"allergens":["Gluten","Milk"],"role":"main","cuisineKey":"italian","type":"Pasta"},{"id":"it-spaghetti-carbonara","name":"Spaghetti alla Carbonara","category":"Pasta","course":"Main","meal":"both","tier":"easy","inspiration":"","minutes":25,"serves":2,"level":"Weeknight","idea":"Rome's most argued-over plate: egg yolks, Pecorino, crisp guanciale and black pepper emulsified into a glossy, clinging sauce. No cream, the silk comes from technique alone.","ingredients":[{"item":"200g spaghetti","note":""},{"item":"120g guanciale or pancetta, cut into lardons","note":"guanciale is cured pork cheek; pancetta (cured belly) or smoked streaky bacon both work"},{"item":"3 large egg yolks plus 1 whole egg","note":""},{"item":"60g Pecorino Romano, finely grated","note":"hard, salty sheep's-milk cheese; Parmesan works as a substitute"},{"item":"1 tsp freshly cracked black pepper, plus extra","note":""},{"item":"salt for the pasta water","note":""}],"steps":["Boil the spaghetti in well-salted water until al dente, reserving a mugful of starchy water before draining.","Render the guanciale in a cold dry pan over medium heat until the fat is golden and the meat crisp, then take off the heat.","Whisk the yolks, whole egg, Pecorino and black pepper into a thick paste.","Add the drained pasta to the guanciale pan off the heat, tossing in the rendered fat.","Loosen the egg mixture with a spoon of hot pasta water, add to the pan and toss vigorously off the heat, adding more water until the sauce turns creamy and coats every strand.","Serve immediately with extra Pecorino and a grind of pepper. The residual heat cooks the egg gently without scrambling it."],"pairing":"A dry Frascati Superiore","tags":["Quick","Comfort","Crowd-pleaser"],"vegetarian":false,"spicy":false,"calories":720,"protein":31,"carbs":72,"fat":34,"allergens":["Gluten","Egg","Milk"],"role":"main","cuisineKey":"italian","type":"Pasta"},{"id":"it-cacio-e-pepe","name":"Cacio e Pepe","category":"Pasta","course":"Main","meal":"both","tier":"easy","inspiration":"","minutes":20,"serves":2,"level":"Weeknight","idea":"Three ingredients, real technique. Pecorino and toasted black pepper bound with starchy water into a creamy sauce. The temperature trick is the whole game.","ingredients":[{"item":"200g spaghetti or tonnarelli","note":"tonnarelli is a thick square-cut spaghetti; ordinary spaghetti is fine"},{"item":"100g Pecorino Romano, very finely grated","note":"hard, salty sheep's-milk cheese; Parmesan works as a substitute"},{"item":"2 tsp whole black peppercorns, coarsely cracked","note":""},{"item":"salt for the pasta water","note":""}],"steps":["Boil the pasta in lightly salted water (Pecorino is salty) until just shy of al dente, reserving plenty of starchy water.","Toast the cracked pepper in a dry pan 30 seconds until fragrant, then add a ladle of pasta water to make a peppery broth.","In a bowl, mix the grated Pecorino with a little cool pasta water into a smooth paste, never hot or it will clump.","Drain the pasta into the pepper pan and toss to coat.","Off the heat, add the Pecorino paste and toss hard, loosening with more starchy water until glossy and creamy.","Serve at once, the sauce should cling, never pool."],"pairing":"A mineral white or sparkling water","tags":["Vegetarian","Quick","Comfort"],"vegetarian":true,"spicy":false,"calories":520,"protein":22,"carbs":72,"fat":15,"allergens":["Gluten","Milk"],"role":"main","cuisineKey":"italian","type":"Pasta"},{"id":"it-penne-all-arrabbiata","name":"Penne all'Arrabbiata","category":"Pasta","course":"Main","meal":"both","tier":"easy","inspiration":"","minutes":25,"serves":2,"level":"Weeknight","idea":"Angry pasta, the Roman way: garlic and dried chilli bloomed in oil, tomatoes reduced to a punchy sauce. Fiery, fast and built from the storecupboard.","ingredients":[{"item":"200g penne rigate","note":"ridged penne ('rigate' means ridged); plain penne works"},{"item":"400g tinned chopped tomatoes","note":""},{"item":"3 garlic cloves, sliced","note":""},{"item":"1 tsp chilli flakes (or 2 crumbled dried chillies)","note":"dried crushed red chilli, also sold as crushed red pepper"},{"item":"4 tbsp olive oil","note":""},{"item":"small handful flat-leaf parsley, chopped","note":"flat-leaf is milder than curly; curly parsley works"},{"item":"salt","note":""}],"steps":["Boil the penne in well-salted water until al dente, reserving some pasta water.","Gently warm the oil with the garlic and chilli until the garlic is pale gold and the oil is fragrant, do not burn it.","Add the tomatoes, season with salt and simmer 12 to 15 minutes until thick and glossy.","Drain the pasta and toss in the sauce with a splash of pasta water to bind.","Stir through the parsley and serve. Traditionally no cheese in Rome.","Adjust the heat with more chilli at the end."],"pairing":"A robust Montepulciano d'Abruzzo","tags":["Vegan","Quick","Spicy"],"vegetarian":true,"spicy":true,"calories":520,"protein":12,"carbs":78,"fat":18,"allergens":["Gluten"],"role":"main","cuisineKey":"italian","type":"Pasta"},{"id":"it-pasta-al-forno","name":"Pasta al Forno","category":"Pasta","course":"Main","meal":"both","tier":"easy","inspiration":"","minutes":35,"serves":4,"level":"Weeknight","idea":"The family baked pasta that beats fiddly lasagne on a busy night: penne tossed in a quick tomato sauce with mozzarella and Parmesan, then baked until the top is bubbling and the edges crisp. One dish, big batch, kids clear the plate.","ingredients":[{"item":"400g penne or rigatoni","note":"rigatoni are large ridged tubes; either pasta works for baking"},{"item":"800g tinned chopped tomatoes (2 tins)","note":""},{"item":"3 garlic cloves, sliced","note":""},{"item":"3 tbsp olive oil","note":""},{"item":"200g fresh mozzarella (fior di latte), torn and drained","note":"soft white Italian cheese sold in balls in water"},{"item":"60g Parmesan, grated","note":"hard Italian cheese; Grana Padano is a cheaper swap"},{"item":"large handful fresh basil","note":""},{"item":"salt and a pinch of sugar","note":""}],"steps":["Heat the oven to 200C. Soften the garlic in the oil over low heat, then add the tomatoes, a pinch of salt and sugar and simmer 15 minutes until thick. Tear in the basil.","Boil the pasta in well-salted water for two minutes less than the packet says, so it finishes in the oven, then drain.","Toss the pasta through most of the sauce in a baking dish, folding in half the mozzarella.","Top with the rest of the sauce, the remaining mozzarella and the Parmesan.","Bake 15 to 18 minutes until bubbling and golden with crisp edges.","Rest 5 minutes, then serve."],"pairing":"A young Sangiovese or red grape juice for the kids","tags":["Vegetarian","Batch-cook","Comfort","Crowd-pleaser"],"vegetarian":true,"spicy":false,"calories":560,"protein":23,"carbs":80,"fat":16,"allergens":["Gluten","Milk"],"role":"main","cuisineKey":"italian","type":"Pasta"},{"id":"it-rigatoni-vodka","name":"Spicy Rigatoni alla Vodka","category":"Pasta","course":"Main","meal":"dinner","tier":"signature","inspiration":"Carbone","minutes":40,"serves":4,"level":"Weekend","idea":"The dish that broke the internet: Carbone's luxe, blushing vodka sauce with a low hum of Calabrian chilli, clinging to ridged rigatoni and finished with a storm of Parmesan. Restaurant decadence built at home.","ingredients":[{"item":"400g rigatoni","note":"large ridged pasta tubes"},{"item":"1 onion, finely chopped","note":""},{"item":"4 garlic cloves, minced","note":""},{"item":"70g tomato puree (double concentrate)","note":"thick concentrated tomato paste sold in tubes or small tins"},{"item":"2 tbsp Calabrian chilli paste (or 1 tsp chilli flakes)","note":"spicy southern Italian chilli paste from the world-foods or deli aisle; chilli flakes or harissa work"},{"item":"60ml vodka","note":""},{"item":"250ml double cream","note":"heavy cream; whipping cream works"},{"item":"60g butter","note":""},{"item":"80g Parmesan, finely grated, plus extra","note":"hard Italian cheese; Grana Padano is a cheaper swap"},{"item":"3 tbsp olive oil","note":""},{"item":"fresh basil","note":""},{"item":"salt","note":""}],"steps":["Soften the onion gently in the oil and half the butter until sweet and translucent, about 8 minutes, then add the garlic for a minute.","Stir in the tomato puree and Calabrian chilli and cook until the paste darkens and turns rust-red, 4 to 5 minutes, to kill the raw edge.","Pour in the vodka and let it cook off for a minute, then stir in the cream to a smooth, blushing sauce. Simmer gently 5 minutes.","Cook the rigatoni in well-salted water until al dente, reserving a mug of water.","Toss the pasta into the sauce with the remaining butter and the Parmesan, loosening with pasta water until glossy and emulsified.","Finish with extra Parmesan and torn basil, and serve at once."],"pairing":"A bright Barbera or a Negroni to start","tags":["Spicy","Date night","Comfort","Crowd-pleaser"],"vegetarian":true,"spicy":true,"calories":680,"protein":18,"carbs":78,"fat":31,"allergens":["Gluten","Milk"],"role":"main","cuisineKey":"italian","type":"Pasta"},{"id":"it-risotto-parmigiano","name":"Risotto al Parmigiano","category":"Risotto","course":"Main","meal":"both","tier":"easy","inspiration":"","minutes":30,"serves":4,"level":"Weeknight","idea":"The plain white risotto every Italian cook leans on: rice toasted, fed with stock and finished with butter and Parmesan into something creamy and comforting. The blank canvas, and delicious on its own.","ingredients":[{"item":"320g Arborio or Carnaroli rice","note":"short-grain Italian risotto rice; either works, Carnaroli holds its bite better"},{"item":"1 small onion, finely diced","note":""},{"item":"150ml dry white wine (optional)","note":""},{"item":"1.2 litres hot vegetable stock","note":""},{"item":"60g butter","note":""},{"item":"70g Parmesan, grated","note":"hard Italian cheese; Grana Padano is a cheaper swap"},{"item":"2 tbsp olive oil","note":""},{"item":"salt and pepper","note":""}],"steps":["Sweat the onion in the oil and half the butter until soft and translucent.","Add the rice and toast 2 minutes until the edges turn glassy. Add the wine if using and let it evaporate.","Add the hot stock a ladle at a time, stirring, letting each addition absorb before the next, about 18 minutes until al dente and creamy.","Off the heat, beat in the cold butter and Parmesan vigorously until glossy.","Rest 1 minute, season and serve loose so it spreads when plated."],"pairing":"A soft Soave or sparkling water","tags":["Vegetarian","Comfort","Gluten-free option"],"vegetarian":true,"spicy":false,"calories":480,"protein":11,"carbs":68,"fat":16,"allergens":["Milk","Sulphites"],"role":"main","cuisineKey":"italian","type":"Rice & Bowls"},{"id":"it-risotto-ai-funghi","name":"Risotto ai Funghi","category":"Risotto","course":"Main","meal":"both","tier":"easy","inspiration":"","minutes":40,"serves":4,"level":"Weekend","idea":"Earthy mushrooms folded into creamy rice, finished with butter and Parmesan. A handful of dried porcini in the stock builds a deep, woodsy flavour that fresh mushrooms alone cannot reach.","ingredients":[{"item":"320g Carnaroli or Arborio rice","note":"short-grain Italian risotto rice; either works"},{"item":"20g dried porcini","note":"dried wild mushrooms with a deep savoury flavour; soak in warm water first, found in the world-foods aisle"},{"item":"250g chestnut mushrooms, sliced","note":"brown cap mushrooms; white button mushrooms work"},{"item":"1 small onion, finely diced","note":""},{"item":"150ml dry white wine","note":""},{"item":"1.2 litres hot vegetable stock","note":""},{"item":"60g butter","note":""},{"item":"60g Parmesan, grated","note":"hard Italian cheese; Grana Padano is a cheaper swap"},{"item":"2 tbsp olive oil","note":""},{"item":"small handful parsley, chopped","note":""},{"item":"salt and pepper","note":""}],"steps":["Soak the dried porcini in 300ml warm water 20 minutes, then lift out, chop, and strain the liquor into the stock.","Sweat the onion in oil and half the butter, add the fresh mushrooms and porcini and cook until golden.","Stir in the rice and toast 2 minutes, then add the wine and let it evaporate.","Add the hot stock a ladle at a time, stirring, about 18 minutes until al dente and creamy.","Off the heat, beat in the cold butter and Parmesan to mantecare.","Rest 1 minute, scatter parsley and serve loose."],"pairing":"A Barbera d'Alba or earthy red","tags":["Vegetarian","Comfort","Gluten-free option"],"vegetarian":true,"spicy":false,"calories":470,"protein":11,"carbs":67,"fat":15,"allergens":["Milk","Sulphites"],"role":"main","cuisineKey":"italian","type":"Rice & Bowls"},{"id":"it-risotto-zucca","name":"Risotto alla Zucca","category":"Risotto","course":"Main","meal":"both","tier":"easy","inspiration":"","minutes":35,"serves":4,"level":"Weeknight","idea":"A sweet, golden butternut squash risotto that kids actually eat. The squash half-melts into the rice for natural creaminess, finished with sage butter and Parmesan. Cosy autumn comfort from supermarket basics.","ingredients":[{"item":"320g Arborio rice","note":"short-grain Italian risotto rice"},{"item":"500g butternut squash, peeled and diced","note":"any firm orange squash or pumpkin works"},{"item":"1 small onion, finely diced","note":""},{"item":"150ml dry white wine (optional)","note":""},{"item":"1.2 litres hot vegetable stock","note":""},{"item":"60g butter","note":""},{"item":"8 sage leaves","note":"soft grey-green herb with an earthy flavour; sold fresh in the herb section"},{"item":"60g Parmesan, grated","note":"hard Italian cheese; Grana Padano is a cheaper swap"},{"item":"2 tbsp olive oil","note":""},{"item":"salt and pepper","note":""}],"steps":["Sweat the onion in oil and half the butter, then add the squash and cook 5 minutes to soften.","Stir in the rice and toast 2 minutes, add the wine if using and let it evaporate.","Add the hot stock a ladle at a time, stirring, about 18 minutes; the squash will break down and thicken the rice.","Crisp the sage in the remaining butter in a small pan.","Off the heat, beat the Parmesan and sage butter through the risotto until glossy.","Rest 1 minute, season and serve."],"pairing":"A light off-dry white or apple juice for the kids","tags":["Vegetarian","Comfort","Gluten-free option","Crowd-pleaser"],"vegetarian":true,"spicy":false,"calories":470,"protein":10,"carbs":72,"fat":15,"allergens":["Milk","Sulphites"],"role":"main","cuisineKey":"italian","type":"Rice & Bowls"},{"id":"it-risotto-oro-zafferano","name":"Riso, Oro e Zafferano","category":"Risotto","course":"Main","meal":"dinner","tier":"signature","inspiration":"Le Calandre","minutes":45,"serves":4,"level":"Weekend","idea":"Gualtiero Marchesi's iconic 1981 reinvention of Risotto alla Milanese: a flawless saffron risotto crowned with a square of edible gold leaf. The defining dish of modern Italian cuisine, all about precision and the all'onda wave.","ingredients":[{"item":"320g Carnaroli rice","note":"short-grain Italian risotto rice; Arborio works too"},{"item":"1 small onion, very finely diced","note":""},{"item":"1 generous pinch saffron threads (about 0.2g)","note":"dried red-gold flower stigmas that colour and flavour the rice; sold in tiny jars in the spice aisle, a small turmeric pinch can stand in for colour only"},{"item":"150ml dry white wine","note":""},{"item":"1.2 litres hot vegetable or light chicken stock","note":""},{"item":"100g cold butter, cubed","note":""},{"item":"80g Parmesan, grated","note":"hard Italian cheese; Grana Padano is a cheaper swap"},{"item":"4 squares edible gold leaf (optional, to finish)","note":"thin edible gold sheets for decoration, from cake-decorating shops; simply leave out if unavailable"},{"item":"salt and white pepper","note":"white pepper is milder and keeps the dish pale; black pepper works"}],"steps":["Bloom the saffron in a small cup of warm stock to release its colour and aroma.","Sweat the onion in a little of the butter until completely soft and translucent, with no colour.","Add the rice dry and toast 2 to 3 minutes until the grains are hot and glassy, then add the wine and let it evaporate.","Add the hot stock a ladle at a time, stirring constantly, for about 16 minutes, stirring in the saffron stock halfway through.","When the rice is al dente, take off the heat and mantecare hard with the cold butter and Parmesan until intensely glossy and rippling.","Plate so the risotto spreads in a smooth all'onda wave, then lay a square of gold leaf at the centre of each plate."],"pairing":"A Franciacorta or a fine oaked Chardonnay","tags":["Vegetarian","Date night","Gluten-free option","Comfort"],"vegetarian":true,"spicy":false,"calories":540,"protein":12,"carbs":66,"fat":23,"allergens":["Milk","Sulphites"],"role":"main","cuisineKey":"italian","type":"Rice & Bowls"},{"id":"it-pollo-alla-parmigiana","name":"Pollo alla Parmigiana","category":"Secondi","course":"Main","meal":"both","tier":"easy","inspiration":"","minutes":45,"serves":4,"level":"Weekend","idea":"Crisp breaded chicken under a bright tomato sauce and melting mozzarella. A trattoria favourite that hinges on a thin, well-seasoned crumb and a sauce that stays lively. A guaranteed family win.","ingredients":[{"item":"4 chicken breasts, butterflied and lightly pounded","note":"sliced almost in half and opened flat, then flattened thin"},{"item":"100g plain flour","note":""},{"item":"2 eggs, beaten","note":""},{"item":"150g fine dried breadcrumbs","note":"use panko or shop-bought dried breadcrumbs"},{"item":"50g Parmesan, grated, plus extra","note":"hard Italian cheese; Grana Padano is a cheaper swap"},{"item":"400g tinned chopped tomatoes","note":""},{"item":"2 garlic cloves, sliced","note":""},{"item":"200g fresh mozzarella (fior di latte), sliced and drained","note":"soft white Italian cheese sold in balls in water"},{"item":"handful fresh basil","note":""},{"item":"olive oil for frying","note":""},{"item":"salt and pepper","note":""}],"steps":["Make a quick sauce: soften the garlic in oil, add the tomatoes, season and simmer 15 minutes until thick. Tear in basil.","Season the chicken, then coat in flour, beaten egg, then the breadcrumbs mixed with the grated Parmesan.","Shallow-fry in hot oil until golden and crisp on both sides, then drain on paper.","Heat the oven to 200C. Spread a little sauce in a dish, lay in the chicken, spoon over more sauce and top with mozzarella and Parmesan.","Bake 12 to 15 minutes until the cheese is bubbling and the chicken reaches 74C at the centre.","Finish with basil and rest 5 minutes before serving."],"pairing":"A medium-bodied Chianti Classico","tags":["Crowd-pleaser","Comfort"],"vegetarian":false,"spicy":false,"calories":620,"protein":52,"carbs":38,"fat":28,"allergens":["Gluten","Egg","Milk"],"role":"main","cuisineKey":"italian","type":"Mains"},{"id":"it-melanzane-alla-parmigiana","name":"Melanzane alla Parmigiana","category":"Secondi","course":"Main","meal":"dinner","tier":"signature","inspiration":"Osteria Francescana (Massimo Bottura)","minutes":75,"serves":4,"level":"Weekend","idea":"Layers of aubergine, tomato, basil and cheese baked into a rich southern classic. Comfort food that eats as a hearty main and is even better the next day. Make-ahead friendly.","ingredients":[{"item":"1kg aubergines, sliced 1cm thick","note":"also called eggplant"},{"item":"700g passata","note":"smooth sieved tomato sauce sold in jars or cartons; blend tinned tomatoes if needed"},{"item":"2 garlic cloves, sliced","note":""},{"item":"250g fresh mozzarella (fior di latte), sliced and drained","note":"soft white Italian cheese sold in balls in water"},{"item":"80g Parmesan, grated","note":"hard Italian cheese; Grana Padano is a cheaper swap"},{"item":"large handful fresh basil","note":""},{"item":"olive oil for frying","note":""},{"item":"1 tsp sugar","note":""},{"item":"salt","note":""}],"steps":["Salt the aubergine slices in a colander 30 minutes, then pat dry.","Make the sauce: soften the garlic in oil, add the passata, sugar and salt, and simmer 20 minutes. Tear in basil.","Fry the aubergine in batches in hot oil until golden, draining on paper. (Or brush with oil and roast at 220C to save time.)","Heat the oven to 180C. Layer: sauce, aubergine, mozzarella, Parmesan, basil. Repeat for three or four layers, ending with sauce and Parmesan.","Bake 35 to 40 minutes until bubbling and golden.","Rest at least 15 minutes before serving so it sets and slices cleanly."],"pairing":"A bright Cerasuolo di Vittoria","tags":["Vegetarian","Make-ahead","Comfort","Crowd-pleaser"],"vegetarian":true,"spicy":false,"calories":430,"protein":19,"carbs":22,"fat":29,"allergens":["Milk"],"role":"main","cuisineKey":"italian","type":"Mains"},{"id":"it-scaloppine-limone","name":"Chicken Scaloppine al Limone","category":"Secondi","course":"Main","meal":"both","tier":"easy","inspiration":"","minutes":25,"serves":4,"level":"Weeknight","idea":"Thin chicken escalopes dusted in flour, pan-fried and finished in a bright lemon-butter sauce. Elegant enough for guests, fast enough for a Tuesday, made from everyday ingredients.","ingredients":[{"item":"4 chicken breasts, sliced thin and lightly pounded","note":"sliced into thin flat cutlets, then flattened"},{"item":"60g plain flour for dusting","note":""},{"item":"150ml chicken stock","note":""},{"item":"juice of 1.5 lemons","note":""},{"item":"50g butter","note":""},{"item":"2 tbsp olive oil","note":""},{"item":"small handful parsley, chopped","note":""},{"item":"salt and pepper","note":""}],"steps":["Season the chicken and dust lightly in flour, shaking off the excess.","Heat the oil and half the butter and fry the escalopes 2 to 3 minutes a side until golden and just cooked, then set aside.","Pour the stock and lemon juice into the pan, scraping up the browned bits, and reduce by half.","Swirl in the remaining cold butter to make a glossy sauce and check the seasoning.","Return the chicken to coat, scatter with parsley and serve at once with the sauce spooned over."],"pairing":"A crisp Vermentino or sparkling water with lemon","tags":["Quick","Light","Crowd-pleaser"],"vegetarian":false,"spicy":false,"calories":410,"protein":42,"carbs":13,"fat":20,"allergens":["Gluten","Milk"],"role":"main","cuisineKey":"italian","type":"Mains"},{"id":"it-saltimbocca-alla-romana","name":"Saltimbocca alla Romana","category":"Secondi","course":"Main","meal":"both","tier":"easy","inspiration":"","minutes":25,"serves":2,"level":"Weeknight","idea":"Veal escalopes wrapped with prosciutto and sage, pan-fried and finished in a white wine butter sauce. The name means jump in the mouth, and it does, fast and elegant.","ingredients":[{"item":"4 thin veal escalopes (about 400g)","note":"thin slices of veal; thin pork or turkey escalopes work"},{"item":"4 slices prosciutto di Parma","note":"thinly sliced cured Italian ham; any prosciutto or Serrano ham works"},{"item":"8 fresh sage leaves","note":"soft grey-green herb with an earthy flavour; from the herb section"},{"item":"30g plain flour for dusting","note":""},{"item":"120ml dry white wine","note":""},{"item":"40g butter","note":""},{"item":"2 tbsp olive oil","note":""},{"item":"salt and black pepper","note":""}],"steps":["Lay a sage leaf on each escalope, cover with a slice of prosciutto and press or secure with a cocktail stick.","Lightly dust the veal side with flour, shaking off the excess.","Heat the oil and half the butter, fry prosciutto side down 1 minute, then flip and cook 1 to 2 minutes until just done, keeping the veal tender.","Remove the veal and keep warm. Pour the wine into the pan, scraping up the browned bits, and reduce by half.","Swirl in the remaining cold butter to make a glossy sauce, seasoning carefully as the prosciutto is salty.","Spoon the sauce over the saltimbocca and serve at once."],"pairing":"A dry Vernaccia di San Gimignano","tags":["Quick","Date night"],"vegetarian":false,"spicy":false,"calories":520,"protein":48,"carbs":10,"fat":29,"allergens":["Gluten","Milk","Sulphites"],"role":"main","cuisineKey":"italian","type":"Mains"},{"id":"it-osso-buco-alla-milanese","name":"Osso Buco alla Milanese","category":"Secondi","course":"Main","meal":"dinner","tier":"signature","inspiration":"Le Calandre","minutes":150,"serves":4,"level":"Project","idea":"The great Lombard braise that Gualtiero Marchesi paired with his gold-leaf saffron risotto: cross-cut veal shanks cooked low and slow with wine and broth until the meat slips from the bone, finished with a vivid lemon, garlic and parsley gremolata.","ingredients":[{"item":"4 thick veal shank slices (osso buco), about 1.2kg","note":"cross-cut slices of veal shin with the marrow bone; ask the butcher for osso buco, beef shin works"},{"item":"plain flour for dusting","note":""},{"item":"1 onion, 1 carrot, 1 celery stick, finely diced","note":""},{"item":"200ml dry white wine","note":""},{"item":"400ml veal or beef stock","note":""},{"item":"2 tbsp tomato puree","note":"concentrated tomato paste from a tube or small tin"},{"item":"40g butter and 2 tbsp olive oil","note":""},{"item":"for the gremolata: zest of 1 lemon, 1 garlic clove and a handful of parsley, all finely chopped","note":"gremolata is a fresh raw garnish of lemon zest, garlic and parsley stirred in at the end"},{"item":"salt and pepper","note":""}],"steps":["Tie each shank around the middle with string so it holds shape, season and dust lightly with flour.","Brown the shanks well in the butter and oil, then set aside.","Sweat the onion, carrot and celery in the same pan until soft. Stir in the tomato puree, pour in the wine and reduce by half.","Return the shanks, add the stock to come most of the way up, cover and braise gently (oven at 160C or low on the hob) about 1.5 to 2 hours until fork-tender.","Make the gremolata by mixing the lemon zest, garlic and parsley.","Scatter the gremolata over the shanks, check the seasoning and serve with saffron risotto."],"pairing":"A structured Barolo or Barbaresco","tags":["Make-ahead","Comfort","Date night"],"vegetarian":false,"spicy":false,"calories":540,"protein":58,"carbs":12,"fat":26,"allergens":["Gluten","Milk","Sulphites"],"role":"main","cuisineKey":"italian","type":"Mains"},{"id":"it-tagliatelle-ragu-bolognese","name":"Tagliatelle al Ragu Bolognese","cuisineKey":"italian","category":"Pasta","course":"Main","meal":"both","tier":"signature","inspiration":"Osteria Francescana (Massimo Bottura)","minutes":150,"serves":4,"level":"Weekend","idea":"The list has vodka and cacio e pepe but no slow ragu, the dish parents most want to batch-cook and freeze. Hazan's milk-and-wine method is the authoritative, forgiving reference.","ingredients":[{"item":"400g fresh tagliatelle","note":"long flat ribbon pasta; dried tagliatelle or pappardelle works"},{"item":"400g beef mince","note":"ground beef"},{"item":"150g pancetta, finely diced","note":"cured Italian pork belly; smoked streaky bacon works"},{"item":"1 onion, finely diced","note":""},{"item":"1 carrot, finely diced","note":""},{"item":"1 celery stalk, finely diced","note":""},{"item":"250ml whole milk","note":""},{"item":"250ml white wine","note":""},{"item":"400g tinned chopped tomatoes","note":""},{"item":"2 tbsp olive oil","note":""},{"item":"Grated nutmeg","note":"warm sweet spice; buy whole and grate, or use a pinch of ground nutmeg"},{"item":"Parmesan to serve","note":"hard Italian cheese; Grana Padano is a cheaper swap"},{"item":"Salt and pepper to taste","note":""}],"steps":["Soften the onion, carrot and celery in the olive oil over medium heat until translucent, about 8 minutes. Add the pancetta and cook 3 minutes.","Add the beef and cook, breaking it up, until it loses its raw colour but does not brown hard.","Pour in the milk and a grating of nutmeg, simmer gently until the milk is absorbed.","Add the wine and simmer until evaporated, then stir in the tomatoes and a little salt.","Cook uncovered on the lowest possible heat for 2 hours, stirring occasionally, until rich and thick. Season.","Cook the tagliatelle, toss with the ragu and a splash of pasta water, and serve with Parmesan. Freezes and reheats beautifully."],"pairing":"A glass of Sangiovese","tags":["make-ahead","freezer-friendly","crowd-pleaser","batch-cook"],"vegetarian":false,"spicy":false,"calories":680,"protein":36,"carbs":62,"fat":30,"allergens":["Gluten","Milk","Sulphites"],"role":"main","type":"Pasta"},{"id":"it-bruschetta-pomodoro","name":"Bruschetta al Pomodoro","cuisineKey":"italian","category":"Secondi","role":"appetizer","course":"Starter","meal":"both","tier":"easy","inspiration":"","minutes":15,"serves":4,"level":"Weeknight","idea":"Grilled rustic bread rubbed with garlic and piled with marinated ripe tomatoes and basil.","ingredients":[{"item":"8 slices rustic sourdough or ciabatta","note":"any firm, crusty country bread works"},{"item":"400g ripe tomatoes, diced","note":""},{"item":"1 garlic clove, halved, plus 1 clove minced","note":""},{"item":"8 fresh basil leaves, torn","note":""},{"item":"4 tbsp extra virgin olive oil","note":""},{"item":"1 tsp red wine vinegar","note":""},{"item":"salt and pepper","note":""}],"steps":["Toss the diced tomatoes with minced garlic, basil, 2 tbsp olive oil, the vinegar, salt and pepper. Let sit 10 minutes.","Grill or toast the bread until golden and crisp on both sides.","Rub each warm slice with the cut side of the halved garlic clove.","Spoon the marinated tomatoes over the bread, drizzle with the remaining olive oil and serve immediately."],"pairing":"A chilled glass of Vermentino or sparkling water with lemon","tags":["quick","classic"],"vegetarian":true,"spicy":false,"calories":230,"protein":6,"carbs":29,"fat":10,"allergens":["Gluten","Sulphites"],"type":"Starters"},{"id":"it-arancini-mozzarella","name":"Arancini di Riso","cuisineKey":"italian","category":"Risotto","role":"appetizer","course":"Starter","meal":"both","tier":"easy","inspiration":"","minutes":50,"serves":4,"level":"Weekend","idea":"Crisp golden risotto balls with a molten mozzarella centre.","ingredients":[{"item":"300g cooked risotto rice, cooled","note":"leftover or freshly made Parmesan risotto, fully cooled so it holds shape"},{"item":"60g Parmesan, grated","note":"hard Italian cheese; Grana Padano is a cheaper swap"},{"item":"2 eggs, beaten","note":""},{"item":"100g fresh mozzarella (fior di latte), cut into small cubes","note":"soft white Italian cheese; the firmer block type is easier to cube and melts neatly"},{"item":"100g plain flour","note":""},{"item":"150g fine dried breadcrumbs","note":"use panko or shop-bought dried breadcrumbs"},{"item":"sunflower oil for frying","note":"any flavourless oil for deep-frying, such as vegetable or rapeseed"},{"item":"salt and pepper","note":""}],"steps":["Mix the cooled risotto with the Parmesan, one beaten egg, salt and pepper.","Take a heaped spoonful, press a cube of mozzarella into the centre and shape into a ball, sealing the cheese inside.","Roll each ball in flour, then the remaining beaten egg, then the breadcrumbs.","Heat oil to 175C and fry the arancini in batches until deep golden and crisp, about 3 to 4 minutes.","Drain on kitchen paper, season lightly and serve hot."],"pairing":"A crisp Sicilian white such as Grillo","tags":["fried","sicilian"],"vegetarian":true,"spicy":false,"calories":420,"protein":15,"carbs":48,"fat":18,"allergens":["Gluten","Milk","Egg"],"type":"Starters"},{"id":"it-caponata-siciliana","name":"Caponata Siciliana","cuisineKey":"italian","category":"Secondi","role":"appetizer","course":"Starter","meal":"both","tier":"easy","inspiration":"","minutes":45,"serves":4,"level":"Weeknight","idea":"Sweet and sour Sicilian aubergine relish with celery, capers and olives, served on toasted bread.","ingredients":[{"item":"2 aubergines, diced","note":"also called eggplant"},{"item":"1 onion, chopped","note":""},{"item":"2 celery sticks, diced","note":""},{"item":"200g tinned chopped tomatoes","note":""},{"item":"2 tbsp capers, rinsed","note":"small pickled flower buds with a salty tang; from the olive or condiment aisle"},{"item":"60g green olives, pitted and chopped","note":""},{"item":"2 tbsp red wine vinegar","note":""},{"item":"1 tbsp sugar","note":""},{"item":"4 tbsp olive oil","note":""},{"item":"8 slices toasted bread to serve","note":""},{"item":"salt and pepper","note":""}],"steps":["Fry the diced aubergine in olive oil over medium high heat until golden, then set aside.","In the same pan soften the onion and celery, then add the tomatoes, capers and olives.","Stir in the vinegar and sugar and simmer 5 minutes to make a sweet and sour base.","Return the aubergine, season and cook gently 10 minutes until thick. Cool to room temperature.","Pile onto toasted bread and serve."],"pairing":"A glass of dry Marsala or Nero d'Avola","tags":["sicilian","sweet-and-sour"],"vegetarian":true,"spicy":false,"calories":260,"protein":6,"carbs":32,"fat":13,"allergens":["Gluten","Sulphites"],"type":"Starters"},{"id":"it-insalata-caprese","name":"Insalata Caprese","cuisineKey":"italian","category":"Secondi","role":"salad","course":"Starter","meal":"both","tier":"easy","inspiration":"","minutes":10,"serves":4,"level":"Weeknight","idea":"Layered fresh mozzarella, ripe tomatoes and basil dressed simply with olive oil.","ingredients":[{"item":"400g buffalo mozzarella, sliced","note":"creamy mozzarella made from buffalo milk; ordinary cow's-milk fresh mozzarella works"},{"item":"500g ripe tomatoes, sliced","note":""},{"item":"large handful fresh basil leaves","note":""},{"item":"4 tbsp extra virgin olive oil","note":""},{"item":"flaky sea salt","note":"coarse flaked salt such as Maldon; any sea salt works"},{"item":"freshly ground black pepper","note":""}],"steps":["Arrange alternating slices of tomato and mozzarella on a platter.","Tuck basil leaves between the slices.","Drizzle generously with extra virgin olive oil.","Finish with flaky salt and black pepper and serve at room temperature."],"pairing":"A chilled glass of Fiano di Avellino","tags":["no-cook","classic"],"vegetarian":true,"spicy":false,"calories":290,"protein":16,"carbs":7,"fat":23,"allergens":["Milk"],"type":"Salads"},{"id":"it-panzanella","name":"Panzanella","cuisineKey":"italian","category":"Secondi","role":"salad","course":"Starter","meal":"both","tier":"easy","inspiration":"","minutes":20,"serves":4,"level":"Weeknight","idea":"Tuscan bread salad of toasted sourdough soaked in ripe tomato juices with cucumber, red onion and basil.","ingredients":[{"item":"300g stale sourdough, torn into chunks","note":"day-old crusty bread; dry fresh bread in a low oven if needed"},{"item":"500g ripe tomatoes, cut into wedges","note":""},{"item":"1 cucumber, diced","note":""},{"item":"0.5 red onion, thinly sliced","note":""},{"item":"large handful fresh basil leaves","note":""},{"item":"4 tbsp extra virgin olive oil","note":""},{"item":"2 tbsp red wine vinegar","note":""},{"item":"salt and pepper","note":""}],"steps":["Toast the bread chunks until crisp and golden, then let cool.","Toss the tomatoes with a good pinch of salt and let them release their juices for 10 minutes.","Combine the bread, tomatoes and their juices, cucumber, red onion and basil.","Dress with olive oil and red wine vinegar, season and let stand 10 minutes so the bread softens slightly before serving."],"pairing":"A light Chianti served cool","tags":["tuscan","bread-salad"],"vegetarian":true,"spicy":false,"calories":280,"protein":7,"carbs":38,"fat":11,"allergens":["Gluten","Sulphites"],"type":"Salads"},{"id":"it-insalata-rucola-parmigiano","name":"Insalata di Rucola e Parmigiano","cuisineKey":"italian","category":"Secondi","role":"salad","course":"Starter","meal":"both","tier":"easy","inspiration":"","minutes":10,"serves":4,"level":"Weeknight","idea":"Peppery rocket with shaved Parmesan, lemon and good olive oil.","ingredients":[{"item":"120g rocket","note":"peppery salad leaf, also labelled arugula"},{"item":"60g Parmesan, shaved","note":"hard Italian cheese; Grana Padano is a cheaper swap"},{"item":"3 tbsp extra virgin olive oil","note":""},{"item":"juice of 0.5 lemon","note":""},{"item":"30g pine nuts, lightly toasted","note":"small soft nuts from pine cones; flaked almonds work as a cheaper swap"},{"item":"salt and pepper","note":""}],"steps":["Whisk the olive oil with the lemon juice, salt and pepper to make a light dressing.","Place the rocket in a bowl and toss gently with just enough dressing to coat.","Scatter over the shaved Parmesan and toasted pine nuts.","Add a final crack of pepper and serve immediately."],"pairing":"A glass of Gavi di Gavi","tags":["quick","no-cook"],"vegetarian":true,"spicy":false,"calories":210,"protein":8,"carbs":4,"fat":18,"allergens":["Milk","Tree nuts"],"type":"Salads"},{"id":"ja-salmon-teriyaki-donburi","name":"Salmon Teriyaki Donburi","category":"Sushi & Rice bowls","course":"Main","meal":"both","tier":"easy","inspiration":"","minutes":30,"serves":2,"level":"Weeknight","idea":"Pan-seared salmon lacquered in a four-ingredient teriyaki reduction over hot rice. The sauce caramelises around the fillet so the skin stays crisp while the flesh stays just-set and silky.","ingredients":[{"item":"2 salmon fillets, skin on (about 150 g each)","note":""},{"item":"300 g Japanese short-grain (sushi) rice","note":"sticky white rice sold as sushi rice; risotto/arborio is the closest fallback"},{"item":"360 ml water","note":""},{"item":"4 tbsp soy sauce","note":""},{"item":"3 tbsp mirin","note":"sweet Japanese rice wine; substitute 3 tbsp water or sake plus 1 tsp sugar"},{"item":"2 tbsp sake","note":"Japanese rice wine; substitute dry sherry or dry white wine, or leave out"},{"item":"1 tbsp caster sugar","note":""},{"item":"1 tsp neutral oil (sunflower or vegetable)","note":""},{"item":"2 spring onions, finely sliced","note":""},{"item":"1 tsp toasted white sesame seeds","note":"sold in the world-foods or baking aisle; any sesame seeds, toasted in a dry pan, work"}],"steps":["Rinse the rice until the water runs clear, drain, then cook with the 360 ml water (rice cooker or covered pan, 12 minutes plus 10 minutes steam off the heat).","Mix soy sauce, mirin, sake and sugar in a small bowl until the sugar dissolves.","Pat the salmon dry. Heat the oil in a non-stick pan over medium-high and sear skin-side down 3 to 4 minutes until crisp, then flip and cook 2 minutes more until the flesh is just opaque.","Pour in the teriyaki mix and let it bubble and reduce 2 to 3 minutes, spooning it over the fish until it turns glossy and thickly coats the fillets.","Divide rice between two bowls, top with salmon, spoon over the pan sauce, and finish with spring onion and sesame seeds."],"pairing":"An off-dry Riesling or a cold glass of Junmai sake.","tags":["Quick","Comfort","Crowd-pleaser","Gluten-free option"],"vegetarian":false,"spicy":false,"calories":620,"protein":34,"carbs":72,"fat":20,"allergens":["Fish","Gluten","Soy","Sesame","Sulphites"],"role":"main","cuisineKey":"japanese","type":"Rice & Bowls"},{"id":"ja-gyudon","name":"Gyudon (Simmered Beef Rice Bowl)","category":"Sushi & Rice bowls","course":"Main","meal":"both","tier":"easy","inspiration":"","minutes":25,"serves":2,"level":"Weeknight","idea":"Thinly sliced beef and sweet onion simmered in a dashi-soy broth until meltingly tender, then piled on rice. Japan's ultimate fast comfort food, done properly at home in under half an hour.","ingredients":[{"item":"300 g thinly sliced beef ribeye or sirloin (shabu-shabu cut)","note":"paper-thin beef from Asian shops; or freeze a steak 30 min and slice it as thin as you can"},{"item":"300 g Japanese short-grain (sushi) rice","note":"sticky white rice sold as sushi rice; risotto/arborio is the closest fallback"},{"item":"360 ml water for rice","note":""},{"item":"1 large onion, thinly sliced","note":""},{"item":"200 ml dashi stock","note":"Japanese sea-stock from kelp and dried fish; make from dashi powder, or use light fish or veg stock"},{"item":"3 tbsp soy sauce","note":""},{"item":"2 tbsp mirin","note":"sweet Japanese rice wine; substitute 2 tbsp water plus 1 tsp sugar"},{"item":"2 tbsp sake","note":"Japanese rice wine; substitute dry sherry or dry white wine, or leave out"},{"item":"1 tbsp caster sugar","note":""},{"item":"2 egg yolks","note":"served raw on top; use the freshest eggs you can, or skip if you prefer"},{"item":"2 spring onions, sliced","note":""},{"item":"1 tsp pickled red ginger (beni shoga)","note":"thin red strips of pickled ginger; or use ordinary pink sushi ginger (gari)"}],"steps":["Rinse and cook the rice with the 360 ml water.","In a wide pan, bring dashi, soy sauce, mirin, sake and sugar to a simmer, add the onion and cook 4 to 5 minutes until soft.","Add the beef, separating the slices, and simmer gently 3 to 4 minutes just until no longer pink, skimming any foam.","Spoon the beef and onion with plenty of broth over bowls of rice.","Top each bowl with a raw egg yolk, sliced spring onion and a pinch of beni shoga."],"pairing":"A cold lager such as Asahi or Sapporo.","tags":["Quick","Comfort","Crowd-pleaser","One-pan"],"vegetarian":false,"spicy":false,"calories":680,"protein":35,"carbs":75,"fat":26,"allergens":["Fish","Gluten","Soy","Egg","Sulphites"],"role":"main","cuisineKey":"japanese","type":"Rice & Bowls"},{"id":"ja-chicken-soboro-don","name":"Chicken Soboro Donburi","category":"Sushi & Rice bowls","course":"Main","meal":"both","tier":"easy","inspiration":"","minutes":20,"serves":2,"level":"Weeknight","idea":"Two-tone rice bowl of savoury-sweet minced chicken alongside a fluffy ribbon of seasoned scrambled egg. A genuine Japanese home-cooking staple that is fast, cheap and a guaranteed hit with kids.","ingredients":[{"item":"300 g chicken mince","note":"minced/ground chicken; turkey mince works too"},{"item":"300 g Japanese short-grain (sushi) rice","note":"sticky white rice sold as sushi rice; risotto/arborio is the closest fallback"},{"item":"360 ml water for rice","note":""},{"item":"3 eggs","note":""},{"item":"3 tbsp soy sauce","note":""},{"item":"2 tbsp mirin","note":"sweet Japanese rice wine; substitute 2 tbsp water plus 1 tsp sugar"},{"item":"1 tbsp sake","note":"Japanese rice wine; substitute dry sherry, or leave out"},{"item":"1 tbsp caster sugar","note":""},{"item":"10 g ginger, grated","note":""},{"item":"1 tsp neutral oil (sunflower or vegetable)","note":""},{"item":"2 spring onions, sliced","note":""},{"item":"1 tsp toasted white sesame seeds","note":"any sesame seeds, toasted in a dry pan, work"}],"steps":["Rinse and cook the rice with the 360 ml water.","Put the chicken mince in a cold pan with soy sauce, mirin, sake, sugar and ginger, then cook over medium heat, stirring to break up clumps, 5 to 6 minutes until the liquid has mostly cooked away.","Beat the eggs with a pinch of salt. Heat the oil in a second pan over low heat and scramble the egg slowly into soft small curds, then remove.","Divide rice between two bowls and spoon the chicken over one half and the egg over the other.","Finish with spring onion and sesame seeds."],"pairing":"Cold barley tea (mugicha) or a light lager.","tags":["Quick","Comfort","Crowd-pleaser","Lunchbox","Make-ahead"],"vegetarian":false,"spicy":false,"calories":640,"protein":38,"carbs":68,"fat":22,"allergens":["Egg","Gluten","Soy","Sesame","Sulphites"],"role":"main","cuisineKey":"japanese","type":"Rice & Bowls"},{"id":"ja-tsujihan-kaisendon","name":"Tsujihan-Style Kaisen Don","category":"Sushi & Rice bowls","course":"Main","meal":"dinner","tier":"signature","inspiration":"Tsujihan (Tsukiji, Tokyo)","minutes":50,"serves":2,"level":"Weekend","idea":"A homage to the queue-out-the-door bowl that made Tsujihan famous: a mound of sashimi-grade fish and ikura over vinegared rice, eaten halfway, then transformed at the table when you pour hot sea bream dashi over the rest to finish it as a silky ochazuke.","ingredients":[{"item":"300 g Japanese short-grain (sushi) rice","note":"sticky white rice sold as sushi rice; risotto/arborio is the closest fallback"},{"item":"360 ml water","note":""},{"item":"3 tbsp rice vinegar","note":"mild vinegar made from rice; substitute cider vinegar or white wine vinegar"},{"item":"1 tbsp caster sugar","note":""},{"item":"1 tsp fine salt","note":""},{"item":"150 g sashimi-grade tuna, sliced","note":"raw-safe tuna from a fishmonger; tell them it is to eat raw"},{"item":"120 g sashimi-grade sea bream or sea bass, sliced","note":"raw-safe white fish; ask the fishmonger for sashimi grade"},{"item":"100 g sashimi-grade salmon, sliced","note":"raw-safe salmon; previously frozen is safest for eating raw"},{"item":"3 tbsp salmon roe (ikura)","note":"large orange salmon eggs; sold in jars at fishmongers or Asian shops, or leave out"},{"item":"400 ml dashi stock","note":"Japanese sea-stock from kelp and dried fish; make from dashi powder, or use light fish stock"},{"item":"1 tsp light soy sauce","note":"thinner, saltier, paler soy sauce; ordinary soy sauce is fine"},{"item":"2 sheets nori, shredded","note":"dried seaweed sheets used for sushi; sold in the world-foods aisle"},{"item":"1 tbsp grated wasabi","note":"fiery green Japanese horseradish; tube or paste is fine"},{"item":"1 tbsp pickled ginger (gari)","note":"thin pink sweet-pickled ginger served with sushi"}],"steps":["Rinse and cook the rice with the water, then tip into a wide bowl.","Warm the rice vinegar, sugar and salt until dissolved, fold through the hot rice with a cutting motion, and fan to cool to body temperature.","Slice all the fish cleanly and evenly, reserving two slices of sea bream per person for the second course.","Pack the seasoned rice into two deep bowls and arrange the tuna, sea bream, salmon and a generous spoon of ikura on top, then scatter with shredded nori and add the wasabi and gari.","Eat the bowl roughly halfway, then warm the dashi with the light soy until just below a simmer.","Lay the reserved sea bream over the remaining rice, pour the hot dashi over the top to gently set the fish, and finish the bowl as ochazuke."],"pairing":"Chilled Junmai Daiginjo sake or hot hojicha to match the dashi finish.","tags":["Date night","Crowd-pleaser","Light"],"vegetarian":false,"spicy":false,"calories":540,"protein":40,"carbs":70,"fat":10,"allergens":["Fish","Soy","Gluten","Sulphites"],"role":"main","cuisineKey":"japanese","type":"Rice & Bowls"},{"id":"ja-yaki-udon","name":"Chicken Yaki Udon","category":"Ramen & Noodles","course":"Main","meal":"both","tier":"easy","inspiration":"","minutes":20,"serves":2,"level":"Weeknight","idea":"Thick, chewy udon stir-fried hard and fast with chicken and cabbage in a savoury-sweet soy and oyster sauce. A 20-minute wok dinner with proper smoky wok hei character.","ingredients":[{"item":"400 g pre-cooked udon noodles","note":"thick white wheat noodles; sold vacuum-packed or frozen; thick wheat noodles or even spaghetti substitute"},{"item":"250 g chicken thigh, thinly sliced","note":""},{"item":"200 g white cabbage, roughly chopped","note":""},{"item":"1 carrot, julienned","note":"cut into thin matchsticks"},{"item":"2 spring onions, cut into batons","note":"cut into short 3-4 cm lengths"},{"item":"2 tbsp soy sauce","note":""},{"item":"1 tbsp oyster sauce","note":"thick savoury-sweet sauce in the Asian aisle; substitute hoisin or extra soy with a pinch of sugar"},{"item":"1 tbsp mirin","note":"sweet Japanese rice wine; substitute 1 tbsp water plus a pinch of sugar"},{"item":"1 tsp dashi powder","note":"instant Japanese stock powder; substitute a crumbled fish or chicken stock cube"},{"item":"1 tbsp neutral oil (sunflower or vegetable)","note":""},{"item":"1 tbsp bonito flakes to finish","note":"wispy dried tuna flakes (katsuobushi); they wave with steam; optional, leave out if unavailable"},{"item":"1 tsp pickled red ginger (beni shoga)","note":"thin red strips of pickled ginger; or use pink sushi ginger"}],"steps":["Loosen the udon under warm water and drain. Mix soy sauce, oyster sauce, mirin and dashi powder.","Heat the oil in a wok over high heat and stir-fry the chicken until lightly browned and cooked through.","Add cabbage and carrot and stir-fry 2 minutes until just wilted but still crisp.","Add the udon and the sauce, toss vigorously over high heat 2 minutes until everything is glossy and coated.","Toss through the spring onions, plate up, and finish with bonito flakes and a little beni shoga."],"pairing":"A cold highball (whisky and soda) or green tea.","tags":["Quick","Comfort","One-pan","Crowd-pleaser"],"vegetarian":false,"spicy":false,"calories":560,"protein":32,"carbs":62,"fat":20,"allergens":["Gluten","Soy","Fish","Shellfish"],"role":"main","cuisineKey":"japanese","type":"Noodles & Ramen"},{"id":"ja-zaru-soba","name":"Zaru Soba with Dipping Sauce","category":"Ramen & Noodles","course":"Main","meal":"lunch","tier":"easy","inspiration":"","minutes":20,"serves":2,"level":"Weeknight","idea":"Chilled buckwheat noodles served on a bamboo mat with an icy kombu-dashi and soy dipping sauce. Clean, nutty and refreshing, the dish Japan turns to on a hot day.","ingredients":[{"item":"200 g dried soba noodles (100% buckwheat for gluten-free)","note":"thin grey-brown buckwheat noodles; sold in the world-foods aisle"},{"item":"300 ml kombu dashi stock","note":"stock from dried kelp (kombu); make from a kombu sheet or dashi powder, or use light veg stock"},{"item":"4 tbsp soy sauce","note":""},{"item":"3 tbsp mirin","note":"sweet Japanese rice wine; substitute 3 tbsp water plus 1 tsp sugar"},{"item":"1 sheet nori, finely shredded","note":"dried seaweed sheet used for sushi; world-foods aisle"},{"item":"2 spring onions, finely sliced","note":""},{"item":"1 tbsp grated wasabi","note":"fiery green Japanese horseradish; tube or paste is fine"},{"item":"1 tsp toasted white sesame seeds","note":"any sesame seeds, toasted in a dry pan, work"}],"steps":["Make the tsuyu: simmer the kombu dashi, soy sauce and mirin for 2 minutes, then chill thoroughly in the fridge or over ice.","Cook the soba in plenty of boiling water per packet, usually 4 to 5 minutes, stirring so they do not clump.","Drain and rinse the noodles under cold running water, rubbing gently to remove surface starch, then chill in iced water and drain well.","Mound the noodles on a bamboo mat or plate and scatter with shredded nori.","Serve the cold tsuyu in cups alongside the spring onion, wasabi and sesame, to stir in and dip each mouthful."],"pairing":"Cold soba-yu (the noodle cooking water) or a chilled dry sake.","tags":["Light","Quick","Make-ahead","Lunchbox"],"vegetarian":false,"spicy":false,"calories":420,"protein":17,"carbs":80,"fat":4,"allergens":["Gluten","Soy","Sesame","Sulphites"],"role":"main","cuisineKey":"japanese","type":"Noodles & Ramen"},{"id":"ja-easy-chicken-shoyu-ramen","name":"Weeknight Chicken Shoyu Ramen","category":"Ramen & Noodles","course":"Main","meal":"both","tier":"easy","inspiration":"","minutes":30,"serves":2,"level":"Weeknight","idea":"A real soy-seasoned ramen built from supermarket chicken stock and a quick soy tare, topped with poached chicken and a jammy egg. All the slurpable comfort of a ramen shop with none of the all-day simmering.","ingredients":[{"item":"1.2 litres chicken stock","note":""},{"item":"2 chicken thigh fillets (about 250 g)","note":""},{"item":"5 tbsp soy sauce","note":""},{"item":"2 tbsp mirin","note":"sweet Japanese rice wine; substitute 2 tbsp water plus 1 tsp sugar"},{"item":"1 tbsp sake","note":"Japanese rice wine; substitute dry sherry, or leave out"},{"item":"1 tsp toasted sesame oil","note":"dark, nutty finishing oil; sold in the Asian aisle"},{"item":"2 garlic cloves, smashed","note":""},{"item":"10 g ginger, sliced","note":""},{"item":"2 portions fresh ramen noodles (about 240 g)","note":"springy yellow wheat noodles; substitute dried ramen or egg noodles (bin the seasoning sachet)"},{"item":"2 eggs","note":""},{"item":"2 spring onions, sliced","note":""},{"item":"1 sheet nori, halved","note":"dried seaweed sheet used for sushi; world-foods aisle"},{"item":"100 g sweetcorn","note":""}],"steps":["Soft-boil the eggs for 6.5 minutes, cool in cold water and peel.","Simmer the chicken stock with the garlic, ginger and chicken thighs for 12 minutes until the chicken is cooked, then lift out the chicken and slice it.","Make the tare by mixing soy sauce, mirin, sake and sesame oil, and divide between two warmed bowls.","Cook the noodles per packet, usually 90 seconds to 2 minutes, and drain well.","Ladle the hot strained stock over the tare, nest in the noodles, and top with sliced chicken, halved egg, sweetcorn, spring onion and nori."],"pairing":"An ice-cold Japanese lager or cold barley tea.","tags":["Comfort","Quick","Crowd-pleaser","One-pan"],"vegetarian":false,"spicy":false,"calories":600,"protein":38,"carbs":60,"fat":22,"allergens":["Gluten","Soy","Egg","Sesame","Sulphites"],"role":"main","cuisineKey":"japanese","type":"Noodles & Ramen"},{"id":"ja-shoyu-ramen","name":"Ivan Ramen Shoyu","category":"Ramen & Noodles","course":"Main","meal":"dinner","tier":"signature","inspiration":"Ivan Ramen (Ivan Orkin)","minutes":120,"serves":2,"level":"Project","idea":"A homage to Ivan Orkin's double-soup shoyu: a clean chicken and dashi broth married to a rich, slow-toasted soy tare, springy noodles, chashu and a jammy marinated egg. The Tokyo benchmark every ramen lover chases.","ingredients":[{"item":"1.2 litres chicken stock","note":""},{"item":"10 g kombu","note":"dried kelp seaweed used for stock; sold in the world-foods aisle, or leave out"},{"item":"10 g bonito flakes (katsuobushi)","note":"wispy dried tuna flakes used for stock; substitute 1 tsp dashi powder"},{"item":"5 tbsp soy sauce","note":""},{"item":"2 tbsp mirin","note":"sweet Japanese rice wine; substitute 2 tbsp water plus 1 tsp sugar"},{"item":"1 tbsp sake","note":"Japanese rice wine; substitute dry sherry, or leave out"},{"item":"1 tsp caster sugar","note":""},{"item":"2 portions fresh ramen noodles (about 240 g)","note":"springy yellow wheat noodles; substitute dried ramen or egg noodles (bin the seasoning sachet)"},{"item":"2 eggs","note":""},{"item":"150 g chashu pork or cooked sliced pork belly","note":"chashu is rolled braised pork belly; any cooked sliced pork belly works"},{"item":"2 spring onions, sliced","note":""},{"item":"1 sheet nori, halved","note":"dried seaweed sheet used for sushi; world-foods aisle"},{"item":"50 g menma (bamboo shoots)","note":"seasoned fermented bamboo strips; substitute plain tinned bamboo shoots, or leave out"}],"steps":["Soft-boil the eggs 6.5 minutes, cool in iced water, peel, and marinate in 2 tbsp of the soy sauce mixed with a splash of water for at least 30 minutes.","Warm the chicken stock with the kombu over low heat; just before it simmers remove the kombu, add bonito flakes, steep 2 minutes off the heat, then strain.","For the tare, gently warm the remaining soy sauce, mirin, sake and sugar until just below a simmer so the soy deepens and mellows, then divide between two warmed bowls.","Ladle the hot broth into each bowl over the tare and stir to combine.","Cook the noodles in boiling water per packet (usually 90 seconds to 2 minutes), drain well, and nest into the bowls.","Top with sliced chashu, halved marinated egg, menma, spring onion and nori, then serve immediately."],"pairing":"Cold barley tea (mugicha) or a crisp Japanese lager.","tags":["Comfort","Crowd-pleaser","Make-ahead"],"vegetarian":false,"spicy":false,"calories":680,"protein":36,"carbs":58,"fat":34,"allergens":["Gluten","Soy","Egg","Fish","Sulphites"],"role":"main","cuisineKey":"japanese","type":"Noodles & Ramen"},{"id":"ja-chicken-yakitori","name":"Chicken Yakitori (Negima)","category":"Yakimono (grilled)","course":"Main","meal":"dinner","tier":"easy","inspiration":"","minutes":35,"serves":4,"level":"Weekend","idea":"Skewers of thigh and spring onion lacquered in a sticky tare that you build by repeated dipping and grilling. Charred, sweet and savoury, the heart of any izakaya night.","ingredients":[{"item":"600 g boneless chicken thigh, skin on, cut into chunks","note":""},{"item":"4 thick spring onions, cut into 3 cm batons","note":"use the thickest spring onions you can find, or small leek pieces"},{"item":"120 ml soy sauce","note":""},{"item":"120 ml mirin","note":"sweet Japanese rice wine; substitute 120 ml water plus 2 tbsp sugar"},{"item":"60 ml sake","note":"Japanese rice wine; substitute dry sherry or dry white wine"},{"item":"2 tbsp caster sugar","note":""},{"item":"1 spring onion white, smashed","note":"the pale base of a spring onion, for the sauce"},{"item":"12 bamboo skewers, soaked 30 minutes","note":"soaking stops them burning; metal skewers also fine"},{"item":"1 tsp shichimi togarashi to serve","note":"Japanese seven-spice chilli blend; substitute a pinch of chilli flakes"}],"steps":["Make the tare: simmer soy sauce, mirin, sake, sugar and the smashed spring onion white until reduced by a third and lightly syrupy, about 8 minutes, then strain.","Thread chicken and spring onion batons alternately onto the soaked skewers.","Grill over high heat or a hot griddle, turning, for 4 to 5 minutes until the chicken is coloured and almost cooked.","Brush generously with tare and return to the heat; repeat the dip-and-grill twice more until lacquered and the chicken reads 74 C.","Serve hot with a dusting of shichimi togarashi."],"pairing":"Cold draft lager or a smoky highball.","tags":["Crowd-pleaser","Date night","Make-ahead"],"vegetarian":false,"spicy":false,"calories":380,"protein":30,"carbs":14,"fat":22,"allergens":["Soy","Gluten","Sulphites"],"role":"main","cuisineKey":"japanese","type":"Grills & BBQ"},{"id":"ja-saba-shioyaki","name":"Saba Shioyaki (Salt-Grilled Mackerel)","category":"Yakimono (grilled)","course":"Main","meal":"both","tier":"easy","inspiration":"","minutes":25,"serves":2,"level":"Weeknight","idea":"Mackerel salted to firm the flesh and draw out moisture, then grilled until the skin blisters and crackles. Pure, honest Japanese home cooking that lets the oily fish sing.","ingredients":[{"item":"2 mackerel fillets, skin on (about 140 g each)","note":""},{"item":"1.5 tsp fine sea salt","note":""},{"item":"1 tbsp sake","note":"Japanese rice wine; substitute dry sherry or dry white wine"},{"item":"150 g daikon radish, grated and lightly drained","note":"large mild white radish (mooli); substitute grated regular radish or turnip"},{"item":"1 lemon, cut into wedges","note":""},{"item":"2 tbsp soy sauce","note":""},{"item":"300 g steamed Japanese short-grain (sushi) rice to serve","note":"sticky white rice sold as sushi rice"}],"steps":["Pat the fillets dry, sprinkle evenly with salt on both sides, and rest 20 minutes; blot away the moisture that beads on the surface.","Brush off excess salt and rub the skin with the sake to help it crisp.","Heat the grill to high. Grill skin-side up first for 5 minutes, then flip and grill 3 to 4 minutes until the flesh flakes and the skin is blistered.","Mound the grated daikon alongside and add a lemon wedge.","Serve with hot rice and a small dish of soy sauce for the daikon."],"pairing":"A dry Junmai sake, served cool.","tags":["Quick","Light","Gluten-free option","Comfort"],"vegetarian":false,"spicy":false,"calories":520,"protein":30,"carbs":42,"fat":26,"allergens":["Fish","Soy","Gluten","Sulphites"],"role":"main","cuisineKey":"japanese","type":"Grills & BBQ"},{"id":"ja-chicken-tsukune","name":"Chicken Tsukune Meatballs","category":"Yakimono (grilled)","course":"Main","meal":"both","tier":"easy","inspiration":"","minutes":30,"serves":4,"level":"Weeknight","idea":"Juicy grilled chicken meatballs glazed in a glossy yakitori tare, with an optional egg-yolk dip the izakaya way. Easy to shape, forgiving to cook, and the kind of thing kids and adults both devour.","ingredients":[{"item":"500 g chicken mince","note":"minced/ground chicken; thigh mince gives juicier meatballs"},{"item":"2 spring onions, finely chopped","note":""},{"item":"15 g ginger, grated","note":""},{"item":"1 tbsp white miso","note":"mild fermented soybean paste; sold in tubs in the world-foods or chilled aisle"},{"item":"1 tbsp potato starch or cornflour","note":"binder/thickener; cornflour (cornstarch) is the easy supermarket option"},{"item":"1 tsp toasted sesame oil","note":"dark, nutty finishing oil; sold in the Asian aisle"},{"item":"4 tbsp soy sauce","note":""},{"item":"4 tbsp mirin","note":"sweet Japanese rice wine; substitute 4 tbsp water plus 2 tsp sugar"},{"item":"1 tbsp caster sugar","note":""},{"item":"1 tbsp neutral oil (sunflower or vegetable)","note":""},{"item":"1 tsp toasted white sesame seeds","note":"any sesame seeds, toasted in a dry pan, work"}],"steps":["Mix the chicken mince with the spring onion, ginger, miso, potato starch and sesame oil until sticky, then shape into 16 small oval meatballs.","Warm the soy sauce, mirin and sugar in a small pan until lightly syrupy to make the tare.","Heat the neutral oil in a non-stick pan over medium and cook the meatballs 6 to 8 minutes, turning, until browned and cooked through.","Pour in the tare and turn the meatballs to coat, letting it bubble and glaze for a minute.","Plate up, spoon over the pan glaze, and finish with sesame seeds."],"pairing":"Cold lager or a dry highball.","tags":["Quick","Crowd-pleaser","Comfort","Lunchbox","Make-ahead"],"vegetarian":false,"spicy":false,"calories":300,"protein":24,"carbs":12,"fat":17,"allergens":["Soy","Gluten","Sesame","Sulphites"],"role":"main","cuisineKey":"japanese","type":"Grills & BBQ"},{"id":"ja-nobu-miso-black-cod","name":"Miso-Marinated Black Cod (Saikyo Yaki)","category":"Yakimono (grilled)","course":"Main","meal":"dinner","tier":"signature","inspiration":"Nobu / Matsuhisa (Nobu Matsuhisa)","minutes":30,"serves":2,"level":"Project","idea":"Nobu's most iconic plate: black cod steeped for days in a sweet white-miso marinade, then grilled until the surface caramelises and the flesh turns to silk. Simple to cook, but the long marinade makes it unforgettable.","ingredients":[{"item":"2 black cod (sablefish) fillets, about 150 g each","note":"buttery, rich white fish; halibut or thick cod loin works as a substitute"},{"item":"120 g white (saikyo) miso","note":"sweet, pale, mild fermented soybean paste; substitute regular white miso plus a little extra sugar"},{"item":"3 tbsp mirin","note":"sweet Japanese rice wine; substitute 3 tbsp water plus 1 tsp sugar"},{"item":"3 tbsp sake","note":"Japanese rice wine; substitute dry sherry or dry white wine"},{"item":"2 tbsp caster sugar","note":""},{"item":"2 pieces pickled ginger stem (hajikami), optional","note":"sweet-pickled young ginger shoots; substitute pink sushi ginger, or leave out"},{"item":"200 g steamed Japanese short-grain (sushi) rice to serve","note":"sticky white rice sold as sushi rice"}],"steps":["Bring the sake and mirin to a gentle simmer to cook off the alcohol, then whisk in the miso and sugar over low heat until smooth, and cool completely.","Pat the cod dry, coat all over in the cooled miso marinade, and refrigerate in a sealed dish for 2 to 3 days for the true effect (a minimum of 24 hours will work).","Wipe most of the marinade off the fillets so they do not scorch.","Heat the grill to medium-high and grill the cod 7 to 10 minutes, watching closely, until deeply caramelised on top and just flaking through.","Serve with a piece of hajikami and steamed rice alongside."],"pairing":"Chilled Junmai Daiginjo sake or a lightly oaked Chardonnay.","tags":["Date night","Make-ahead","Gluten-free option"],"vegetarian":false,"spicy":false,"calories":480,"protein":30,"carbs":48,"fat":15,"allergens":["Fish","Soy","Sulphites"],"role":"main","cuisineKey":"japanese","type":"Grills & BBQ"},{"id":"ja-agedashi-tofu","name":"Agedashi Tofu","category":"Small plates","course":"Starter","meal":"both","tier":"easy","inspiration":"","minutes":25,"serves":2,"level":"Weeknight","idea":"Silken tofu dusted in potato starch and fried until crisp-shelled and custardy within, sitting in a warm kombu and shiitake dashi. A delicate, restaurant-favourite small plate that comes together fast.","ingredients":[{"item":"300 g silken tofu","note":"soft, custardy tofu; handle gently; sold in the chilled or world-foods aisle"},{"item":"4 tbsp potato starch (katakuriko)","note":"starch for a light crisp coating; cornflour (cornstarch) is the easy substitute"},{"item":"200 ml kombu and shiitake dashi stock","note":"vegetarian stock from dried kelp and dried mushrooms; or use light veg stock with a splash of soy"},{"item":"2 tbsp soy sauce","note":""},{"item":"2 tbsp mirin","note":"sweet Japanese rice wine; substitute 2 tbsp water plus 1 tsp sugar"},{"item":"50 g daikon radish, grated and drained","note":"large mild white radish (mooli); substitute grated regular radish or turnip"},{"item":"10 g ginger, grated","note":""},{"item":"2 spring onions, finely sliced","note":""},{"item":"500 ml neutral oil for frying (sunflower or vegetable)","note":""}],"steps":["Drain the tofu on kitchen paper for 15 minutes, then cut into large cubes and pat dry.","Warm the kombu and shiitake dashi, soy sauce and mirin together to make the broth and keep hot.","Coat the tofu cubes all over in potato starch, brushing off the excess.","Heat the oil to 180 C and fry the tofu 3 to 4 minutes until the coating is crisp and pale gold; drain on a rack.","Sit the tofu in shallow bowls, pour the warm broth around it, and top with grated daikon, ginger and spring onion."],"pairing":"Warm or room-temperature Junmai sake.","tags":["Vegetarian","Quick","Light","Comfort"],"vegetarian":true,"spicy":false,"calories":280,"protein":10,"carbs":22,"fat":17,"allergens":["Soy","Gluten","Fish","Sulphites"],"role":"appetizer","cuisineKey":"japanese","type":"Starters"},{"id":"ja-prawn-gyoza","name":"Prawn and Cabbage Gyoza","category":"Small plates","course":"Starter","meal":"both","tier":"easy","inspiration":"","minutes":45,"serves":4,"level":"Weekend","idea":"Pan-fried dumplings with a sweet, juicy prawn and cabbage filling, crisp lace-bottomed and steam-finished. The izakaya staple everyone reaches for, with a sharp soy-vinegar dip.","ingredients":[{"item":"30 gyoza wrappers","note":"round thin dumpling skins; sold frozen in Asian shops; wonton wrappers substitute"},{"item":"300 g raw prawns, peeled and roughly chopped","note":""},{"item":"200 g Chinese cabbage, finely chopped","note":"pale, crisp napa cabbage; substitute ordinary white cabbage"},{"item":"2 cloves garlic, grated","note":""},{"item":"15 g ginger, grated","note":""},{"item":"2 spring onions, finely chopped","note":""},{"item":"1 tbsp soy sauce","note":""},{"item":"1 tbsp toasted sesame oil","note":"dark, nutty finishing oil; sold in the Asian aisle"},{"item":"1 tsp caster sugar","note":""},{"item":"2 tbsp neutral oil for frying (sunflower or vegetable)","note":""},{"item":"3 tbsp rice vinegar and 3 tbsp soy sauce for dipping","note":"rice vinegar is a mild rice-based vinegar; cider vinegar substitutes"},{"item":"1 tsp chilli oil (rayu) to serve","note":"Japanese chilli-infused sesame oil; any chilli oil works"}],"steps":["Salt the cabbage lightly, rest 10 minutes, then squeeze out as much water as possible.","Mix the prawns, cabbage, garlic, ginger, spring onion, soy sauce, sesame oil and sugar until sticky and well combined.","Place a teaspoon of filling on each wrapper, wet the edge, and pleat to seal into a crescent.","Heat the oil in a non-stick pan, arrange the gyoza flat-side down, and fry 2 minutes until the bases are golden.","Add 80 ml water, cover immediately, and steam 5 minutes until the water evaporates and the prawn is cooked through; uncover and crisp the bases another minute.","Serve crisp-side up with a dip of rice vinegar, soy sauce and a few drops of rayu."],"pairing":"Ice-cold lager or a dry sparkling sake.","tags":["Crowd-pleaser","Make-ahead","Date night"],"vegetarian":false,"spicy":false,"calories":290,"protein":17,"carbs":30,"fat":11,"allergens":["Gluten","Shellfish","Soy","Sesame"],"role":"appetizer","cuisineKey":"japanese","type":"Starters"},{"id":"ja-tamagoyaki","name":"Tamagoyaki (Rolled Omelette)","category":"Small plates","course":"Starter","meal":"both","tier":"easy","inspiration":"","minutes":15,"serves":2,"level":"Weeknight","idea":"The sweet-savoury rolled egg omelette built layer by layer into a tender, golden log. A breakfast and bento mainstay that is endlessly comforting and ready in minutes.","ingredients":[{"item":"4 eggs","note":""},{"item":"3 tbsp dashi stock","note":"Japanese sea-stock from kelp and dried fish; make from dashi powder, or use light stock"},{"item":"1 tbsp mirin","note":"sweet Japanese rice wine; substitute 1 tbsp water plus a pinch of sugar"},{"item":"1 tbsp soy sauce","note":""},{"item":"1 tsp caster sugar","note":""},{"item":"1 tbsp neutral oil (sunflower or vegetable)","note":""},{"item":"50 g daikon radish, grated to serve","note":"large mild white radish (mooli); substitute grated regular radish"},{"item":"1 tsp soy sauce to serve","note":""}],"steps":["Beat the eggs with the dashi, mirin, soy sauce and sugar until just combined, avoiding too many bubbles.","Heat a non-stick pan over medium-low and wipe with a little oil on kitchen paper.","Pour in a thin layer of egg, and once just set, roll it to one side of the pan with a spatula.","Oil the pan again, pour in another thin layer letting it run under the roll, set, then roll back over the new layer; repeat until all the egg is used.","Tip out, shape gently, cool a minute, then slice into thick pieces and serve with grated daikon and a drop of soy."],"pairing":"Green tea or a light Junmai sake.","tags":["Vegetarian","Quick","Lunchbox","Comfort"],"vegetarian":true,"spicy":false,"calories":210,"protein":13,"carbs":6,"fat":14,"allergens":["Egg","Fish","Soy","Gluten","Sulphites"],"role":"appetizer","cuisineKey":"japanese","type":"Starters"},{"id":"ja-vegetable-miso-soup","name":"Root Vegetable and Tofu Miso Soup","category":"Small plates","course":"Starter","meal":"both","tier":"easy","inspiration":"","minutes":25,"serves":4,"level":"Weeknight","idea":"A hearty everyday miso soup loaded with sweet root vegetables and tofu, simmered in dashi and finished with miso off the boil. The home-cooked bowl that turns a simple meal into a warming one.","ingredients":[{"item":"800 ml dashi stock","note":"Japanese sea-stock from kelp and dried fish; make from dashi powder, or use light veg stock"},{"item":"100 g daikon radish, quartered and sliced","note":"large mild white radish (mooli); substitute regular radish or turnip"},{"item":"1 carrot, sliced into half-moons","note":""},{"item":"1 small potato, cubed","note":""},{"item":"100 g shiitake mushrooms, sliced","note":"meaty Asian mushrooms; chestnut or button mushrooms substitute"},{"item":"150 g firm tofu, cubed","note":"holds its shape when cubed; chilled or world-foods aisle"},{"item":"4 tbsp miso paste","note":"fermented soybean paste; sold in tubs; brown/red miso gives a deeper flavour than white"},{"item":"1 tsp toasted sesame oil","note":"dark, nutty finishing oil; sold in the Asian aisle"},{"item":"2 spring onions, sliced","note":""},{"item":"shichimi togarashi to serve","note":"Japanese seven-spice chilli blend; substitute a pinch of chilli flakes"}],"steps":["Heat the sesame oil in a pot and stir-fry the daikon, carrot, potato and shiitake for a minute until glossy.","Pour in the dashi, bring to a simmer, and cook gently 12 to 15 minutes, skimming any foam, until the vegetables are tender.","Add the tofu, then turn the heat to low and whisk in the miso through a ladle until dissolved; do not let it boil.","Ladle into bowls and finish with spring onion and a pinch of shichimi togarashi."],"pairing":"Hot green tea or a warm Junmai sake.","tags":["Vegetarian","Comfort","Quick","One-pan","Make-ahead"],"vegetarian":true,"spicy":false,"calories":140,"protein":8,"carbs":12,"fat":7,"allergens":["Soy","Fish","Sesame"],"role":"appetizer","cuisineKey":"japanese","type":"Starters"},{"id":"ja-kikunoi-chawanmushi","name":"Dashi Chawanmushi with Prawn and Ginkgo","category":"Small plates","course":"Starter","meal":"dinner","tier":"signature","inspiration":"Kikunoi (Yoshihiro Murata)","minutes":45,"serves":2,"level":"Weekend","idea":"A homage to the kaiseki dashi mastery Yoshihiro Murata is known for: a barely-set savoury egg custard built on a clean ichiban dashi, trembling and silken, hiding prawn, chicken and ginkgo beneath a glossy surface. The dish that proves restraint is the hardest technique of all.","ingredients":[{"item":"3 eggs","note":""},{"item":"450 ml ichiban dashi (kombu and bonito), cooled","note":"first-press Japanese stock from kelp and dried tuna; make from dashi powder, or use light fish stock"},{"item":"1 tbsp light soy sauce (usukuchi)","note":"thinner, saltier, paler soy sauce that keeps the custard pale; ordinary soy is fine"},{"item":"1 tbsp mirin","note":"sweet Japanese rice wine; substitute 1 tbsp water plus a pinch of sugar"},{"item":"0.5 tsp fine salt","note":""},{"item":"4 raw prawns, peeled","note":""},{"item":"60 g chicken thigh, diced small","note":""},{"item":"8 ginkgo nuts or edamame, peeled","note":"ginkgo are small mild Japanese nuts in tins; podded edamame (soya beans) are the easy swap"},{"item":"4 slices kamaboko fish cake","note":"steamed white-and-pink fish cake; substitute crab sticks (surimi), or leave out"},{"item":"mitsuba or a few coriander leaves to finish","note":"mitsuba is a mild Japanese herb; flat-leaf parsley or coriander substitute"},{"item":"yuzu zest to finish","note":"fragrant Japanese citrus; substitute a little lemon plus lime zest"}],"steps":["Make a clean ichiban dashi by steeping kombu in water warmed to just below a simmer, removing it, adding bonito flakes off the heat for 2 minutes, then straining and cooling.","Beat the eggs gently without frothing, then stir in the cooled dashi, light soy, mirin and salt and pass the mixture through a fine sieve for a smooth set.","Divide the prawn, chicken, ginkgo and kamaboko between two heatproof cups and pour the strained custard over, skimming off any surface bubbles.","Cover each cup with foil and steam over low heat 12 to 15 minutes, keeping the steam gentle, until just set with a soft wobble in the centre.","Finish with mitsuba and a fine grating of yuzu zest, and serve warm with a spoon."],"pairing":"Warm Junmai sake or a delicate green sencha.","tags":["Date night","Light","Make-ahead"],"vegetarian":false,"spicy":false,"calories":180,"protein":16,"carbs":5,"fat":10,"allergens":["Egg","Fish","Shellfish","Soy","Gluten","Sulphites"],"role":"appetizer","cuisineKey":"japanese","type":"Starters"},{"id":"ja-oyakodon","name":"Oyakodon (Chicken and Egg Rice Bowl)","cuisineKey":"japanese","category":"Sushi & Rice bowls","course":"Main","meal":"both","tier":"easy","inspiration":"","minutes":20,"serves":4,"level":"Weeknight","idea":"A genuine Japanese home staple: one pan, four pantry seasonings, deeply kid-friendly and mild. Faster and more approachable than the 2-hour shoyu ramen anchoring the category.","ingredients":[{"item":"400 g boneless chicken thigh, sliced","note":""},{"item":"4 eggs, lightly beaten","note":""},{"item":"1 onion, thinly sliced","note":""},{"item":"200 ml dashi stock","note":"Japanese sea-stock from kelp and dried fish; make from dashi powder, or use light chicken stock"},{"item":"3 tbsp soy sauce","note":""},{"item":"2 tbsp mirin","note":"sweet Japanese rice wine; substitute 2 tbsp water plus 1 tsp sugar"},{"item":"1 tbsp sugar","note":""},{"item":"4 portions cooked Japanese short-grain (sushi) rice","note":"sticky white rice sold as sushi rice"},{"item":"2 spring onions, sliced","note":""}],"steps":["In a wide pan combine the dashi, soy, mirin and sugar and bring to a simmer.","Add the onion and simmer 3 minutes until soft.","Add the chicken and cook 5-6 minutes until just cooked through.","Pour the beaten eggs over the surface in a swirl, cover and cook 1-2 minutes until just set but still soft.","Slide each portion over a bowl of hot rice.","Scatter with spring onion and serve immediately."],"pairing":"Miso soup and quick-pickled cucumber","tags":["kid-friendly","quick","one-pan"],"vegetarian":false,"spicy":false,"calories":520,"protein":32,"carbs":62,"fat":15,"allergens":["Egg","Fish","Soy","Gluten","Sulphites"],"role":"main","type":"Rice & Bowls"},{"id":"ja-unagi-don-signature","name":"Charcoal Unagi Don with Sansho","cuisineKey":"japanese","category":"Sushi & Rice bowls","role":"main","course":"Main","meal":"lunch","tier":"signature","inspiration":"Den (Zaiyu Hasegawa)","minutes":45,"serves":2,"level":"Weekend","idea":"Glazed grilled eel over rice with a lacquered tare and a lift of sansho pepper, a refined lunch bowl in the spirit of Den.","ingredients":[{"item":"2 ready-grilled unagi (eel) fillets, about 130 g each","note":"pre-cooked glazed freshwater eel; sold frozen in Asian shops, ready to reheat"},{"item":"300 g Japanese short-grain (sushi) rice","note":"sticky white rice sold as sushi rice; risotto/arborio is the closest fallback"},{"item":"360 ml water","note":""},{"item":"6 tbsp soy sauce","note":""},{"item":"6 tbsp mirin","note":"sweet Japanese rice wine; substitute 6 tbsp water plus 1 tbsp sugar"},{"item":"3 tbsp sake","note":"Japanese rice wine; substitute dry sherry or dry white wine"},{"item":"2 tbsp caster sugar","note":""},{"item":"1 tsp ground sansho pepper","note":"citrusy, tingly Japanese pepper that suits eel; substitute a little Sichuan pepper or black pepper"},{"item":"1 sheet nori, finely shredded","note":"dried seaweed sheet used for sushi; world-foods aisle"},{"item":"2 tbsp pickled ginger (gari)","note":"thin pink sweet-pickled ginger served with sushi"}],"steps":["Rinse and cook the rice with the water until fluffy, then rest covered for 10 minutes.","Simmer soy sauce, mirin, sake and sugar in a small pan until glossy and slightly thickened to make the tare.","Brush the unagi fillets with tare and grill or blast under a hot grill for 4 to 5 minutes until lacquered and hot through.","Divide the rice between bowls and spoon over a little tare.","Lay the glazed unagi on top, brush again with tare, dust with sansho and finish with shredded nori and pickled ginger."],"pairing":"Cold barley tea or a crisp dry sake","tags":["eel","rice bowl","grilled","lunch"],"vegetarian":false,"spicy":false,"calories":640,"protein":34,"carbs":78,"fat":20,"allergens":["Gluten","Fish","Soy"],"type":"Rice & Bowls"},{"id":"ja-katsudon-easy","name":"Pork Katsudon","cuisineKey":"japanese","category":"Sushi & Rice bowls","role":"main","course":"Main","meal":"both","tier":"easy","inspiration":"","minutes":35,"serves":2,"level":"Weeknight","idea":"Crisp panko pork cutlet simmered with onion and silky egg over rice, the ultimate comfort donburi.","ingredients":[{"item":"2 boneless pork loin steaks, about 150 g each","note":""},{"item":"60 g plain flour","note":""},{"item":"1 egg, beaten, for coating","note":""},{"item":"100 g panko breadcrumbs","note":"light, crisp Japanese breadcrumbs; ordinary dried breadcrumbs substitute but are denser"},{"item":"500 ml neutral oil for frying (sunflower or vegetable)","note":""},{"item":"300 g Japanese short-grain (sushi) rice","note":"sticky white rice sold as sushi rice"},{"item":"360 ml water for rice","note":""},{"item":"1 onion, thinly sliced","note":""},{"item":"200 ml dashi stock","note":"Japanese sea-stock from kelp and dried fish; make from dashi powder, or use light stock"},{"item":"3 tbsp soy sauce","note":""},{"item":"2 tbsp mirin","note":"sweet Japanese rice wine; substitute 2 tbsp water plus 1 tsp sugar"},{"item":"1 tbsp caster sugar","note":""},{"item":"4 eggs, lightly beaten","note":""},{"item":"2 spring onions, sliced","note":""}],"steps":["Cook the rice with the water and keep warm.","Coat the pork in flour, then beaten egg, then panko, and deep-fry at 175C for 5 to 6 minutes until golden. Drain and slice into strips.","Simmer onion in dashi, soy sauce, mirin and sugar for 4 minutes until soft.","Lay the sliced cutlet over the onion, pour the beaten eggs around it and cover until just set.","Slide each portion onto a bowl of rice and finish with spring onions."],"pairing":"Green tea or a light lager","tags":["pork","katsu","rice bowl","comfort"],"vegetarian":false,"spicy":false,"calories":760,"protein":38,"carbs":82,"fat":30,"allergens":["Gluten","Egg","Soy"],"type":"Rice & Bowls"},{"id":"ja-tonkotsu-style-ramen","name":"Quick Miso Tonkotsu-Style Ramen","cuisineKey":"japanese","category":"Ramen & Noodles","role":"main","course":"Main","meal":"dinner","tier":"easy","inspiration":"","minutes":40,"serves":2,"level":"Weeknight","idea":"A rich, creamy miso broth with chashu-style pork and soft egg for a hearty bowl on a cold night.","ingredients":[{"item":"1.2 litres chicken stock","note":""},{"item":"200 ml whole milk","note":"adds the creamy white look of tonkotsu broth"},{"item":"3 tbsp white miso","note":"mild fermented soybean paste; sold in tubs in the world-foods or chilled aisle"},{"item":"1 tbsp tahini or sesame paste","note":"smooth sesame-seed paste; sold by the hummus or world-foods aisle"},{"item":"2 garlic cloves, grated","note":""},{"item":"10 g ginger, grated","note":""},{"item":"1 tbsp soy sauce","note":""},{"item":"1 tsp toasted sesame oil","note":"dark, nutty finishing oil; sold in the Asian aisle"},{"item":"200 g cooked sliced pork belly","note":""},{"item":"2 portions fresh ramen noodles, about 240 g","note":"springy yellow wheat noodles; substitute dried ramen or egg noodles (bin the seasoning sachet)"},{"item":"2 eggs","note":""},{"item":"2 spring onions, sliced","note":""},{"item":"50 g sweetcorn","note":""},{"item":"100 g beansprouts","note":""}],"steps":["Soft-boil the eggs for 6.5 minutes, cool in iced water and peel.","Warm the stock with garlic and ginger, then whisk in milk, miso, tahini, soy sauce and sesame oil and keep below a simmer.","Crisp the pork belly slices in a dry pan for 2 minutes each side.","Cook the ramen noodles to packet timing and divide between deep bowls.","Pour over the broth, top with pork, halved eggs, sweetcorn, beansprouts and spring onions."],"pairing":"Cold beer or sparkling water with yuzu","tags":["ramen","miso","pork","dinner"],"vegetarian":false,"spicy":false,"calories":720,"protein":40,"carbs":68,"fat":32,"allergens":["Gluten","Milk","Egg","Soy","Sesame"],"type":"Noodles & Ramen"},{"id":"ja-nobu-tiradito","name":"Sea Bass Tiradito with Yuzu and Aji","cuisineKey":"japanese","category":"Small plates","role":"appetizer","course":"Starter","meal":"both","tier":"signature","inspiration":"Nobu / Matsuhisa (Nobu Matsuhisa)","minutes":20,"serves":2,"level":"Weekend","idea":"Paper-thin sashimi of sea bass dressed in a sharp yuzu and aji amarillo sauce, the signature Nobu-Peruvian plate.","ingredients":[{"item":"200 g sashimi-grade sea bass, very thinly sliced","note":"raw-safe sea bass; ask the fishmonger for sashimi grade; sea bream substitutes"},{"item":"3 tbsp yuzu juice or lime juice","note":"yuzu is a tart Japanese citrus; bottled yuzu or plain lime juice works"},{"item":"1 tbsp light soy sauce","note":"thinner, saltier, paler soy sauce; ordinary soy sauce is fine"},{"item":"1 tsp aji amarillo paste","note":"fruity Peruvian yellow chilli paste; substitute a little mild chilli paste with a pinch of sugar"},{"item":"1 tsp grated ginger","note":""},{"item":"1 small garlic clove, grated","note":""},{"item":"1 tbsp coriander, finely chopped","note":""},{"item":"1 mild red chilli, finely sliced","note":""},{"item":"1 tsp toasted white sesame seeds","note":"any sesame seeds, toasted in a dry pan, work"},{"item":"flaky sea salt","note":""}],"steps":["Lay the sliced sea bass in a single overlapping layer on a chilled plate.","Whisk yuzu juice, soy sauce, aji amarillo, ginger and garlic into a smooth dressing.","Spoon the dressing evenly over the fish just before serving.","Scatter with coriander, sliced chilli, sesame seeds and a few flakes of sea salt."],"pairing":"Chilled junmai sake or a dry Riesling","tags":["sashimi","ceviche","fish","starter"],"vegetarian":false,"spicy":true,"calories":160,"protein":22,"carbs":4,"fat":6,"allergens":["Fish","Soy","Sesame"],"type":"Starters"},{"id":"ja-edamame-garlic","name":"Charred Garlic Edamame","cuisineKey":"japanese","category":"Small plates","role":"appetizer","course":"Starter","meal":"both","tier":"easy","inspiration":"","minutes":12,"serves":2,"level":"Weeknight","idea":"Blistered edamame pods tossed in garlic, sesame oil and flaky salt, the easiest izakaya starter.","ingredients":[{"item":"300 g frozen edamame in the pod","note":"young green soya beans in pods; sold frozen in most supermarkets"},{"item":"1 tbsp toasted sesame oil","note":"dark, nutty finishing oil; sold in the Asian aisle"},{"item":"3 garlic cloves, thinly sliced","note":""},{"item":"1 tsp flaky sea salt","note":""},{"item":"0.5 tsp shichimi togarashi","note":"Japanese seven-spice chilli blend; substitute a pinch of chilli flakes"},{"item":"1 tsp toasted white sesame seeds","note":"any sesame seeds, toasted in a dry pan, work"}],"steps":["Boil the edamame for 4 minutes, then drain well.","Heat the sesame oil and gently fry the garlic until just golden.","Add the edamame and toss over high heat for 2 minutes until lightly blistered.","Tip into a bowl and toss with salt, shichimi and sesame seeds. Serve hot, squeezing the beans from the pods."],"pairing":"Cold beer or iced green tea","tags":["edamame","izakaya","starter"],"vegetarian":true,"spicy":true,"calories":190,"protein":13,"carbs":12,"fat":10,"allergens":["Soy","Sesame"],"type":"Starters"},{"id":"ja-jiro-tamago-nigiri","name":"Tamago Nigiri, Jiro Style","cuisineKey":"japanese","category":"Sushi & Rice bowls","role":"appetizer","course":"Starter","meal":"both","tier":"signature","inspiration":"Sukiyabashi Jiro (Jiro Ono)","minutes":40,"serves":2,"level":"Project","idea":"A dense, cake-like sweet tamago set on vinegared rice and bound with nori, the famous closing piece at Jiro.","ingredients":[{"item":"4 eggs","note":""},{"item":"2 raw prawns, peeled and pureed","note":"blended to a paste to enrich the omelette; optional, leave out for a plain version"},{"item":"20 g grated yamaimo or 1 tsp cornflour","note":"yamaimo is Japanese mountain yam used as a binder; cornflour (cornstarch) is the easy swap"},{"item":"1 tbsp caster sugar","note":""},{"item":"1 tsp mirin","note":"sweet Japanese rice wine; substitute 1 tsp water plus a pinch of sugar"},{"item":"0.5 tsp light soy sauce","note":"thinner, paler soy sauce; ordinary soy sauce is fine"},{"item":"pinch of salt","note":""},{"item":"1 tbsp neutral oil (sunflower or vegetable)","note":""},{"item":"200 g cooked Japanese short-grain (sushi) rice","note":"sticky white rice sold as sushi rice"},{"item":"1.5 tbsp rice vinegar","note":"mild rice-based vinegar for seasoning the rice; cider vinegar substitutes"},{"item":"1 tsp sugar for the rice","note":""},{"item":"0.5 tsp salt for the rice","note":""},{"item":"1 sheet nori, cut into strips","note":"dried seaweed sheet; the strips tie the omelette to the rice"}],"steps":["Season the warm rice with rice vinegar, sugar and salt and cool to body temperature.","Blend the eggs, prawn puree, yamaimo, sugar, mirin, soy sauce and salt until smooth.","Pour into an oiled square pan over low heat and cook slowly, covered, for 20 to 25 minutes until set and cake-like, then cool and cut into thick slabs.","Press small ovals of rice and lay a slab of tamago on each.","Wrap a band of nori around the middle to hold each piece together."],"pairing":"Hot hojicha or a delicate sake","tags":["sushi","tamago","nigiri","starter"],"vegetarian":false,"spicy":false,"calories":300,"protein":16,"carbs":34,"fat":11,"allergens":["Egg","Shellfish","Soy"],"type":"Starters"},{"id":"ja-sunomono-salad","name":"Cucumber and Wakame Sunomono","cuisineKey":"japanese","category":"Small plates","role":"salad","course":"Starter","meal":"both","tier":"easy","inspiration":"","minutes":15,"serves":2,"level":"Weeknight","idea":"Cool ribbons of cucumber and wakame in a bright sweet-sour rice vinegar dressing, the classic Japanese salad.","ingredients":[{"item":"2 cucumbers, very thinly sliced","note":""},{"item":"10 g dried wakame seaweed","note":"soft green seaweed that swells when soaked; sold in the world-foods aisle"},{"item":"4 tbsp rice vinegar","note":"mild rice-based vinegar; cider vinegar or white wine vinegar substitutes"},{"item":"1 tbsp caster sugar","note":""},{"item":"1 tbsp light soy sauce","note":"thinner, paler soy sauce; ordinary soy sauce is fine"},{"item":"0.5 tsp salt","note":""},{"item":"1 tsp toasted white sesame seeds","note":"any sesame seeds, toasted in a dry pan, work"},{"item":"10 g ginger, finely julienned","note":"cut into thin matchsticks"}],"steps":["Toss the cucumber slices with the salt and leave for 10 minutes, then squeeze out the excess water.","Soak the wakame in cold water for 5 minutes until soft, then drain well.","Whisk the rice vinegar, sugar and soy sauce until the sugar dissolves.","Toss the cucumber, wakame and ginger in the dressing and chill briefly.","Finish with toasted sesame seeds before serving."],"pairing":"Cold green tea or a light lager","tags":["salad","cucumber","seaweed"],"vegetarian":true,"spicy":false,"calories":80,"protein":3,"carbs":14,"fat":2,"allergens":["Soy","Sesame"],"type":"Salads"},{"id":"ja-goma-spinach-salad","name":"Spinach Gomaae with Sesame Dressing","cuisineKey":"japanese","category":"Small plates","role":"salad","course":"Starter","meal":"both","tier":"easy","inspiration":"","minutes":15,"serves":2,"level":"Weeknight","idea":"Blanched spinach dressed in a nutty toasted-sesame paste, a deeply savoury little salad.","ingredients":[{"item":"300 g spinach","note":""},{"item":"3 tbsp toasted white sesame seeds","note":"toasted and ground into the dressing; any sesame seeds work"},{"item":"1 tbsp soy sauce","note":""},{"item":"1 tbsp mirin","note":"sweet Japanese rice wine; substitute 1 tbsp water plus a pinch of sugar"},{"item":"1 tsp caster sugar","note":""},{"item":"1 tsp dashi stock or water","note":"Japanese sea-stock; plain water is fine here"}],"steps":["Blanch the spinach for 30 seconds, refresh in iced water, then squeeze out all the water and cut into bite lengths.","Toast the sesame seeds until fragrant and grind two thirds to a coarse paste in a mortar.","Stir the soy sauce, mirin, sugar and dashi into the sesame paste to make a thick dressing.","Toss the spinach through the dressing and pile into bowls.","Scatter with the reserved whole sesame seeds."],"pairing":"Steamed rice and miso soup, or green tea","tags":["salad","spinach","sesame"],"vegetarian":true,"spicy":false,"calories":140,"protein":7,"carbs":9,"fat":9,"allergens":["Soy","Sesame"],"type":"Salads"},{"id":"ja-kani-avocado-salad","name":"Crab and Avocado Salad with Wasabi Mayo","cuisineKey":"japanese","category":"Small plates","role":"salad","course":"Starter","meal":"both","tier":"easy","inspiration":"","minutes":15,"serves":2,"level":"Weeknight","idea":"Creamy crab and avocado over crisp leaves with a wasabi-spiked Japanese mayo, an izakaya-style salad.","ingredients":[{"item":"150 g white crab meat or seafood sticks, flaked","note":"fresh/tinned white crab, or crab sticks (surimi) as a cheaper swap"},{"item":"1 ripe avocado, diced","note":""},{"item":"80 g mixed salad leaves","note":""},{"item":"2 tbsp Japanese (Kewpie) mayonnaise","note":"richer, tangier Japanese mayo; substitute regular mayo with a few drops of rice vinegar"},{"item":"0.5 tsp wasabi paste","note":"fiery green Japanese horseradish; tube or paste is fine"},{"item":"1 tsp light soy sauce","note":"thinner, paler soy sauce; ordinary soy sauce is fine"},{"item":"1 tsp rice vinegar","note":"mild rice-based vinegar; cider vinegar substitutes"},{"item":"1 spring onion, sliced","note":""},{"item":"1 tsp toasted white sesame seeds","note":"any sesame seeds, toasted in a dry pan, work"},{"item":"1 sheet nori, finely shredded","note":"dried seaweed sheet used for sushi; world-foods aisle"}],"steps":["Whisk the mayonnaise, wasabi, soy sauce and rice vinegar into a smooth dressing.","Gently fold the crab and most of the dressing together.","Arrange the salad leaves and avocado on plates.","Spoon the dressed crab over the top and drizzle with the remaining dressing.","Finish with spring onion, sesame seeds and shredded nori."],"pairing":"Chilled sake or sparkling water with lime","tags":["salad","crab","avocado","seafood"],"vegetarian":false,"spicy":true,"calories":260,"protein":14,"carbs":8,"fat":19,"allergens":["Fish","Shellfish","Egg","Soy","Sesame","Mustard"],"type":"Salads"},{"id":"am-classic-smash-burger","name":"Classic Smash Burger","category":"Burgers","course":"Main","meal":"both","tier":"easy","inspiration":"","minutes":25,"serves":4,"level":"Weeknight","idea":"Loose balls of fatty beef smashed hard onto a screaming-hot pan so the edges fry into lacy, crisp brown lace. The deep Maillard crust is the whole reward, so reach for 20 percent fat mince and never lean.","ingredients":[{"item":"600 g beef mince, 20% fat","note":"ground beef with around 20% fat (chuck is ideal); the fat keeps smash burgers juicy"},{"item":"8 slices American cheese (e.g. Kraft Singles)","note":"mild, ultra-melting processed cheese; mild cheddar slices also work"},{"item":"4 soft brioche burger buns","note":"slightly sweet, soft enriched buns; any soft burger bun works"},{"item":"1 large white onion, very thinly sliced","note":""},{"item":"2 tbsp neutral oil (sunflower, vegetable or canola)","note":"flavourless oil with a high smoke point; not olive oil"},{"item":"Salt and freshly ground black pepper","note":""},{"item":"4 tbsp mayonnaise","note":""},{"item":"2 tbsp yellow mustard (American mild mustard)","note":"mild, tangy bright-yellow mustard; not English or Dijon, which are much hotter"},{"item":"8 dill pickle slices","note":"sliced pickled cucumbers in a salty, dilly brine; gherkins work too"}],"steps":["Divide the mince into 8 loose 75 g balls without compacting them. Do not season yet.","Heat a heavy cast-iron pan over high heat until smoking, then add the oil.","Smash each ball flat with a stiff spatula for 10 seconds until very thin, working in batches. Season the tops with salt and pepper.","Scatter a little onion onto each patty and press in lightly. After about 2 minutes the edges will be deeply browned and lacy.","Flip, top each with cheese, and cook 1 minute more until melted and cooked through to 71 C.","Stack two patties per bun. Spread the buns with mayonnaise mixed with mustard, add pickles, and serve at once."],"pairing":"An ice-cold lager or a chocolate malt shake","tags":["Quick","Crowd-pleaser","Comfort"],"vegetarian":false,"spicy":false,"calories":680,"protein":36,"carbs":34,"fat":44,"allergens":["Gluten","Milk","Egg","Mustard"],"role":"main","cuisineKey":"american","type":"Burgers"},{"id":"am-bacon-cheeseburger","name":"Bacon Cheeseburger","category":"Burgers","course":"Main","meal":"both","tier":"easy","inspiration":"","minutes":30,"serves":4,"level":"Weeknight","idea":"A thick, juicy pub-style burger layered with smoky streaky bacon and sharp aged cheddar. Pressing a shallow dimple into each patty stops it ballooning so it grills flat and even.","ingredients":[{"item":"700 g beef mince, 20% fat","note":"ground beef with around 20% fat for juicy patties"},{"item":"8 rashers smoked streaky bacon","note":"thin, fatty bacon slices from the belly (US-style bacon); regular smoked bacon is fine"},{"item":"4 slices mature cheddar","note":"sharp, aged cheddar; any melting cheese works"},{"item":"4 sesame burger buns","note":""},{"item":"1 beef tomato, sliced","note":"a large, meaty tomato good for thick slices; any large tomato works"},{"item":"4 crisp lettuce leaves (iceberg or romaine)","note":""},{"item":"2 tbsp neutral oil (sunflower, vegetable or canola)","note":"flavourless high-smoke-point oil"},{"item":"Salt and freshly ground black pepper","note":""},{"item":"4 tbsp burger sauce, or ketchup and mayonnaise","note":"creamy, tangy ready-made burger sauce; or just mix equal ketchup and mayo"}],"steps":["Fry the bacon in a dry pan over medium heat until crisp, then drain on kitchen paper, leaving the fat in the pan.","Gently form the mince into 4 patties slightly wider than the buns, pressing a shallow dimple in the centre of each. Season both sides well.","Heat the oil in a fresh pan over high heat and cook the patties 3 to 4 minutes on the first side until well crusted.","Flip, lay cheddar on each, and cook a further 3 minutes for medium, to 71 C.","Toast the cut buns in the reserved bacon fat until golden.","Build with sauce on the base, lettuce, tomato, the patty, then two bacon rashers crossed on top. Rest 1 minute and serve."],"pairing":"A hoppy IPA or a smoky bourbon on the rocks","tags":["Crowd-pleaser","Comfort"],"vegetarian":false,"spicy":false,"calories":720,"protein":42,"carbs":33,"fat":46,"allergens":["Gluten","Milk","Egg","Sesame"],"role":"main","cuisineKey":"american","type":"Burgers"},{"id":"am-turkey-burger","name":"Juicy Turkey Burger","category":"Burgers","course":"Main","meal":"both","tier":"easy","inspiration":"","minutes":25,"serves":4,"level":"Weeknight","idea":"A lighter weeknight burger that stays moist thanks to grated onion and a spoon of mayonnaise worked into the mince. Lean turkey dries out fast, so the hidden moisture and a quick sear are what save it.","ingredients":[{"item":"600 g turkey mince (preferably thigh, not all breast)","note":"ground turkey; thigh meat stays juicier than lean breast mince"},{"item":"1 small onion, coarsely grated","note":""},{"item":"2 tbsp mayonnaise","note":""},{"item":"1 garlic clove, minced","note":""},{"item":"1 tsp dried oregano","note":""},{"item":"4 slices Swiss or Monterey Jack cheese","note":"Swiss is a mild nutty holey cheese (Emmental works); Monterey Jack is a mild creamy melter (mild cheddar works)"},{"item":"4 soft burger buns","note":""},{"item":"1 tbsp neutral oil (sunflower, vegetable or canola)","note":"flavourless high-smoke-point oil"},{"item":"Salt and freshly ground black pepper","note":""},{"item":"4 lettuce leaves and tomato slices, to serve","note":""}],"steps":["Mix the turkey with the grated onion, mayonnaise, garlic, oregano, salt and pepper until just combined.","Shape into 4 patties slightly wider than the buns and chill 5 minutes to firm up.","Heat the oil in a pan over medium-high and cook the patties 4 to 5 minutes per side until cooked through to 74 C.","Top each with cheese in the last minute and cover the pan to melt.","Toast the buns, then build with lettuce, tomato and the patty.","Serve hot with extra mayonnaise or mustard."],"pairing":"A crisp green salad and sparkling water with lime","tags":["Quick","Light","Comfort"],"vegetarian":false,"spicy":false,"calories":520,"protein":40,"carbs":32,"fat":25,"allergens":["Gluten","Milk","Egg"],"role":"main","cuisineKey":"american","type":"Burgers"},{"id":"am-black-bean-burger","name":"Black Bean Veggie Burger","category":"Burgers","course":"Main","meal":"both","tier":"easy","inspiration":"","minutes":30,"serves":4,"level":"Weeknight","idea":"A hearty meat-free patty of mashed black beans, breadcrumbs and smoky spice that holds together and crisps in the pan. Drying the beans well is the trick to a patty that sears instead of crumbling.","ingredients":[{"item":"2 x 400 g tins black beans, drained","note":"small black turtle beans; tinned kidney beans can substitute"},{"item":"80 g breadcrumbs","note":""},{"item":"1 small onion, finely diced","note":""},{"item":"1 egg, beaten","note":""},{"item":"2 tsp ground cumin","note":"warm, earthy ground spice common in Mexican cooking"},{"item":"1 tsp smoked paprika","note":"smoky-flavoured dried red pepper powder; ordinary paprika works minus the smokiness"},{"item":"1 tbsp tomato puree (tomato paste)","note":"thick concentrated tomato in a tube or small tin"},{"item":"4 burger buns","note":""},{"item":"2 tbsp neutral oil (sunflower, vegetable or canola)","note":"flavourless high-smoke-point oil"},{"item":"Salt and pepper, lettuce and sliced avocado to serve","note":""}],"steps":["Pat the beans dry on a tray, then mash about three quarters of them, leaving some whole for texture.","Mix in the breadcrumbs, onion, egg, cumin, paprika, tomato puree, salt and pepper until it holds together.","Shape into 4 firm patties and chill 10 minutes.","Heat the oil in a pan over medium and cook the patties 4 to 5 minutes per side until crisp and heated through.","Toast the buns while the patties finish.","Build with lettuce, avocado and the patty, adding mayonnaise or salsa to taste."],"pairing":"Sweet potato fries and an amber ale","tags":["Vegetarian","Comfort","Crowd-pleaser"],"vegetarian":true,"spicy":false,"calories":440,"protein":17,"carbs":62,"fat":13,"allergens":["Gluten","Egg"],"role":"main","cuisineKey":"american","type":"Burgers"},{"id":"am-shake-shack-burger","name":"ShackBurger-Style Griddle Burger","category":"Burgers","course":"Main","meal":"both","tier":"signature","inspiration":"Shake Shack (Danny Meyer)","minutes":35,"serves":4,"level":"Weekend","idea":"A homage to Danny Meyer's ShackBurger: a thin, deeply seared beef patty on a buttered, griddle-toasted potato bun with American cheese, crisp lettuce, tomato and the cult ShackSauce. Restraint is the point, every element dialled for balance rather than size.","ingredients":[{"item":"600 g beef mince, 20% fat, in 4 loose balls","note":"ground beef around 20% fat, shaped into loose balls to smash on the griddle"},{"item":"4 slices American cheese (e.g. Kraft Singles)","note":"mild, ultra-melting processed cheese; mild cheddar slices also work"},{"item":"4 soft potato buns","note":"soft, slightly sweet buns made with potato flour; any soft burger bun works"},{"item":"4 green-leaf lettuce leaves","note":"soft, frilly lettuce; any soft leaf lettuce works"},{"item":"4 thin plum tomato slices","note":"plum tomatoes are oval Roma-type; any firm tomato works"},{"item":"30 g butter, softened","note":""},{"item":"For the sauce: 120 g mayonnaise, 1 tbsp ketchup, 1 tbsp yellow mustard, 1 tbsp finely chopped pickle, 0.25 tsp each garlic powder, smoked paprika and cayenne","note":"yellow mustard is mild American mustard; cayenne is hot chilli powder; smoked paprika is smoky red pepper powder"},{"item":"Salt and pepper","note":""}],"steps":["Whisk all the sauce ingredients together and chill so the flavours meld.","Butter the cut sides of the buns and toast face-down on a griddle until deep gold, then set aside.","Heat a heavy flat pan or griddle until very hot. Smash each ball into a thin patty, season, and sear 2 to 3 minutes until a dark crust forms.","Flip, top with American cheese and cook 1 minute more to 71 C as the cheese melts.","Spread sauce on both bun halves, lay lettuce and a tomato slice on the base.","Add the cheesy patty, close, and serve straight away with fries."],"pairing":"A frozen custard shake or a craft lager","tags":["Crowd-pleaser","Comfort","Date night"],"vegetarian":false,"spicy":false,"calories":700,"protein":34,"carbs":35,"fat":47,"allergens":["Gluten","Milk","Egg","Mustard"],"role":"main","cuisineKey":"american","type":"Burgers"},{"id":"am-bbq-glazed-meatballs","name":"BBQ Glazed Meatballs","category":"BBQ & Grill","course":"Main","meal":"both","tier":"easy","inspiration":"","minutes":30,"serves":4,"level":"Weeknight","idea":"Tender beef meatballs baked fast and tossed in a sticky barbecue glaze, the cookout-and-potluck staple that comes together in one tray. A milk-soaked breadcrumb binder keeps them soft while the high oven heat sets a savoury crust for the sauce to cling to.","ingredients":[{"item":"700 g beef mince","note":"ground beef"},{"item":"50 g breadcrumbs","note":""},{"item":"4 tbsp whole milk","note":"full-fat milk"},{"item":"1 egg, beaten","note":""},{"item":"1 small onion, finely grated","note":""},{"item":"1 tsp garlic powder","note":"dried ground garlic; mince 1 fresh clove instead if needed"},{"item":"1 tsp smoked paprika","note":"smoky dried red pepper powder; ordinary paprika works minus the smokiness"},{"item":"250 ml barbecue sauce","note":"sweet, smoky, tangy tomato-based sauce; sold in the condiments aisle"},{"item":"1 tbsp honey","note":""},{"item":"Salt and freshly ground black pepper","note":""}],"steps":["Heat the oven to 220 C and line a baking tray. Soak the breadcrumbs in the milk for 5 minutes.","Mix the mince with the soaked breadcrumbs, egg, onion, garlic powder, paprika, salt and pepper until just combined.","Roll into 20 even balls and space them out on the tray.","Bake 12 to 14 minutes until browned and cooked through to 71 C.","Warm the barbecue sauce with the honey in a wide pan, add the meatballs and toss to coat in the sticky glaze.","Serve over rice or with cocktail sticks as sliders, scattered with extra sauce."],"pairing":"Buttered rice and a cold lager","tags":["Quick","Crowd-pleaser","Comfort"],"vegetarian":false,"spicy":false,"calories":520,"protein":38,"carbs":38,"fat":24,"allergens":["Gluten","Milk","Egg"],"role":"main","cuisineKey":"american","type":"Grills & BBQ"},{"id":"am-grilled-bbq-chicken","name":"Grilled BBQ Chicken","category":"BBQ & Grill","course":"Main","meal":"both","tier":"easy","inspiration":"","minutes":45,"serves":4,"level":"Weeknight","idea":"Bone-in thighs and drumsticks grilled over moderate heat, then mopped with sauce only at the very end so the sugars char rather than scorch. A quick dry-salt keeps the meat juicy through the fire.","ingredients":[{"item":"8 bone-in, skin-on chicken thighs and drumsticks, about 1.2 kg","note":""},{"item":"1 tbsp sea salt","note":""},{"item":"2 tsp smoked paprika","note":"smoky dried red pepper powder; ordinary paprika works minus the smokiness"},{"item":"1 tsp garlic powder","note":"dried ground garlic"},{"item":"1 tsp ground black pepper","note":""},{"item":"2 tbsp neutral oil (sunflower, vegetable or canola)","note":"flavourless high-smoke-point oil"},{"item":"200 ml barbecue sauce","note":"sweet, smoky, tangy tomato-based sauce"},{"item":"1 tbsp cider vinegar","note":"apple cider vinegar; white wine vinegar works"},{"item":"1 tsp hot sauce (e.g. Frank's or Tabasco)","note":"vinegary chilli sauce"}],"steps":["Pat the chicken dry and toss with the salt, paprika, garlic powder, pepper and oil. Leave 20 minutes at room temperature.","Heat a barbecue or griddle to medium. Place the chicken skin-side down and grill 6 to 7 minutes until well marked.","Turn and continue cooking over moderate heat, turning occasionally, for about 20 minutes.","Stir the vinegar and hot sauce into the barbecue sauce.","When the chicken reaches 75 C, brush with sauce and grill 2 minutes per side to glaze, watching for flare-ups.","Rest 5 minutes and serve with extra sauce on the side."],"pairing":"Grilled corn and a crisp rosé","tags":["Crowd-pleaser","Gluten-free option","Spicy"],"vegetarian":false,"spicy":true,"calories":560,"protein":48,"carbs":22,"fat":31,"allergens":[],"role":"main","cuisineKey":"american","type":"Grills & BBQ"},{"id":"am-grilled-corn-elote","name":"Grilled Street Corn (Elote)","category":"BBQ & Grill","course":"Starter","meal":"both","tier":"easy","inspiration":"","minutes":25,"serves":4,"level":"Weeknight","idea":"Charred corn slathered in a lime-spiked crema, dusted with chilli and crumbled cotija. A Mexican-American grill staple where the smoky char playing against the cool, creamy coating is the whole magic.","ingredients":[{"item":"4 corn cobs, husked","note":"fresh sweetcorn on the cob, leaves removed"},{"item":"4 tbsp mayonnaise","note":""},{"item":"3 tbsp soured cream","note":"thick, tangy cultured cream; creme fraiche or plain yogurt works"},{"item":"60 g cotija or feta, crumbled","note":"cotija is a dry, salty crumbly Mexican cheese; feta is the easy substitute"},{"item":"1 lime, juiced and zested","note":""},{"item":"1 tsp chilli powder","note":"ground dried chilli; a mild blend, not pure cayenne"},{"item":"0.5 tsp smoked paprika","note":"smoky dried red pepper powder"},{"item":"2 tbsp coriander (cilantro), chopped","note":"fresh green coriander leaves, called cilantro in the US"},{"item":"1 tbsp neutral oil (sunflower, vegetable or canola)","note":"flavourless high-smoke-point oil"}],"steps":["Heat a barbecue or griddle to high. Lightly oil the corn.","Grill the cobs, turning, for 8 to 10 minutes until charred in spots and tender.","Mix the mayonnaise, soured cream and lime juice into a loose coating.","Brush the hot corn all over with the crema mixture.","Sprinkle with the crumbled cheese, chilli powder, smoked paprika and lime zest.","Finish with chopped coriander and serve at once with lime wedges."],"pairing":"A cold Mexican lager with lime","tags":["Vegetarian","Quick","Gluten-free option","Spicy"],"vegetarian":true,"spicy":true,"calories":260,"protein":6,"carbs":22,"fat":18,"allergens":["Milk"],"role":"appetizer","cuisineKey":"american","type":"Starters"},{"id":"am-bbq-chicken-skewers","name":"BBQ Chicken Skewers","category":"BBQ & Grill","course":"Main","meal":"both","tier":"easy","inspiration":"","minutes":30,"serves":4,"level":"Weeknight","idea":"Cubes of thigh threaded with peppers and onion, grilled fast and glazed with barbecue sauce for a quick, colourful plate. Thigh meat over breast is the choice that keeps the skewers juicy on a hot grill.","ingredients":[{"item":"700 g boneless, skinless chicken thighs, cubed","note":""},{"item":"2 bell peppers, cut into chunks","note":"sweet capsicum (any colour)"},{"item":"1 red onion, cut into wedges","note":""},{"item":"2 tbsp neutral oil (sunflower, vegetable or canola)","note":"flavourless high-smoke-point oil"},{"item":"1 tsp smoked paprika","note":"smoky dried red pepper powder"},{"item":"1 tsp garlic powder","note":"dried ground garlic"},{"item":"150 ml barbecue sauce","note":"sweet, smoky, tangy tomato-based sauce"},{"item":"Salt and pepper","note":""},{"item":"Wooden or metal skewers","note":"soak wooden ones in water first so they don't burn"}],"steps":["If using wooden skewers, soak them in water for 15 minutes.","Toss the chicken with oil, paprika, garlic powder, salt and pepper.","Thread the chicken, peppers and onion alternately onto the skewers.","Heat a barbecue or griddle to medium-high and grill 10 to 12 minutes, turning, until the chicken reaches 75 C.","Brush with barbecue sauce in the last 3 minutes and turn to glaze without burning.","Rest 3 minutes and serve over rice or with salad."],"pairing":"Fluffy rice and a cold lager","tags":["Quick","Crowd-pleaser","Gluten-free option"],"vegetarian":false,"spicy":false,"calories":410,"protein":36,"carbs":24,"fat":19,"allergens":[],"role":"main","cuisineKey":"american","type":"Grills & BBQ"},{"id":"am-grilled-brisket","name":"Central Texas Smoked Brisket","category":"BBQ & Grill","course":"Main","meal":"dinner","tier":"signature","inspiration":"Franklin Barbecue (Aaron Franklin)","minutes":900,"serves":8,"level":"Project","idea":"A homage to Aaron Franklin's Austin brisket: a whole packer rubbed simply with salt and coarse pepper, smoked low over post oak until the bark turns mahogany and the fat renders to butter. Patience and a steady fire, not seasoning tricks, are the whole craft, and the leftovers make the finest lunch sandwiches.","ingredients":[{"item":"1 whole beef brisket (packer cut), about 5 kg, fat cap trimmed to 6 mm","note":"a large fatty cut from the cow's chest; ask the butcher for a whole untrimmed packer brisket"},{"item":"60 g coarse sea salt","note":"large-grain salt; kosher salt is ideal"},{"item":"60 g coarse-ground black pepper","note":"coarsely cracked peppercorns, not fine pepper"},{"item":"Post oak or hickory wood for smoking","note":"hardwood chunks or logs that give brisket its smoke flavour; oak or hickory chunks from a BBQ shop"},{"item":"Butcher paper, for wrapping","note":"unwaxed, uncoated pink or brown paper that lets the meat breathe; foil works in a pinch"},{"item":"Water, for the smoker pan","note":""}],"steps":["Trim the brisket, leaving an even 6 mm fat cap, and bring it to room temperature.","Mix the salt and pepper in equal parts and coat the brisket evenly on all sides.","Set a smoker to a steady 110 to 120 C with post oak and a water pan. Smoke the brisket fat-side up for about 6 hours until the bark is set and deep mahogany.","When the internal temperature hits 70 C and the bark holds, wrap tightly in butcher paper and return to the smoker.","Continue until the thickest point reads 95 to 96 C and probes like soft butter. Do not cook to a clock: a brisket stalls for hours around 70 C, so total smoking time is commonly 12 to 18 hours. Push through the stall and judge by feel.","Rest wrapped in a cool oven or cooler for at least 1 hour, then slice against the grain into pencil-thick slices."],"pairing":"White bread, pickles, raw onion and a cold longneck beer","tags":["Make-ahead","Crowd-pleaser","Comfort","Gluten-free option","Batch-cook"],"vegetarian":false,"spicy":false,"calories":650,"protein":52,"carbs":1,"fat":48,"allergens":[],"role":"main","cuisineKey":"american","type":"Grills & BBQ"},{"id":"am-mac-and-cheese","name":"Baked Macaroni and Cheese","category":"Comfort classics","course":"Main","meal":"both","tier":"easy","inspiration":"","minutes":50,"serves":4,"level":"Weeknight","idea":"A proper baked mac built on a silky béchamel and a two-cheese blend, finished with a crunchy buttered panko crust. Cheddar brings the sharp bite while Gruyère gives the molten stretch.","ingredients":[{"item":"350 g elbow macaroni","note":"short curved pasta tubes"},{"item":"50 g butter, plus 15 g for the topping","note":""},{"item":"50 g plain flour (all-purpose)","note":""},{"item":"700 ml whole milk","note":"full-fat milk"},{"item":"250 g mature cheddar, grated","note":"sharp aged cheddar"},{"item":"100 g Gruyère, grated","note":"firm, nutty Swiss melting cheese; Emmental or extra cheddar works"},{"item":"1 tsp Dijon mustard","note":"smooth, mild-sharp French mustard"},{"item":"0.5 tsp grated nutmeg","note":"warm sweet baking spice; buy whole and grate, or use pre-ground"},{"item":"50 g panko breadcrumbs","note":"light, extra-crispy Japanese breadcrumbs; ordinary dried breadcrumbs work"},{"item":"Salt and white pepper","note":"white pepper blends in invisibly; black pepper is fine"}],"steps":["Heat the oven to 200 C. Cook the macaroni in salted water 2 minutes short of the packet time, then drain.","Melt the 50 g butter in a saucepan, whisk in the flour and cook 1 minute to a pale roux.","Gradually whisk in the milk and simmer, stirring, for 5 minutes until thickened enough to coat the back of a spoon.","Off the heat, stir in most of the cheddar and Gruyère, the mustard, nutmeg, salt and white pepper until smooth.","Fold in the macaroni, tip into a baking dish, and scatter with the remaining cheese, the panko and the 15 g melted topping butter.","Bake 20 to 25 minutes until bubbling and golden. Rest 5 minutes before serving."],"pairing":"A lightly oaked Chardonnay or a green salad with sharp vinaigrette","tags":["Vegetarian","Comfort","Crowd-pleaser"],"vegetarian":true,"spicy":false,"calories":830,"protein":37,"carbs":78,"fat":42,"allergens":["Gluten","Milk","Mustard"],"role":"main","cuisineKey":"american","type":"Mains"},{"id":"am-meatloaf","name":"Classic Glazed Meatloaf","category":"Comfort classics","course":"Main","meal":"dinner","tier":"easy","inspiration":"","minutes":80,"serves":4,"level":"Weeknight","idea":"A tender beef-and-pork loaf bound with a milk-soaked panade and lacquered with a tangy ketchup glaze. The panade is the trick that keeps every slice moist instead of dense and dry.","ingredients":[{"item":"500 g beef mince","note":"ground beef"},{"item":"250 g pork mince","note":"ground pork"},{"item":"80 g fresh breadcrumbs","note":"made from blitzed fresh bread, softer than dried"},{"item":"100 ml whole milk","note":"full-fat milk"},{"item":"1 onion, finely diced","note":""},{"item":"2 garlic cloves, minced","note":""},{"item":"1 egg, beaten","note":""},{"item":"1 tbsp Worcestershire sauce","note":"savoury, tangy fermented brown sauce (say 'wuster'); soy sauce is a rough substitute"},{"item":"1 tsp sea salt","note":""},{"item":"120 g ketchup","note":""},{"item":"2 tbsp light brown sugar","note":"soft pale-brown sugar"},{"item":"1 tbsp cider vinegar","note":"apple cider vinegar; white wine vinegar works"}],"steps":["Heat the oven to 180 C. Soak the breadcrumbs in the milk for 5 minutes to form a panade.","Soften the onion and garlic in a little oil over medium heat for 5 minutes, then cool slightly.","Combine the beef, pork, panade, onion mixture, egg, Worcestershire and salt, mixing just until bound, not overworked.","Shape into a loaf on a lined tray. Mix the ketchup, brown sugar and vinegar and brush half over the top.","Bake 45 minutes, brush with the remaining glaze, then bake a further 15 minutes until 71 C.","Rest 10 minutes before slicing so it holds together."],"pairing":"Buttery mashed potato and a glass of Merlot","tags":["Comfort","Make-ahead","Crowd-pleaser"],"vegetarian":false,"spicy":false,"calories":620,"protein":40,"carbs":35,"fat":35,"allergens":["Gluten","Milk","Egg","Sulphites"],"role":"main","cuisineKey":"american","type":"Mains"},{"id":"am-buffalo-wings","name":"Buffalo Wings","category":"Comfort classics","course":"Starter","meal":"both","tier":"easy","inspiration":"","minutes":45,"serves":4,"level":"Weeknight","idea":"Crisp baked wings tossed in the original Buffalo emulsion of cayenne hot sauce and butter. The butter rounds the vinegar heat into something glossy and addictive rather than just fiery.","ingredients":[{"item":"1 kg chicken wings, split at the joint","note":"separated into drumette and flat; discard or save the wing tips"},{"item":"1 tbsp baking powder (not bicarbonate of soda)","note":"raising agent that crisps the skin; make sure it's baking powder, not bicarb"},{"item":"1 tsp sea salt","note":""},{"item":"1 tsp garlic powder","note":"dried ground garlic"},{"item":"120 ml cayenne pepper hot sauce, such as Frank's RedHot","note":"the classic tangy, medium-hot wing sauce; Frank's is traditional"},{"item":"60 g butter","note":""},{"item":"1 tbsp white vinegar","note":"plain distilled vinegar"},{"item":"100 g blue cheese (e.g. Roquefort or Stilton)","note":"strong, tangy veined cheese for the dip"},{"item":"100 ml soured cream","note":"thick, tangy cultured cream; creme fraiche or plain yogurt works"},{"item":"2 tbsp mayonnaise","note":""}],"steps":["Heat the oven to 220 C. Pat the wings very dry and toss with the baking powder, salt and garlic powder, which helps them crisp.","Spread on a rack over a tray and bake 40 to 45 minutes, turning once, until deep golden and crisp at 75 C.","Gently warm the hot sauce, butter and vinegar in a pan, whisking into a smooth emulsified sauce.","Toss the hot wings in the sauce until fully coated.","Mash the blue cheese into the soured cream and mayonnaise for a dip.","Serve the wings with celery sticks and the blue cheese dip alongside."],"pairing":"An ice-cold lager and a blue cheese dip","tags":["Spicy","Crowd-pleaser","Gluten-free option"],"vegetarian":false,"spicy":true,"calories":620,"protein":42,"carbs":6,"fat":47,"allergens":["Milk"],"role":"appetizer","cuisineKey":"american","type":"Starters"},{"id":"am-cornbread","name":"Skillet Cornbread","category":"Comfort classics","course":"Starter","meal":"both","tier":"easy","inspiration":"","minutes":35,"serves":4,"level":"Weeknight","idea":"Golden cornbread baked in a sizzling buttered cast-iron skillet for a deep, crunchy crust and a tender, faintly sweet crumb. Preheating the skillet with butter is what gives that prized fried-edge bottom.","ingredients":[{"item":"200 g fine cornmeal (fine yellow polenta)","note":"ground dried corn; fine polenta or maize meal works"},{"item":"100 g plain flour (all-purpose)","note":""},{"item":"2 tbsp caster sugar","note":"fine white sugar; ordinary granulated sugar works"},{"item":"2 tsp baking powder","note":""},{"item":"0.5 tsp bicarbonate of soda","note":"baking soda; raising agent that reacts with the buttermilk"},{"item":"1 tsp sea salt","note":""},{"item":"250 ml buttermilk","note":"tangy cultured milk; substitute 250 ml milk with 1 tbsp lemon juice or vinegar stirred in, left 5 min"},{"item":"2 eggs, beaten","note":""},{"item":"60 g butter, melted, plus 1 tbsp for the skillet","note":""}],"steps":["Heat the oven to 200 C and put a 23 cm cast-iron skillet inside with the 1 tbsp butter to heat.","Whisk together the cornmeal, flour, sugar, baking powder, bicarbonate of soda and salt.","In a second bowl whisk the buttermilk, eggs and 60 g melted butter.","Fold the wet into the dry just until combined, leaving the batter slightly lumpy.","Pour the batter into the hot skillet, which should sizzle, and bake 20 to 25 minutes until golden and a skewer comes out clean.","Rest 5 minutes, then cut into wedges and serve warm with butter."],"pairing":"A bowl of chilli or a drizzle of honey","tags":["Vegetarian","Quick","Comfort","Crowd-pleaser"],"vegetarian":true,"spicy":false,"calories":420,"protein":10,"carbs":58,"fat":16,"allergens":["Gluten","Milk","Egg"],"role":"appetizer","cuisineKey":"american","type":"Starters"},{"id":"am-tuna-melt","name":"Diner Tuna Melt","category":"Comfort classics","course":"Main","meal":"lunch","tier":"easy","inspiration":"","minutes":20,"serves":4,"level":"Weeknight","idea":"A griddled open sandwich of creamy tuna mayo under a blanket of melted cheddar on buttery toasted bread. Toasting the bread first keeps it from going soggy under the warm filling.","ingredients":[{"item":"2 x 145 g tins tuna in spring water, drained","note":"tinned tuna packed in water, not oil or brine"},{"item":"4 tbsp mayonnaise","note":""},{"item":"1 celery stick, finely diced","note":""},{"item":"2 tbsp finely diced red onion","note":""},{"item":"1 tsp Dijon mustard","note":"smooth, mild-sharp French mustard"},{"item":"1 tbsp lemon juice","note":""},{"item":"8 slices sourdough or bloomer bread","note":"bloomer is a soft white crusty loaf; any sturdy sandwich bread works"},{"item":"6 slices mature cheddar","note":"sharp aged cheddar"},{"item":"30 g butter, softened","note":""},{"item":"Salt and pepper","note":""}],"steps":["Flake the tuna and mix with the mayonnaise, celery, onion, mustard, lemon juice, salt and pepper.","Butter the bread on the outsides. Heat a pan or griddle over medium.","Lay 4 slices butter-side down, pile on the tuna and top with cheddar.","Close with the remaining slices, butter-side up.","Griddle 3 to 4 minutes per side, pressing lightly, until golden and the cheese melts.","Cut in half and serve hot with pickles or crisps."],"pairing":"A bowl of tomato soup and an iced tea","tags":["Quick","Lunchbox","Comfort"],"vegetarian":false,"spicy":false,"calories":620,"protein":33,"carbs":48,"fat":33,"allergens":["Gluten","Milk","Fish","Mustard"],"role":"main","cuisineKey":"american","type":"Mains"},{"id":"am-cobb-salad","name":"Chicken Cobb Salad","category":"Comfort classics","course":"Main","meal":"both","tier":"easy","inspiration":"","minutes":25,"serves":4,"level":"Weeknight","idea":"The classic American chopped salad of chicken, egg, avocado, tomato and blue cheese in tidy rows over crisp lettuce with a sharp dressing. Arranging the toppings in stripes before tossing is what makes it feel composed rather than thrown together.","ingredients":[{"item":"2 cooked chicken breasts, sliced","note":""},{"item":"1 romaine (cos) lettuce, chopped","note":"long crisp lettuce; little gem works too"},{"item":"4 eggs, hard-boiled and halved","note":""},{"item":"2 ripe avocados, sliced","note":""},{"item":"200 g cherry tomatoes, halved","note":""},{"item":"100 g blue cheese, crumbled (e.g. Roquefort or Stilton)","note":"strong, tangy veined cheese; feta works for a milder option"},{"item":"6 rashers cooked bacon, chopped","note":""},{"item":"For the dressing: 4 tbsp olive oil, 2 tbsp red wine vinegar, 1 tsp Dijon mustard, salt and pepper","note":"Dijon is smooth mild-sharp French mustard"}],"steps":["Spread the chopped lettuce over a large platter.","Arrange the chicken, eggs, avocado, tomatoes, blue cheese and bacon in neat rows on top.","Whisk the olive oil, vinegar, mustard, salt and pepper into a dressing.","Drizzle the dressing over just before serving.","Toss at the table or serve as composed for everyone to help themselves."],"pairing":"A chilled Sauvignon Blanc or sparkling water with lemon","tags":["Light","Quick","Gluten-free option","Lunchbox"],"vegetarian":false,"spicy":false,"calories":580,"protein":38,"carbs":12,"fat":42,"allergens":["Milk","Egg","Mustard","Sulphites"],"role":"salad","cuisineKey":"american","type":"Salads"},{"id":"am-buttermilk-fried-chicken","name":"Buttermilk Fried Chicken, Keller Style","category":"Comfort classics","course":"Main","meal":"both","tier":"signature","inspiration":"Ad Hoc (Thomas Keller)","minutes":90,"serves":4,"level":"Weekend","idea":"Thomas Keller's Ad Hoc method: a long lemon-and-herb buttermilk brine, then a double dredge fried in two stages so white and dark meat both finish perfectly. The herb-and-lemon brine and staggered frying are what raise this above ordinary fried chicken.","ingredients":[{"item":"1 whole chicken, jointed into 8 pieces","note":"ask the butcher to joint it, or buy a pack of mixed bone-in pieces"},{"item":"For the brine: 1.5 litres water, 60 g salt, 2 tbsp honey, 1 lemon halved, 4 garlic cloves, a small bunch each of thyme and parsley, 1 tbsp black peppercorns","note":"a saltwater soak that seasons and moistens the chicken"},{"item":"500 ml buttermilk","note":"tangy cultured milk; substitute 500 ml milk with 2 tbsp lemon juice or vinegar stirred in, left 5 min"},{"item":"400 g plain flour (all-purpose)","note":""},{"item":"2 tsp garlic powder, 2 tsp onion powder, 2 tsp smoked paprika, 1 tsp cayenne","note":"onion powder is dried ground onion; cayenne is hot red chilli powder; smoked paprika is smoky red pepper powder"},{"item":"2 tsp salt and 1 tsp black pepper","note":""},{"item":"2 litres neutral oil, for frying (sunflower, vegetable or canola)","note":"flavourless high-smoke-point oil for deep-frying"}],"steps":["Simmer the brine ingredients for 5 minutes, cool completely, then submerge the chicken and brine 8 to 12 hours in the fridge.","Drain and pat dry. Whisk the flour with the garlic and onion powders, paprika, cayenne, salt and pepper.","Dredge each piece in the seasoned flour, dip in buttermilk, then dredge again for a craggy crust.","Heat the oil to 165 C. Fry the dark meat first for 12 to 14 minutes to 75 C, keeping the oil near 160 C.","Fry the white meat for 10 to 12 minutes to 74 C, then drain on a rack.","Season lightly with salt while hot and rest 5 minutes before serving."],"pairing":"Buttermilk biscuits, hot honey and a cold Pilsner","tags":["Make-ahead","Comfort","Crowd-pleaser","Date night","Spicy"],"vegetarian":false,"spicy":true,"calories":780,"protein":48,"carbs":48,"fat":42,"allergens":["Gluten","Milk"],"role":"main","cuisineKey":"american","type":"Mains"},{"id":"am-mac-and-cheese-keller","name":"Three-Cheese Baked Mac and Cheese","cuisineKey":"american","category":"Comfort classics","course":"Main","meal":"both","tier":"signature","inspiration":"Ad Hoc (Thomas Keller)","minutes":50,"serves":4,"level":"Weekend","idea":"The defining busy-parent crowd-pleaser, absent from the American list. Keller's Ad Hoc version builds a proper bechamel and folds in three cheeses before baking, which lifts it above the boxed version while staying genuinely make-ahead and freezer-friendly.","ingredients":[{"item":"300g dried elbow macaroni","note":"short curved pasta tubes"},{"item":"60g unsalted butter","note":""},{"item":"60g plain flour (all-purpose)","note":""},{"item":"700ml whole milk, warmed","note":"full-fat milk"},{"item":"150g sharp cheddar, grated","note":"mature, tangy cheddar"},{"item":"100g Gruyere, grated","note":"firm, nutty Swiss melting cheese; Emmental or extra cheddar works"},{"item":"60g Parmesan, grated","note":"hard, salty Italian cheese; Grana Padano works"},{"item":"60g panko breadcrumbs","note":"light, extra-crispy Japanese breadcrumbs; ordinary dried breadcrumbs work"},{"item":"1/2 tsp Dijon mustard","note":"smooth, mild-sharp French mustard"},{"item":"Pinch of grated nutmeg","note":"warm sweet baking spice"},{"item":"Salt and black pepper to taste","note":""}],"steps":["Heat oven to 190C. Boil the macaroni 2 minutes short of the packet time, drain and set aside.","Melt 45g of the butter in a saucepan, whisk in the flour and cook 2 minutes without colouring.","Whisk in the warm milk a little at a time until smooth, then simmer 5 minutes until it coats the back of a spoon. Off the heat stir in the Dijon, nutmeg, cheddar and Gruyere until melted. Season.","Fold the macaroni through the sauce and tip into a buttered baking dish.","Melt the remaining 15g butter, toss with the panko and Parmesan, and scatter over the top.","Bake 20-25 minutes until bubbling and golden. Rest 5 minutes before serving. Freezes well unbaked; add 10 minutes from chilled."],"pairing":"A crisp green salad with a sharp vinaigrette to cut the richness","tags":["kid-friendly","make-ahead","freezer-friendly","vegetarian"],"vegetarian":true,"spicy":false,"calories":760,"protein":34,"carbs":68,"fat":40,"allergens":["Gluten","Milk","Mustard"],"role":"main","type":"Mains"},{"id":"am-grilled-chicken-club","name":"Grilled Chicken Club Sandwich","cuisineKey":"american","category":"Comfort classics","role":"main","course":"Main","meal":"lunch","tier":"easy","inspiration":"","minutes":25,"serves":4,"level":"Weeknight","idea":"A toasted triple-decker stacked with grilled chicken, bacon, lettuce and tomato for a satisfying lunch plate.","ingredients":[{"item":"4 boneless skinless chicken breasts, about 600 g","note":""},{"item":"12 slices white sandwich bread","note":""},{"item":"8 rashers streaky bacon","note":"thin, fatty bacon from the belly; regular bacon is fine"},{"item":"2 beef tomatoes, sliced","note":"large meaty tomatoes; any large tomato works"},{"item":"8 crisp lettuce leaves (iceberg or romaine)","note":""},{"item":"6 tbsp mayonnaise","note":""},{"item":"1 tbsp Dijon mustard","note":"smooth, mild-sharp French mustard"},{"item":"2 tbsp olive oil","note":""},{"item":"1 tsp garlic powder","note":"dried ground garlic"},{"item":"Salt and freshly ground black pepper","note":""}],"steps":["Season the chicken with garlic powder, salt and pepper, then rub with olive oil.","Grill or pan-fry the chicken over medium-high heat for 6 to 7 minutes per side until cooked through, then rest and slice.","Fry the bacon until crisp and drain on kitchen paper.","Toast the bread and mix the mayonnaise with the Dijon mustard.","Spread each slice with the mustard mayo, then build triple-deckers with chicken, bacon, lettuce and tomato.","Secure with picks, halve and serve."],"pairing":"Crisp dill pickle spears and kettle chips","tags":["sandwich","chicken","lunch","family"],"vegetarian":false,"spicy":false,"calories":620,"protein":48,"carbs":42,"fat":29,"allergens":["Gluten","Egg","Mustard"],"type":"Mains"},{"id":"am-pulled-pork-sandwich","name":"Carolina Pulled Pork Sandwich","cuisineKey":"american","category":"BBQ & Grill","role":"main","course":"Main","meal":"lunch","tier":"easy","inspiration":"","minutes":40,"serves":4,"level":"Weekend","idea":"Slow-cooker pork shoulder pulled into a vinegary, smoky pile and piled on soft buns with slaw.","ingredients":[{"item":"1.2 kg boneless pork shoulder","note":"a fatty, collagen-rich cut that shreds when slow-cooked; also sold as pork butt"},{"item":"1 tbsp smoked paprika","note":"smoky dried red pepper powder; ordinary paprika works minus the smokiness"},{"item":"1 tbsp light brown sugar","note":"soft pale-brown sugar"},{"item":"1 tsp garlic powder","note":"dried ground garlic"},{"item":"1 tsp onion powder","note":"dried ground onion"},{"item":"1 tsp sea salt","note":""},{"item":"200 ml cider vinegar","note":"apple cider vinegar, the tangy base of Carolina-style pork; white wine vinegar works"},{"item":"150 ml barbecue sauce","note":"sweet, smoky, tangy tomato-based sauce"},{"item":"4 soft burger buns","note":""},{"item":"200 g white cabbage, finely shredded","note":""},{"item":"3 tbsp mayonnaise","note":""}],"steps":["Rub the pork with paprika, sugar, garlic powder, onion powder and salt.","Slow-cook with 100 ml of the vinegar on low for 8 hours, or pressure-cook for 75 minutes, until fork-tender.","Shred the pork and toss with the remaining vinegar and the barbecue sauce.","Toss the cabbage with the mayonnaise and a pinch of salt for a quick slaw.","Pile the pork onto toasted buns, top with slaw and serve."],"pairing":"Skillet cornbread and extra hot sauce","tags":["pork","bbq","sandwich","slow-cook"],"vegetarian":false,"spicy":false,"calories":640,"protein":45,"carbs":44,"fat":30,"allergens":["Gluten","Egg","Mustard","Sulphites"],"type":"Grills & BBQ"},{"id":"am-ad-hoc-roast-chicken","name":"Ad Hoc Buttermilk-Brined Roast Chicken","cuisineKey":"american","category":"Comfort classics","role":"main","course":"Main","meal":"lunch","tier":"signature","inspiration":"Ad Hoc (Thomas Keller)","minutes":120,"serves":4,"level":"Project","idea":"A buttermilk-brined whole chicken roasted to a lacquered, herb-scented finish in the Keller family-style tradition.","ingredients":[{"item":"1 whole chicken, about 1.6 kg","note":""},{"item":"1 litre buttermilk","note":"tangy cultured milk; substitute 1 litre milk with 4 tbsp lemon juice or vinegar stirred in, left 10 min"},{"item":"30 g sea salt, plus extra for roasting","note":""},{"item":"2 garlic cloves, smashed","note":""},{"item":"4 sprigs thyme","note":"fresh woody herb; 1 tsp dried thyme works"},{"item":"1 lemon, halved","note":""},{"item":"2 tbsp olive oil","note":""},{"item":"20 g butter, softened","note":""},{"item":"Freshly ground black pepper","note":""}],"steps":["Whisk the buttermilk with the salt, garlic and thyme, then submerge the chicken and brine in the fridge for 12 to 24 hours.","Remove the chicken, pat very dry and let it sit at room temperature for 30 minutes.","Heat the oven to 220 C. Rub the chicken with olive oil and softened butter, season with salt and pepper, and tuck the lemon inside.","Roast for 50 to 60 minutes until the juices run clear and the skin is deep golden.","Rest for 15 minutes, then carve and serve family-style."],"pairing":"Skillet cornbread and a green salad","tags":["chicken","roast","signature","sunday"],"vegetarian":false,"spicy":false,"calories":580,"protein":52,"carbs":6,"fat":38,"allergens":["Milk"],"type":"Mains"},{"id":"am-bbq-baby-back-ribs","name":"Sticky Oven Baby Back Ribs","cuisineKey":"american","category":"BBQ & Grill","role":"main","course":"Main","meal":"dinner","tier":"easy","inspiration":"","minutes":180,"serves":4,"level":"Weekend","idea":"Low-and-slow oven ribs with a smoky dry rub finished under a sticky barbecue glaze.","ingredients":[{"item":"2 racks baby back pork ribs, about 1.6 kg","note":"shorter, leaner ribs from the top of the ribcage; loin ribs are the same thing"},{"item":"2 tbsp smoked paprika","note":"smoky dried red pepper powder; ordinary paprika works minus the smokiness"},{"item":"2 tbsp light brown sugar","note":"soft pale-brown sugar"},{"item":"1 tbsp garlic powder","note":"dried ground garlic"},{"item":"1 tbsp sea salt","note":""},{"item":"1 tsp ground black pepper","note":""},{"item":"250 ml barbecue sauce","note":"sweet, smoky, tangy tomato-based sauce"},{"item":"2 tbsp cider vinegar","note":"apple cider vinegar; white wine vinegar works"},{"item":"1 tbsp honey","note":""}],"steps":["Heat the oven to 150 C and peel the membrane from the back of the ribs.","Mix the paprika, sugar, garlic powder, salt and pepper, then rub all over the ribs.","Wrap each rack tightly in foil and bake for 2.5 hours until tender.","Mix the barbecue sauce with the vinegar and honey.","Unwrap, brush generously with the glaze and grill or roast at 220 C for 12 minutes until sticky.","Rest for 10 minutes, then cut between the bones and serve."],"pairing":"Grilled street corn and coleslaw","tags":["pork","ribs","bbq","dinner"],"vegetarian":false,"spicy":false,"calories":720,"protein":48,"carbs":32,"fat":44,"allergens":["Mustard","Sulphites"],"type":"Grills & BBQ"},{"id":"am-philly-cheesesteak","name":"Philly Cheesesteak","cuisineKey":"american","category":"Comfort classics","role":"main","course":"Main","meal":"dinner","tier":"easy","inspiration":"","minutes":30,"serves":4,"level":"Weeknight","idea":"Thin-sliced ribeye griddled with onions and melted cheese piled into soft hoagie rolls.","ingredients":[{"item":"700 g ribeye steak, very thinly sliced","note":"well-marbled steak; freeze 30 min before slicing to get it paper-thin; sirloin works"},{"item":"2 white onions, thinly sliced","note":""},{"item":"1 green bell pepper, thinly sliced","note":"sweet green capsicum"},{"item":"8 slices provolone, or 200 g Cheez Whiz","note":"provolone is a mild, smooth Italian melting cheese; Cheez Whiz is a soft processed cheese sauce; mild mozzarella works"},{"item":"4 hoagie or sub rolls","note":"long, soft white sandwich rolls; baguette or any soft sub roll works"},{"item":"3 tbsp neutral oil (sunflower, vegetable or canola)","note":"flavourless high-smoke-point oil"},{"item":"20 g butter","note":""},{"item":"Salt and freshly ground black pepper","note":""}],"steps":["Heat the oil on a griddle or large frying pan over high heat.","Cook the onions and pepper with the butter until soft and golden, then push to one side.","Add the sliced ribeye, season and cook quickly, chopping with the spatula until just browned.","Combine the meat and onions, lay the cheese over the top and let it melt.","Scoop into split, lightly toasted rolls and serve hot."],"pairing":"Crinkle-cut fries and pickles","tags":["beef","sandwich","cheese","dinner"],"vegetarian":false,"spicy":false,"calories":760,"protein":46,"carbs":46,"fat":44,"allergens":["Gluten","Milk"],"type":"Mains"},{"id":"am-french-laundry-short-rib","name":"Braised Beef Short Ribs with Red Wine","cuisineKey":"american","category":"Comfort classics","role":"main","course":"Main","meal":"dinner","tier":"signature","inspiration":"The French Laundry (Thomas Keller)","minutes":210,"serves":4,"level":"Project","idea":"Wine-braised bone-in short ribs cooked until spoon-tender with a glossy reduction, in the French Laundry style.","ingredients":[{"item":"1.4 kg bone-in beef short ribs","note":"meaty, fatty ribs from the lower chest; great for slow braising"},{"item":"2 tbsp neutral oil (sunflower, vegetable or canola)","note":"flavourless high-smoke-point oil for searing"},{"item":"1 onion, diced","note":""},{"item":"2 carrots, diced","note":""},{"item":"2 celery sticks, diced","note":""},{"item":"3 garlic cloves, crushed","note":""},{"item":"500 ml dry red wine","note":"a full-bodied dry red such as Cabernet or Merlot"},{"item":"500 ml beef stock","note":""},{"item":"2 tbsp tomato puree (tomato paste)","note":"thick concentrated tomato in a tube or small tin"},{"item":"3 sprigs thyme","note":"fresh woody herb; 1 tsp dried thyme works"},{"item":"Salt and freshly ground black pepper","note":""}],"steps":["Heat the oven to 160 C. Season the ribs well and sear in the oil in a casserole until deeply browned on all sides, then remove.","Soften the onion, carrots, celery and garlic in the same pan for 8 minutes.","Stir in the tomato puree, pour in the red wine and simmer to reduce by half.","Return the ribs, add the stock and thyme, bring to a simmer, cover and braise in the oven for 3 hours until tender.","Lift out the ribs, strain and reduce the sauce until glossy, then spoon over the ribs to serve."],"pairing":"Buttery mashed potatoes and a glass of red","tags":["beef","braise","signature","dinner"],"vegetarian":false,"spicy":false,"calories":680,"protein":50,"carbs":12,"fat":42,"allergens":["Sulphites"],"type":"Mains"},{"id":"am-deviled-eggs","name":"Classic Deviled Eggs","cuisineKey":"american","category":"Comfort classics","role":"appetizer","course":"Starter","meal":"both","tier":"easy","inspiration":"","minutes":25,"serves":4,"level":"Weeknight","idea":"Halved hard-boiled eggs filled with a creamy, tangy mustard yolk mixture and dusted with paprika.","ingredients":[{"item":"8 eggs","note":""},{"item":"4 tbsp mayonnaise","note":""},{"item":"1 tsp Dijon mustard","note":"smooth, mild-sharp French mustard"},{"item":"1 tsp white wine vinegar","note":""},{"item":"0.25 tsp smoked paprika, plus extra to dust","note":"smoky dried red pepper powder; ordinary paprika works"},{"item":"2 spring onions, finely sliced","note":"slim mild onions, called scallions or green onions"},{"item":"Salt and freshly ground black pepper","note":""}],"steps":["Boil the eggs for 9 minutes, then cool in iced water and peel.","Halve the eggs and scoop the yolks into a bowl.","Mash the yolks with the mayonnaise, mustard, vinegar, salt and pepper until smooth.","Pipe or spoon the filling back into the whites.","Dust with paprika, scatter the spring onions over and serve chilled."],"pairing":"A platter alongside cold beer","tags":["eggs","starter","party","make-ahead"],"vegetarian":true,"spicy":false,"calories":190,"protein":11,"carbs":2,"fat":15,"allergens":["Egg","Mustard"],"type":"Starters"},{"id":"am-loaded-potato-skins","name":"Loaded Potato Skins","cuisineKey":"american","category":"Comfort classics","role":"appetizer","course":"Starter","meal":"both","tier":"easy","inspiration":"","minutes":60,"serves":4,"level":"Weeknight","idea":"Crisp baked potato shells filled with melted cheddar and bacon, topped with soured cream and chives.","ingredients":[{"item":"6 medium baking potatoes (russet or Maris Piper)","note":"floury baking potatoes that crisp well"},{"item":"6 rashers streaky bacon, chopped","note":"thin, fatty bacon from the belly; regular bacon is fine"},{"item":"150 g mature cheddar, grated","note":"sharp aged cheddar"},{"item":"3 tbsp neutral oil (sunflower, vegetable or canola)","note":"flavourless high-smoke-point oil"},{"item":"100 ml soured cream","note":"thick, tangy cultured cream; creme fraiche or plain yogurt works"},{"item":"3 tbsp chives, snipped","note":"thin mild green herb with a faint onion taste; spring onion tops work"},{"item":"Salt and freshly ground black pepper","note":""}],"steps":["Heat the oven to 200 C and bake the potatoes for 50 minutes until tender.","Fry the bacon until crisp and drain.","Halve the potatoes and scoop out most of the flesh, leaving a shell.","Brush the shells with oil, season and bake for a further 10 minutes until crisp.","Fill with cheddar and bacon and return to the oven until melted.","Top with soured cream and chives and serve hot."],"pairing":"Buffalo wings and a cold drink","tags":["potato","cheese","bacon","party"],"vegetarian":false,"spicy":false,"calories":340,"protein":13,"carbs":30,"fat":19,"allergens":["Milk"],"type":"Starters"},{"id":"am-jalapeno-poppers","name":"Baked Jalapeno Poppers","cuisineKey":"american","category":"BBQ & Grill","role":"appetizer","course":"Starter","meal":"both","tier":"easy","inspiration":"","minutes":35,"serves":4,"level":"Weeknight","idea":"Jalapenos stuffed with a creamy cheese filling, wrapped in bacon and baked until bubbling.","ingredients":[{"item":"12 large jalapeno peppers","note":"medium-hot green chillies; scrape out the seeds and pith to tame the heat"},{"item":"200 g cream cheese","note":"soft spreadable white cheese (e.g. Philadelphia)"},{"item":"80 g mature cheddar, grated","note":"sharp aged cheddar"},{"item":"12 rashers thin streaky bacon","note":"thin, fatty bacon from the belly; regular thin bacon is fine"},{"item":"1 tsp garlic powder","note":"dried ground garlic"},{"item":"2 tbsp chives, snipped","note":"thin mild green herb with a faint onion taste; spring onion tops work"},{"item":"Salt and freshly ground black pepper","note":""}],"steps":["Heat the oven to 200 C. Halve the jalapenos lengthways and scrape out the seeds.","Beat the cream cheese with the cheddar, garlic powder, chives, salt and pepper.","Spoon the filling into each jalapeno half.","Wrap each with a piece of bacon and set on a lined tray.","Bake for 20 to 25 minutes until the bacon is crisp and the filling is golden. Serve warm."],"pairing":"Soured cream dip and cold beer","tags":["cheese","bacon","party"],"vegetarian":false,"spicy":true,"calories":280,"protein":12,"carbs":5,"fat":24,"allergens":["Milk"],"type":"Starters"},{"id":"am-wedge-salad","name":"Steakhouse Wedge Salad","cuisineKey":"american","category":"Comfort classics","role":"salad","course":"Starter","meal":"both","tier":"easy","inspiration":"","minutes":20,"serves":4,"level":"Weeknight","idea":"A crisp iceberg wedge drenched in blue cheese dressing with bacon, tomatoes and chives.","ingredients":[{"item":"1 large iceberg lettuce, quartered into wedges","note":"crisp round lettuce; cut into 4 chunky wedges through the core"},{"item":"100 g blue cheese, crumbled (e.g. Roquefort or Stilton)","note":"strong, tangy veined cheese"},{"item":"100 ml buttermilk","note":"tangy cultured milk; substitute 100 ml milk with 1 tsp lemon juice or vinegar stirred in, left 5 min"},{"item":"3 tbsp mayonnaise","note":""},{"item":"2 tbsp soured cream","note":"thick, tangy cultured cream; creme fraiche or plain yogurt works"},{"item":"6 rashers cooked bacon, chopped","note":""},{"item":"150 g cherry tomatoes, halved","note":""},{"item":"2 tbsp chives, snipped","note":"thin mild green herb with a faint onion taste; spring onion tops work"},{"item":"Salt and freshly ground black pepper","note":""}],"steps":["Whisk the buttermilk, mayonnaise, soured cream and half the blue cheese into a dressing, then season.","Set each iceberg wedge on a plate.","Spoon the dressing generously over each wedge.","Scatter with the remaining blue cheese, bacon, tomatoes and chives.","Finish with black pepper and serve at once."],"pairing":"Grilled steak or burgers","tags":["salad","blue cheese","starter","steakhouse"],"vegetarian":false,"spicy":false,"calories":280,"protein":12,"carbs":9,"fat":22,"allergens":["Milk"],"type":"Salads"},{"id":"am-classic-coleslaw","name":"Creamy Buttermilk Coleslaw","cuisineKey":"american","category":"BBQ & Grill","role":"salad","course":"Starter","meal":"both","tier":"easy","inspiration":"","minutes":15,"serves":4,"level":"Weeknight","idea":"Crunchy shredded cabbage and carrot in a tangy buttermilk dressing, the classic barbecue side.","ingredients":[{"item":"400 g white cabbage, finely shredded","note":""},{"item":"100 g red cabbage, finely shredded","note":""},{"item":"2 carrots, grated","note":""},{"item":"5 tbsp mayonnaise","note":""},{"item":"3 tbsp buttermilk","note":"tangy cultured milk; substitute 3 tbsp milk with a squeeze of lemon juice, left 5 min"},{"item":"1 tbsp cider vinegar","note":"apple cider vinegar; white wine vinegar works"},{"item":"1 tsp Dijon mustard","note":"smooth, mild-sharp French mustard"},{"item":"1 tsp caster sugar","note":"fine white sugar; ordinary granulated works"},{"item":"Salt and freshly ground black pepper","note":""}],"steps":["Combine the white cabbage, red cabbage and carrots in a large bowl.","Whisk the mayonnaise, buttermilk, vinegar, mustard and sugar into a dressing.","Pour over the vegetables and toss to coat.","Season with salt and pepper and chill for at least 30 minutes.","Toss again and serve cold."],"pairing":"Pulled pork or barbecue ribs","tags":["salad","slaw","bbq","make-ahead"],"vegetarian":true,"spicy":false,"calories":190,"protein":2,"carbs":12,"fat":15,"allergens":["Egg","Milk","Mustard","Sulphites"],"type":"Salads"},{"id":"am-classic-potato-salad","name":"All-American Potato Salad","cuisineKey":"american","category":"BBQ & Grill","role":"salad","course":"Starter","meal":"both","tier":"easy","inspiration":"","minutes":35,"serves":4,"level":"Weeknight","idea":"Tender potatoes folded with a creamy mustard dressing, celery, egg and pickles for the cookout table.","ingredients":[{"item":"800 g waxy potatoes, peeled and cubed (e.g. Charlotte or new potatoes)","note":"firm potatoes that hold their shape when boiled"},{"item":"3 eggs, hard-boiled and chopped","note":""},{"item":"2 celery sticks, finely diced","note":""},{"item":"4 tbsp finely diced dill pickle","note":"pickled cucumber in salty, dilly brine; gherkins work"},{"item":"5 tbsp mayonnaise","note":""},{"item":"1 tbsp yellow mustard (American mild mustard)","note":"mild, tangy bright-yellow mustard"},{"item":"2 spring onions, sliced","note":"slim mild onions, called scallions or green onions"},{"item":"Salt and freshly ground black pepper","note":""}],"steps":["Boil the potatoes in salted water for 12 to 15 minutes until just tender, then drain and cool.","Whisk the mayonnaise with the mustard and season.","Fold the potatoes with the celery, pickle, egg and spring onions.","Stir through the dressing until evenly coated.","Chill for 30 minutes, season again and serve cold."],"pairing":"Burgers, hot dogs or grilled chicken","tags":["salad","potato","bbq","make-ahead"],"vegetarian":true,"spicy":false,"calories":300,"protein":7,"carbs":34,"fat":15,"allergens":["Egg","Mustard"],"type":"Salads"},{"id":"me-tacos-de-pollo","name":"Tacos de Pollo","category":"Tacos","course":"Main","meal":"both","tier":"easy","inspiration":"","minutes":25,"serves":4,"level":"Weeknight","idea":"Quick chicken tacos with a warm rub of cumin, paprika and oregano, pan-charred and piled into soft corn tortillas with onion, coriander and lime. The everyday taco that comes together while the kids' bath runs.","ingredients":[{"item":"500 g boneless chicken breast or thigh, thinly sliced","note":""},{"item":"1 tsp ground cumin","note":""},{"item":"1 tsp paprika","note":""},{"item":"1 tsp dried oregano (Mexican oregano if available)","note":"Mexican oregano is more citrusy than the Mediterranean type; ordinary dried oregano is a fine substitute"},{"item":"1 clove garlic, grated","note":""},{"item":"1 tbsp neutral oil (sunflower, vegetable or canola)","note":"any flavourless oil with a high smoke point"},{"item":"12 small corn tortillas","note":"soft flatbreads made from corn (maize); look in the world-foods aisle, or use small flour tortillas"},{"item":"1 white onion, finely chopped","note":""},{"item":"1 small bunch fresh coriander (cilantro), chopped","note":"the leafy green herb sold as cilantro in some countries"},{"item":"2 limes, cut into wedges","note":""}],"steps":["Toss the chicken with cumin, paprika, oregano, garlic, oil and a good pinch of salt.","Heat a pan over medium-high and cook the chicken for 6 to 8 minutes until lightly charred and cooked through.","Warm the tortillas in a dry pan until soft and pliable.","Fill each tortilla with chicken, onion and coriander.","Serve with lime wedges to squeeze over."],"pairing":"A cold lager or a sparkling limeade.","tags":["Quick","Crowd-pleaser","Gluten-free option","Lunchbox"],"vegetarian":false,"spicy":false,"calories":380,"protein":33,"carbs":36,"fat":12,"allergens":[],"role":"main","cuisineKey":"mexican","type":"Tacos"},{"id":"me-tacos-carne-asada","name":"Tacos de Carne Asada","category":"Tacos","course":"Main","meal":"both","tier":"easy","inspiration":"","minutes":30,"serves":4,"level":"Weeknight","idea":"Steak quickly marinated in lime, garlic and cumin, seared hard and chopped into tender, charred pieces for warm tortillas with onion and coriander. Fast, juicy and a guaranteed family favourite.","ingredients":[{"item":"600 g skirt or flank steak","note":"long, flat, well-flavoured cuts from the belly area; bavette or rump steak also work well"},{"item":"2 limes, juiced","note":""},{"item":"2 cloves garlic, grated","note":""},{"item":"1 tsp ground cumin","note":""},{"item":"1 tbsp neutral oil (sunflower, vegetable or canola)","note":"any flavourless oil with a high smoke point"},{"item":"12 small corn tortillas","note":"soft flatbreads made from corn (maize); look in the world-foods aisle, or use small flour tortillas"},{"item":"1 white onion, finely chopped","note":""},{"item":"1 small bunch fresh coriander (cilantro), chopped","note":"the leafy green herb sold as cilantro in some countries"},{"item":"1 lime, cut into wedges","note":""}],"steps":["Mix the lime juice, garlic, cumin, oil and 1 tsp salt, then coat the steak and leave 15 minutes.","Heat a heavy pan very hot and sear the steak for 2 to 3 minutes a side for medium, then rest 5 minutes.","Chop the steak into small pieces against the grain.","Warm the tortillas in a dry pan until pliable.","Fill with steak, onion and coriander, and serve with lime wedges."],"pairing":"A cold Mexican lager or a michelada.","tags":["Quick","Crowd-pleaser","Gluten-free option"],"vegetarian":false,"spicy":false,"calories":430,"protein":36,"carbs":35,"fat":16,"allergens":[],"role":"main","cuisineKey":"mexican","type":"Tacos"},{"id":"me-tacos-de-camaron","name":"Tacos de Camaron","category":"Tacos","course":"Main","meal":"both","tier":"easy","inspiration":"","minutes":20,"serves":4,"level":"Weeknight","idea":"Garlicky prawns flashed in a hot pan with chilli and lime, folded into warm tortillas with crunchy cabbage and a quick lime crema. Light, fresh and on the table in twenty minutes.","ingredients":[{"item":"500 g raw prawns (shrimp), peeled and deveined","note":"raw, grey prawns rather than pre-cooked pink ones"},{"item":"2 cloves garlic, grated","note":""},{"item":"1 tsp paprika","note":""},{"item":"1/2 tsp dried chilli flakes","note":"crushed dried red chilli; use a pinch of cayenne if you only have ground"},{"item":"1 tbsp neutral oil (sunflower, vegetable or canola)","note":"any flavourless oil with a high smoke point"},{"item":"150 g white cabbage, finely shredded","note":""},{"item":"120 g sour cream","note":""},{"item":"1 lime, juiced, plus extra wedges to serve","note":""},{"item":"12 small corn tortillas","note":"soft flatbreads made from corn (maize); look in the world-foods aisle, or use small flour tortillas"},{"item":"1 small bunch fresh coriander (cilantro), chopped","note":"the leafy green herb sold as cilantro in some countries"}],"steps":["Toss the prawns with garlic, paprika, chilli flakes and a pinch of salt.","Stir the sour cream with the lime juice and a pinch of salt to make a quick crema.","Heat the oil in a pan over high heat and cook the prawns for 2 to 3 minutes until pink and just firm.","Warm the tortillas in a dry pan until pliable.","Fill each tortilla with cabbage, prawns and a drizzle of lime crema.","Finish with coriander and serve with lime wedges."],"pairing":"A crisp Sauvignon Blanc or a cold lager.","tags":["Quick","Light","Spicy","Gluten-free option"],"vegetarian":false,"spicy":true,"calories":390,"protein":28,"carbs":37,"fat":14,"allergens":["Shellfish","Milk"],"role":"main","cuisineKey":"mexican","type":"Tacos"},{"id":"me-tacos-de-pescado","name":"Baja Fish Tacos","category":"Tacos","course":"Main","meal":"both","tier":"easy","inspiration":"","minutes":35,"serves":4,"level":"Weeknight","idea":"The classic of Ensenada: beer-battered white fish fried shatteringly crisp, piled onto warm corn tortillas with shredded cabbage and a tangy chipotle-lime crema. Light, crunchy and built for a hot day.","ingredients":[{"item":"600 g firm white fish (cod or pollock), cut into 12 strips","note":"any firm white fish works; haddock or hake are good substitutes"},{"item":"120 g plain (all-purpose) flour","note":""},{"item":"1 tsp baking powder","note":""},{"item":"180 ml cold Mexican lager (such as Corona or Modelo)","note":"any cold light lager works; for alcohol-free use sparkling water"},{"item":"1 tsp paprika","note":""},{"item":"200 g white cabbage, finely shredded","note":""},{"item":"120 g Mexican crema (or sour cream)","note":"thin, pourable soured cream; sour cream loosened with a little milk is a fine substitute"},{"item":"1 lime, juiced, plus wedges to serve","note":""},{"item":"1 tbsp chipotle in adobo, mashed","note":"smoked jalapeno chillies in a tangy red sauce, sold tinned in the world-foods aisle; substitute a little smoked paprika plus a dash of tomato puree and vinegar"},{"item":"12 small corn tortillas","note":"soft flatbreads made from corn (maize); look in the world-foods aisle, or use small flour tortillas"},{"item":"Neutral oil (sunflower, vegetable or canola), for frying","note":"any flavourless oil with a high smoke point"},{"item":"1 small bunch fresh coriander (cilantro), chopped","note":"the leafy green herb sold as cilantro in some countries"}],"steps":["Whisk the flour, baking powder, paprika and 1 tsp salt, then whisk in the cold beer to a smooth, just-pourable batter.","Stir the crema with lime juice, mashed chipotle and a pinch of salt to make the dressing.","Heat oil to 180 C. Dip the fish strips in batter and fry in batches for 3 to 4 minutes until golden and crisp and cooked through, then drain on paper.","Warm the tortillas on a dry comal until pliable.","Fill each tortilla with cabbage, a fish strip and a drizzle of chipotle crema.","Finish with coriander and serve with lime wedges."],"pairing":"A crisp Mexican lager or a chilled Sauvignon Blanc.","tags":["Quick","Crowd-pleaser","Light","Spicy"],"vegetarian":false,"spicy":true,"calories":480,"protein":34,"carbs":48,"fat":17,"allergens":["Fish","Gluten","Milk","Sulphites"],"role":"main","cuisineKey":"mexican","type":"Tacos"},{"id":"me-tacos-al-pastor","name":"Tacos al Pastor","category":"Tacos","course":"Main","meal":"dinner","tier":"signature","inspiration":"Cosme (Enrique Olvera)","minutes":90,"serves":4,"level":"Weekend","idea":"Mexico City's emblematic spit-roasted pork, marinated in dried guajillo and ancho chiles, achiote and pineapple, then crisped and tucked into warm corn tortillas with charred pineapple, raw onion and coriander. The fruit's acidity cuts the richness beautifully.","ingredients":[{"item":"800 g boneless pork shoulder, sliced 5 mm thick","note":"fatty, flavourful cut also sold as pork collar or pork butt"},{"item":"3 dried guajillo chiles, stemmed and seeded","note":"mild, fruity dried red chilli; substitute 1 tbsp mild paprika plus a pinch of chilli powder"},{"item":"2 dried ancho chiles, stemmed and seeded","note":"mild, sweet-smoky dried poblano chilli; substitute extra paprika or 1 tbsp ancho chilli powder"},{"item":"30 g achiote (annatto) paste","note":"deep-red seasoning block of ground annatto seed and spices; sold in Latin/world-foods aisles; substitute 1 tbsp paprika plus a pinch of turmeric for colour"},{"item":"3 cloves garlic","note":""},{"item":"60 ml white vinegar","note":""},{"item":"60 ml pineapple juice","note":""},{"item":"1 tsp dried oregano (Mexican oregano if available)","note":"ordinary dried oregano is a fine substitute"},{"item":"1 tsp ground cumin","note":""},{"item":"300 g fresh pineapple, finely diced","note":""},{"item":"1 white onion, finely chopped","note":""},{"item":"16 small corn tortillas","note":"soft flatbreads made from corn (maize); look in the world-foods aisle, or use small flour tortillas"},{"item":"1 small bunch fresh coriander (cilantro), chopped","note":"the leafy green herb sold as cilantro in some countries"},{"item":"2 limes, cut into wedges","note":""}],"steps":["Toast the guajillo and ancho chiles in a dry pan for 30 seconds until fragrant, then soak in hot water for 15 minutes until soft.","Blend the soaked chiles with achiote, garlic, vinegar, pineapple juice, oregano, cumin and 1 tsp salt into a smooth marinade.","Coat the pork slices fully and marinate overnight in the fridge for the deepest colour and flavour.","Sear the pork in batches over high heat in a hot pan or griddle until charred at the edges and cooked through to at least 63 C, then rest and chop finely.","Char the diced pineapple in the same pan for 2 minutes to caramelise.","Warm the tortillas on a dry comal until pliable and just blistered.","Fill each tortilla with pork, top with charred pineapple, raw onion and coriander, and serve with lime wedges to squeeze over."],"pairing":"An ice-cold Mexican lager with lime, or a tart hibiscus agua de jamaica.","tags":["Spicy","Make-ahead","Crowd-pleaser","Gluten-free option"],"vegetarian":false,"spicy":true,"calories":560,"protein":42,"carbs":52,"fat":20,"allergens":["Sulphites"],"role":"main","cuisineKey":"mexican","type":"Tacos"},{"id":"me-burrito-bowl","name":"Chipotle Chicken Burrito Bowl","category":"Bowls & Enchiladas","course":"Main","meal":"both","tier":"easy","inspiration":"","minutes":30,"serves":2,"level":"Weeknight","idea":"A fresh, balanced bowl of coriander-lime rice, cumin black beans and smoky chipotle chicken topped with quick pico de gallo and sliced avocado. Fast, vibrant and endlessly satisfying on a weeknight.","ingredients":[{"item":"300 g cooked chicken thigh, sliced","note":""},{"item":"2 tbsp chipotle in adobo, chopped","note":"smoked jalapeno chillies in a tangy red sauce, sold tinned; substitute smoked paprika plus a dash of tomato puree and vinegar"},{"item":"180 g long-grain rice","note":""},{"item":"1 lime, juiced, plus wedges","note":""},{"item":"1 small bunch fresh coriander (cilantro), chopped","note":"the leafy green herb sold as cilantro in some countries"},{"item":"240 g cooked black beans, drained (tinned is fine)","note":""},{"item":"1 tsp ground cumin","note":""},{"item":"2 plum tomatoes, diced","note":"firm, oval Roma-type tomatoes; any ripe tomato works"},{"item":"1/2 white onion, finely chopped","note":""},{"item":"1 avocado, sliced","note":""},{"item":"1 tbsp neutral oil (sunflower, vegetable or canola)","note":"any flavourless oil with a high smoke point"}],"steps":["Cook the rice until tender, then fork through half the lime juice, half the coriander and a pinch of salt.","Toss the chicken with chopped chipotle, then warm through in the oil over medium-high heat until lightly charred.","Warm the black beans with cumin and a splash of water until saucy.","Make a quick pico de gallo by mixing the tomatoes, onion, remaining coriander and a squeeze of lime with salt.","Divide the rice between two bowls and top with beans, chipotle chicken, pico de gallo and avocado.","Serve with lime wedges to squeeze over."],"pairing":"A cold lager, or a sparkling lime agua mineral.","tags":["Quick","Light","Spicy","Gluten-free option","Lunchbox"],"vegetarian":false,"spicy":true,"calories":720,"protein":42,"carbs":78,"fat":26,"allergens":[],"role":"main","cuisineKey":"mexican","type":"Rice & Bowls"},{"id":"me-enchiladas-verdes","name":"Enchiladas Verdes de Pollo","category":"Bowls & Enchiladas","course":"Main","meal":"both","tier":"easy","inspiration":"","minutes":45,"serves":4,"level":"Weeknight","idea":"Corn tortillas rolled around shredded chicken and bathed in a roasted tomatillo and serrano salsa verde, finished with crema and crumbled queso fresco. Tangy, comforting and gently spicy.","ingredients":[{"item":"500 g tomatillos, husked","note":"small green tomato-like fruit with a papery husk and tart flavour; sold tinned as tomatillos, or substitute green tomatoes with a squeeze of lime"},{"item":"2 serrano chiles","note":"small, hot fresh green chilli; substitute 1-2 green finger chillies or jalapenos for less heat"},{"item":"3 cloves garlic","note":""},{"item":"1/2 white onion","note":""},{"item":"1 small bunch fresh coriander (cilantro)","note":"the leafy green herb sold as cilantro in some countries"},{"item":"400 g cooked chicken, shredded","note":""},{"item":"12 corn tortillas","note":"soft flatbreads made from corn (maize); look in the world-foods aisle"},{"item":"150 ml Mexican crema","note":"thin, pourable soured cream; sour cream loosened with a little milk is a fine substitute"},{"item":"120 g queso fresco, crumbled","note":"mild, fresh, lightly salty white cheese; substitute mild feta or a young white cheese"},{"item":"1 white onion, thinly sliced, to serve","note":""},{"item":"2 tbsp neutral oil (sunflower, vegetable or canola)","note":"any flavourless oil with a high smoke point"}],"steps":["Boil the tomatillos and serranos for 8 minutes until soft and olive-green, then blend with the garlic, onion, coriander and 1 tsp salt.","Fry the blended salsa in 1 tbsp hot oil for 5 minutes to deepen the flavour, then keep warm.","Lightly fry each tortilla in the remaining oil for a few seconds to soften, then drain.","Fill each tortilla with shredded chicken, roll up and arrange seam-side down in a dish.","Pour the warm salsa verde generously over the top.","Finish with crema, crumbled queso fresco and sliced onion, then serve at once."],"pairing":"A dry Mexican rosado, or a tamarind agua fresca.","tags":["Comfort","Crowd-pleaser","Spicy","Make-ahead"],"vegetarian":false,"spicy":true,"calories":480,"protein":32,"carbs":38,"fat":22,"allergens":["Milk"],"role":"main","cuisineKey":"mexican","type":"Rice & Bowls"},{"id":"me-enchiladas-frijol-queso","name":"Black Bean & Cheese Enchiladas","category":"Bowls & Enchiladas","course":"Main","meal":"both","tier":"easy","inspiration":"","minutes":35,"serves":4,"level":"Weeknight","idea":"Corn tortillas rolled around mashed cumin black beans and melting cheese, baked under a quick tomato-chipotle sauce. A hearty meat-free tray bake that pleases the whole table.","ingredients":[{"item":"480 g cooked black beans, drained (tinned is fine)","note":""},{"item":"1 tsp ground cumin","note":""},{"item":"200 g grated cheddar or Monterey Jack","note":"Monterey Jack is a mild, smooth melting cheese; cheddar or a mild mozzarella works"},{"item":"400 g tinned chopped tomatoes","note":""},{"item":"1 tbsp chipotle in adobo, mashed","note":"smoked jalapeno chillies in a tangy red sauce, sold tinned; substitute smoked paprika plus a dash of tomato puree and vinegar"},{"item":"1 clove garlic, grated","note":""},{"item":"12 corn tortillas","note":"soft flatbreads made from corn (maize); look in the world-foods aisle"},{"item":"1/2 white onion, finely chopped","note":""},{"item":"2 tbsp neutral oil (sunflower, vegetable or canola)","note":"any flavourless oil with a high smoke point"},{"item":"1 small bunch fresh coriander (cilantro), chopped","note":"the leafy green herb sold as cilantro in some countries"}],"steps":["Warm the tomatoes with the chipotle, garlic and a pinch of salt for 5 minutes to make a quick sauce.","Mash the black beans with the cumin, onion and a splash of water until spreadable.","Soften the tortillas briefly in the oil, then fill each with beans and a little cheese and roll up.","Arrange seam-side down in a baking dish, pour over the sauce and scatter the remaining cheese.","Bake at 200 C for 15 minutes until bubbling and golden.","Scatter with coriander and serve."],"pairing":"A light Mexican lager or a hibiscus agua fresca.","tags":["Vegetarian","Comfort","Make-ahead","Crowd-pleaser","Batch-cook"],"vegetarian":true,"spicy":false,"calories":470,"protein":21,"carbs":48,"fat":22,"allergens":["Milk"],"role":"main","cuisineKey":"mexican","type":"Rice & Bowls"},{"id":"me-bowl-carne-frijol","name":"Beef & Black Bean Rice Bowl","category":"Bowls & Enchiladas","course":"Main","meal":"both","tier":"easy","inspiration":"","minutes":25,"serves":4,"level":"Weeknight","idea":"Spiced beef mince browned with cumin and tomato, spooned over rice and black beans with corn, avocado and a squeeze of lime. A one-pan, batch-friendly bowl kids actually finish.","ingredients":[{"item":"500 g beef mince (ground beef)","note":""},{"item":"1 tsp ground cumin","note":""},{"item":"1 tsp paprika","note":""},{"item":"1/2 white onion, chopped","note":""},{"item":"1 clove garlic, grated","note":""},{"item":"2 tbsp tomato paste (tomato puree)","note":"concentrated tomato in a tube or small tin"},{"item":"240 g cooked black beans, drained (tinned is fine)","note":""},{"item":"150 g sweetcorn (tinned or frozen)","note":""},{"item":"250 g cooked rice","note":""},{"item":"1 avocado, sliced","note":""},{"item":"1 lime, cut into wedges","note":""},{"item":"1 tbsp neutral oil (sunflower, vegetable or canola)","note":"any flavourless oil with a high smoke point"}],"steps":["Heat the oil and soften the onion and garlic for 3 minutes.","Add the beef, cumin and paprika and brown well, breaking it up, for 6 minutes.","Stir in the tomato paste, beans and a splash of water and simmer 3 minutes until saucy.","Warm the corn through with the rice.","Divide rice and beans between bowls, top with the spiced beef, corn and avocado.","Serve with lime wedges."],"pairing":"A cold lager or a sparkling limeade.","tags":["Quick","One-pan","Batch-cook","Comfort","Gluten-free option","Lunchbox"],"vegetarian":false,"spicy":false,"calories":520,"protein":33,"carbs":42,"fat":25,"allergens":[],"role":"main","cuisineKey":"mexican","type":"Rice & Bowls"},{"id":"me-enchiladas-mole","name":"Enchiladas de Mole Poblano","category":"Bowls & Enchiladas","course":"Main","meal":"dinner","tier":"signature","inspiration":"Pujol (Enrique Olvera)","minutes":75,"serves":4,"level":"Project","idea":"Tortillas folded into a velvety Pueblan mole built on a trinity of dried chiles, toasted seeds and nuts, ripe tomato and a whisper of Mexican chocolate. Deep, layered and faintly sweet, this is Mexican cooking at its most celebratory.","ingredients":[{"item":"3 dried ancho chiles, stemmed and seeded","note":"mild, sweet-smoky dried poblano chilli; substitute 1 tbsp ancho chilli powder or extra paprika"},{"item":"2 dried mulato chiles, stemmed and seeded","note":"dark, mild dried chilli with chocolate-raisin notes; substitute extra ancho chiles"},{"item":"2 dried pasilla chiles, stemmed and seeded","note":"mild, raisiny dried chilli; substitute extra ancho chiles"},{"item":"2 plum tomatoes","note":"firm, oval Roma-type tomatoes; any ripe tomato works"},{"item":"1/2 white onion, chopped","note":""},{"item":"2 cloves garlic","note":""},{"item":"40 g sesame seeds, plus extra to garnish","note":""},{"item":"30 g raisins","note":""},{"item":"30 g almonds (whole or flaked)","note":""},{"item":"30 g Mexican chocolate (or dark chocolate 70%)","note":"grainy cinnamon-spiced chocolate; substitute 70% dark chocolate with a pinch of cinnamon"},{"item":"1 corn tortilla, torn (for thickening)","note":"soft corn flatbread; a slice of stale bread can stand in as a thickener"},{"item":"1 tsp ground cinnamon","note":""},{"item":"750 ml chicken stock","note":""},{"item":"400 g cooked chicken, shredded","note":""},{"item":"12 corn tortillas","note":"soft flatbreads made from corn (maize); look in the world-foods aisle"},{"item":"80 g queso fresco, crumbled","note":"mild, fresh, lightly salty white cheese; substitute mild feta"},{"item":"2 tbsp neutral oil (sunflower, vegetable or canola)","note":"any flavourless oil with a high smoke point"}],"steps":["Toast the dried chiles in a dry pan for 30 seconds until fragrant, then soak in hot water for 15 minutes.","Char the tomatoes, onion and garlic in a dry pan until softened and blistered.","Toast the sesame, almonds, raisins and torn tortilla until golden, then blend with the drained chiles, charred tomato, onion, garlic, cinnamon and enough stock to make a smooth paste.","Fry the paste in the oil for 8 minutes, stirring constantly, then loosen with the remaining stock and simmer 20 minutes until glossy.","Stir in the chocolate until melted and season with salt; the mole should coat the back of a spoon.","Soften the 12 tortillas briefly in a little oil, fill with shredded chicken and fold into quarters.","Nap the folded enchiladas with warm mole, scatter with sesame and crumbled queso fresco, and serve."],"pairing":"A medium-bodied Mexican red such as Nebbiolo from Valle de Guadalupe.","tags":["Comfort","Date night","Spicy","Make-ahead"],"vegetarian":false,"spicy":true,"calories":540,"protein":32,"carbs":45,"fat":27,"allergens":["Sesame","Tree nuts","Milk","Sulphites"],"role":"main","cuisineKey":"mexican","type":"Rice & Bowls"},{"id":"me-guacamole","name":"Guacamole","category":"Sides & Salsas","course":"Starter","meal":"both","tier":"easy","inspiration":"","minutes":15,"serves":4,"level":"Weeknight","idea":"The proper molcajete way: ripe avocado coarsely mashed with onion, serrano, coriander and lime, kept chunky and bright with a little diced tomato. Simple, but only as good as the avocados.","ingredients":[{"item":"3 ripe avocados","note":"ripe means they yield to gentle pressure"},{"item":"1/2 white onion, finely chopped","note":""},{"item":"1 serrano chile, finely chopped","note":"small, hot fresh green chilli; substitute a green finger chilli or jalapeno for less heat"},{"item":"1 small bunch fresh coriander (cilantro), chopped","note":"the leafy green herb sold as cilantro in some countries"},{"item":"1 lime, juiced","note":""},{"item":"1 plum tomato, deseeded and diced","note":"firm, oval Roma-type tomato; any ripe tomato works"},{"item":"1/2 tsp fine salt","note":""}],"steps":["Mash the onion, serrano, half the coriander and the salt to a rough paste in a molcajete or bowl.","Halve and stone the avocados, scoop the flesh in and mash coarsely, keeping plenty of texture.","Fold through the lime juice, diced tomato and remaining coriander.","Taste and adjust salt and lime, then serve immediately to keep the colour fresh."],"pairing":"Warm totopos (corn tortilla chips) and a cold beer.","tags":["Vegetarian","Vegan","Quick","Spicy","Gluten-free option","Crowd-pleaser"],"vegetarian":true,"spicy":true,"calories":230,"protein":3,"carbs":13,"fat":20,"allergens":[],"role":"appetizer","cuisineKey":"mexican","type":"Starters"},{"id":"me-salsa-roja","name":"Salsa Roja Asada","category":"Sides & Salsas","course":"All-day","meal":"both","tier":"easy","inspiration":"","minutes":25,"serves":4,"level":"Weeknight","idea":"A smoky table salsa of charred tomatoes, garlic and chiles de arbol blended with raw onion and lime. Roasting the vegetables on a dry comal gives it that unmistakable depth.","ingredients":[{"item":"500 g plum tomatoes","note":"firm, oval Roma-type tomatoes; any ripe tomato works"},{"item":"3 dried chiles de arbol","note":"small, slim, very hot dried red chilli; substitute 1/2 tsp dried chilli flakes"},{"item":"2 cloves garlic, unpeeled","note":""},{"item":"1/4 white onion","note":""},{"item":"1 small bunch fresh coriander (cilantro)","note":"the leafy green herb sold as cilantro in some countries"},{"item":"1 lime, juiced","note":""},{"item":"1/2 tsp fine salt","note":""}],"steps":["Char the tomatoes and unpeeled garlic on a dry comal or hot pan, turning, until blackened in spots and softened.","Toast the chiles de arbol for 20 seconds until fragrant, taking care not to burn them.","Peel the garlic, then blend with the tomatoes, chiles, onion, coriander, lime juice and salt to a coarse salsa.","Taste for salt and heat, then cool slightly before serving. Keeps 3 days in the fridge."],"pairing":"Spoon over tacos, eggs or grilled meats.","tags":["Vegetarian","Vegan","Spicy","Make-ahead","Quick","Gluten-free option"],"vegetarian":true,"spicy":true,"calories":45,"protein":2,"carbs":9,"fat":1,"allergens":[],"role":"appetizer","cuisineKey":"mexican","type":"Starters"},{"id":"me-elote","name":"Elote (Mexican Street Corn)","category":"Sides & Salsas","course":"Starter","meal":"both","tier":"easy","inspiration":"","minutes":25,"serves":4,"level":"Weeknight","idea":"Grilled corn cobs slathered in lime-spiked mayo and crema, rolled in salty cotija and dusted with chile powder. The street snack of Mexico: smoky, creamy and tangy all at once.","ingredients":[{"item":"4 corn cobs, husked","note":""},{"item":"60 g mayonnaise","note":""},{"item":"60 g Mexican crema (or sour cream)","note":"thin, pourable soured cream; sour cream loosened with a little milk is a fine substitute"},{"item":"80 g cotija cheese, finely crumbled","note":"dry, salty, crumbly aged cow's-milk cheese; substitute crumbled feta or grated Parmesan"},{"item":"1 tsp chile powder (ancho or chile piquin)","note":"ground dried chilli (ancho is mild, piquin is hot); substitute mild chilli powder or paprika"},{"item":"1 lime, cut into wedges","note":""},{"item":"1 small bunch fresh coriander (cilantro), chopped","note":"the leafy green herb sold as cilantro in some countries"}],"steps":["Grill or char the corn over high heat, turning, for 8 to 10 minutes until blistered and tender.","Mix the mayonnaise and crema together with a pinch of salt.","Brush each hot cob all over with the mayo-crema mixture.","Roll in crumbled cotija until well coated.","Dust with chile powder, scatter with coriander and serve with lime wedges to squeeze over."],"pairing":"A cold michelada or a tamarind agua fresca.","tags":["Vegetarian","Spicy","Quick","Crowd-pleaser","Gluten-free option"],"vegetarian":true,"spicy":true,"calories":260,"protein":7,"carbs":24,"fat":16,"allergens":["Milk","Egg"],"role":"appetizer","cuisineKey":"mexican","type":"Starters"},{"id":"me-pico-de-gallo","name":"Pico de Gallo","category":"Sides & Salsas","course":"All-day","meal":"both","tier":"easy","inspiration":"","minutes":10,"serves":4,"level":"Weeknight","idea":"The fresh, raw salsa that brightens everything: ripe tomato, onion, jalapeno, coriander and lime, chopped fine and seasoned well. No cooking, no equipment, ready in minutes.","ingredients":[{"item":"4 ripe plum tomatoes, deseeded and diced","note":"firm, oval Roma-type tomatoes; any ripe tomato works"},{"item":"1/2 white onion, finely chopped","note":""},{"item":"1 jalapeno, finely chopped","note":"medium-hot fresh green chilli; remove the seeds for milder heat"},{"item":"1 small bunch fresh coriander (cilantro), chopped","note":"the leafy green herb sold as cilantro in some countries"},{"item":"1 lime, juiced","note":""},{"item":"1/2 tsp fine salt","note":""}],"steps":["Combine the tomato, onion, jalapeno and coriander in a bowl.","Stir through the lime juice and salt.","Let it sit for 5 minutes for the flavours to come together, then taste and adjust.","Serve with chips, tacos or grilled meats."],"pairing":"Spoon over tacos, eggs, grilled chicken or fish.","tags":["Vegetarian","Vegan","Quick","Spicy","Gluten-free option","Light"],"vegetarian":true,"spicy":true,"calories":35,"protein":1,"carbs":8,"fat":0,"allergens":[],"role":"appetizer","cuisineKey":"mexican","type":"Starters"},{"id":"me-esquites-cosme","name":"Esquites with Lime and Epazote","category":"Sides & Salsas","course":"Starter","meal":"both","tier":"signature","inspiration":"Cosme (Enrique Olvera)","minutes":30,"serves":4,"level":"Weekend","idea":"The celebrated corn dish reimagined in the Cosme spirit: sweetcorn charred hard then folded warm through a whipped lime crema heady with epazote, finished with cotija, chile and a snowfall of cured egg yolk. Smoky, creamy and quietly luxurious.","ingredients":[{"item":"500 g sweetcorn kernels (from about 4 cobs; tinned or frozen also fine)","note":""},{"item":"2 tbsp neutral oil (sunflower, vegetable or canola)","note":"any flavourless oil with a high smoke point"},{"item":"100 g Mexican crema","note":"thin, pourable soured cream; sour cream loosened with a little milk is a fine substitute"},{"item":"60 g mayonnaise","note":""},{"item":"1 lime, zested and juiced","note":""},{"item":"1 tbsp chopped epazote (or coriander)","note":"pungent Mexican herb with a distinctive savoury flavour; fresh coriander is the easy substitute"},{"item":"60 g cotija cheese, finely crumbled","note":"dry, salty, crumbly aged cow's-milk cheese; substitute crumbled feta or grated Parmesan"},{"item":"1 tsp chile piquin or ancho powder","note":"ground dried chilli (piquin is hot, ancho is mild); substitute chilli powder or paprika to taste"},{"item":"1 cured or grated hard-boiled egg yolk, to finish","note":"a firm cooked yolk grated over the top for richness; optional, simply omit if preferred"},{"item":"1/2 tsp fine salt","note":""}],"steps":["Heat the oil in a wide pan until almost smoking, add the corn in a single layer and leave undisturbed for 3 minutes to char, then toss and char again.","Whisk the crema, mayonnaise, lime zest and juice, epazote and salt into a light, whipped dressing.","Fold the hot charred corn through the dressing while still warm so it loosens and coats.","Spoon into bowls and top with crumbled cotija and a dusting of chile powder.","Finish with a fine grating of cured egg yolk over the top and serve warm with spoons."],"pairing":"A mezcal sour, or a chilled dry Mexican rosado.","tags":["Vegetarian","Spicy","Date night","Gluten-free option"],"vegetarian":true,"spicy":true,"calories":290,"protein":7,"carbs":24,"fat":20,"allergens":["Milk","Egg"],"role":"appetizer","cuisineKey":"mexican","type":"Starters"},{"id":"me-ensalada-nopales","name":"Ensalada de Nopales","cuisineKey":"mexican","category":"Sides & Salsas","role":"salad","course":"Starter","meal":"both","tier":"easy","inspiration":"","minutes":25,"serves":4,"level":"Weeknight","idea":"Grilled cactus paddle salad tossed with tomato, onion and queso fresco, a classic Mexican market salad.","ingredients":[{"item":"6 fresh nopales (cactus paddles), spines removed","note":"the flat green pads of the prickly-pear cactus, with a tangy green-bean-like taste; sold fresh or in jars in Latin shops; substitute jarred nopales or, at a push, blanched green beans"},{"item":"2 ripe plum tomatoes, diced","note":"firm, oval Roma-type tomatoes; any ripe tomato works"},{"item":"1/2 white onion, finely chopped","note":""},{"item":"100 g queso fresco, crumbled","note":"mild, fresh, lightly salty white cheese; substitute mild feta"},{"item":"1 small bunch fresh coriander (cilantro), chopped","note":"the leafy green herb sold as cilantro in some countries"},{"item":"2 limes, juiced","note":""},{"item":"2 tbsp olive oil","note":""},{"item":"1 serrano chile, finely chopped","note":"small, hot fresh green chilli; substitute a green finger chilli or jalapeno for less heat"},{"item":"1/2 tsp dried oregano (Mexican oregano if available)","note":"ordinary dried oregano is a fine substitute"},{"item":"1/2 tsp fine salt","note":""}],"steps":["Grill or boil the nopales until tender, about 8 minutes, then dice.","Rinse to remove any sliminess and drain well.","Combine nopales with tomato, onion, coriander and serrano.","Whisk lime juice, olive oil, oregano and salt, then toss through.","Scatter crumbled queso fresco over the top and serve."],"pairing":"Warm corn tortillas","tags":["salad","fresh","grilled"],"vegetarian":true,"spicy":true,"calories":180,"protein":7,"carbs":12,"fat":12,"allergens":["Milk"],"type":"Salads"},{"id":"me-ensalada-jicama","name":"Jicama, Orange and Chile Salad","cuisineKey":"mexican","category":"Sides & Salsas","role":"salad","course":"Starter","meal":"both","tier":"easy","inspiration":"","minutes":15,"serves":4,"level":"Weeknight","idea":"Crisp jicama matchsticks with juicy orange segments, lime and chile piquin, bright and refreshing.","ingredients":[{"item":"1 large jicama (about 500 g), peeled and cut into matchsticks","note":"a round, crunchy, mildly sweet root vegetable eaten raw; substitute a firm pear, water chestnuts, or a crisp apple"},{"item":"3 oranges, segmented","note":""},{"item":"2 limes, juiced","note":""},{"item":"1 tsp chile piquin or ancho powder","note":"ground dried chilli (piquin is hot, ancho is mild); substitute chilli powder or paprika to taste"},{"item":"1/2 tsp fine salt","note":""},{"item":"1 small bunch fresh coriander (cilantro), chopped","note":"the leafy green herb sold as cilantro in some countries"},{"item":"1 cucumber, diced","note":""}],"steps":["Toss jicama and cucumber matchsticks in a bowl.","Add orange segments and any captured juice.","Dress with lime juice and salt.","Dust with chile powder and scatter coriander.","Chill 10 minutes and serve cold."],"pairing":"Grilled fish or tacos","tags":["salad","refreshing","no-cook"],"vegetarian":true,"spicy":true,"calories":120,"protein":2,"carbs":27,"fat":1,"allergens":[],"type":"Salads"},{"id":"me-ensalada-frijol-aguacate","name":"Black Bean, Corn and Avocado Salad","cuisineKey":"mexican","category":"Sides & Salsas","role":"salad","course":"Starter","meal":"both","tier":"easy","inspiration":"","minutes":15,"serves":4,"level":"Weeknight","idea":"A hearty bean and corn salad with avocado, lime and coriander, the kind kids actually finish.","ingredients":[{"item":"320 g cooked black beans, drained (tinned is fine)","note":""},{"item":"200 g sweetcorn kernels (tinned or frozen)","note":""},{"item":"2 avocados, diced","note":""},{"item":"2 plum tomatoes, diced","note":"firm, oval Roma-type tomatoes; any ripe tomato works"},{"item":"1/2 red onion, finely chopped","note":""},{"item":"1 small bunch fresh coriander (cilantro), chopped","note":"the leafy green herb sold as cilantro in some countries"},{"item":"2 limes, juiced","note":""},{"item":"2 tbsp olive oil","note":""},{"item":"1/2 tsp ground cumin","note":""},{"item":"1/2 tsp fine salt","note":""}],"steps":["Combine black beans, sweetcorn, tomato and onion in a bowl.","Whisk lime juice, olive oil, cumin and salt.","Pour dressing over and toss gently.","Fold in diced avocado just before serving.","Finish with coriander."],"pairing":"Grilled chicken or as a taco side","tags":["salad","hearty","no-cook"],"vegetarian":true,"spicy":false,"calories":290,"protein":9,"carbs":31,"fat":16,"allergens":[],"type":"Salads"},{"id":"me-queso-fundido","name":"Queso Fundido con Chorizo","cuisineKey":"mexican","category":"Sides & Salsas","role":"appetizer","course":"Starter","meal":"both","tier":"easy","inspiration":"","minutes":20,"serves":4,"level":"Weeknight","idea":"Molten melted cheese baked with chorizo, scooped up with warm tortillas, a sizzling table starter.","ingredients":[{"item":"300 g Oaxaca or mozzarella cheese, grated","note":"Oaxaca is a stretchy, mild Mexican melting cheese much like mozzarella; low-moisture mozzarella is the easy substitute"},{"item":"150 g Mexican chorizo, casing removed","note":"soft, raw, spiced sausage that crumbles when cooked (not the firm cured Spanish type); substitute fresh spicy sausagemeat with extra paprika"},{"item":"1/2 white onion, finely chopped","note":""},{"item":"1 poblano chile, diced","note":"large, mild, dark-green fresh chilli; substitute a green pepper with a pinch of chilli flakes"},{"item":"8 small corn tortillas, to serve","note":"soft flatbreads made from corn (maize); look in the world-foods aisle"},{"item":"1 small bunch fresh coriander (cilantro), chopped","note":"the leafy green herb sold as cilantro in some countries"}],"steps":["Cook chorizo in an ovenproof skillet, breaking it up, until browned.","Add onion and poblano and soften for 4 minutes.","Spoon off excess fat, then scatter grated cheese over the top.","Bake or grill until the cheese is fully melted and bubbling.","Scatter coriander and serve with warm tortillas for scooping."],"pairing":"Warm corn tortillas","tags":["appetizer","cheese","sharing","hot"],"vegetarian":false,"spicy":false,"calories":380,"protein":22,"carbs":18,"fat":25,"allergens":["Milk"],"type":"Starters"},{"id":"me-tostada-tinga","name":"Tostadas de Tinga de Pollo","cuisineKey":"mexican","category":"Tacos","role":"appetizer","course":"Starter","meal":"both","tier":"easy","inspiration":"","minutes":35,"serves":4,"level":"Weeknight","idea":"Crisp tostadas topped with smoky chipotle chicken tinga, crema and queso fresco.","ingredients":[{"item":"8 corn tostadas (crisp flat shells)","note":"flat, crisp fried corn tortillas; substitute corn tortillas crisped in the oven, or flat tortilla chips"},{"item":"350 g cooked chicken, shredded","note":""},{"item":"2 plum tomatoes, blended","note":"firm, oval Roma-type tomatoes; any ripe tomato works"},{"item":"1/2 white onion, thinly sliced","note":""},{"item":"2 tbsp chipotle in adobo, mashed","note":"smoked jalapeno chillies in a tangy red sauce, sold tinned; substitute smoked paprika plus a dash of tomato puree and vinegar"},{"item":"1 clove garlic, grated","note":""},{"item":"120 ml Mexican crema","note":"thin, pourable soured cream; sour cream loosened with a little milk is a fine substitute"},{"item":"80 g queso fresco, crumbled","note":"mild, fresh, lightly salty white cheese; substitute mild feta"},{"item":"1 avocado, sliced","note":""},{"item":"1 tbsp neutral oil (sunflower, vegetable or canola)","note":"any flavourless oil with a high smoke point"}],"steps":["Soften onion and garlic in oil for 3 minutes.","Add blended tomato and chipotle and simmer 5 minutes.","Stir in shredded chicken and cook until coated and saucy.","Spread tinga over each tostada shell.","Top with avocado, crema and crumbled queso fresco."],"pairing":"Pico de gallo","tags":["appetizer","chicken","smoky","crisp"],"vegetarian":false,"spicy":true,"calories":310,"protein":21,"carbs":22,"fat":16,"allergens":["Milk"],"type":"Starters"},{"id":"me-quesadillas-flor","name":"Quesadillas de Flor de Calabaza","cuisineKey":"mexican","category":"Tacos","role":"appetizer","course":"Starter","meal":"both","tier":"easy","inspiration":"","minutes":25,"serves":4,"level":"Weeknight","idea":"Griddled corn quesadillas filled with squash blossom and melting Oaxaca cheese, a Mexico City market classic.","ingredients":[{"item":"8 small corn tortillas","note":"soft flatbreads made from corn (maize); look in the world-foods aisle"},{"item":"200 g Oaxaca or mozzarella cheese, grated","note":"Oaxaca is a stretchy, mild Mexican melting cheese much like mozzarella; low-moisture mozzarella is the easy substitute"},{"item":"150 g squash blossoms (flor de calabaza), cleaned","note":"the delicate yellow flowers of the courgette/squash plant; found at farmers' markets in summer; substitute thinly sliced courgette"},{"item":"1/2 white onion, finely chopped","note":""},{"item":"1 serrano chile, finely chopped","note":"small, hot fresh green chilli; substitute a green finger chilli or jalapeno for less heat"},{"item":"2 epazote leaves, chopped (or coriander)","note":"pungent Mexican herb with a distinctive savoury flavour; fresh coriander is the easy substitute"},{"item":"1 tbsp neutral oil (sunflower, vegetable or canola)","note":"any flavourless oil with a high smoke point"}],"steps":["Soften onion and serrano in oil for 3 minutes.","Add squash blossoms and epazote and wilt for 2 minutes.","Lay cheese and blossom mix on each tortilla and fold over.","Griddle the quesadillas until golden and the cheese melts.","Cut and serve warm with salsa."],"pairing":"Salsa roja asada","tags":["appetizer","cheese","griddled"],"vegetarian":true,"spicy":true,"calories":280,"protein":13,"carbs":26,"fat":14,"allergens":["Milk"],"type":"Starters"},{"id":"me-pollo-pibil","name":"Cochinita-Style Pollo Pibil","cuisineKey":"mexican","category":"Bowls & Enchiladas","role":"main","course":"Main","meal":"lunch","tier":"easy","inspiration":"","minutes":50,"serves":4,"level":"Weeknight","idea":"Achiote-marinated chicken roasted until tender, served with pickled red onion and rice, lighter than the pork classic.","ingredients":[{"item":"700 g boneless chicken thighs","note":""},{"item":"40 g achiote (annatto) paste","note":"deep-red seasoning block of ground annatto seed and spices; sold in Latin/world-foods aisles; substitute 1 tbsp paprika plus a pinch of turmeric for colour"},{"item":"3 oranges, juiced","note":""},{"item":"2 limes, juiced","note":""},{"item":"3 cloves garlic","note":""},{"item":"1 tsp dried oregano (Mexican oregano if available)","note":"ordinary dried oregano is a fine substitute"},{"item":"1 tsp ground cumin","note":""},{"item":"1 red onion, thinly sliced","note":""},{"item":"60 ml white vinegar","note":""},{"item":"250 g cooked rice, to serve","note":""},{"item":"1 tbsp neutral oil (sunflower, vegetable or canola)","note":"any flavourless oil with a high smoke point"},{"item":"1/2 tsp fine salt","note":""}],"steps":["Blend achiote, orange juice, half the lime juice, garlic, oregano and cumin.","Coat chicken in the marinade and rest 20 minutes.","Pickle red onion in vinegar, remaining lime juice and salt.","Roast chicken at 200C for 30 minutes until cooked and tender.","Slice and serve over rice topped with pickled onion."],"pairing":"Warm corn tortillas","tags":["main","chicken","achiote","roasted"],"vegetarian":false,"spicy":false,"calories":480,"protein":38,"carbs":34,"fat":20,"allergens":[],"type":"Rice & Bowls"},{"id":"me-chiles-rellenos","name":"Chiles Rellenos de Queso","cuisineKey":"mexican","category":"Bowls & Enchiladas","role":"main","course":"Main","meal":"lunch","tier":"signature","inspiration":"Quintonil (Jorge Vallejo)","minutes":70,"serves":4,"level":"Weekend","idea":"Roasted poblano chiles stuffed with cheese, dipped in airy egg batter and bathed in tomato caldillo.","ingredients":[{"item":"4 large poblano chiles","note":"large, mild, dark-green fresh chilli; substitute green (bell) peppers for almost no heat"},{"item":"250 g Oaxaca or mozzarella cheese, in batons","note":"Oaxaca is a stretchy, mild Mexican melting cheese much like mozzarella; low-moisture mozzarella is the easy substitute"},{"item":"4 eggs, separated","note":""},{"item":"60 g plain (all-purpose) flour","note":""},{"item":"500 g plum tomatoes","note":"firm, oval Roma-type tomatoes; any ripe tomato works"},{"item":"1/2 white onion","note":""},{"item":"1 clove garlic","note":""},{"item":"250 ml chicken or vegetable stock","note":""},{"item":"1 tsp dried oregano (Mexican oregano if available)","note":"ordinary dried oregano is a fine substitute"},{"item":"Neutral oil (sunflower, vegetable or canola), for frying","note":"any flavourless oil with a high smoke point"},{"item":"1/2 tsp fine salt","note":""}],"steps":["Char poblanos, steam in a bag, then peel and slit to deseed.","Stuff each chile with cheese batons and dust in flour.","Whisk egg whites to stiff peaks, then fold in beaten yolks.","Coat chiles in the batter and fry until golden, then drain.","Blend tomato, onion and garlic, simmer with stock and oregano, then serve the chiles in the caldillo."],"pairing":"Mexican red rice","tags":["main","poblano","signature"],"vegetarian":true,"spicy":false,"calories":520,"protein":24,"carbs":28,"fat":34,"allergens":["Milk","Egg","Gluten"],"type":"Rice & Bowls"},{"id":"me-pescado-veracruz","name":"Pescado a la Veracruzana","cuisineKey":"mexican","category":"Bowls & Enchiladas","role":"main","course":"Main","meal":"lunch","tier":"easy","inspiration":"","minutes":35,"serves":4,"level":"Weeknight","idea":"White fish fillets simmered in a bright tomato sauce with olives, capers and herbs, a Gulf coast classic.","ingredients":[{"item":"4 white fish fillets (cod or hake, about 600 g)","note":"any firm white fish works; haddock or pollock are good substitutes"},{"item":"500 g plum tomatoes, chopped","note":"firm, oval Roma-type tomatoes; any ripe tomato works"},{"item":"1/2 white onion, sliced","note":""},{"item":"2 cloves garlic, sliced","note":""},{"item":"60 g green olives, sliced","note":"use pitted (stoned) green olives"},{"item":"2 tbsp capers","note":"small pickled flower buds, sold in jars near the olives; rinse before using"},{"item":"2 bay leaves","note":""},{"item":"1 tsp dried oregano (Mexican oregano if available)","note":"ordinary dried oregano is a fine substitute"},{"item":"2 pickled jalapenos, sliced","note":"jarred pickled green chillies; substitute a fresh jalapeno or a pinch of chilli flakes"},{"item":"2 tbsp olive oil","note":""},{"item":"250 g cooked rice, to serve","note":""},{"item":"1/2 tsp fine salt","note":""}],"steps":["Soften onion and garlic in olive oil for 4 minutes.","Add tomato, bay, oregano and salt, simmer 10 minutes.","Stir in olives, capers and jalapenos.","Nestle fish fillets into the sauce and poach gently for 8 minutes.","Serve over rice spooned with the sauce."],"pairing":"Crusty bread or rice","tags":["main","fish","tomato","coastal"],"vegetarian":false,"spicy":false,"calories":420,"protein":36,"carbs":30,"fat":16,"allergens":["Fish"],"type":"Rice & Bowls"},{"id":"me-carnitas","name":"Carnitas con Tortillas","cuisineKey":"mexican","category":"Bowls & Enchiladas","role":"main","course":"Main","meal":"dinner","tier":"easy","inspiration":"","minutes":180,"serves":6,"level":"Weekend","idea":"Slow-braised pork shoulder confit until meltingly tender, then crisped, piled into tortillas.","ingredients":[{"item":"1.2 kg boneless pork shoulder, in chunks","note":"fatty, flavourful cut also sold as pork collar or pork butt"},{"item":"2 oranges, halved","note":""},{"item":"1 white onion, quartered","note":""},{"item":"4 cloves garlic","note":""},{"item":"2 bay leaves","note":""},{"item":"1 tsp ground cumin","note":""},{"item":"1 tsp dried oregano (Mexican oregano if available)","note":"ordinary dried oregano is a fine substitute"},{"item":"100 g lard or neutral oil","note":"lard is rendered pork fat (traditional here); flavourless vegetable oil works fine"},{"item":"18 small corn tortillas","note":"soft flatbreads made from corn (maize); look in the world-foods aisle"},{"item":"1 white onion, finely chopped, to serve","note":""},{"item":"1 small bunch fresh coriander (cilantro), chopped","note":"the leafy green herb sold as cilantro in some countries"},{"item":"2 limes, cut into wedges","note":""},{"item":"1 tsp fine salt","note":""}],"steps":["Place pork, onion, garlic, bay, cumin, oregano and salt in a heavy pot.","Squeeze oranges over, drop in the spent halves, and add lard.","Cover with water and simmer gently for 2 hours until very tender.","Raise the heat to evaporate liquid and crisp the pork in its own fat.","Shred and serve in warm tortillas with onion, coriander and lime."],"pairing":"Salsa verde and pickled onion","tags":["main","pork","braised","crispy"],"vegetarian":false,"spicy":false,"calories":620,"protein":42,"carbs":34,"fat":34,"allergens":[],"type":"Rice & Bowls"},{"id":"me-birria-res","name":"Birria de Res","cuisineKey":"mexican","category":"Bowls & Enchiladas","role":"main","course":"Main","meal":"dinner","tier":"signature","inspiration":"Quintonil (Jorge Vallejo)","minutes":210,"serves":6,"level":"Project","idea":"Deeply spiced beef stew in a guajillo and ancho chile broth, served with consome for dipping.","ingredients":[{"item":"1.4 kg beef chuck or short rib","note":"well-marbled stewing cuts that turn tender with long cooking; brisket also works"},{"item":"4 dried guajillo chiles, stemmed and seeded","note":"mild, fruity dried red chilli; substitute 1 tbsp mild paprika plus a pinch of chilli powder"},{"item":"3 dried ancho chiles, stemmed and seeded","note":"mild, sweet-smoky dried poblano chilli; substitute 1 tbsp ancho chilli powder or extra paprika"},{"item":"2 dried chiles de arbol","note":"small, slim, very hot dried red chilli; substitute 1/2 tsp dried chilli flakes"},{"item":"4 plum tomatoes","note":"firm, oval Roma-type tomatoes; any ripe tomato works"},{"item":"1 white onion, halved","note":""},{"item":"5 cloves garlic","note":""},{"item":"1 tbsp cider vinegar","note":""},{"item":"1 tsp ground cumin","note":""},{"item":"1 tsp dried oregano (Mexican oregano if available)","note":"ordinary dried oregano is a fine substitute"},{"item":"2 bay leaves","note":""},{"item":"1 cinnamon stick","note":""},{"item":"18 small corn tortillas","note":"soft flatbreads made from corn (maize); look in the world-foods aisle"},{"item":"1 white onion, finely chopped, to serve","note":""},{"item":"1 small bunch fresh coriander (cilantro), chopped","note":"the leafy green herb sold as cilantro in some countries"},{"item":"2 limes, cut into wedges","note":""},{"item":"1 tsp fine salt","note":""}],"steps":["Toast and soak the dried chiles, then blend with tomato, onion, garlic, vinegar and spices.","Brown the beef, then pour over the chile sauce and add bay and cinnamon.","Cover with water and braise gently for 3 hours until the beef pulls apart.","Shred the meat and strain the rich consome.","Serve the birria with consome on the side, tortillas, onion, coriander and lime."],"pairing":"Dip tortillas in the consome quesabirria style","tags":["main","beef","stew","signature","chile"],"vegetarian":false,"spicy":true,"calories":640,"protein":48,"carbs":32,"fat":36,"allergens":[],"type":"Rice & Bowls"},{"id":"in-quick-chicken-curry","name":"Everyday Chicken Curry","category":"Curries","course":"Main","meal":"both","tier":"easy","inspiration":"","minutes":30,"serves":4,"level":"Weeknight","idea":"A no-fuss home-style chicken curry built on onion, tomato and pantry spices. No marinating, no blending, just one pan and twenty minutes of gentle simmering for a curry that tastes like it took far longer.","ingredients":[{"item":"600g boneless, skinless chicken thighs, cut into 3cm chunks","note":"thigh meat stays juicier than breast; chicken breast works if you prefer"},{"item":"3 tbsp vegetable oil","note":""},{"item":"2 onions, finely chopped","note":""},{"item":"2 tbsp ginger-garlic paste","note":"a smooth blend of equal fresh ginger and garlic; sold in jars in the world-foods aisle, or blitz a thumb of ginger with 4 garlic cloves"},{"item":"400g tin chopped tomatoes","note":""},{"item":"1 tsp ground turmeric","note":"bright yellow earthy spice; in every supermarket spice rack"},{"item":"1 tbsp ground coriander","note":"mild citrusy spice ground from coriander seeds"},{"item":"1 tsp ground cumin","note":"warm earthy spice; standard in the spice aisle"},{"item":"1 tsp Kashmiri chilli powder","note":"mild, deep-red chilli powder more about colour than heat; use half regular chilli powder plus a pinch of paprika"},{"item":"1 tsp garam masala","note":"warm Indian spice blend (cardamom, cinnamon, clove etc.); sold ready-mixed in the spice aisle"},{"item":"Small handful fresh coriander, chopped","note":"the leafy green herb, also called cilantro"},{"item":"Salt to taste","note":""}],"steps":["Fry the onions in oil over medium heat until soft and golden, about 8 minutes.","Stir in the ginger-garlic paste, turmeric, coriander, cumin and chilli powder and cook 1 minute until fragrant.","Add the tomatoes and cook 5 minutes until they break down and thicken.","Add the chicken, season with salt, and stir to coat in the masala.","Pour in a splash of water, cover and simmer 12 to 15 minutes until the chicken is cooked through.","Stir in the garam masala, finish with fresh coriander and serve."],"pairing":"Steamed basmati or warm chapati","tags":["Quick","One-pan","Comfort","Gluten-free option","Make-ahead"],"vegetarian":false,"spicy":false,"calories":380,"protein":31,"carbs":11,"fat":24,"allergens":[],"role":"main","cuisineKey":"indian","type":"Curry"},{"id":"in-palak-paneer","name":"Palak Paneer","category":"Curries","course":"Main","meal":"both","tier":"easy","inspiration":"","minutes":35,"serves":4,"level":"Weeknight","idea":"Soft cubes of paneer in a vibrant, lightly spiced spinach gravy. Blanching the spinach briefly and shocking it in ice water keeps the colour a bright living green rather than a dull khaki.","ingredients":[{"item":"400g fresh spinach leaves","note":"frozen spinach (thawed and squeezed dry) works fine too"},{"item":"250g paneer, cubed","note":"firm, mild Indian cheese that holds its shape when cooked; firm halloumi or extra-firm tofu can stand in"},{"item":"2 tbsp ghee","note":"Indian clarified butter with a nutty taste; plain butter or oil works"},{"item":"1 large onion, finely chopped","note":""},{"item":"1 tbsp ginger-garlic paste","note":"smooth blend of equal ginger and garlic; jarred in world-foods, or blitz ginger with garlic cloves"},{"item":"2 green chillies, slit lengthways","note":"mild-to-medium green chillies; deseed for less heat or leave out"},{"item":"1 tsp ground cumin","note":"warm earthy spice"},{"item":"1 tsp garam masala","note":"warm Indian spice blend; sold ready-mixed"},{"item":"1 medium tomato, chopped","note":""},{"item":"60ml double cream","note":"heavy whipping cream"},{"item":"1 tsp dried fenugreek leaves (kasuri methi)","note":"dried herb with a faintly bitter, maple-like aroma; world-foods aisle, or just leave out"},{"item":"Salt to taste","note":""}],"steps":["Blanch the spinach for 60 seconds, plunge into ice water, then blend to a coarse puree.","Lightly fry the paneer cubes in 1 tbsp ghee until golden, then set aside (soak in warm water to keep them soft).","In the remaining ghee fry the onion until soft, add ginger-garlic paste, chillies and cumin and cook until fragrant.","Add the tomato and cook until broken down, then stir in the spinach puree and simmer 5 minutes.","Add the paneer, cream, garam masala and crushed fenugreek, then simmer 3 minutes until everything is hot.","Season and finish with a swirl of cream."],"pairing":"Hot tandoori roti and a cucumber raita","tags":["Vegetarian","Gluten-free option","Comfort","Quick"],"vegetarian":true,"spicy":false,"calories":340,"protein":15,"carbs":12,"fat":26,"allergens":["Milk"],"role":"main","cuisineKey":"indian","type":"Curry"},{"id":"in-chana-masala","name":"Chana Masala","category":"Curries","course":"Main","meal":"both","tier":"easy","inspiration":"","minutes":40,"serves":4,"level":"Weeknight","idea":"Chickpeas in a tangy, deeply spiced tomato-onion masala sharpened with amchur and a final lift of garam masala. Naturally vegan, satisfying and quick enough for a weeknight.","ingredients":[{"item":"2 x 400g tins chickpeas, drained","note":"also labelled garbanzo beans"},{"item":"3 tbsp vegetable oil","note":""},{"item":"2 onions, finely chopped","note":""},{"item":"1 tbsp ginger-garlic paste","note":"smooth blend of equal ginger and garlic; jarred, or blitz your own"},{"item":"2 green chillies, chopped","note":"mild-to-medium green chillies; deseed or reduce for less heat"},{"item":"400g tin chopped tomatoes","note":""},{"item":"1.5 tsp ground coriander","note":"mild citrusy ground spice"},{"item":"1 tsp ground cumin","note":"warm earthy spice"},{"item":"1 tsp Kashmiri chilli powder","note":"mild deep-red chilli for colour; sub half regular chilli powder plus a pinch of paprika"},{"item":"1 tsp amchur (dried mango powder)","note":"tangy, sour beige powder made from dried unripe mango; substitute a squeeze of lemon juice"},{"item":"1 tsp garam masala","note":"warm Indian spice blend"},{"item":"Small handful fresh coriander, chopped","note":"leafy green herb, also called cilantro"},{"item":"Salt to taste","note":""}],"steps":["Fry the onions in oil until golden brown, then add ginger-garlic paste and green chillies.","Add the coriander, cumin and chilli powder and toast for 30 seconds until fragrant.","Stir in the tomatoes and cook 10 to 12 minutes until thick and the oil separates.","Add the chickpeas with a splash of water and simmer 12 minutes, lightly crushing a few to thicken the gravy.","Stir in the amchur and garam masala, season well and simmer 2 more minutes.","Finish with fresh coriander."],"pairing":"Bhatura or steamed rice with sliced red onion and lemon","tags":["Vegan","Vegetarian","Quick","One-pan","Gluten-free option"],"vegetarian":true,"spicy":true,"calories":300,"protein":12,"carbs":34,"fat":13,"allergens":[],"role":"main","cuisineKey":"indian","type":"Curry"},{"id":"in-egg-curry","name":"Anda Curry (Egg Curry)","category":"Curries","course":"Main","meal":"both","tier":"easy","inspiration":"","minutes":30,"serves":4,"level":"Weeknight","idea":"Boiled eggs simmered in a quick, spiced onion-tomato gravy. A brilliant cheap and fast protein when the fridge is bare, ready in half an hour from store-cupboard basics and gentle enough for the whole table.","ingredients":[{"item":"6 large eggs","note":""},{"item":"3 tbsp vegetable oil","note":""},{"item":"2 onions, finely chopped","note":""},{"item":"1 tbsp ginger-garlic paste","note":"smooth blend of equal ginger and garlic; jarred or homemade"},{"item":"400g tin chopped tomatoes","note":""},{"item":"1 tsp ground turmeric","note":"bright yellow earthy spice"},{"item":"1 tsp Kashmiri chilli powder","note":"mild deep-red chilli for colour; sub half regular chilli powder plus a pinch of paprika"},{"item":"1 tbsp ground coriander","note":"mild citrusy ground spice"},{"item":"1 tsp garam masala","note":"warm Indian spice blend"},{"item":"Small handful fresh coriander, chopped","note":"leafy green herb, also called cilantro"},{"item":"Salt to taste","note":""}],"steps":["Hard-boil the eggs for 9 minutes, cool, peel and prick each a few times with a fork.","Fry the onions in oil until golden, then add ginger-garlic paste, turmeric, chilli powder and coriander.","Add the tomatoes and cook 8 to 10 minutes until thick and glossy.","Add a splash of water to loosen into a gravy, season with salt and simmer 5 minutes.","Slip in the eggs, spoon over the sauce and simmer 5 minutes.","Stir in garam masala and finish with fresh coriander."],"pairing":"Jeera rice or buttered chapati","tags":["Quick","One-pan","Comfort","Gluten-free option"],"vegetarian":false,"spicy":false,"calories":250,"protein":12,"carbs":12,"fat":17,"allergens":["Egg"],"role":"main","cuisineKey":"indian","type":"Curry"},{"id":"in-dal-tadka","name":"Dal Tadka","category":"Curries","course":"Main","meal":"both","tier":"easy","inspiration":"","minutes":35,"serves":4,"level":"Weeknight","idea":"Everyday yellow lentils simmered soft and finished with a sizzling tempering of cumin, garlic and chilli in ghee. Comforting, cheap, freezer-friendly and naturally gentle enough for kids.","ingredients":[{"item":"250g toor dal (split pigeon peas) or red split lentils","note":"toor dal is a yellow split lentil; red lentils (masoor dal) cook faster and work well"},{"item":"1 tsp ground turmeric","note":"bright yellow earthy spice"},{"item":"1 tomato, chopped","note":""},{"item":"3 tbsp ghee","note":"Indian clarified butter; plain butter or oil works"},{"item":"1 tsp cumin seeds","note":"whole seeds of the cumin spice; sold whole in the spice aisle"},{"item":"4 cloves garlic, sliced","note":""},{"item":"2 dried red chillies","note":"whole dried red chillies for mild heat and aroma; a pinch of chilli flakes works"},{"item":"1 small onion, finely chopped","note":""},{"item":"1 tsp Kashmiri chilli powder","note":"mild deep-red chilli for colour; sub half regular chilli powder plus a pinch of paprika"},{"item":"Small handful fresh coriander, chopped","note":"leafy green herb, also called cilantro"},{"item":"Salt to taste","note":""}],"steps":["Rinse the lentils, then simmer with the turmeric, tomato and plenty of water for 20 to 25 minutes until soft, topping up water as needed.","Whisk the cooked dal until creamy and season with salt, loosening to a soft pouring consistency.","Heat the ghee in a small pan, add the cumin seeds and let them crackle.","Add the garlic, dried chillies and onion and fry until the garlic is golden.","Stir in the chilli powder off the heat, then pour the sizzling tempering over the dal.","Stir through, finish with coriander and serve."],"pairing":"Steamed rice or chapati and a spoon of yoghurt","tags":["Vegetarian","Comfort","Make-ahead","Batch-cook","Gluten-free option"],"vegetarian":true,"spicy":false,"calories":290,"protein":13,"carbs":35,"fat":11,"allergens":["Milk"],"role":"main","cuisineKey":"indian","type":"Curry"},{"id":"in-dal-bukhara","name":"Dal Bukhara","category":"Curries","course":"Main","meal":"dinner","tier":"signature","inspiration":"Bukhara (ITC Maurya)","minutes":150,"serves":4,"level":"Project","idea":"The legendary black dal of Bukhara at ITC Maurya: whole black urad slow-simmered for hours over the gentlest heat with butter, tomato and cream until glossy and unctuous. No rajma, no shortcuts. Time and a low flame are the real ingredients.","ingredients":[{"item":"250g whole black urad dal (sabut urad / whole black lentils)","note":"small whole black lentils with a creamy texture when slow-cooked; sold dried in world-foods, no easy substitute (canned black lentils at a push)"},{"item":"80g unsalted butter","note":""},{"item":"2 tbsp ginger-garlic paste","note":"smooth blend of equal ginger and garlic; jarred or homemade"},{"item":"1 large onion, finely chopped","note":""},{"item":"300g tomato puree (passata / sieved tomatoes)","note":"smooth strained tomatoes sold in cartons or jars; not the concentrated tube paste"},{"item":"1 tsp Kashmiri chilli powder","note":"mild deep-red chilli for colour; sub half regular chilli powder plus a pinch of paprika"},{"item":"1 tsp ground cumin","note":"warm earthy spice"},{"item":"1 tsp garam masala","note":"warm Indian spice blend"},{"item":"120ml double cream","note":"heavy whipping cream"},{"item":"1 tbsp dried fenugreek leaves (kasuri methi)","note":"dried herb with a faintly bitter, maple-like aroma; world-foods aisle, or leave out"},{"item":"Salt to taste","note":""}],"steps":["Soak the urad dal overnight, then pressure-cook with salt and plenty of water until completely soft, around 40 minutes.","Melt half the butter, fry the onion until golden, add ginger-garlic paste and cook off the rawness.","Add the tomato puree, chilli powder and cumin and cook 10 minutes until the fat separates.","Tip in the cooked dal with its liquid and simmer uncovered on the lowest heat for at least 60 to 90 minutes, stirring often and mashing some lentils against the pan until thick and glossy.","Stir through the cream, garam masala, crushed fenugreek and remaining butter and cook a final 10 minutes.","Season and finish with an extra drizzle of cream."],"pairing":"Naan or jeera rice and a glass of Shiraz","tags":["Vegetarian","Make-ahead","Comfort","Gluten-free option"],"vegetarian":true,"spicy":false,"calories":400,"protein":15,"carbs":35,"fat":24,"allergens":["Milk"],"role":"main","cuisineKey":"indian","type":"Curry"},{"id":"in-butter-chicken","name":"Butter Chicken (Murgh Makhani)","category":"Curries","course":"Main","meal":"both","tier":"signature","inspiration":"Dishoom","minutes":75,"serves":4,"level":"Weekend","idea":"A faithful homage to the Dishoom house murgh makhani: yoghurt-marinated chicken charred for smoke, then folded into a velvety tomato gravy enriched with butter and cream. Cashews add silk and crushed kasuri methi gives that unmistakable restaurant aroma.","ingredients":[{"item":"800g boneless, skinless chicken thighs, cut into 3cm chunks","note":"thigh meat stays tender; breast works if preferred"},{"item":"150g full-fat Greek yoghurt","note":"thick strained plain yoghurt; not the sweetened or low-fat kind"},{"item":"2 tbsp ginger-garlic paste","note":"smooth blend of equal ginger and garlic; jarred or homemade"},{"item":"2 tsp Kashmiri chilli powder","note":"mild deep-red chilli for colour; sub half regular chilli powder plus a pinch of paprika"},{"item":"600g ripe tomatoes, roughly chopped (or 400g tin chopped tomatoes plus 200g fresh)","note":""},{"item":"80g unsalted butter","note":""},{"item":"150ml double cream","note":"heavy whipping cream"},{"item":"1 tsp garam masala","note":"warm Indian spice blend"},{"item":"1 tbsp dried fenugreek leaves (kasuri methi)","note":"dried herb with a maple-like aroma, key to the classic flavour; world-foods aisle, or leave out"},{"item":"1 tbsp sugar","note":""},{"item":"30g cashews, soaked in warm water 15 min","note":"plain unsalted cashew nuts; they blend in to thicken and enrich the sauce"},{"item":"Salt to taste","note":""}],"steps":["Marinate the chicken in yoghurt, half the ginger-garlic paste, 1 tsp chilli powder and salt for at least 30 minutes, ideally overnight.","Char the chicken under a hot grill or in a screaming-hot pan until edges blacken and it is just cooked through, then set aside.","Simmer the tomatoes with the remaining ginger-garlic paste, cashews and chilli powder for 15 minutes until pulpy, then blend until silky and pass through a sieve.","Melt the butter, add the smooth tomato base and cook gently for 10 minutes until it deepens in colour and the fat separates.","Stir in the cream, sugar, garam masala and crushed kasuri methi, then fold in the chicken and any resting juices.","Simmer 5 minutes until the sauce coats the chicken, check salt and finish with a knob of butter."],"pairing":"Garlic naan and a glass of off-dry Riesling","tags":["Crowd-pleaser","Comfort","Make-ahead","Date night","Gluten-free option"],"vegetarian":false,"spicy":false,"calories":620,"protein":44,"carbs":14,"fat":44,"allergens":["Milk","Tree nuts"],"role":"main","cuisineKey":"indian","type":"Curry"},{"id":"in-rogan-josh","name":"Lamb Rogan Josh","category":"Curries","course":"Main","meal":"dinner","tier":"signature","inspiration":"Indian Accent","minutes":120,"serves":4,"level":"Weekend","idea":"A Michelin-chef take on the aromatic Kashmiri lamb curry, built on browned onions, whisked yoghurt and Kashmiri chilli for a deep red colour without ferocious heat. Slow cooking renders the lamb fork-tender in a glossy sauce scented with fennel and cardamom.","ingredients":[{"item":"800g lamb shoulder, cut into 4cm pieces","note":"a well-marbled cut that turns meltingly tender when slow-cooked; diced stewing lamb works"},{"item":"3 tbsp ghee or mustard oil","note":"ghee is Indian clarified butter; mustard oil is a sharp, pungent oil from the world-foods aisle; any vegetable oil works"},{"item":"2 large onions, finely sliced","note":""},{"item":"2 tbsp ginger-garlic paste","note":"smooth blend of equal ginger and garlic; jarred or homemade"},{"item":"150g Greek yoghurt, whisked smooth","note":"thick strained plain yoghurt; whisking stops it splitting in the pan"},{"item":"2 tsp Kashmiri chilli powder","note":"mild deep-red chilli for colour; sub half regular chilli powder plus a pinch of paprika"},{"item":"1 tsp ground fennel","note":"sweet, aniseed-like ground spice; grind fennel seeds if you can't find it ground"},{"item":"1 tsp ground ginger","note":"dried powdered ginger from the spice rack"},{"item":"4 green cardamom pods","note":"small pale-green pods with fragrant seeds; lightly crush before using"},{"item":"2 cloves and 1 small cinnamon stick","note":"whole cloves and a piece of cinnamon bark for warm aroma"},{"item":"2 bay leaves","note":""},{"item":"1 tsp garam masala","note":"warm Indian spice blend"},{"item":"Salt to taste","note":""}],"steps":["Heat the ghee and brown the lamb in batches, then set aside.","Fry the onions in the same pan until deep golden, add the whole spices and bay leaves and let them sizzle.","Stir in the ginger-garlic paste, then lower the heat and add the whisked yoghurt a spoonful at a time so it does not split.","Add the chilli powder, fennel and ground ginger and cook into a thick paste.","Return the lamb with a splash of water, cover and simmer gently for 75 to 90 minutes until fork-tender.","Finish with garam masala, check seasoning and rest 5 minutes before serving."],"pairing":"Steamed basmati and a glass of Syrah","tags":["Comfort","Make-ahead","Gluten-free option","Date night"],"vegetarian":false,"spicy":false,"calories":520,"protein":40,"carbs":12,"fat":35,"allergens":["Milk","Mustard"],"role":"main","cuisineKey":"indian","type":"Curry"},{"id":"in-chicken-tikka","name":"Chicken Tikka","category":"Tandoori & Grills","course":"Starter","meal":"both","tier":"easy","inspiration":"","minutes":35,"serves":4,"level":"Weeknight","idea":"Boneless chicken in a quick yoghurt and spice coating, charred hard so the edges catch and smoke. The classic starter and the building block of tikka masala, simple enough for any weeknight.","ingredients":[{"item":"700g boneless, skinless chicken thighs, cut into large chunks","note":"thigh meat stays juicy under high heat; breast works too"},{"item":"150g thick Greek yoghurt","note":"thick strained plain yoghurt; tenderises and coats the meat"},{"item":"2 tbsp ginger-garlic paste","note":"smooth blend of equal ginger and garlic; jarred or homemade"},{"item":"2 tsp Kashmiri chilli powder","note":"mild deep-red chilli for colour; sub half regular chilli powder plus a pinch of paprika"},{"item":"1 tsp ground cumin","note":"warm earthy spice"},{"item":"1 tsp garam masala","note":"warm Indian spice blend"},{"item":"2 tbsp lemon juice","note":""},{"item":"2 tbsp vegetable oil","note":""},{"item":"1 tbsp dried fenugreek leaves (kasuri methi)","note":"dried herb with a maple-like aroma; world-foods aisle, or leave out"},{"item":"Salt to taste","note":""}],"steps":["Mix the yoghurt with the ginger-garlic paste, chilli powder, cumin, garam masala, lemon juice, oil, crushed fenugreek and salt.","Coat the chicken in the marinade and chill at least 30 minutes, ideally 2 hours.","Thread onto skewers, or spread on a lined tray.","Grill on the highest heat, or under a hot grill, turning until charred and cooked through, around 12 to 15 minutes.","Brush with a little butter or oil in the last minute for shine.","Rest briefly and serve with lemon and onion."],"pairing":"Mint-coriander chutney and a cold lager","tags":["Gluten-free option","Quick","Crowd-pleaser","Make-ahead","Lunchbox"],"vegetarian":false,"spicy":true,"calories":340,"protein":40,"carbs":6,"fat":17,"allergens":["Milk"],"role":"main","cuisineKey":"indian","type":"Grills & BBQ"},{"id":"in-paneer-tikka","name":"Paneer Tikka","category":"Tandoori & Grills","course":"Starter","meal":"both","tier":"easy","inspiration":"","minutes":35,"serves":4,"level":"Weeknight","idea":"Cubes of paneer and peppers in a spiced yoghurt marinade, char-grilled until the edges blister. The vegetarian centrepiece of the grill, smoky outside and soft within.","ingredients":[{"item":"400g paneer, cut into 3cm cubes","note":"firm, mild Indian cheese that holds its shape on a grill; firm halloumi or extra-firm tofu can stand in"},{"item":"1 red pepper and 1 green pepper, in chunks","note":"bell peppers / capsicums"},{"item":"1 red onion, cut into petals","note":"cut into wedges, then separate the layers into petal-shaped pieces"},{"item":"200g thick Greek yoghurt","note":"thick strained plain yoghurt"},{"item":"2 tbsp ginger-garlic paste","note":"smooth blend of equal ginger and garlic; jarred or homemade"},{"item":"1 tbsp gram flour (besan)","note":"flour ground from chickpeas; helps the marinade cling; world-foods or free-from aisle"},{"item":"2 tsp Kashmiri chilli powder","note":"mild deep-red chilli for colour; sub half regular chilli powder plus a pinch of paprika"},{"item":"1 tsp garam masala","note":"warm Indian spice blend"},{"item":"1 tsp ground cumin","note":"warm earthy spice"},{"item":"2 tbsp vegetable oil","note":""},{"item":"1 tbsp dried fenugreek leaves (kasuri methi)","note":"dried herb with a maple-like aroma; world-foods aisle, or leave out"},{"item":"Salt to taste","note":""}],"steps":["Toast the gram flour in a dry pan until fragrant, then whisk into the yoghurt with the ginger-garlic paste, spices, oil and crushed fenugreek.","Fold in the paneer, peppers and onion and marinate at least 30 minutes.","Thread onto skewers, alternating paneer and vegetables.","Grill on high heat or under a hot grill, turning, until the edges char and blister, around 10 minutes.","Brush with a little oil or butter for gloss.","Finish with a squeeze of lemon and a dusting of chaat masala if you have it."],"pairing":"Mint-coriander chutney and a crisp Sauvignon Blanc","tags":["Vegetarian","Gluten-free option","Crowd-pleaser","Quick"],"vegetarian":true,"spicy":true,"calories":390,"protein":18,"carbs":16,"fat":28,"allergens":["Milk"],"role":"main","cuisineKey":"indian","type":"Grills & BBQ"},{"id":"in-tandoori-prawns","name":"Tandoori Prawns","category":"Tandoori & Grills","course":"Starter","meal":"both","tier":"easy","inspiration":"","minutes":25,"serves":4,"level":"Weeknight","idea":"Big prawns in a quick spiced yoghurt marinade, grilled fast and hot until smoky and just firm. A fifteen-minute marinade and a screaming pan put a restaurant starter on the table in no time.","ingredients":[{"item":"500g large raw prawns, peeled and deveined","note":"raw shrimp with the dark vein along the back removed; raw, not pre-cooked, so they stay plump"},{"item":"120g thick Greek yoghurt","note":"thick strained plain yoghurt"},{"item":"2 tbsp ginger-garlic paste","note":"smooth blend of equal ginger and garlic; jarred or homemade"},{"item":"2 tsp Kashmiri chilli powder","note":"mild deep-red chilli for colour; sub half regular chilli powder plus a pinch of paprika"},{"item":"1 tsp garam masala","note":"warm Indian spice blend"},{"item":"1 tsp ground turmeric","note":"bright yellow earthy spice"},{"item":"2 tbsp lemon juice","note":""},{"item":"2 tbsp vegetable oil","note":""},{"item":"Small handful fresh coriander, chopped","note":"leafy green herb, also called cilantro"},{"item":"Salt to taste","note":""}],"steps":["Pat the prawns dry, then toss with the yoghurt, ginger-garlic paste, chilli powder, garam masala, turmeric, lemon juice, oil and salt.","Marinate 15 minutes while you heat a grill pan or grill until very hot.","Thread onto skewers, or lay flat on a hot pan.","Grill 2 to 3 minutes per side until charred at the edges and just opaque through, taking care not to overcook.","Squeeze over more lemon and scatter with coriander.","Serve hot with chutney."],"pairing":"Mint chutney, lemon wedges and a chilled white","tags":["Gluten-free option","Quick","Light","Date night"],"vegetarian":false,"spicy":true,"calories":190,"protein":26,"carbs":5,"fat":8,"allergens":["Shellfish","Milk"],"role":"main","cuisineKey":"indian","type":"Grills & BBQ"},{"id":"in-seekh-kebab","name":"Chicken Seekh Kebabs","category":"Tandoori & Grills","course":"Starter","meal":"both","tier":"easy","inspiration":"","minutes":30,"serves":4,"level":"Weeknight","idea":"Spiced minced chicken pressed onto skewers and grilled until juicy and charred. Mix, shape, grill: a fast, kid-friendly favourite that needs nothing more than a squeeze of lemon.","ingredients":[{"item":"600g chicken mince","note":"ground chicken; ask the butcher for thigh mince for a juicier result"},{"item":"1 small onion, very finely chopped","note":""},{"item":"2 tbsp ginger-garlic paste","note":"smooth blend of equal ginger and garlic; jarred or homemade"},{"item":"2 green chillies, finely chopped","note":"mild-to-medium green chillies; deseed for less heat"},{"item":"1 tsp garam masala","note":"warm Indian spice blend"},{"item":"1 tsp ground cumin","note":"warm earthy spice"},{"item":"1 tsp Kashmiri chilli powder","note":"mild deep-red chilli for colour; sub half regular chilli powder plus a pinch of paprika"},{"item":"3 tbsp chopped fresh coriander","note":"leafy green herb, also called cilantro"},{"item":"2 tbsp gram flour (besan)","note":"chickpea flour; binds the mince so the kebabs hold together; world-foods or free-from aisle"},{"item":"2 tbsp vegetable oil","note":""},{"item":"Salt to taste","note":""}],"steps":["Mix all the ingredients except the oil thoroughly until the mince becomes slightly sticky.","Chill 15 minutes to firm up, which helps it hold on the skewer.","With wet hands, press the mixture into sausage shapes around skewers or roll into logs.","Brush with oil and grill on high heat or under a hot grill, turning, until browned and cooked through, around 12 minutes.","Rest 2 minutes so the juices settle.","Serve with lemon, sliced onion and mint chutney."],"pairing":"Mint-coriander chutney and warm naan","tags":["Gluten-free option","Quick","Crowd-pleaser","Lunchbox","Make-ahead"],"vegetarian":false,"spicy":true,"calories":290,"protein":29,"carbs":7,"fat":16,"allergens":[],"role":"main","cuisineKey":"indian","type":"Grills & BBQ"},{"id":"in-tandoori-chicken","name":"Tandoori Chicken","category":"Tandoori & Grills","course":"Main","meal":"dinner","tier":"signature","inspiration":"Bukhara (ITC Maurya)","minutes":60,"serves":4,"level":"Weekend","idea":"The dish Moti Mahal made famous: bone-in chicken slashed to the bone, marinated in spiced yoghurt, then roasted hard so the surface blisters and the meat stays juicy. The deep colour comes from Kashmiri chilli, never food dye.","ingredients":[{"item":"1.2kg chicken legs and thighs, skin removed, slashed deeply to the bone","note":"deep cuts let the marinade reach the meat; bone-in, skinless"},{"item":"200g thick Greek yoghurt","note":"thick strained plain yoghurt"},{"item":"2 tbsp ginger-garlic paste","note":"smooth blend of equal ginger and garlic; jarred or homemade"},{"item":"2 tsp Kashmiri chilli powder","note":"mild deep-red chilli for colour; sub half regular chilli powder plus a pinch of paprika"},{"item":"1 tsp ground turmeric","note":"bright yellow earthy spice"},{"item":"1 tbsp garam masala","note":"warm Indian spice blend"},{"item":"2 tbsp lemon juice","note":""},{"item":"3 tbsp mustard oil","note":"sharp, pungent oil from the world-foods aisle; any vegetable oil works"},{"item":"1 tsp ground cumin","note":"warm earthy spice"},{"item":"1 tbsp dried fenugreek leaves (kasuri methi)","note":"dried herb with a maple-like aroma; world-foods aisle, or leave out"},{"item":"Salt to taste","note":""}],"steps":["Rub the slashed chicken with lemon juice, half the chilli powder and salt and leave 20 minutes.","Mix the yoghurt with ginger-garlic paste, remaining spices, mustard oil and crushed fenugreek.","Coat the chicken thoroughly, working the marinade into the slashes, and chill at least 4 hours or overnight.","Roast in a very hot oven at 240C, or on a hot barbecue, for 30 to 35 minutes, turning once, until charred and the juices run clear.","Finish under a high grill for a few minutes to blister the surface.","Squeeze over lemon and serve hot."],"pairing":"Onion salad, mint chutney and a chilled rosé","tags":["Gluten-free option","Crowd-pleaser","Make-ahead","Date night"],"vegetarian":false,"spicy":true,"calories":420,"protein":52,"carbs":7,"fat":20,"allergens":["Milk","Mustard"],"role":"main","cuisineKey":"indian","type":"Grills & BBQ"},{"id":"in-jeera-rice","name":"Jeera Rice","category":"Rice & Breads","course":"All-day","meal":"both","tier":"easy","inspiration":"","minutes":30,"serves":4,"level":"Weeknight","idea":"Fluffy basmati tempered with cumin seeds bloomed in ghee, the everyday partner to any dal or curry. The trick is soaking the rice so the grains stay long, separate and never sticky.","ingredients":[{"item":"300g basmati rice","note":"long-grain aromatic Indian rice; rinse until the water runs clear before cooking"},{"item":"2 tbsp ghee","note":"Indian clarified butter; plain butter or oil works"},{"item":"2 tsp cumin seeds (jeera)","note":"whole cumin seeds; jeera is simply the Hindi name for them"},{"item":"1 small bay leaf","note":""},{"item":"2 green cardamom pods","note":"small pale-green fragrant pods; lightly crush before using"},{"item":"1 small cinnamon stick","note":"a piece of cinnamon bark for warm aroma"},{"item":"600ml water","note":""},{"item":"Salt to taste","note":""},{"item":"Small handful fresh coriander, chopped","note":"leafy green herb, also called cilantro"}],"steps":["Rinse the rice until the water runs clear, then soak for 20 minutes and drain.","Heat the ghee, add the cumin seeds and whole spices and let them sizzle until the cumin crackles and smells nutty.","Tip in the drained rice and toss gently for a minute to coat the grains.","Add the water and salt, bring to a boil, then cover and cook on the lowest heat for 12 minutes.","Rest covered off the heat for 5 minutes, then fluff with a fork.","Scatter with coriander and serve."],"pairing":"Dal bukhara, chana masala or any rich curry","tags":["Vegetarian","Quick","Comfort","Gluten-free option"],"vegetarian":true,"spicy":false,"calories":330,"protein":6,"carbs":58,"fat":7,"allergens":["Milk"],"role":"main","cuisineKey":"indian","type":"Rice & Bowls"},{"id":"in-lemon-rice","name":"Lemon Rice","category":"Rice & Breads","course":"All-day","meal":"both","tier":"easy","inspiration":"","minutes":20,"serves":4,"level":"Weeknight","idea":"A bright South Indian rice tossed with a mustard-seed and curry-leaf tempering, turmeric and fresh lemon. The fastest way to turn leftover rice into something zingy, and excellent cold in a lunchbox.","ingredients":[{"item":"500g cooked basmati rice, cooled","note":"day-old or fully cooled rice works best as it won't clump"},{"item":"3 tbsp vegetable oil","note":""},{"item":"1 tsp mustard seeds","note":"tiny round seeds that pop and turn nutty in hot oil; black or brown, from the spice aisle"},{"item":"1 tbsp chana dal or peanuts","note":"chana dal is split skinned chickpeas (adds crunch); plain unsalted peanuts work just as well"},{"item":"10 fresh curry leaves","note":"glossy aromatic leaves with a citrusy savoury scent; sold fresh or frozen in world-foods; no real substitute, just leave out if unavailable"},{"item":"2 dried red chillies","note":"whole dried red chillies for mild heat; a pinch of chilli flakes works"},{"item":"1 tsp ground turmeric","note":"bright yellow earthy spice"},{"item":"3 tbsp lemon juice","note":""},{"item":"Salt to taste","note":""},{"item":"Small handful fresh coriander, chopped","note":"leafy green herb, also called cilantro"}],"steps":["Heat the oil, add the mustard seeds and let them pop.","Add the chana dal or peanuts and fry until golden, then add curry leaves and dried chillies.","Stir in the turmeric off the heat so it does not burn.","Add the cooled rice and salt and toss gently to coat every grain yellow.","Squeeze in the lemon juice and fold through.","Finish with coriander and serve warm or at room temperature."],"pairing":"Coconut chutney or a simple yoghurt","tags":["Vegan","Vegetarian","Quick","One-pan","Light","Lunchbox","Gluten-free option"],"vegetarian":true,"spicy":false,"calories":270,"protein":5,"carbs":42,"fat":10,"allergens":["Peanut"],"role":"main","cuisineKey":"indian","type":"Rice & Bowls"},{"id":"in-chapati","name":"Chapati (Roti)","category":"Rice & Breads","course":"All-day","meal":"both","tier":"easy","inspiration":"","minutes":30,"serves":4,"level":"Weeknight","idea":"Soft everyday wholemeal flatbreads cooked on a dry pan and puffed over the flame. Just flour and water, no yeast and no proving, the daily bread that goes with everything.","ingredients":[{"item":"300g chapati flour (atta) or wholemeal flour","note":"atta is finely milled wholemeal wheat flour for soft flatbreads; ordinary wholemeal flour works, ideally sifted"},{"item":"Around 200ml warm water","note":""},{"item":"1 tsp vegetable oil","note":""},{"item":"1/2 tsp salt","note":""},{"item":"A little extra flour for dusting","note":""},{"item":"A little butter or ghee to finish","note":"ghee is Indian clarified butter; butter is fine"}],"steps":["Mix the flour and salt, then add the water a little at a time, bringing it together into a soft, pliable dough.","Knead 5 minutes, rub with the oil, cover and rest 15 minutes.","Divide into 8 balls and roll each into a thin round on a floured surface.","Cook on a hot dry pan for about 30 seconds a side until brown spots appear.","Press the edges gently or hold over a flame so the chapati puffs up.","Brush with a little butter and keep warm under a cloth."],"pairing":"Any dal or curry","tags":["Vegetarian","Vegan","Quick","Comfort","Make-ahead"],"vegetarian":true,"spicy":false,"calories":270,"protein":8,"carbs":51,"fat":4,"allergens":["Gluten","Milk"],"role":"main","cuisineKey":"indian","type":"Rice & Bowls"},{"id":"in-garlic-naan","name":"Quick Garlic Naan","category":"Rice & Breads","course":"All-day","meal":"both","tier":"easy","inspiration":"","minutes":30,"serves":4,"level":"Weeknight","idea":"A fast no-yeast naan leavened with yoghurt and baking powder, slapped onto a screaming-hot pan and finished with garlic butter and coriander. Soft, blistered and on the table in half an hour with no proving.","ingredients":[{"item":"350g plain flour, plus extra for dusting","note":"plain / all-purpose white flour"},{"item":"1 tsp baking powder","note":""},{"item":"1/2 tsp bicarbonate of soda","note":"baking soda"},{"item":"1 tsp sugar","note":""},{"item":"150g plain yoghurt","note":"natural unsweetened yoghurt"},{"item":"60ml warm milk","note":""},{"item":"2 tbsp vegetable oil","note":""},{"item":"1 tsp salt","note":""},{"item":"4 cloves garlic, finely minced","note":""},{"item":"50g butter, melted","note":""},{"item":"Small handful fresh coriander, chopped","note":"leafy green herb, also called cilantro"}],"steps":["Mix the flour, baking powder, bicarbonate of soda, sugar and salt, then stir in the yoghurt, warm milk and oil to form a soft dough.","Knead 3 to 4 minutes until smooth, cover and rest just 15 minutes.","Divide into 6 balls and roll each into a teardrop about 5mm thick.","Heat a heavy skillet until smoking, slap on a naan, cook until large bubbles form, then flip and press until charred in spots.","Mix the garlic into the melted butter and brush generously over the hot naan, scattering coriander.","Keep warm under a cloth and serve straight away."],"pairing":"Any rich curry such as butter chicken or dal bukhara","tags":["Vegetarian","Quick","Comfort","Crowd-pleaser"],"vegetarian":true,"spicy":false,"calories":420,"protein":11,"carbs":66,"fat":12,"allergens":["Gluten","Milk"],"role":"main","cuisineKey":"indian","type":"Rice & Bowls"},{"id":"in-chicken-biryani","name":"Hyderabadi Dum Biryani","category":"Rice & Breads","course":"Main","meal":"dinner","tier":"signature","inspiration":"Dishoom","minutes":90,"serves":4,"level":"Project","idea":"The slow-sealed dum biryani in the Dum Pukht tradition: marinated chicken layered with par-cooked saffron basmati and sealed to steam in its own aromas. The reward is separate, perfumed grains over tender, spiced meat.","ingredients":[{"item":"700g bone-in chicken pieces","note":"on-the-bone pieces add flavour; thighs and drumsticks work well"},{"item":"400g aged basmati rice","note":"long-grain aromatic rice; aged grains stay separate and fluffy; any good basmati works"},{"item":"200g Greek yoghurt","note":"thick strained plain yoghurt"},{"item":"3 onions, finely sliced and fried golden (birista)","note":"birista is crisp golden fried onions; buy them ready-fried in world-foods to save time"},{"item":"2 tbsp ginger-garlic paste","note":"smooth blend of equal ginger and garlic; jarred or homemade"},{"item":"2 tsp Kashmiri chilli powder","note":"mild deep-red chilli for colour; sub half regular chilli powder plus a pinch of paprika"},{"item":"1 tbsp biryani masala","note":"a ready-mixed spice blend made for biryani; world-foods aisle, or use garam masala at a pinch"},{"item":"Large pinch saffron soaked in 60ml warm milk","note":"saffron is fine red threads that give colour and aroma; a pinch is plenty; turmeric gives colour but not the flavour"},{"item":"5 green cardamom pods, 4 cloves, 1 cinnamon stick, 2 bay leaves","note":"whole warm spices; cardamom are small pale-green fragrant pods"},{"item":"4 tbsp ghee","note":"Indian clarified butter; butter works"},{"item":"Handful each chopped fresh mint and coriander","note":"coriander is also called cilantro"},{"item":"2 tbsp lemon juice","note":""},{"item":"Salt to taste","note":""}],"steps":["Marinate the chicken in yoghurt, ginger-garlic paste, chilli powder, biryani masala, half the fried onions, lemon juice and salt for at least 1 hour.","Soak the rice 30 minutes, then boil in heavily salted water with the whole spices until 70 percent cooked, and drain.","Layer the marinated chicken in a heavy pot, top with the par-cooked rice, then scatter the remaining fried onions, mint, coriander, saffron milk and ghee.","Seal the pot tightly with a lid or foil and cook on the lowest heat (dum) for 25 to 30 minutes until the chicken is cooked through and the rice is steamed.","Rest sealed for 10 minutes off the heat so the steam settles.","Open at the table and fold gently from the edges to bring up the layers."],"pairing":"Cooling boondi raita and a glass of Gewürztraminer","tags":["Crowd-pleaser","Date night","Gluten-free option","Make-ahead"],"vegetarian":false,"spicy":true,"calories":620,"protein":35,"carbs":62,"fat":26,"allergens":["Milk"],"role":"main","cuisineKey":"indian","type":"Rice & Bowls"},{"id":"in-samosa-chaat","name":"Samosa Chaat","cuisineKey":"indian","category":"Tandoori & Grills","role":"appetizer","course":"Starter","meal":"both","tier":"easy","inspiration":"","minutes":20,"serves":4,"level":"Weeknight","idea":"Crushed crisp samosas smothered in spiced chickpeas, yoghurt, and tangy chutneys, the classic Indian street-food starter.","ingredients":[{"item":"4 ready-made vegetable samosas","note":"fried pastry parcels with a spiced potato-and-pea filling; from the freezer or chilled world-foods aisle"},{"item":"400g tin chickpeas, drained and warmed","note":"also labelled garbanzo beans"},{"item":"200g plain yoghurt, whisked smooth","note":"natural unsweetened yoghurt, loosened with a little water"},{"item":"4 tbsp tamarind chutney","note":"sweet-and-sour dark brown sauce from tamarind fruit; sold in jars in world-foods; brown sauce mixed with a little date or fig works in a pinch"},{"item":"3 tbsp coriander-mint chutney","note":"fresh green chutney of coriander, mint and chilli; jarred in world-foods, or blitz the herbs with chilli and lemon"},{"item":"1 tsp chaat masala","note":"tangy, slightly sulphurous spice blend used to season Indian snacks; world-foods aisle; no close substitute, leave out if needed"},{"item":"1 tsp roasted cumin powder","note":"ground cumin toasted in a dry pan for a smoky depth; toast plain ground cumin yourself"},{"item":"1 small red onion, finely chopped","note":""},{"item":"30g sev (crisp gram-flour noodles)","note":"fine crunchy strands fried from chickpea-flour batter; the topping in bhel/chaat; world-foods aisle, or crush a few plain salted crisps"},{"item":"Small handful fresh coriander, chopped","note":"leafy green herb, also called cilantro"},{"item":"Salt to taste","note":""}],"steps":["Bake or fry the samosas until hot and crisp, then roughly crush them onto a serving plate.","Spoon the warm chickpeas over the crushed samosas.","Drizzle generously with whisked yoghurt, then the tamarind and coriander-mint chutneys.","Scatter over chopped red onion, then dust with chaat masala and roasted cumin.","Top with sev and fresh coriander and serve immediately while crisp."],"pairing":"Masala chai or a cold lassi","tags":["street food","chaat","sharing"],"vegetarian":true,"spicy":true,"calories":340,"protein":11,"carbs":45,"fat":13,"allergens":["Gluten","Milk"],"type":"Starters"},{"id":"in-aloo-tikki","name":"Aloo Tikki with Chutneys","cuisineKey":"indian","category":"Tandoori & Grills","role":"appetizer","course":"Starter","meal":"both","tier":"easy","inspiration":"","minutes":35,"serves":4,"level":"Weeknight","idea":"Golden pan-fried spiced potato cakes served with green and tamarind chutneys, a crisp, comforting starter.","ingredients":[{"item":"600g floury potatoes, boiled and mashed","note":"a starchy variety like Maris Piper or Russet that mashes fluffy"},{"item":"3 tbsp cornflour","note":"cornstarch; binds the patties so they don't fall apart"},{"item":"2 green chillies, finely chopped","note":"mild-to-medium green chillies; deseed for less heat"},{"item":"1 tbsp ginger, grated","note":"fresh root ginger"},{"item":"1 tsp ground cumin","note":"warm earthy spice"},{"item":"1 tsp garam masala","note":"warm Indian spice blend"},{"item":"1 tsp amchur (dried mango powder)","note":"tangy sour powder from dried unripe mango; substitute a squeeze of lemon"},{"item":"3 tbsp chopped fresh coriander","note":"leafy green herb, also called cilantro"},{"item":"4 tbsp vegetable oil for shallow frying","note":""},{"item":"4 tbsp coriander-mint chutney","note":"fresh green chutney of coriander, mint and chilli; jarred, or blitz the herbs with chilli and lemon"},{"item":"4 tbsp tamarind chutney","note":"sweet-and-sour dark brown sauce; jarred in world-foods; brown sauce with a little date works in a pinch"},{"item":"Salt to taste","note":""}],"steps":["Mix the mashed potato with cornflour, chillies, ginger, cumin, garam masala, amchur, coriander, and salt.","Shape the mixture into 8 flat round patties about 2cm thick.","Heat the oil in a frying pan and shallow-fry the tikkis over medium heat until deep golden and crisp on both sides.","Drain on kitchen paper.","Serve hot with coriander-mint and tamarind chutneys spooned alongside."],"pairing":"Cold mint lassi","tags":["street food","crispy","sharing"],"vegetarian":true,"spicy":true,"calories":290,"protein":5,"carbs":42,"fat":12,"allergens":[],"type":"Starters"},{"id":"in-onion-bhaji","name":"Onion Bhaji","cuisineKey":"indian","category":"Tandoori & Grills","role":"appetizer","course":"Starter","meal":"both","tier":"easy","inspiration":"","minutes":30,"serves":4,"level":"Weeknight","idea":"Crisp, lacy gram-flour onion fritters spiced with cumin and chilli, the ultimate Indian starter to share.","ingredients":[{"item":"3 large onions, thinly sliced","note":""},{"item":"150g gram flour (besan)","note":"flour ground from chickpeas; the traditional batter base; world-foods or free-from aisle"},{"item":"2 tbsp rice flour","note":"finely ground rice; adds extra crispness; world-foods or free-from aisle, or use a little cornflour"},{"item":"1 tsp ground turmeric","note":"bright yellow earthy spice"},{"item":"1 tsp Kashmiri chilli powder","note":"mild deep-red chilli for colour; sub half regular chilli powder plus a pinch of paprika"},{"item":"1 tsp cumin seeds","note":"whole cumin seeds"},{"item":"1 tsp ground coriander","note":"mild citrusy ground spice"},{"item":"2 green chillies, finely chopped","note":"mild-to-medium green chillies; deseed for less heat"},{"item":"3 tbsp chopped fresh coriander","note":"leafy green herb, also called cilantro"},{"item":"Around 80ml cold water","note":""},{"item":"Vegetable oil for deep frying","note":""},{"item":"Salt to taste","note":""}],"steps":["Toss the sliced onions with salt and leave for 10 minutes to soften and release moisture.","Add gram flour, rice flour, turmeric, chilli powder, cumin seeds, ground coriander, green chillies, and fresh coriander.","Mix well, adding only enough cold water to form a thick batter that coats the onions.","Heat oil to 170C and drop in small clusters of the mixture.","Fry until deep golden and crisp, drain on kitchen paper, and serve hot with chutney."],"pairing":"Mango chutney and a cold beer or lassi","tags":["fritter","crispy","sharing"],"vegetarian":true,"spicy":true,"calories":260,"protein":8,"carbs":30,"fat":12,"allergens":[],"type":"Starters"},{"id":"in-kachumber-salad","name":"Kachumber Salad","cuisineKey":"indian","category":"Tandoori & Grills","role":"salad","course":"Starter","meal":"both","tier":"easy","inspiration":"","minutes":15,"serves":4,"level":"Weeknight","idea":"The crunchy North Indian table salad of diced cucumber, tomato, and onion sharpened with lemon and toasted cumin.","ingredients":[{"item":"1 cucumber, finely diced","note":""},{"item":"3 tomatoes, deseeded and finely diced","note":""},{"item":"1 red onion, finely diced","note":""},{"item":"2 green chillies, finely chopped","note":"mild-to-medium green chillies; deseed for less heat or leave out"},{"item":"3 tbsp chopped fresh coriander","note":"leafy green herb, also called cilantro"},{"item":"2 tbsp lemon juice","note":""},{"item":"1 tsp roasted cumin powder","note":"ground cumin toasted in a dry pan for a smoky note; toast plain ground cumin yourself"},{"item":"1/2 tsp Kashmiri chilli powder","note":"mild deep-red chilli for colour; sub a pinch of regular chilli powder plus paprika"},{"item":"Salt to taste","note":""}],"steps":["Combine the cucumber, tomato, red onion, green chillies, and coriander in a bowl.","Add the lemon juice, roasted cumin, and chilli powder.","Season with salt and toss gently to combine.","Chill for 10 minutes and toss again just before serving so it stays crisp."],"pairing":"Any rich curry or biryani","tags":["salad","fresh","side"],"vegetarian":true,"spicy":true,"calories":70,"protein":2,"carbs":12,"fat":1,"allergens":[],"type":"Salads"},{"id":"in-chana-chaat-salad","name":"Chickpea Chaat Salad","cuisineKey":"indian","category":"Tandoori & Grills","role":"salad","course":"Starter","meal":"both","tier":"easy","inspiration":"","minutes":15,"serves":4,"level":"Weeknight","idea":"A protein-rich chaat-style salad of chickpeas, onion, tomato, and cucumber tossed in tamarind and lime with chaat masala.","ingredients":[{"item":"2 x 400g tins chickpeas, drained and rinsed","note":"also labelled garbanzo beans"},{"item":"1 red onion, finely diced","note":""},{"item":"2 tomatoes, finely diced","note":""},{"item":"1/2 cucumber, finely diced","note":""},{"item":"2 tbsp tamarind chutney","note":"sweet-and-sour dark brown sauce; jarred in world-foods; brown sauce with a little date works in a pinch"},{"item":"2 tbsp lime juice","note":""},{"item":"1 tsp chaat masala","note":"tangy spice blend for Indian snacks; world-foods aisle; leave out if unavailable"},{"item":"1 tsp roasted cumin powder","note":"ground cumin toasted in a dry pan; toast plain ground cumin yourself"},{"item":"2 green chillies, finely chopped","note":"mild-to-medium green chillies; deseed for less heat"},{"item":"4 tbsp chopped fresh coriander","note":"leafy green herb, also called cilantro"},{"item":"Salt to taste","note":""}],"steps":["Tip the chickpeas into a large bowl with the onion, tomato, and cucumber.","Add the tamarind chutney, lime juice, chaat masala, and roasted cumin.","Add the green chillies and coriander, season with salt, and toss well.","Rest for 5 minutes to let the flavours meld, then taste and adjust lime and salt before serving."],"pairing":"Grilled tandoori chicken or eaten on its own as a light lunch","tags":["salad","protein","chaat"],"vegetarian":true,"spicy":true,"calories":210,"protein":10,"carbs":34,"fat":4,"allergens":[],"type":"Salads"},{"id":"in-cucumber-raita-salad","name":"Cucumber and Pomegranate Raita Salad","cuisineKey":"indian","category":"Tandoori & Grills","role":"salad","course":"Starter","meal":"both","tier":"easy","inspiration":"","minutes":15,"serves":4,"level":"Weeknight","idea":"Cool yoghurt-dressed cucumber salad jewelled with pomegranate and toasted cumin, a refreshing foil to spice.","ingredients":[{"item":"300g thick Greek yoghurt","note":"thick strained plain yoghurt"},{"item":"1 cucumber, coarsely grated and squeezed dry","note":"squeezing out the water keeps the raita thick"},{"item":"80g pomegranate seeds","note":"the jewel-like seeds from inside a pomegranate; sold ready-podded in tubs"},{"item":"1 tsp roasted cumin powder","note":"ground cumin toasted in a dry pan for a smoky note; toast plain ground cumin yourself"},{"item":"1/2 tsp Kashmiri chilli powder","note":"mild deep-red chilli for colour; sub a pinch of regular chilli powder plus paprika"},{"item":"2 tbsp chopped fresh mint","note":""},{"item":"2 tbsp chopped fresh coriander","note":"leafy green herb, also called cilantro"},{"item":"1 tsp sugar","note":""},{"item":"Salt to taste","note":""}],"steps":["Whisk the yoghurt with sugar and a pinch of salt until smooth.","Fold in the grated cucumber and most of the pomegranate seeds.","Stir through the roasted cumin, mint, and coriander.","Spoon into a bowl, scatter over the remaining pomegranate and a dusting of chilli powder, and serve chilled."],"pairing":"Biryani or any tandoori grill","tags":["salad","raita","cooling"],"vegetarian":true,"spicy":false,"calories":120,"protein":7,"carbs":13,"fat":4,"allergens":["Milk"],"type":"Salads"},{"id":"in-fish-tikka","name":"Amritsari Fish Tikka","cuisineKey":"indian","category":"Tandoori & Grills","role":"main","course":"Main","meal":"both","tier":"easy","inspiration":"","minutes":45,"serves":4,"level":"Weeknight","idea":"Firm white fish marinated in yoghurt, carom seeds, and gram flour, then chargrilled until smoky and golden.","ingredients":[{"item":"700g firm white fish fillets (cod or pollock), cut into 4cm chunks","note":"firm fish holds together on the grill; haddock or monkfish also work"},{"item":"150g thick Greek yoghurt","note":"thick strained plain yoghurt"},{"item":"2 tbsp ginger-garlic paste","note":"smooth blend of equal ginger and garlic; jarred or homemade"},{"item":"2 tbsp gram flour (besan)","note":"chickpea flour; helps the marinade cling and crisp; world-foods or free-from aisle"},{"item":"2 tsp Kashmiri chilli powder","note":"mild deep-red chilli for colour; sub half regular chilli powder plus a pinch of paprika"},{"item":"1 tsp ground turmeric","note":"bright yellow earthy spice"},{"item":"1 tsp carom seeds (ajwain)","note":"small seeds with a sharp thyme-like taste, classic with fish; world-foods aisle; substitute a pinch of dried thyme"},{"item":"1 tsp garam masala","note":"warm Indian spice blend"},{"item":"2 tbsp lemon juice","note":""},{"item":"2 tbsp mustard oil","note":"sharp, pungent oil from world-foods; any vegetable oil works"},{"item":"Salt to taste","note":""}],"steps":["Pat the fish dry and toss gently with lemon juice, turmeric, and salt.","Whisk the yoghurt with ginger-garlic paste, gram flour, chilli powder, carom seeds, garam masala, and mustard oil.","Coat the fish in the marinade and chill for 30 minutes.","Thread onto skewers or lay on a lined tray and grill or bake at 220C for 10 to 12 minutes, turning once, until charred at the edges and just cooked.","Rest briefly, then serve with kachumber and lemon wedges."],"pairing":"Kachumber salad and garlic naan","tags":["tandoori","fish","grilled","high protein"],"vegetarian":false,"spicy":true,"calories":300,"protein":38,"carbs":8,"fat":12,"allergens":["Fish","Milk","Mustard"],"type":"Grills & BBQ"},{"id":"th-red-curry-chicken","name":"Quick Thai Red Chicken Curry","category":"Curries & Stir-fry","course":"Main","meal":"both","tier":"easy","inspiration":"","minutes":25,"serves":4,"level":"Weeknight","idea":"A weeknight curry built on a tub of shop-bought red curry paste, coconut milk and chicken. Frying the paste in a little of the thick coconut cream first is the one move that makes it taste cooked rather than canned.","ingredients":[{"item":"600g chicken breast or boneless thigh, thinly sliced","note":""},{"item":"400ml full-fat coconut milk (1 tin)","note":"thick, creamy liquid pressed from coconut flesh; sold in tins in the world-foods aisle, not the same as carton coconut drink"},{"item":"3 tbsp Thai red curry paste","note":"a blended paste of red chilli, lemongrass, galangal and garlic; jars sold in the world-foods aisle (Thai Taste, Mae Ploy)"},{"item":"2 tbsp fish sauce (nam pla)","note":"salty amber liquid made from fermented fish; adds savoury depth. Light soy sauce works at a pinch"},{"item":"1 tbsp soft light brown sugar","note":""},{"item":"1 red bell pepper, sliced","note":""},{"item":"150g green beans, halved","note":""},{"item":"2 makrut lime leaves, or zest of 1 lime","note":"glossy double leaves (often labelled kaffir lime) with a citrus aroma; found dried or frozen. Lime zest is the easy swap"},{"item":"Handful Thai basil leaves","note":"aniseed-scented basil with purple stems; ordinary sweet basil is a fine substitute"},{"item":"1 tbsp neutral oil (sunflower or vegetable)","note":""}],"steps":["Spoon the thick cream from the top of the coconut milk into a wide pan with the oil and heat until bubbling.","Add the red curry paste and fry 2 minutes until it smells fragrant.","Add the chicken and stir to coat, cooking 3 minutes until it turns opaque.","Pour in the rest of the coconut milk plus a splash of water, then add pepper, beans and lime leaves.","Simmer 10 minutes until the chicken is cooked and the vegetables are just tender.","Season with fish sauce and sugar, stir through the basil and serve with rice."],"pairing":"Jasmine rice and a cold lager","tags":["Quick","One-pan","Gluten-free option","Crowd-pleaser","Comfort"],"vegetarian":false,"spicy":true,"calories":430,"protein":35,"carbs":12,"fat":27,"allergens":["Fish"],"role":"main","cuisineKey":"thai","type":"Curry"},{"id":"th-cashew-chicken","name":"Thai Cashew Chicken Stir-fry","category":"Curries & Stir-fry","course":"Main","meal":"both","tier":"easy","inspiration":"","minutes":20,"serves":2,"level":"Weeknight","idea":"A gentle, mild stir-fry the whole family eats: chicken and toasted cashews in a glossy oyster-soy sauce with sweet pepper and onion. Friendly enough for kids but quick enough for a tired cook.","ingredients":[{"item":"300g chicken breast, thinly sliced","note":""},{"item":"60g roasted unsalted cashews","note":""},{"item":"1 onion, cut into wedges","note":""},{"item":"1 red bell pepper, sliced","note":""},{"item":"3 spring onions, cut into 4cm batons","note":"slim green onions, also called scallions"},{"item":"3 garlic cloves, chopped","note":""},{"item":"2 tbsp oyster sauce","note":"thick, savoury-sweet brown sauce made from oyster extract; sold in the world-foods aisle. Use a vegetarian mushroom stir-fry sauce to keep it meat-free"},{"item":"1 tbsp light soy sauce","note":"thinner, saltier soy used for seasoning; ordinary soy sauce is fine"},{"item":"1 tsp caster sugar","note":""},{"item":"2 tbsp neutral oil (sunflower or vegetable)","note":""}],"steps":["Mix the oyster sauce, soy sauce and sugar with 2 tablespoons water in a small bowl.","Heat the oil in a wok or large pan until hot, add the garlic and onion and stir-fry 1 minute.","Add the chicken and stir-fry over high heat 4 minutes until cooked and lightly golden.","Add the pepper and toss 1 minute until just softened.","Pour in the sauce and the cashews and toss to glaze.","Finish with the spring onions and serve over rice."],"pairing":"Steamed rice and iced jasmine tea","tags":["Quick","One-pan","Crowd-pleaser","Comfort"],"vegetarian":false,"spicy":false,"calories":510,"protein":42,"carbs":22,"fat":28,"allergens":["Fish","Shellfish","Soy","Gluten","Tree nuts"],"role":"main","cuisineKey":"thai","type":"Curry"},{"id":"th-pad-krapow-gai","name":"Pad Krapow Gai (Holy Basil Chicken Stir-fry)","category":"Curries & Stir-fry","course":"Main","meal":"both","tier":"easy","inspiration":"","minutes":20,"serves":2,"level":"Weeknight","idea":"Thailand's ultimate fast food: minced chicken seared hard with chilli, garlic and pungent basil, served over rice with a crisp-edged fried egg. Punchy, salty-savoury and on the table in minutes. Dial the chilli down for younger eaters.","ingredients":[{"item":"300g minced (ground) chicken","note":""},{"item":"4 garlic cloves, chopped","note":""},{"item":"2 to 4 red bird's eye chillies, chopped","note":"small, very hot Thai chillies; use fewer, or a milder red chilli, for less heat"},{"item":"Large handful holy basil (or Thai basil) leaves","note":"peppery, slightly clove-like basil; Thai basil or sweet basil are the usual stand-ins"},{"item":"1 tbsp oyster sauce","note":"thick savoury-sweet brown sauce from oyster extract; world-foods aisle. Mushroom stir-fry sauce for a veggie version"},{"item":"1 tbsp light soy sauce","note":"saltier seasoning soy; ordinary soy sauce is fine"},{"item":"1 tsp dark soy sauce","note":"thicker, sweeter, less salty soy that adds colour; a little extra light soy works in a pinch"},{"item":"1 tsp caster sugar","note":""},{"item":"2 tbsp neutral oil (sunflower or vegetable)","note":""},{"item":"2 eggs, to fry","note":""},{"item":"Steamed jasmine rice, to serve","note":"fragrant Thai long-grain rice; any long-grain rice works"}],"steps":["Fry the eggs in hot oil until the edges are lacy and crisp but the yolks stay soft, then set aside.","Heat a wok until hot, add oil, garlic and chilli and fry 20 seconds until fragrant.","Add the chicken and stir-fry over high heat, breaking it up, until cooked and slightly caramelised, about 4 minutes.","Add both soy sauces, oyster sauce and sugar with a splash of water and toss to glaze.","Kill the heat and fold through the basil until just wilted.","Serve over rice topped with a fried egg."],"pairing":"Ice-cold lager or lime soda","tags":["Spicy","Quick","One-pan","Comfort"],"vegetarian":false,"spicy":true,"calories":620,"protein":38,"carbs":52,"fat":29,"allergens":["Fish","Shellfish","Soy","Gluten","Egg"],"role":"main","cuisineKey":"thai","type":"Curry"},{"id":"th-tofu-veg-stirfry","name":"Tofu and Vegetable Stir-fry with Sweet Chilli","category":"Curries & Stir-fry","course":"Main","meal":"both","tier":"easy","inspiration":"","minutes":25,"serves":2,"level":"Weeknight","idea":"A meat-free workhorse: golden pan-fried tofu and crunchy mixed vegetables in a sweet-chilli and soy glaze. Vegan, fast and endlessly flexible with whatever vegetables are in the drawer.","ingredients":[{"item":"300g firm tofu, cut into cubes","note":"pressed soybean curd; buy the firm or extra-firm block, not silken, so it holds its shape"},{"item":"200g tenderstem broccoli or green beans","note":"tenderstem is a slim long-stemmed broccoli (broccolini); regular broccoli florets also work"},{"item":"1 carrot, sliced","note":""},{"item":"1 red bell pepper, sliced","note":""},{"item":"3 garlic cloves, chopped","note":""},{"item":"3 tbsp sweet chilli sauce","note":"sticky, mild, sweet-and-tangy red dipping sauce; widely sold near the ketchup or world-foods aisle"},{"item":"2 tbsp light soy sauce","note":"saltier seasoning soy; ordinary soy sauce is fine"},{"item":"1 tsp rice vinegar","note":"mild, slightly sweet vinegar made from rice; cider vinegar diluted with a little water works"},{"item":"2 tbsp neutral oil (sunflower or vegetable)","note":""},{"item":"1 tbsp cornflour (cornstarch)","note":"fine white thickening starch; used to coat the tofu and thicken the sauce"}],"steps":["Toss the tofu cubes in the cornflour to coat.","Heat the oil in a wok and fry the tofu until golden on all sides, then lift out.","Add the garlic, broccoli, carrot and pepper and stir-fry 3 to 4 minutes until crisp-tender.","Mix the sweet chilli sauce, soy and vinegar with a splash of water.","Return the tofu, pour over the sauce and toss to glaze for 1 minute.","Serve over rice or noodles."],"pairing":"Steamed rice and cold coconut water","tags":["Vegetarian","Vegan","Quick","One-pan","Gluten-free option","Comfort"],"vegetarian":true,"spicy":false,"calories":390,"protein":18,"carbs":33,"fat":21,"allergens":["Soy","Gluten"],"role":"main","cuisineKey":"thai","type":"Curry"},{"id":"th-massaman-beef","name":"Massaman Beef Curry","category":"Curries & Stir-fry","course":"Main","meal":"dinner","tier":"signature","inspiration":"Nahm (David Thompson)","minutes":150,"serves":4,"level":"Project","idea":"A slow, Muslim-influenced southern curry layered with warm spice, tamarind and roasted peanuts, in the painstaking style David Thompson made famous at Nahm. The long braise melts the beef while cinnamon and cardamom perfume the coconut sauce into something deep and almost stew-like.","ingredients":[{"item":"800g beef shin or chuck, cut into large chunks","note":"shin and chuck are tough, well-marbled cuts that turn meltingly tender with slow cooking; stewing or braising beef is the same idea"},{"item":"400ml full-fat coconut milk (1 tin)","note":"creamy tinned coconut liquid; world-foods aisle"},{"item":"200ml coconut cream","note":"the thicker, richer top fraction of coconut; sold in small tins. Use the firm layer scooped from a chilled tin of coconut milk"},{"item":"4 tbsp massaman curry paste","note":"a mild, warmly spiced Thai-Muslim curry paste with cinnamon and cardamom notes; jars in the world-foods aisle (Mae Ploy, Maesri)"},{"item":"3 tbsp fish sauce (nam pla)","note":"salty fermented-fish seasoning; light soy sauce at a pinch"},{"item":"2 tbsp palm sugar, grated or chopped","note":"unrefined sugar from palm sap, sold as hard discs or soft paste with a caramel flavour; soft light brown sugar is a fine swap"},{"item":"2 tbsp tamarind paste","note":"tangy, dark, sweet-sour pulp from the tamarind pod; jars in the world-foods aisle. Mix lime juice with a little brown sugar if needed"},{"item":"3 waxy potatoes, in chunks","note":"firm salad-type potatoes (Charlotte, new potatoes) that hold their shape; avoid fluffy baking potatoes"},{"item":"1 onion, cut into wedges","note":""},{"item":"80g roasted unsalted peanuts","note":""},{"item":"1 cinnamon stick","note":""},{"item":"3 green cardamom pods, lightly crushed","note":"fragrant green seed pods; crush so the aroma escapes. Leave out if you can't find them"},{"item":"2 bay leaves","note":""}],"steps":["Fry the coconut cream in a heavy pot over medium heat until it splits and the oil surfaces, then add the massaman paste and fry 4 minutes until aromatic.","Add the beef and turn to coat, sealing the surfaces for a few minutes.","Pour in the coconut milk and 300ml water, then add cinnamon, cardamom and bay. Bring to a gentle simmer.","Cover and braise low for 1.5 hours until the beef is starting to turn tender.","Add potatoes, onion and peanuts and cook uncovered another 30 to 40 minutes until potatoes are soft and sauce has thickened.","Season with fish sauce, palm sugar and tamarind, balancing sweet, salty and sour. Rest 10 minutes before serving with rice."],"pairing":"Soft Grenache or a malty amber ale","tags":["Make-ahead","Gluten-free option","Comfort","Crowd-pleaser"],"vegetarian":false,"spicy":false,"calories":720,"protein":48,"carbs":34,"fat":44,"allergens":["Fish","Peanut","Sulphites"],"role":"main","cuisineKey":"thai","type":"Curry"},{"id":"th-green-curry-chicken","name":"Gaeng Keow Wan Gai (Thai Green Chicken Curry)","category":"Curries & Stir-fry","course":"Main","meal":"both","tier":"signature","inspiration":"Nahm (David Thompson)","minutes":40,"serves":4,"level":"Weekend","idea":"The benchmark Thai curry done the Nahm way: a fragrant green paste fried in cracked coconut cream until the fat surfaces, then balanced sweet, salty and hot. Splitting the cream and frying the paste hard is what separates a great version from a muddy, flat one.","ingredients":[{"item":"600g boneless chicken thigh, sliced","note":""},{"item":"400ml full-fat coconut milk (1 tin)","note":"creamy tinned coconut liquid; world-foods aisle"},{"item":"150ml coconut cream, skimmed from the top of a second tin","note":"the thick layer that sets on top of a chilled tin of coconut milk; or buy a small tin of coconut cream"},{"item":"4 tbsp Thai green curry paste","note":"a blended paste of green chilli, lemongrass, galangal and coriander; jars in the world-foods aisle (Mae Ploy, Thai Taste)"},{"item":"2 tbsp fish sauce (nam pla)","note":"salty fermented-fish seasoning; light soy sauce at a pinch"},{"item":"1 tbsp palm sugar, grated","note":"unrefined caramel-flavoured palm sap sugar; soft light brown sugar works"},{"item":"3 makrut lime leaves, torn","note":"aromatic citrus-scented double leaves (kaffir lime); use a strip of lime zest if unavailable"},{"item":"1 large Thai aubergine or 6 pea aubergines, quartered","note":"small round, slightly bitter Thai eggplants; substitute a chunk of ordinary aubergine or a handful of frozen peas"},{"item":"100g bamboo shoots, drained","note":"crunchy pale shoots of young bamboo, sold in tins or pouches; drain and rinse before use"},{"item":"1 long red chilli, sliced","note":"mild-to-medium red chilli, mostly for colour"},{"item":"Large handful Thai basil leaves","note":"aniseed-scented basil with purple stems; sweet basil is a fair substitute"}],"steps":["Heat the coconut cream in a wide pan over medium heat until it bubbles and the oil starts to separate, about 4 minutes.","Add the green curry paste and fry hard in the split cream for 3 to 4 minutes until deeply fragrant and the fat surfaces around the paste.","Add the chicken and stir to coat, cooking 3 minutes until it turns opaque at the edges.","Pour in the coconut milk and 100ml water, then add lime leaves, aubergine and bamboo shoots. Simmer 12 to 15 minutes until chicken is cooked through and aubergine is tender.","Season with fish sauce and palm sugar, tasting for a salty-sweet-hot balance.","Off the heat, stir through Thai basil and scatter sliced chilli. Serve with jasmine rice."],"pairing":"Off-dry Riesling or jasmine rice and a cold Singha beer","tags":["Spicy","One-pan","Gluten-free option","Crowd-pleaser","Comfort"],"vegetarian":false,"spicy":true,"calories":450,"protein":32,"carbs":13,"fat":30,"allergens":["Fish"],"role":"main","cuisineKey":"thai","type":"Curry"},{"id":"th-pad-thai-goong","name":"Pad Thai Goong (Prawn Pad Thai)","category":"Noodles","course":"Main","meal":"both","tier":"easy","inspiration":"","minutes":30,"serves":2,"level":"Weeknight","idea":"The dish everyone knows, done properly: rice noodles tossed in a tamarind-palm sugar sauce until glossy and chewy, with sweet prawns, egg and a crunch of crushed peanuts. A jar of ready-made pad thai sauce makes this even faster on a busy night.","ingredients":[{"item":"180g flat rice noodles, 5mm wide (dried)","note":"thin flat noodles made from rice; soak in warm water until pliable before stir-frying. Sold dried in the world-foods aisle"},{"item":"200g raw prawns, peeled","note":"raw shrimp; use the largest you can get"},{"item":"2 eggs","note":""},{"item":"100g firm tofu, diced","note":"pressed soybean curd; the firm block type, not silken"},{"item":"3 tbsp tamarind paste","note":"tangy sweet-sour tamarind pulp; the signature pad Thai sourness. Lime juice with a little brown sugar in a pinch"},{"item":"2.5 tbsp palm sugar","note":"caramel-flavoured palm sap sugar; soft light brown sugar works"},{"item":"2 tbsp fish sauce (nam pla)","note":"salty fermented-fish seasoning; light soy sauce at a pinch"},{"item":"100g beansprouts","note":"crisp white sprouted mung beans; sold fresh in the salad or world-foods section"},{"item":"3 spring onions, cut into batons","note":"slim green onions (scallions)"},{"item":"40g roasted peanuts, crushed","note":""},{"item":"2 tbsp neutral oil (sunflower or vegetable)","note":""},{"item":"1 lime, cut into wedges","note":""}],"steps":["Soak the rice noodles in warm water for 20 minutes until pliable but not soft, then drain.","Whisk tamarind, palm sugar and fish sauce into a smooth sauce; taste for a sour-sweet-salty balance.","Heat oil in a wok, fry tofu until golden, then add prawns and cook until just pink. Push aside.","Crack in the eggs, scramble lightly, then add the drained noodles and the sauce.","Toss constantly over high heat 2 to 3 minutes until noodles absorb the sauce and turn glossy; add a splash of water if they tighten.","Throw in beansprouts and spring onions, toss briefly, then plate with peanuts and lime."],"pairing":"Crisp Sauvignon Blanc or Thai iced tea","tags":["Quick","Gluten-free option","Crowd-pleaser"],"vegetarian":false,"spicy":false,"calories":620,"protein":33,"carbs":78,"fat":20,"allergens":["Fish","Shellfish","Egg","Soy","Peanut"],"role":"main","cuisineKey":"thai","type":"Noodles & Ramen"},{"id":"th-pad-see-ew","name":"Pad See Ew (Soy-fried Wide Noodles)","category":"Noodles","course":"Main","meal":"both","tier":"easy","inspiration":"","minutes":25,"serves":2,"level":"Weeknight","idea":"Smoky, savoury and comforting: wide rice noodles charred in a hot wok with chicken, egg and Chinese broccoli in a dark-and-light soy glaze. All about wok hei, the elusive breath of the wok.","ingredients":[{"item":"400g fresh wide rice noodles (or 180g dried wide rice noodles, soaked)","note":"broad, flat rice noodles; fresh ones come in a slab you separate, dried ones need soaking until soft. World-foods aisle"},{"item":"250g chicken thigh, sliced","note":""},{"item":"2 eggs","note":""},{"item":"200g Chinese broccoli (gai lan), cut into batons","note":"leafy green with thick stems and a mild bitterness; substitute tenderstem broccoli or chard stems with leaves"},{"item":"3 garlic cloves, chopped","note":""},{"item":"2 tbsp dark soy sauce","note":"thick, sweeter, colour-rich soy; gives the noodles their brown sheen. A little molasses-darkened soy at a pinch"},{"item":"1.5 tbsp light soy sauce","note":"saltier seasoning soy; ordinary soy sauce is fine"},{"item":"1 tbsp oyster sauce","note":"thick savoury-sweet oyster sauce; mushroom stir-fry sauce for a veggie version"},{"item":"1 tsp caster sugar","note":""},{"item":"2.5 tbsp neutral oil (sunflower or vegetable)","note":""},{"item":"White pepper, to finish","note":"milder, earthier than black pepper; black pepper works if that's what you have"}],"steps":["If using fresh noodles, gently separate the strands. Mix both soys, oyster sauce and sugar in a bowl.","Heat a wok until smoking, add oil and garlic, then the chicken, stir-frying until cooked through.","Push to one side, crack in the eggs and scramble lightly.","Add the gai lan stems first, then the leaves, tossing 1 minute until bright green.","Add the noodles and sauce, then leave them to sit against the hot wok for 20 seconds at a time before tossing, to build char and smokiness.","Stir-fry 2 to 3 minutes until noodles are glossy and the edges slightly crisp. Finish with white pepper."],"pairing":"Lager or chrysanthemum tea","tags":["Quick","One-pan","Comfort"],"vegetarian":false,"spicy":false,"calories":640,"protein":33,"carbs":74,"fat":24,"allergens":["Gluten","Fish","Shellfish","Soy","Egg"],"role":"main","cuisineKey":"thai","type":"Noodles & Ramen"},{"id":"th-singapore-noodles","name":"Singapore-style Curry Noodles","category":"Noodles","course":"Main","meal":"both","tier":"easy","inspiration":"","minutes":20,"serves":2,"level":"Weeknight","idea":"Thin rice vermicelli tossed with curry powder, prawns, egg and crunchy vegetables until everything is fragrant and golden. A fast, one-wok dinner that uses pantry curry powder for big flavour with little effort.","ingredients":[{"item":"150g rice vermicelli","note":"very thin rice noodles (rice sticks); soak in hot water to soften. World-foods aisle"},{"item":"150g raw prawns, peeled","note":"raw shrimp"},{"item":"2 eggs, beaten","note":""},{"item":"1 red bell pepper, sliced","note":""},{"item":"2 spring onions, sliced","note":"slim green onions (scallions)"},{"item":"1 carrot, cut into thin matchsticks (julienned)","note":""},{"item":"100g beansprouts","note":"crisp sprouted mung beans; salad or world-foods section"},{"item":"2 tbsp mild curry powder","note":"a yellow blend of turmeric, cumin and coriander; any mild curry powder works"},{"item":"2 tbsp light soy sauce","note":"saltier seasoning soy; ordinary soy sauce is fine"},{"item":"1 tsp caster sugar","note":""},{"item":"2 tbsp neutral oil (sunflower or vegetable)","note":""}],"steps":["Soak the vermicelli in hot water for 4 minutes until soft, then drain well.","Heat the oil in a wok, pour in the beaten egg and scramble, then push to one side.","Add the prawns, pepper and carrot and stir-fry 2 minutes until the prawns turn pink.","Sprinkle in the curry powder and toss 30 seconds until fragrant.","Add the noodles, soy sauce and sugar and toss over high heat until evenly coated and golden.","Stir through the beansprouts and spring onions and serve at once."],"pairing":"Cold lager or iced lemongrass tea","tags":["Quick","One-pan","Gluten-free option","Lunchbox"],"vegetarian":false,"spicy":true,"calories":480,"protein":24,"carbs":58,"fat":17,"allergens":["Shellfish","Egg","Gluten","Soy"],"role":"main","cuisineKey":"thai","type":"Noodles & Ramen"},{"id":"th-pad-woon-sen-veg","name":"Pad Woon Sen (Glass Noodle Stir-fry)","category":"Noodles","course":"Main","meal":"both","tier":"easy","inspiration":"","minutes":20,"serves":2,"level":"Weeknight","idea":"Springy glass noodles stir-fried with egg, mixed vegetables and a light soy seasoning. Naturally meat-free and quick, it is a soothing bowl that even fussy eaters tend to like.","ingredients":[{"item":"120g dried glass (mung bean) noodles","note":"thin translucent noodles made from mung bean starch, also called cellophane or bean-thread noodles; turn clear when soaked. World-foods aisle"},{"item":"2 eggs, beaten","note":""},{"item":"3 garlic cloves, chopped","note":""},{"item":"1 carrot, cut into thin matchsticks (julienned)","note":""},{"item":"100g white cabbage, shredded","note":""},{"item":"3 spring onions, sliced","note":"slim green onions (scallions)"},{"item":"1 tomato, cut into wedges","note":""},{"item":"2 tbsp light soy sauce","note":"saltier seasoning soy; ordinary soy sauce is fine"},{"item":"1 tbsp oyster sauce or vegetarian stir-fry sauce","note":"oyster sauce is a thick savoury-sweet brown sauce; the mushroom-based veggie version is the meat-free swap"},{"item":"1 tsp caster sugar","note":""},{"item":"2 tbsp neutral oil (sunflower or vegetable)","note":""}],"steps":["Soak the glass noodles in warm water for 8 minutes until soft, then drain and snip into shorter lengths.","Heat the oil in a wok, add the garlic, then pour in the egg and scramble lightly.","Add the carrot, cabbage and tomato and stir-fry 2 minutes until softened.","Add the noodles, soy sauce, oyster sauce and sugar with a splash of water.","Toss over high heat until the noodles soak up the sauce and turn glossy.","Stir through the spring onions and serve."],"pairing":"Jasmine tea or a light lager","tags":["Vegetarian","Quick","One-pan","Gluten-free option","Comfort"],"vegetarian":true,"spicy":false,"calories":420,"protein":12,"carbs":60,"fat":15,"allergens":["Egg","Shellfish","Gluten","Soy"],"role":"main","cuisineKey":"thai","type":"Noodles & Ramen"},{"id":"th-khao-soi-gai","name":"Khao Soi Gai (Northern Curry Noodle Soup)","category":"Noodles","course":"Main","meal":"both","tier":"signature","inspiration":"Le Du (Thitid Tassanakajohn)","minutes":60,"serves":4,"level":"Weekend","idea":"Chiang Mai's signature bowl, the dish Andy Ricker built Pok Pok's reputation on: a rich, turmeric-gold coconut curry broth over soft egg noodles, crowned with a tangle of crisp fried noodles, with pickled mustard greens, shallot and lime alongside. Deep, creamy and layered.","ingredients":[{"item":"8 bone-in chicken thighs or drumsticks","note":""},{"item":"500g fresh egg noodles (reserve 100g for frying)","note":"yellow wheat-and-egg noodles; most of the batch is boiled, a handful is fried crisp for the topping. Dried egg noodles also work"},{"item":"400ml full-fat coconut milk (1 tin)","note":"creamy tinned coconut liquid; world-foods aisle"},{"item":"200ml coconut cream","note":"thicker, richer coconut; small tin, or the set top layer of a chilled coconut-milk tin"},{"item":"4 tbsp khao soi paste (or red curry paste plus extra)","note":"a northern Thai curry paste; if you can't find it, use red curry paste with the added turmeric and curry powder below"},{"item":"1 tbsp ground turmeric","note":"earthy yellow spice that gives the broth its golden colour"},{"item":"1 tbsp mild curry powder","note":"a mild yellow spice blend; any will do"},{"item":"3 tbsp fish sauce (nam pla)","note":"salty fermented-fish seasoning; light soy sauce at a pinch"},{"item":"1 tbsp palm sugar","note":"caramel-flavoured palm sap sugar; soft light brown sugar works"},{"item":"600ml chicken stock","note":""},{"item":"Pickled mustard greens, sliced shallot and lime wedges, to serve","note":"pickled mustard greens are tangy preserved leafy greens sold in pouches in the world-foods aisle; a little drained sauerkraut or pickled gherkin gives a similar sour bite"},{"item":"Neutral oil for frying (sunflower or vegetable)","note":""}],"steps":["Fry 100g of the egg noodles in hot oil until golden and crisp, then drain on paper for the topping.","In a pot, fry the coconut cream until split, add the curry paste, turmeric and curry powder, frying 4 minutes until fragrant.","Add the chicken and turn to coat, then pour in the coconut milk and stock.","Simmer gently 30 to 35 minutes until the chicken is tender and the broth is rich and golden.","Season with fish sauce and palm sugar, adjusting to a rounded salty-sweet curry flavour.","Boil the remaining egg noodles until just tender, divide into bowls, ladle over broth and chicken, then top with crispy noodles. Serve with mustard greens, shallot and lime."],"pairing":"Off-dry Gewürztraminer or a wheat beer","tags":["Make-ahead","Comfort","Crowd-pleaser","Spicy"],"vegetarian":false,"spicy":true,"calories":720,"protein":42,"carbs":48,"fat":40,"allergens":["Gluten","Egg","Fish","Mustard"],"role":"main","cuisineKey":"thai","type":"Noodles & Ramen"},{"id":"th-som-tam","name":"Som Tam Thai (Green Papaya Salad)","category":"Salads & Small plates","course":"Starter","meal":"both","tier":"easy","inspiration":"","minutes":20,"serves":2,"level":"Weeknight","idea":"The pounded Isaan classic: crunchy green papaya bruised in a mortar with chilli, garlic, lime, fish sauce and palm sugar, lifted by sweet tomatoes and salty dried shrimp. Fiery, fresh and dangerously addictive. Swap papaya for shredded carrot if it is hard to find.","ingredients":[{"item":"300g green (unripe) papaya, peeled and shredded","note":"hard, crisp unripe papaya used as a vegetable; sold at Asian grocers. Shredded carrot, mooli or firm green cabbage stands in"},{"item":"2 garlic cloves","note":""},{"item":"3 Thai bird's eye chillies","note":"small, very hot chillies; reduce for less heat"},{"item":"8 cherry tomatoes, halved","note":""},{"item":"30g long beans (yardlong beans), in 3cm pieces","note":"extra-long thin green beans; ordinary green beans work fine"},{"item":"2 tbsp fish sauce (nam pla)","note":"salty fermented-fish seasoning; light soy sauce at a pinch"},{"item":"2 tbsp lime juice","note":""},{"item":"1.5 tbsp palm sugar","note":"caramel-flavoured palm sap sugar; soft light brown sugar works"},{"item":"1 tbsp dried shrimp","note":"tiny dried, salted prawns that add savoury depth; sold in bags in the world-foods aisle. Leave out, or use a little extra fish sauce"},{"item":"2 tbsp roasted peanuts","note":""},{"item":"1 tsp tamarind paste","note":"tangy sweet-sour tamarind pulp; lime juice with a pinch of sugar in a pinch"}],"steps":["Pound the garlic and chillies in a large mortar to a coarse paste.","Add palm sugar, fish sauce, lime juice and tamarind, pounding lightly to dissolve the sugar.","Add the long beans and dried shrimp and bruise them gently to release their flavour.","Add the tomatoes and crush just until they weep their juice.","Add the shredded papaya and peanuts, then pound and turn with a spoon so the papaya softens slightly and soaks up the dressing.","Taste for the signature hot-sour-salty-sweet balance and serve immediately, while crunchy."],"pairing":"Sticky rice and grilled chicken, or a cold light lager","tags":["Spicy","Quick","Light","Gluten-free option"],"vegetarian":false,"spicy":true,"calories":160,"protein":6,"carbs":22,"fat":6,"allergens":["Fish","Shellfish","Peanut"],"role":"salad","cuisineKey":"thai","type":"Salads"},{"id":"th-larb-gai","name":"Larb Gai (Isaan Chicken Larb)","category":"Salads & Small plates","course":"Starter","meal":"both","tier":"easy","inspiration":"","minutes":25,"serves":2,"level":"Weeknight","idea":"A warm minced-chicken salad from the northeast, lifted with lime and fish sauce and given a nutty crunch by toasted rice powder, tangled with shallot, mint and coriander. Bright, savoury and intensely herby.","ingredients":[{"item":"300g minced (ground) chicken","note":""},{"item":"2 tbsp uncooked Thai sticky (glutinous) rice, for toasted rice powder","note":"short-grain glutinous rice toasted dry then ground to a nutty powder that thickens the dressing; any raw rice can be toasted and ground if needed"},{"item":"2.5 tbsp lime juice","note":""},{"item":"2 tbsp fish sauce (nam pla)","note":"salty fermented-fish seasoning; light soy sauce at a pinch"},{"item":"1 tsp palm sugar","note":"caramel-flavoured palm sap sugar; soft light brown sugar works"},{"item":"1 tsp roasted chilli flakes (prik bon)","note":"toasted, slightly smoky ground dried Thai chilli; ordinary chilli flakes, lightly toasted in a dry pan, work"},{"item":"2 shallots, thinly sliced","note":"small, mild onions; half a regular onion is fine"},{"item":"3 spring onions, sliced","note":"slim green onions (scallions)"},{"item":"Large handful mint leaves","note":""},{"item":"Large handful coriander (cilantro), chopped","note":""},{"item":"60ml chicken stock or water","note":""}],"steps":["Toast the sticky rice in a dry pan over medium heat until golden brown and fragrant, then grind to a coarse powder in a mortar.","Simmer the chicken in the stock over medium heat, breaking it up, until just cooked through, about 5 minutes; do not let it dry out.","Take off the heat and dress while warm with lime juice, fish sauce, palm sugar and chilli flakes.","Stir through the shallots, spring onions and most of the toasted rice powder.","Fold in the mint and coriander just before serving so they stay fresh.","Taste for a sharp, salty, mildly hot balance and finish with the remaining rice powder. Serve with sticky rice and raw vegetables."],"pairing":"Sticky rice and a crisp Riesling or cold beer","tags":["Spicy","Quick","Light","Gluten-free option"],"vegetarian":false,"spicy":true,"calories":260,"protein":30,"carbs":10,"fat":11,"allergens":["Fish"],"role":"salad","cuisineKey":"thai","type":"Salads"},{"id":"th-thai-cucumber-salad","name":"Thai Cucumber Salad","category":"Salads & Small plates","course":"Starter","meal":"both","tier":"easy","inspiration":"","minutes":15,"serves":2,"level":"Weeknight","idea":"A cooling five-minute side: crisp cucumber and red onion in a sweet-sour lime and chilli dressing, scattered with peanuts and coriander. Mild, refreshing and the perfect foil for anything spicy on the table.","ingredients":[{"item":"1 large cucumber, sliced","note":""},{"item":"1/2 red onion, thinly sliced","note":""},{"item":"2 tbsp lime juice","note":""},{"item":"1 tbsp fish sauce (nam pla)","note":"salty fermented-fish seasoning; light soy sauce at a pinch"},{"item":"1 tbsp caster sugar","note":""},{"item":"1 small red chilli, sliced (optional)","note":""},{"item":"2 tbsp roasted peanuts, crushed","note":""},{"item":"Handful coriander (cilantro), chopped","note":""}],"steps":["Whisk the lime juice, fish sauce and sugar until the sugar dissolves.","Add the chilli to the dressing if using.","Toss the cucumber and red onion in the dressing.","Let it sit 5 minutes so the flavours mingle.","Scatter with peanuts and coriander just before serving."],"pairing":"Anything grilled, or a cold lager","tags":["Quick","Light","Gluten-free option"],"vegetarian":false,"spicy":false,"calories":110,"protein":4,"carbs":13,"fat":5,"allergens":["Fish","Peanut"],"role":"salad","cuisineKey":"thai","type":"Salads"},{"id":"th-spring-rolls","name":"Fresh Vegetable Summer Rolls with Peanut Dip","category":"Salads & Small plates","course":"Starter","meal":"both","tier":"easy","inspiration":"","minutes":30,"serves":2,"level":"Weeknight","idea":"No-cook rice-paper rolls packed with crunchy vegetables, herbs and noodles, served with a creamy peanut dipping sauce. A fun, hands-on plate kids love to help build, and naturally light.","ingredients":[{"item":"8 rice paper wrappers (22cm rounds)","note":"thin, brittle translucent discs of dried rice that turn soft and pliable after a quick dip in warm water; sold in the world-foods aisle as spring roll or summer roll wrappers"},{"item":"60g rice vermicelli","note":"very thin rice noodles; soak in hot water until soft"},{"item":"1 carrot, cut into thin matchsticks (julienned)","note":""},{"item":"1/2 cucumber, cut into thin matchsticks (julienned)","note":""},{"item":"1 small lettuce (Little Gem or butterhead), shredded","note":""},{"item":"Handful mint and coriander (cilantro) leaves","note":""},{"item":"3 tbsp smooth peanut butter","note":"the base of the dip; smooth, not crunchy"},{"item":"1 tbsp soy sauce","note":""},{"item":"1 tbsp lime juice","note":""},{"item":"1 tsp honey","note":""},{"item":"Warm water, to loosen the dip","note":""}],"steps":["Soak the vermicelli in hot water for 4 minutes, drain and cool under cold water.","Whisk the peanut butter, soy, lime juice and honey with warm water until it is a smooth dip.","Dip a rice paper wrapper in warm water for a few seconds until pliable, then lay on a board.","Pile a little of each vegetable, the herbs and noodles in the centre.","Fold in the sides and roll up tightly like a small parcel.","Repeat with the rest and serve with the peanut dip."],"pairing":"Iced green tea or coconut water","tags":["Vegetarian","Light","Quick","Lunchbox","Gluten-free option"],"vegetarian":true,"spicy":false,"calories":340,"protein":11,"carbs":42,"fat":15,"allergens":["Peanut","Soy"],"role":"appetizer","cuisineKey":"thai","type":"Starters"},{"id":"th-tom-yum-goong","name":"Tom Yum Goong (Hot and Sour Prawn Soup)","category":"Salads & Small plates","course":"Starter","meal":"both","tier":"signature","inspiration":"Nahm (David Thompson)","minutes":35,"serves":4,"level":"Weekend","idea":"Thailand's most famous soup, treated with the aromatic precision David Thompson brought to Nahm: a clear, electric broth singing with lemongrass, galangal, makrut lime and chilli, sharpened with lime and rounded out by plump prawns. Aromatic, sour and invigorating.","ingredients":[{"item":"400g raw prawns, peeled, shells reserved","note":"raw shrimp; simmer the reserved shells in the stock for extra flavour"},{"item":"1.2 litres water or light stock","note":""},{"item":"2 lemongrass stalks, bruised and sliced","note":"fibrous, citrus-scented stalks; bash to release the aroma. A strip of lemon zest gives a similar lift if you can't find them"},{"item":"4 slices galangal","note":"a sharp, piney root that looks like ginger but tastes more peppery and citrusy; fresh ginger is the closest swap"},{"item":"5 makrut lime leaves, torn","note":"citrus-scented double leaves (kaffir lime); a strip of lime zest stands in"},{"item":"200g oyster or straw mushrooms, halved","note":"oyster mushrooms are soft, fan-shaped; straw mushrooms come tinned. Chestnut or button mushrooms work"},{"item":"4 Thai bird's eye chillies, bruised","note":"small, very hot chillies; bruise to release heat, reduce for a milder soup"},{"item":"3 tbsp fish sauce (nam pla)","note":"salty fermented-fish seasoning; light soy sauce at a pinch"},{"item":"4 tbsp lime juice","note":""},{"item":"1 tbsp nam prik pao (Thai roasted chilli paste)","note":"a sweet, smoky jarred chilli-in-oil paste; world-foods aisle. A little sweet chilli sauce with a pinch of smoked paprika approximates it"},{"item":"1 tomato, cut into wedges","note":""},{"item":"Handful coriander (cilantro) leaves","note":""}],"steps":["Simmer the prawn shells in the water for 10 minutes to build a quick stock, then strain and return to the pan.","Add lemongrass, galangal, lime leaves and chillies, and simmer 5 minutes to infuse.","Add the mushrooms and tomato and cook 2 minutes until softened.","Add the prawns and cook just until they turn pink, about 2 minutes; do not overcook.","Take off the heat and season with fish sauce, nam prik pao and lime juice, balancing hot, sour and salty.","Scatter with coriander and serve immediately, while fragrant and steaming."],"pairing":"Dry Riesling or chilled jasmine tea","tags":["Spicy","Light","Gluten-free option","Crowd-pleaser"],"vegetarian":false,"spicy":true,"calories":140,"protein":20,"carbs":8,"fat":3,"allergens":["Fish","Shellfish"],"role":"appetizer","cuisineKey":"thai","type":"Starters"},{"id":"th-tod-man-pla","name":"Tod Man Pla (Thai Fish Cakes with Cucumber Relish)","cuisineKey":"thai","category":"Salads & Small plates","role":"appetizer","course":"Starter","meal":"both","tier":"easy","inspiration":"","minutes":35,"serves":4,"level":"Weeknight","idea":"Bouncy red-curry fish cakes flecked with long beans and lime leaf, fried until springy and served with a sweet-sour cucumber relish.","ingredients":[{"item":"400g skinless white fish fillet (cod or pollock), roughly chopped","note":"any firm white fish works; haddock or coley are fine alternatives"},{"item":"2 tbsp Thai red curry paste","note":"blended red chilli, lemongrass and galangal paste; world-foods aisle"},{"item":"1 tbsp fish sauce (nam pla)","note":"salty fermented-fish seasoning; light soy sauce at a pinch"},{"item":"1 egg","note":""},{"item":"60g long beans (yardlong beans), very thinly sliced","note":"extra-long thin green beans; ordinary green beans work fine"},{"item":"4 makrut lime leaves, finely shredded","note":"citrus-scented double leaves (kaffir lime); fine lime zest stands in"},{"item":"1 tsp caster sugar","note":""},{"item":"Neutral oil for shallow frying (sunflower or vegetable)","note":""},{"item":"1 cucumber, quartered lengthways and sliced","note":""},{"item":"3 tbsp rice vinegar","note":"mild, slightly sweet rice vinegar; cider vinegar with a splash of water works"},{"item":"2 tbsp caster sugar (for the relish)","note":""},{"item":"1 small red chilli, sliced","note":""},{"item":"2 tbsp roasted peanuts, crushed","note":""}],"steps":["Blitz the fish, red curry paste, fish sauce, egg and 1 tsp sugar to a sticky paste.","Mix in the long beans and shredded lime leaves by hand.","Wet your hands and shape into 12 small flat patties.","Shallow fry in hot oil for 2 to 3 minutes each side until golden and springy. Drain.","For the relish, warm the rice vinegar with 2 tbsp sugar until dissolved, cool, then add cucumber and chilli.","Serve the fish cakes hot with the relish and a scatter of crushed peanuts."],"pairing":"Steamed jasmine rice or a cold Singha","tags":["seafood","fried","crowd-pleaser","make-ahead"],"vegetarian":false,"spicy":true,"calories":280,"protein":24,"carbs":14,"fat":14,"allergens":["Fish","Egg","Peanut"],"type":"Starters"},{"id":"th-satay-gai","name":"Gai Satay (Grilled Chicken Skewers with Peanut Sauce)","cuisineKey":"thai","category":"Salads & Small plates","role":"appetizer","course":"Starter","meal":"both","tier":"easy","inspiration":"","minutes":45,"serves":4,"level":"Weeknight","idea":"Turmeric-marinated chicken skewers grilled over high heat, served with a glossy peanut sauce and quick cucumber pickle.","ingredients":[{"item":"500g chicken thigh, cut into strips","note":""},{"item":"1 tsp ground turmeric","note":"earthy golden spice that colours the marinade"},{"item":"1 tsp ground coriander","note":""},{"item":"1 tsp ground cumin","note":""},{"item":"100ml full-fat coconut milk (for the marinade)","note":"creamy tinned coconut liquid; world-foods aisle"},{"item":"1 tbsp fish sauce (nam pla)","note":"salty fermented-fish seasoning; light soy sauce at a pinch"},{"item":"1 tbsp soft light brown sugar","note":""},{"item":"3 tbsp smooth peanut butter","note":"the base of the satay sauce; smooth, not crunchy"},{"item":"2 tbsp Thai red curry paste","note":"blended red chilli and aromatics paste; world-foods aisle"},{"item":"150ml full-fat coconut milk (for the sauce)","note":"more of the same tinned coconut milk"},{"item":"1 tbsp tamarind paste","note":"tangy sweet-sour tamarind pulp; lime juice with a pinch of sugar in a pinch"},{"item":"1 tbsp palm sugar","note":"caramel-flavoured palm sap sugar; soft light brown sugar works"},{"item":"8 to 10 bamboo skewers, soaked in water","note":"soak 30 minutes so they don't burn on the grill"}],"steps":["Mix turmeric, coriander, cumin, 100ml coconut milk, fish sauce and brown sugar. Marinate the chicken for at least 30 minutes.","Thread the chicken onto soaked skewers.","For the sauce, gently simmer red curry paste in a little of the 150ml coconut milk, then stir in peanut butter, the rest of the coconut milk, tamarind and palm sugar until glossy.","Grill or griddle the skewers over high heat for 3 to 4 minutes a side until charred and cooked through.","Serve hot with the warm peanut sauce for dipping."],"pairing":"Cucumber relish and steamed rice","tags":["grilled","skewers","kid-friendly","make-ahead"],"vegetarian":false,"spicy":false,"calories":360,"protein":30,"carbs":12,"fat":21,"allergens":["Peanut","Fish"],"type":"Starters"},{"id":"th-miang-kham","name":"Miang Kham (Betel Leaf One-bite Wraps)","cuisineKey":"thai","category":"Salads & Small plates","role":"appetizer","course":"Starter","meal":"both","tier":"signature","inspiration":"Sorn (Supaksorn Jongsiri)","minutes":30,"serves":4,"level":"Weekend","idea":"A do-it-yourself royal Thai snack: each leaf is topped with toasted coconut, ginger, lime, peanuts and a dark palm-sugar tamarind sauce for a single explosive bite.","ingredients":[{"item":"20 wild betel leaves (or baby spinach leaves)","note":"glossy heart-shaped leaves used as edible wrappers (not the same as betel-nut leaves); baby spinach or small lettuce leaves are the easy swap"},{"item":"60g desiccated coconut, toasted","note":"dried shredded coconut, toasted dry until golden and nutty"},{"item":"2 shallots, finely diced","note":"small mild onions; half a regular onion works"},{"item":"2cm fresh ginger, finely diced","note":""},{"item":"1 lime, cut into tiny cubes with skin on","note":"yes, peel and all; the bitter skin is part of the flavour"},{"item":"40g roasted peanuts","note":""},{"item":"2 tbsp dried shrimp","note":"tiny dried salted prawns for savoury depth; world-foods aisle. Leave out for a veggie version"},{"item":"2 red chillies, finely diced","note":""},{"item":"120g palm sugar","note":"caramel-flavoured palm sap sugar that forms the base of the syrupy sauce; soft dark brown sugar is the closest swap"},{"item":"2 tbsp tamarind paste","note":"tangy sweet-sour tamarind pulp; lime juice with extra sugar in a pinch"},{"item":"2 tbsp fish sauce (nam pla)","note":"salty fermented-fish seasoning; light soy sauce at a pinch"},{"item":"1 tbsp toasted desiccated coconut (for the sauce)","note":"a little of the toasted coconut, blended into the sauce for body"}],"steps":["Make the sauce: melt palm sugar with 4 tbsp water, then add tamarind, fish sauce and 1 tbsp toasted coconut. Simmer to a thick pourable syrup and cool.","Arrange the toasted coconut, shallots, ginger, lime cubes, peanuts, dried shrimp and chilli in small piles.","To eat, fold a leaf into a cone, add a pinch of each topping, then a drizzle of the sauce.","Serve as a help-yourself platter so each person builds their own bite."],"pairing":"Chilled jasmine tea","tags":["royal-thai","sharing","no-cook-assembly","gluten-free"],"vegetarian":false,"spicy":true,"calories":190,"protein":5,"carbs":28,"fat":8,"allergens":["Shellfish","Fish","Peanut"],"type":"Starters"},{"id":"th-yam-talay","name":"Yam Talay (Hot and Sour Seafood Salad)","cuisineKey":"thai","category":"Salads & Small plates","role":"salad","course":"Starter","meal":"both","tier":"easy","inspiration":"","minutes":25,"serves":4,"level":"Weeknight","idea":"Poached prawns and squid tossed with celery, tomato and red onion in a punchy lime, fish sauce and chilli dressing.","ingredients":[{"item":"200g raw prawns, peeled","note":"raw shrimp"},{"item":"150g squid, cleaned and sliced into rings","note":"buy cleaned squid tubes and slice across into rings"},{"item":"1 stick Chinese celery, sliced","note":"slimmer, stronger-tasting celery with thin stalks and lots of leaf; ordinary celery with extra leaves works"},{"item":"1 tomato, cut into wedges","note":""},{"item":"1/2 red onion, thinly sliced","note":""},{"item":"3 spring onions, sliced","note":"slim green onions (scallions)"},{"item":"3 tbsp lime juice","note":""},{"item":"2 tbsp fish sauce (nam pla)","note":"salty fermented-fish seasoning; light soy sauce at a pinch"},{"item":"1 tsp caster sugar","note":""},{"item":"2 Thai bird's eye chillies, sliced","note":"small, very hot chillies; reduce for less heat"},{"item":"2 garlic cloves, minced","note":""},{"item":"Handful coriander (cilantro) leaves","note":""}],"steps":["Bring a pan of water to a simmer and poach the prawns and squid for 1 to 2 minutes until just opaque. Drain and cool.","Whisk lime juice, fish sauce, sugar, chilli and garlic into a sharp dressing.","Combine the seafood with celery, tomato, red onion and spring onion.","Pour over the dressing and toss gently.","Finish with coriander and serve at room temperature."],"pairing":"Steamed jasmine rice","tags":["seafood","light","gluten-free","high-protein"],"vegetarian":false,"spicy":true,"calories":170,"protein":24,"carbs":9,"fat":3,"allergens":["Shellfish","Fish"],"type":"Salads"},{"id":"th-yam-woon-sen","name":"Yam Woon Sen (Glass Noodle Salad)","cuisineKey":"thai","category":"Salads & Small plates","role":"salad","course":"Starter","meal":"both","tier":"easy","inspiration":"","minutes":30,"serves":4,"level":"Weeknight","idea":"Slippery glass noodles tossed with minced pork, prawns, tomato and herbs in a bright lime dressing, a Thai lunch-counter classic.","ingredients":[{"item":"80g dried glass (mung bean) noodles","note":"thin translucent bean-thread noodles; turn clear when soaked. World-foods aisle"},{"item":"150g minced (ground) pork","note":""},{"item":"100g raw prawns, peeled","note":"raw shrimp"},{"item":"1 tomato, cut into wedges","note":""},{"item":"1/2 red onion, thinly sliced","note":""},{"item":"3 spring onions, sliced","note":"slim green onions (scallions)"},{"item":"2 tbsp roasted peanuts","note":""},{"item":"3 tbsp lime juice","note":""},{"item":"2 tbsp fish sauce (nam pla)","note":"salty fermented-fish seasoning; light soy sauce at a pinch"},{"item":"1 tsp caster sugar","note":""},{"item":"2 Thai bird's eye chillies, sliced","note":"small, very hot chillies; reduce for less heat"},{"item":"Handful coriander (cilantro), chopped","note":""}],"steps":["Soak the glass noodles in hot water for 5 minutes until soft, drain and cut into shorter lengths.","Poach the minced pork and prawns in simmering water until just cooked, then drain.","Whisk lime juice, fish sauce, sugar and chilli into a dressing.","Toss the noodles, pork, prawns, tomato, red onion and spring onion with the dressing.","Top with peanuts and coriander and serve."],"pairing":"Grilled chicken skewers","tags":["noodle-salad","light","high-protein","make-ahead"],"vegetarian":false,"spicy":true,"calories":250,"protein":20,"carbs":28,"fat":7,"allergens":["Shellfish","Fish","Peanut"],"type":"Salads"},{"id":"th-pomelo-salad","name":"Yam Som-O (Pomelo and Prawn Salad)","cuisineKey":"thai","category":"Salads & Small plates","role":"salad","course":"Starter","meal":"both","tier":"signature","inspiration":"Le Du (Thitid Tassanakajohn)","minutes":35,"serves":4,"level":"Weekend","idea":"Jewel-like pomelo segments with prawns, toasted coconut and crispy shallots in a tamarind-palm sugar dressing, balanced sweet, sour and savoury.","ingredients":[{"item":"1 large pomelo, segmented and broken into pieces","note":"a giant citrus like a mild, sweeter grapefruit with firm flesh that doesn't go soggy; ruby grapefruit is the closest swap"},{"item":"200g raw prawns, peeled","note":"raw shrimp"},{"item":"40g desiccated coconut, toasted","note":"dried shredded coconut toasted until golden"},{"item":"30g roasted peanuts, crushed","note":""},{"item":"2 tbsp crispy fried shallots","note":"golden deep-fried shallot flakes that add crunch; sold in tubs in the world-foods aisle, or fry thinly sliced shallots yourself"},{"item":"2 tbsp tamarind paste","note":"tangy sweet-sour tamarind pulp; lime juice with a pinch of sugar in a pinch"},{"item":"1.5 tbsp palm sugar","note":"caramel-flavoured palm sap sugar; soft light brown sugar works"},{"item":"1.5 tbsp fish sauce (nam pla)","note":"salty fermented-fish seasoning; light soy sauce at a pinch"},{"item":"1 tbsp lime juice","note":""},{"item":"1 red chilli, finely sliced","note":""},{"item":"Handful mint leaves","note":""}],"steps":["Warm the tamarind, palm sugar and fish sauce gently until the sugar dissolves, then cool and add lime juice and chilli.","Poach the prawns in simmering water for 1 to 2 minutes until just opaque, drain and cool.","Gently fold the pomelo, prawns and most of the toasted coconut with the dressing, keeping the segments intact.","Pile onto a plate and top with peanuts, crispy shallots, remaining coconut and mint."],"pairing":"Chilled coconut water","tags":["fruit-salad","seafood","gluten-free","special-occasion"],"vegetarian":false,"spicy":true,"calories":230,"protein":16,"carbs":24,"fat":8,"allergens":["Shellfish","Fish","Peanut"],"type":"Salads"},{"id":"fr-poulet-moutarde","name":"Creamy Mustard Chicken","category":"Bistro mains","course":"Main","meal":"both","tier":"easy","inspiration":"","minutes":30,"serves":4,"level":"Weeknight","idea":"Golden seared chicken thighs simmered in a quick Dijon and creme fraiche sauce, all in one pan. Bistro comfort that lands on the table in the time it takes to boil the kids' pasta.","ingredients":[{"item":"8 boneless chicken thighs, skin on","note":""},{"item":"2 tbsp Dijon mustard","note":"smooth, sharp French mustard; any plain mustard works"},{"item":"1 tbsp wholegrain mustard","note":"mustard with visible whole seeds; sold beside the regular mustard"},{"item":"200 ml creme fraiche or double cream","note":"creme fraiche is a thick, slightly tangy cream; sour cream or heavy cream works"},{"item":"200 ml chicken stock","note":"chicken broth; a stock cube dissolved in hot water is fine"},{"item":"1 onion, finely chopped","note":""},{"item":"2 cloves garlic, crushed","note":""},{"item":"1 tbsp olive oil","note":""},{"item":"2 sprigs fresh thyme","note":"small woody herb; use 1/2 tsp dried thyme instead"},{"item":"Salt and black pepper","note":""}],"steps":["Season the chicken and sear skin-side down in the oil over medium-high heat until deep golden, about 6 minutes, then turn and brown the other side. Lift out.","Soften the onion and garlic in the same pan with the thyme until translucent.","Stir in both mustards and the stock, scraping up the browned bits, then return the chicken skin-side up.","Simmer gently for 12 to 15 minutes until the chicken is cooked through.","Stir the creme fraiche into the sauce, season, and warm through without boiling hard.","Serve with rice, mash or crusty bread to catch the sauce."],"pairing":"A glass of unoaked Chardonnay","tags":["Quick","One-pan","Comfort","Crowd-pleaser","Gluten-free option"],"vegetarian":false,"spicy":false,"calories":520,"protein":34,"carbs":6,"fat":40,"allergens":["Milk","Mustard"],"role":"main","cuisineKey":"french","type":"Mains"},{"id":"fr-poulet-basquaise","name":"Poulet Basquaise","category":"Bistro mains","course":"Main","meal":"both","tier":"easy","inspiration":"","minutes":35,"serves":4,"level":"Weeknight","idea":"Chicken braised with sweet peppers, tomatoes and a whisper of paprika in the sunny Basque style. One pot, common ingredients, and a sauce the whole family scoops up with bread.","ingredients":[{"item":"8 boneless chicken thighs","note":""},{"item":"2 red peppers, sliced","note":"red bell peppers (capsicum)"},{"item":"1 green pepper, sliced","note":"green bell pepper (capsicum)"},{"item":"1 onion, sliced","note":""},{"item":"3 cloves garlic, crushed","note":""},{"item":"400 g tin chopped tomatoes","note":""},{"item":"1 tbsp tomato paste","note":"concentrated tomato puree sold in a tube or small tin"},{"item":"1 tsp sweet paprika","note":"mild ground red pepper spice; not the hot or smoked kind"},{"item":"2 tbsp olive oil","note":""},{"item":"1 bay leaf","note":"dried aromatic leaf; remove before serving"},{"item":"Salt and black pepper","note":""}],"steps":["Season and brown the chicken in the oil over medium-high heat until golden on both sides, then lift out.","Soften the onion, peppers and garlic in the same pan until they begin to colour.","Stir in the tomato paste and paprika for a minute, then add the chopped tomatoes and bay leaf.","Return the chicken, season, and simmer gently for 20 to 25 minutes until cooked through and the sauce has thickened.","Check the seasoning and serve with rice or crusty bread."],"pairing":"A glass of red Irouleguy or a light Rioja","tags":["One-pan","Comfort","Crowd-pleaser","Gluten-free option","Make-ahead"],"vegetarian":false,"spicy":false,"calories":390,"protein":33,"carbs":14,"fat":22,"allergens":[],"role":"main","cuisineKey":"french","type":"Mains"},{"id":"fr-saumon-en-papillote","name":"Salmon en Papillote with Leeks","category":"Bistro mains","course":"Main","meal":"both","tier":"easy","inspiration":"","minutes":30,"serves":4,"level":"Weeknight","idea":"Salmon steamed in paper parcels with leeks, lemon and a splash of white wine. Almost no washing up and nearly impossible to overcook, so it suits a busy night.","ingredients":[{"item":"4 salmon fillets, about 150 g each","note":""},{"item":"2 leeks, finely sliced","note":"long mild onion-family vegetable; use spring onions or a mild onion if unavailable"},{"item":"1 lemon, sliced","note":""},{"item":"4 knobs of butter (about 40 g total)","note":"a knob is roughly 1 tbsp"},{"item":"4 tbsp dry white wine or stock","note":"a crisp non-sweet white wine; chicken or veg stock works without wine"},{"item":"2 sprigs fresh dill or tarragon","note":"delicate aniseed-flavoured herbs; parsley is a milder stand-in"},{"item":"Salt and black pepper","note":""}],"steps":["Heat the oven to 200C. Cut four large squares of baking parchment.","Divide the sliced leeks among the squares and sit a salmon fillet on each.","Top each with lemon slices, a knob of butter, a herb sprig, a tablespoon of wine, salt and pepper.","Fold the parchment into sealed parcels, leaving room for steam.","Bake on a tray for 14 to 16 minutes until the salmon is just cooked.","Open the parcels at the table and serve with new potatoes or rice."],"pairing":"A cool glass of Sancerre","tags":["Quick","Light","Gluten-free option","Date night"],"vegetarian":false,"spicy":false,"calories":380,"protein":31,"carbs":6,"fat":25,"allergens":["Fish","Milk","Sulphites"],"role":"main","cuisineKey":"french","type":"Mains"},{"id":"fr-steak-frites","name":"Steak Frites","category":"Bistro mains","course":"Main","meal":"dinner","tier":"easy","inspiration":"","minutes":35,"serves":2,"level":"Weeknight","idea":"The bistro plate made weeknight-simple: a quick-seared steak with oven-crisp fries and a fast pan sauce built on the steak's own browned juices. No deep-frying, no fuss.","ingredients":[{"item":"2 sirloin steaks, about 200 g each","note":"tender cut from the back; ribeye or rump also work"},{"item":"600 g floury potatoes (Maris Piper or Russet), cut into chips","note":"a starchy frying potato; avoid waxy or new potatoes for crisp chips"},{"item":"2 tbsp olive oil","note":""},{"item":"20 g butter","note":""},{"item":"1 shallot, finely chopped","note":"small mild-sweet onion; use 1/4 regular onion if needed"},{"item":"100 ml beef stock","note":"beef broth; a stock cube in hot water is fine"},{"item":"1 tsp Dijon mustard","note":"smooth, sharp French mustard; any plain mustard works"},{"item":"1 tbsp chopped fresh parsley","note":""},{"item":"Salt and black pepper","note":""}],"steps":["Heat the oven to 220C. Toss the chips with 1 tbsp oil and salt, spread on a tray and bake for 25 to 30 minutes, turning once, until crisp and golden.","Pat the steaks dry and season well. Sear in the remaining oil over high heat for 2 to 3 minutes per side for medium-rare, then rest on a board.","In the same pan soften the shallot in the butter, add the stock and mustard, and simmer until lightly thickened. Stir in any resting juices and the parsley.","Slice the steaks, spoon over the sauce and serve with the fries and a green salad."],"pairing":"A bold Cotes du Rhone rouge","tags":["Comfort","Date night","Gluten-free option"],"vegetarian":false,"spicy":false,"calories":780,"protein":48,"carbs":52,"fat":42,"allergens":["Milk","Mustard"],"role":"main","cuisineKey":"french","type":"Mains"},{"id":"fr-coq-au-vin","name":"Coq au Vin","category":"Bistro mains","course":"Main","meal":"dinner","tier":"signature","inspiration":"Bouchon (Thomas Keller)","minutes":120,"serves":4,"level":"Project","idea":"Chicken braised slowly in red wine with lardons, mushrooms and pearl onions until the sauce turns deep, glossy and silky. The Lyonnais standard codified by Paul Bocuse, rewarding patience and tasting even better the next day.","ingredients":[{"item":"1 large chicken, about 1.8 kg, jointed into 8 pieces","note":"cut into legs, thighs, wings and breast halves; ask the butcher to joint it"},{"item":"750 ml red Burgundy or Pinot Noir","note":"a light dry red wine; any dry red works"},{"item":"150 g smoked lardons or thick smoked bacon, diced","note":"lardons are small strips of fatty bacon; chopped smoked streaky bacon is the same thing"},{"item":"250 g button mushrooms, halved","note":"small white mushrooms"},{"item":"200 g pearl onions, peeled","note":"tiny round onions; use frozen pearl or baby onions, or quartered shallots"},{"item":"2 tbsp plain flour","note":"all-purpose flour"},{"item":"3 cloves garlic, crushed","note":""},{"item":"2 bay leaves and 4 sprigs fresh thyme","note":"aromatic herbs; use 1 tsp dried thyme for the sprigs"},{"item":"400 ml chicken stock","note":"chicken broth; a stock cube in hot water is fine"},{"item":"40 g unsalted butter","note":""},{"item":"2 tbsp olive oil","note":""},{"item":"Salt and black pepper","note":""}],"steps":["Marinate the chicken in the wine with the herbs and garlic for at least 4 hours, ideally overnight. Drain, reserving the wine, and pat the pieces dry.","Render the lardons in a casserole until crisp, then set aside. Brown the chicken in the rendered fat plus a little oil on all sides until deeply coloured, working in batches.","Dust the chicken with flour, return the lardons, then pour in the reserved wine and stock. Add the herbs, season, and braise gently, covered, for about 1 hour until the meat is tender and pulling from the bone.","Meanwhile, brown the pearl onions and mushrooms in the butter until golden, then add them to the pot for the final 20 minutes.","Lift out the chicken and vegetables, reduce the sauce until it coats the back of a spoon, and check the seasoning.","Return everything to the sauce to warm through and serve with mashed potato or buttered noodles."],"pairing":"The same red Burgundy used in the braise","tags":["Make-ahead","Comfort","Crowd-pleaser","Date night"],"vegetarian":false,"spicy":false,"calories":680,"protein":48,"carbs":16,"fat":42,"allergens":["Gluten","Milk","Sulphites"],"role":"main","cuisineKey":"french","type":"Mains"},{"id":"fr-boeuf-bourguignon","name":"Boeuf Bourguignon","category":"Bistro mains","course":"Main","meal":"dinner","tier":"signature","inspiration":"Alain Ducasse","minutes":180,"serves":4,"level":"Project","idea":"Beef braised for hours in red wine with bacon, mushrooms and onions until the meat collapses at a fork and the sauce glosses like lacquer. The dish Julia Child called the finest beef stew known to man, all about deep browning and slow time.","ingredients":[{"item":"1.2 kg beef chuck or shin, cut into 4 cm cubes","note":"cheaper stewing cuts that turn tender when slow-cooked; any braising or stewing beef works"},{"item":"750 ml red Burgundy or other dry red wine","note":"a dry red wine; any non-sweet red works"},{"item":"150 g smoked lardons, diced","note":"small strips of fatty smoked bacon; chopped smoked streaky bacon works"},{"item":"250 g chestnut mushrooms, quartered","note":"brown cap mushrooms; white button mushrooms are fine"},{"item":"200 g pearl onions, peeled","note":"tiny round onions; use frozen baby onions or quartered shallots"},{"item":"2 carrots, cut into chunks","note":""},{"item":"3 cloves garlic, crushed","note":""},{"item":"2 tbsp tomato paste","note":"concentrated tomato puree from a tube or small tin"},{"item":"2 tbsp plain flour","note":"all-purpose flour"},{"item":"500 ml beef stock","note":"beef broth; a stock cube in hot water is fine"},{"item":"Bouquet garni of thyme, parsley and bay","note":"a small bundle of herbs tied with string; remove before serving"},{"item":"40 g butter and 2 tbsp oil","note":""},{"item":"Salt and black pepper","note":""}],"steps":["Pat the beef very dry, season, and brown hard in batches in the oil until each piece is dark on all sides. Remove and reserve.","Render the lardons, soften the carrots, then stir in the tomato paste and flour and cook for a minute.","Deglaze with the wine, scraping the base clean, then return the beef with the stock, garlic and bouquet garni. Bring to a bare simmer.","Cover and braise in a 150C oven for about 2.5 hours until the beef is fork-tender.","Brown the pearl onions and mushrooms in the butter, then fold them in for the last 30 minutes.","Skim any fat, reduce the sauce on the hob if it is loose, adjust the seasoning, and serve with mash or boiled potatoes."],"pairing":"A structured Cote de Beaune or Cotes du Rhone","tags":["Make-ahead","Comfort","Crowd-pleaser","Date night"],"vegetarian":false,"spicy":false,"calories":720,"protein":62,"carbs":20,"fat":40,"allergens":["Gluten","Milk","Sulphites"],"role":"main","cuisineKey":"french","type":"Mains"},{"id":"fr-omelette-fines-herbes","name":"Omelette aux Fines Herbes","category":"Brasserie classics","course":"All-day","meal":"both","tier":"easy","inspiration":"","minutes":15,"serves":1,"level":"Weeknight","idea":"The pure French omelette: eggs beaten with fresh herbs, cooked fast in butter and rolled while still creamy inside. A five-minute lunch that feels like a treat.","ingredients":[{"item":"3 eggs","note":""},{"item":"1 tbsp chopped fresh chives","note":"thin green onion-family herb with a mild oniony taste"},{"item":"1 tbsp chopped fresh parsley","note":""},{"item":"1 tsp chopped fresh tarragon, optional","note":"herb with a gentle aniseed flavour; just leave out if unavailable"},{"item":"15 g unsalted butter","note":""},{"item":"Salt and black pepper","note":""}],"steps":["Beat the eggs with the herbs, salt and pepper until just combined.","Melt the butter in a non-stick pan over medium-high heat until foaming.","Pour in the eggs and stir briskly with a fork for a few seconds, then let the base set.","Tilt the pan and fold the omelette over itself into a neat roll.","Slide onto a plate, seam-side down, and serve at once with a green salad or bread."],"pairing":"A light glass of Chablis","tags":["Quick","Vegetarian","Light","Gluten-free option"],"vegetarian":true,"spicy":false,"calories":340,"protein":19,"carbs":2,"fat":29,"allergens":["Egg","Milk"],"role":"main","cuisineKey":"french","type":"Mains"},{"id":"fr-salade-nicoise","name":"Salade Nicoise","category":"Brasserie classics","course":"Main","meal":"both","tier":"easy","inspiration":"","minutes":25,"serves":4,"level":"Weeknight","idea":"A composed Provencal salad of tuna, green beans, eggs, olives and tomatoes over leaves in a sharp mustard vinaigrette. Bright, mostly no-cook, and it travels well to a lunchbox.","ingredients":[{"item":"2 tins good tuna in olive oil (about 320 g total), drained","note":""},{"item":"4 eggs","note":""},{"item":"200 g green beans, trimmed","note":"also sold as French or fine beans"},{"item":"400 g new potatoes","note":"small waxy potatoes that hold their shape; baby or salad potatoes work"},{"item":"250 g cherry tomatoes, halved","note":""},{"item":"100 g black olives","note":"Nicoise or Kalamata olives are traditional; any black olive is fine"},{"item":"1 tin anchovies in oil, optional","note":"small salty cured fish fillets; simply leave out if you prefer"},{"item":"Mixed salad leaves (about 100 g)","note":""},{"item":"5 tbsp olive oil","note":""},{"item":"2 tbsp red wine vinegar","note":"tangy vinegar made from red wine; white wine vinegar works"},{"item":"1 tsp Dijon mustard","note":"smooth, sharp French mustard; any plain mustard works"},{"item":"Salt and black pepper","note":""}],"steps":["Boil the potatoes until tender, adding the green beans for the last 4 minutes, then drain and cool.","Soft-boil the eggs for 7 minutes, cool under cold water, peel and halve.","Whisk the oil, vinegar, mustard, salt and pepper into a dressing.","Arrange the leaves, potatoes, beans, tomatoes and olives on a platter.","Flake over the tuna and add the eggs and anchovies if using.","Spoon over the dressing just before serving."],"pairing":"A chilled Provence rose","tags":["Light","Gluten-free option","Make-ahead","Lunchbox"],"vegetarian":false,"spicy":false,"calories":420,"protein":24,"carbs":22,"fat":27,"allergens":["Egg","Fish","Mustard","Sulphites"],"role":"salad","cuisineKey":"french","type":"Salads"},{"id":"fr-croque-monsieur","name":"Croque Monsieur","category":"Brasserie classics","course":"All-day","meal":"both","tier":"easy","inspiration":"","minutes":30,"serves":2,"level":"Weeknight","idea":"The grown-up French toasted sandwich: ham and Gruyere bound by a nutmeg-scented bechamel, capped with more cheese and grilled until bubbling and blistered. Rich, savoury and built for a cafe lunch.","ingredients":[{"item":"4 thick slices good white bread (sourdough or pain de mie)","note":"pain de mie is a soft white sandwich loaf; any sturdy white bread works"},{"item":"150 g cooked ham, sliced","note":""},{"item":"120 g Gruyere, grated","note":"firm, nutty Swiss-style melting cheese; Emmental or a strong Cheddar substitutes"},{"item":"250 ml whole milk","note":"full-fat milk"},{"item":"25 g unsalted butter, plus extra for the bread","note":""},{"item":"25 g plain flour","note":"all-purpose flour"},{"item":"1 tsp Dijon mustard","note":"smooth, sharp French mustard; any plain mustard works"},{"item":"1 pinch freshly grated nutmeg","note":"warm sweet spice; pre-ground nutmeg is fine"},{"item":"Salt and white pepper","note":"white pepper is milder-looking ground pepper; black pepper is fine"}],"steps":["Make a bechamel: melt the butter, stir in the flour and cook for a minute, then whisk in the milk gradually until thick and smooth. Season with nutmeg, salt and white pepper, then beat in the Dijon and a third of the cheese.","Lightly butter the bread on the outside. Spread a little bechamel on the inside of two slices, layer with the ham, and close the sandwiches.","Toast in a dry pan over medium heat until golden on both sides.","Transfer to a tray, spoon the remaining bechamel over the tops, and scatter with the rest of the Gruyere.","Grill under a hot broiler for 3 to 4 minutes until the cheese is molten and blistered.","Serve hot with a sharp green salad."],"pairing":"A green salad in mustard vinaigrette","tags":["Quick","Comfort"],"vegetarian":false,"spicy":false,"calories":620,"protein":31,"carbs":38,"fat":38,"allergens":["Gluten","Milk","Mustard"],"role":"main","cuisineKey":"french","type":"Mains"},{"id":"fr-moules-mariniere","name":"Moules Mariniere","category":"Brasserie classics","course":"Main","meal":"both","tier":"easy","inspiration":"","minutes":30,"serves":2,"level":"Weeknight","idea":"Mussels steamed open in white wine, shallots and parsley with a knob of butter to round the broth. A ten-minute brasserie staple that lives or dies on truly fresh mussels and good bread to mop up.","ingredients":[{"item":"2 kg fresh mussels, scrubbed and debearded","note":"debearding means pulling off the stringy tuft on the shell; discard any that stay open when tapped"},{"item":"250 ml dry white wine such as Muscadet","note":"a crisp non-sweet white; any dry white works"},{"item":"3 shallots, finely chopped","note":"small mild-sweet onions; use 1 small onion instead"},{"item":"3 cloves garlic, finely chopped","note":""},{"item":"50 g unsalted butter","note":""},{"item":"1 large handful flat-leaf parsley, chopped","note":"flat Italian-style parsley; curly parsley is fine"},{"item":"2 tbsp creme fraiche, optional","note":"thick, slightly tangy cream; sour cream or a splash of double cream works"},{"item":"1 bay leaf","note":"dried aromatic leaf; remove before serving"},{"item":"Black pepper","note":""},{"item":"1 crusty baguette, to serve","note":"a long thin French loaf"}],"steps":["Tap any open mussels and discard those that do not close, along with any with cracked shells.","In a large deep pot, melt the butter and sweat the shallots and garlic with the bay leaf until soft but not coloured.","Pour in the wine and bring to a rolling boil, then tip in the mussels and clamp on the lid.","Steam for 3 to 4 minutes, shaking the pot once or twice, until the shells have opened. Discard any that stay firmly shut.","Stir through the parsley and the creme fraiche if using, and grind over black pepper.","Serve immediately in deep bowls with the broth poured over and the baguette alongside."],"pairing":"A crisp Muscadet sur lie","tags":["Quick","Date night","Light"],"vegetarian":false,"spicy":false,"calories":620,"protein":42,"carbs":34,"fat":28,"allergens":["Gluten","Milk","Shellfish","Sulphites"],"role":"main","cuisineKey":"french","type":"Mains"},{"id":"fr-quiche-poireaux","name":"Leek and Gruyere Quiche","category":"Brasserie classics","course":"All-day","meal":"both","tier":"easy","inspiration":"","minutes":75,"serves":6,"level":"Weekend","idea":"A buttery pastry shell filled with sweet softened leeks and a silky custard of eggs, cream and Gruyere. A meat-free brasserie staple, just as good warm from the oven or cold in a lunchbox the next day.","ingredients":[{"item":"320 g shortcrust pastry (1 ready-rolled sheet)","note":"plain savoury pie crust; sold chilled or frozen, ready-rolled saves time"},{"item":"3 leeks, sliced","note":"long mild onion-family vegetable; use a mild onion if needed"},{"item":"25 g butter","note":""},{"item":"3 eggs plus 1 egg yolk","note":""},{"item":"300 ml double cream","note":"heavy or thick pouring cream (about 48% fat)"},{"item":"100 ml whole milk","note":"full-fat milk"},{"item":"100 g Gruyere, grated","note":"firm, nutty Swiss-style melting cheese; Emmental or Cheddar substitutes"},{"item":"1 pinch grated nutmeg","note":"warm sweet spice; pre-ground is fine"},{"item":"Salt and black pepper","note":""}],"steps":["Line a 23 cm tart tin with the pastry, prick the base, and blind bake at 190C for 15 minutes with baking beans, then 5 minutes more uncovered.","Soften the leeks gently in the butter with a pinch of salt until sweet and collapsed, about 10 minutes, then cool slightly and scatter over the base with the cheese.","Whisk the eggs, yolk, cream, milk, nutmeg, salt and pepper.","Pour the custard into the shell.","Bake at 170C for 30 to 35 minutes until just set with a slight wobble.","Cool for 10 minutes before slicing, or chill and serve cold."],"pairing":"A glass of Alsace Pinot Blanc","tags":["Make-ahead","Lunchbox","Comfort","Crowd-pleaser","Vegetarian"],"vegetarian":true,"spicy":false,"calories":520,"protein":13,"carbs":26,"fat":40,"allergens":["Gluten","Milk","Egg"],"role":"main","cuisineKey":"french","type":"Mains"},{"id":"fr-soupe-oignon","name":"Soupe a l'Oignon Gratinee","category":"Brasserie classics","course":"Starter","meal":"both","tier":"signature","inspiration":"Le Cirque","minutes":75,"serves":4,"level":"Weekend","idea":"Onions caramelised low and slow into a sweet, mahogany base, deglazed with wine and crowned with a raft of toasted baguette under a blanket of melted Gruyere. The gratineed onion soup codified by Auguste Escoffier in Le Guide Culinaire, done properly.","ingredients":[{"item":"1 kg onions, thinly sliced","note":""},{"item":"50 g unsalted butter","note":""},{"item":"1 tbsp olive oil","note":""},{"item":"1 tsp sugar","note":""},{"item":"150 ml dry white wine","note":"a non-sweet white; extra stock works without wine"},{"item":"1.2 litres beef stock","note":"beef broth; stock cubes in hot water are fine"},{"item":"2 cloves garlic, crushed","note":""},{"item":"2 sprigs fresh thyme","note":"small woody herb; 1/2 tsp dried thyme works"},{"item":"1 tbsp plain flour","note":"all-purpose flour"},{"item":"1 baguette, sliced","note":"a long thin French loaf, for the cheesy croutons on top"},{"item":"200 g Gruyere, grated","note":"firm, nutty melting cheese; Emmental or Cheddar substitutes"},{"item":"Salt and black pepper","note":""}],"steps":["Melt the butter with the oil in a heavy pot, add the onions, sugar and a pinch of salt, and cook over low heat, stirring often, for 35 to 45 minutes until deep brown and jammy.","Stir in the garlic, thyme and flour and cook for 2 minutes.","Deglaze with the wine and reduce briefly, then pour in the stock and simmer gently for 20 minutes. Season well.","Toast the baguette slices until dry and crisp.","Ladle the soup into ovenproof bowls, float the toasts on top, and pile on the Gruyere.","Grill under a hot broiler until the cheese is bubbling and golden, then serve at once with care, as the bowls are very hot."],"pairing":"A glass of dry white such as Aligote","tags":["Make-ahead","Comfort","Crowd-pleaser"],"vegetarian":false,"spicy":false,"calories":480,"protein":19,"carbs":42,"fat":25,"allergens":["Gluten","Milk","Sulphites"],"role":"main","cuisineKey":"french","type":"Mains"},{"id":"fr-creme-brulee","name":"Creme Brulee","category":"Desserts","course":"Dessert","meal":"both","tier":"signature","inspiration":"Le Cirque","minutes":60,"serves":4,"level":"Weekend","idea":"Silky vanilla custard set just to a tremble, finished with a thin sheet of bitter caramel you crack with a spoon. The textbook contrast of cool cream against hot, brittle sugar, perfected in the kitchens of Joel Robuchon.","ingredients":[{"item":"500 ml double cream","note":"heavy or thick pouring cream (about 48% fat)"},{"item":"1 vanilla pod, split and seeds scraped","note":"a real vanilla bean; use 1 tsp vanilla extract or paste instead"},{"item":"5 egg yolks","note":""},{"item":"75 g caster sugar, plus 4 tsp for the tops","note":"fine white sugar; blitz granulated sugar briefly if you only have that"},{"item":"1 pinch fine salt","note":""}],"steps":["Heat the cream gently with the vanilla pod and seeds until steaming, then take off the heat and infuse for 15 minutes.","Whisk the yolks with the 75 g sugar and salt until pale, then slowly pour in the warm cream, whisking constantly, and strain.","Divide among four ramekins set in a deep tray and pour boiling water halfway up their sides.","Bake at 150C for 30 to 35 minutes until just set with a faint wobble in the centre.","Cool, then chill for at least 3 hours.","Sprinkle each with a teaspoon of caster sugar and torch or grill until the top forms an even amber crust; rest a minute before serving."],"pairing":"A small glass of Sauternes","tags":["Make-ahead","Date night","Gluten-free option","Vegetarian"],"vegetarian":true,"spicy":false,"calories":520,"protein":5,"carbs":28,"fat":43,"allergens":["Milk","Egg"],"role":"dessert","cuisineKey":"french","type":"Desserts"},{"id":"fr-mousse-chocolat","name":"Chocolate Mousse","category":"Desserts","course":"Dessert","meal":"both","tier":"easy","inspiration":"","minutes":20,"serves":4,"level":"Weeknight","idea":"Dark chocolate folded into airy whipped egg whites for a classic French mousse that needs no special kit, just a bowl and a whisk. Make it after lunch and it is set by pudding time.","ingredients":[{"item":"200 g dark chocolate (about 70% cocoa), chopped","note":""},{"item":"4 eggs, separated","note":"yolks and whites kept apart"},{"item":"30 g caster sugar","note":"fine white sugar; granulated works"},{"item":"1 pinch salt","note":""},{"item":"1 tsp vanilla extract","note":""}],"steps":["Melt the chocolate gently in a bowl over barely simmering water, then let it cool slightly.","Beat the egg yolks with the vanilla and stir into the warm chocolate.","Whisk the egg whites with the salt to soft peaks, then add the sugar and whisk to glossy peaks.","Fold a spoonful of whites into the chocolate to loosen it, then fold in the rest gently.","Spoon into glasses and chill for at least 2 hours before serving."],"pairing":"A small espresso or a glass of Banyuls","tags":["Make-ahead","Vegetarian","Gluten-free option","Date night"],"vegetarian":true,"spicy":false,"calories":340,"protein":7,"carbs":28,"fat":22,"allergens":["Milk","Egg"],"role":"dessert","cuisineKey":"french","type":"Desserts"},{"id":"fr-clafoutis-cerises","name":"Cherry Clafoutis","category":"Desserts","course":"Dessert","meal":"both","tier":"easy","inspiration":"","minutes":45,"serves":6,"level":"Weeknight","idea":"Cherries baked in a simple vanilla batter somewhere between a flan and a pancake. A rustic Limousin pudding you whisk in one bowl and pour over the fruit.","ingredients":[{"item":"500 g cherries, stoned, or a 400 g tin, drained","note":"stoned means pits removed; frozen cherries (thawed) also work"},{"item":"3 eggs","note":""},{"item":"100 g caster sugar","note":"fine white sugar; granulated works"},{"item":"80 g plain flour","note":"all-purpose flour"},{"item":"300 ml whole milk","note":"full-fat milk"},{"item":"1 tsp vanilla extract","note":""},{"item":"25 g butter, melted","note":""},{"item":"1 pinch salt","note":""},{"item":"Icing sugar, to dust","note":"powdered or confectioners' sugar"}],"steps":["Heat the oven to 180C and butter a baking dish.","Scatter the cherries evenly across the dish.","Whisk the eggs, sugar, flour, milk, vanilla, melted butter and salt into a smooth batter.","Pour the batter over the cherries.","Bake for 30 to 35 minutes until puffed, set and golden.","Cool slightly, dust with icing sugar and serve warm."],"pairing":"A glass of chilled Cremant","tags":["Make-ahead","Vegetarian","Comfort","Crowd-pleaser"],"vegetarian":true,"spicy":false,"calories":250,"protein":6,"carbs":38,"fat":8,"allergens":["Gluten","Milk","Egg"],"role":"dessert","cuisineKey":"french","type":"Desserts"},{"id":"fr-tarte-tatin","name":"Tarte Tatin","category":"Desserts","course":"Dessert","meal":"both","tier":"easy","inspiration":"","minutes":75,"serves":6,"level":"Weekend","idea":"Apples caramelised in butter and sugar, baked under pastry and flipped to reveal a glossy, burnished top. The famous upside-down tart from the Tatin sisters, best served just warm with cream.","ingredients":[{"item":"8 firm apples such as Braeburn, peeled, halved and cored","note":"use a firm eating apple that holds its shape; Gala or Pink Lady also work"},{"item":"150 g caster sugar","note":"fine white sugar; granulated works for the caramel"},{"item":"80 g unsalted butter","note":""},{"item":"320 g all-butter puff pastry (1 ready-rolled sheet)","note":"flaky layered pastry; ready-rolled saves time"},{"item":"1 tsp lemon juice","note":""},{"item":"1 pinch fine salt","note":""},{"item":"Creme fraiche or vanilla ice cream, to serve","note":"creme fraiche is a thick, slightly tangy cream"}],"steps":["Toss the apples with the lemon juice. In an ovenproof frying pan, melt the sugar with a splash of water and cook to a medium amber caramel, then stir in the butter and salt.","Arrange the apple halves tightly, cut-side up, in the caramel and cook over medium heat for about 15 minutes until they soften and the caramel deepens.","Roll the pastry to a circle slightly larger than the pan, lay it over the apples and tuck the edges down inside.","Bake at 200C for 25 to 30 minutes until the pastry is puffed and deep golden.","Rest for 5 minutes, then confidently invert onto a plate larger than the pan, holding both firmly.","Serve warm with creme fraiche or vanilla ice cream."],"pairing":"A chilled glass of Coteaux du Layon","tags":["Crowd-pleaser","Comfort","Vegetarian"],"vegetarian":true,"spicy":false,"calories":420,"protein":3,"carbs":58,"fat":20,"allergens":["Gluten","Milk"],"role":"dessert","cuisineKey":"french","type":"Desserts"},{"id":"fr-poulet-roti","name":"Poulet Roti (Roast Chicken with Pan Jus)","cuisineKey":"french","category":"Bistro mains","course":"Main","meal":"dinner","tier":"signature","inspiration":"Joel Robuchon","minutes":80,"serves":4,"level":"Weekend","idea":"Keller calls his salt-and-truss roast chicken his favourite thing to eat. It is the ultimate achievable signature for a busy parent and a clean, honest attribution, far more weeknight-realistic than the brisket that currently represents the heavier end.","ingredients":[{"item":"1 whole chicken, about 1.6 kg","note":""},{"item":"1 tbsp fine sea salt","note":""},{"item":"1 tsp black pepper","note":""},{"item":"2 sprigs fresh thyme","note":"small woody herb; 1/2 tsp dried thyme works"},{"item":"1 tbsp Dijon mustard","note":"smooth, sharp French mustard; any plain mustard works"},{"item":"150 ml dry white wine","note":"a non-sweet white; extra stock works without wine"},{"item":"150 ml chicken stock","note":"chicken broth; a stock cube in hot water is fine"},{"item":"1 tbsp butter","note":""}],"steps":["Heat oven to 220C. Pat the chicken bone-dry inside and out, then season generously all over with the salt and pepper.","Truss the legs with kitchen string and set breast-up in a roasting pan with the thyme.","Roast 50-60 minutes until the juices run clear and a thigh reads 74C internal.","Rest the chicken on a board 10 minutes; brush the skin lightly with Dijon.","Place the pan over a burner, pour in the wine and stock, scrape up the browned bits and reduce by half. Whisk in the butter.","Carve and serve with the pan jus."],"pairing":"Roast potatoes and a green salad; a glass of Chardonnay","tags":["crowd-pleaser","one-pan","leftovers"],"vegetarian":false,"spicy":false,"calories":480,"protein":42,"carbs":2,"fat":33,"allergens":["Milk","Mustard","Sulphites"],"role":"main","type":"Mains"},{"id":"fr-salade-lyonnaise","name":"Salade Lyonnaise","cuisineKey":"french","category":"Brasserie classics","role":"salad","course":"Starter","meal":"both","tier":"easy","inspiration":"","minutes":25,"serves":4,"level":"Weeknight","idea":"The classic Lyon bistro salad of frisee with crisp lardons, a soft poached egg and a warm sharp mustard dressing.","ingredients":[{"item":"2 heads frisee or curly endive, torn","note":"a frilly, slightly bitter salad leaf; substitute escarole or crunchy romaine"},{"item":"200 g smoked lardons or thick smoked bacon, diced","note":"small strips of fatty smoked bacon; chopped smoked streaky bacon is the same"},{"item":"4 eggs","note":"for poaching to top the salad"},{"item":"1 small shallot, finely chopped","note":"small mild-sweet onion; use 1/4 regular onion"},{"item":"2 tbsp red wine vinegar","note":"tangy red-wine vinegar; white wine vinegar works"},{"item":"1 tbsp Dijon mustard","note":"smooth, sharp French mustard; any plain mustard works"},{"item":"4 tbsp olive oil","note":""},{"item":"2 slices day-old bread, cubed for croutons","note":"slightly stale bread crisps up best"},{"item":"Salt and black pepper","note":""}],"steps":["Wash and dry the frisee and pile into a large bowl.","Fry the lardons in a dry pan until crisp, then lift out, leaving the fat behind.","Toss the bread cubes in the fat until golden, then drain.","In the same pan soften the shallot, then whisk in the mustard, vinegar and olive oil with a splash of water to make a warm dressing.","Poach the eggs in barely simmering water with a little vinegar for 3 minutes until the white is set and yolk runny.","Toss the frisee with the warm dressing, lardons and croutons, divide between plates and top each with a poached egg and a grind of pepper."],"pairing":"A glass of cold Beaujolais","tags":["bistro","egg","bacon","classic"],"vegetarian":false,"spicy":false,"calories":380,"protein":18,"carbs":12,"fat":29,"allergens":["Egg","Gluten","Mustard","Sulphites"],"type":"Salads"},{"id":"fr-salade-chevre-chaud","name":"Salade de Chevre Chaud","cuisineKey":"french","category":"Brasserie classics","role":"salad","course":"Starter","meal":"both","tier":"easy","inspiration":"","minutes":20,"serves":4,"level":"Weeknight","idea":"Warm goat cheese toasts over dressed leaves with walnuts and honey, a bistro lunch staple.","ingredients":[{"item":"150 g mixed salad leaves","note":""},{"item":"2 logs soft goat cheese (about 200 g), cut into 8 rounds","note":"chevre, a soft tangy white cheese; use a firmer goat cheese so it holds when warmed"},{"item":"8 thin slices baguette","note":"a long thin French loaf, toasted under the cheese"},{"item":"2 tbsp clear honey","note":"runny honey"},{"item":"50 g walnuts, roughly chopped","note":""},{"item":"2 tbsp red wine vinegar","note":"tangy red-wine vinegar; white wine vinegar works"},{"item":"1 tsp Dijon mustard","note":"smooth, sharp French mustard; any plain mustard works"},{"item":"5 tbsp olive oil","note":""},{"item":"Salt and black pepper","note":""}],"steps":["Heat the grill to high.","Lay the baguette slices on a tray, top each with a round of goat cheese and drizzle with a little honey.","Grill for 3 to 4 minutes until the cheese is soft and golden.","Whisk the vinegar, mustard, olive oil, salt and pepper into a dressing.","Toast the walnuts briefly in a dry pan.","Toss the leaves with the dressing, divide between plates, scatter with walnuts and top each with two warm goat cheese toasts."],"pairing":"A chilled Sancerre or dry rose","tags":["goat cheese","walnut","honey"],"vegetarian":true,"spicy":false,"calories":420,"protein":14,"carbs":24,"fat":30,"allergens":["Milk","Gluten","Tree nuts","Mustard","Sulphites"],"type":"Salads"},{"id":"fr-celeri-remoulade","name":"Celeri Remoulade","cuisineKey":"french","category":"Brasserie classics","role":"salad","course":"Starter","meal":"both","tier":"easy","inspiration":"","minutes":15,"serves":4,"level":"Weeknight","idea":"Crisp matchsticks of celeriac in a sharp mustard mayonnaise, the quintessential French deli salad.","ingredients":[{"item":"1 celeriac, about 600 g, peeled","note":"a knobbly root vegetable that tastes of mild celery; sold near the celery and root veg"},{"item":"3 tbsp mayonnaise","note":""},{"item":"1 tbsp creme fraiche","note":"thick, slightly tangy cream; sour cream works"},{"item":"2 tbsp Dijon mustard","note":"smooth, sharp French mustard; any plain mustard works"},{"item":"1 tbsp lemon juice","note":""},{"item":"1 tbsp chopped fresh parsley","note":""},{"item":"1 tsp capers, chopped","note":"small pickled flower buds with a salty-tangy taste; sold by the olives and pickles"},{"item":"Salt and black pepper","note":""}],"steps":["Cut the celeriac into fine matchsticks or coarsely grate it.","Toss immediately with the lemon juice to stop it browning.","Whisk the mayonnaise, creme fraiche, mustard, salt and pepper into a smooth dressing.","Fold the dressing through the celeriac with the capers until well coated.","Chill for 10 minutes, then stir through the parsley and check the seasoning before serving."],"pairing":"Cured ham and crusty bread","tags":["celeriac","mustard","deli","make-ahead"],"vegetarian":true,"spicy":false,"calories":190,"protein":3,"carbs":10,"fat":15,"allergens":["Egg","Milk","Mustard","Sulphites"],"type":"Salads"},{"id":"fr-rillettes-porc","name":"Pork Rillettes with Cornichons","cuisineKey":"french","category":"Brasserie classics","role":"appetizer","course":"Starter","meal":"both","tier":"easy","inspiration":"","minutes":35,"serves":6,"level":"Weekend","idea":"Slow-cooked shredded pork potted under its own fat, spread thick on toast with sharp cornichons.","ingredients":[{"item":"600 g pork shoulder, cubed","note":"a fatty, flavourful cut ideal for slow cooking"},{"item":"150 g pork fat or lardons","note":"diced pork back fat, or fatty smoked bacon strips"},{"item":"2 cloves garlic, crushed","note":""},{"item":"2 sprigs fresh thyme","note":"small woody herb; 1/2 tsp dried thyme works"},{"item":"1 bay leaf","note":"dried aromatic leaf; remove before shredding"},{"item":"150 ml white wine","note":"a non-sweet white; stock works without wine"},{"item":"100 ml water","note":""},{"item":"Cornichons and toasted baguette, to serve","note":"cornichons are tiny tangy French gherkins; baby dill pickles work"},{"item":"Salt and black pepper","note":""}],"steps":["Put the pork, fat, garlic, herbs, wine and water in a heavy pan and season well.","Cover and cook very gently for 3 hours until the meat falls apart, topping up with water if needed.","Lift out the meat and shred finely with two forks, discarding the herbs.","Beat in enough of the strained cooking fat to make a soft, spreadable paste and check the seasoning.","Press into ramekins, smooth the tops and seal with a thin layer of melted fat.","Chill until firm and serve with cornichons and toasted baguette."],"pairing":"A crisp dry Chenin Blanc","tags":["charcuterie","pork","make-ahead","potted"],"vegetarian":false,"spicy":false,"calories":340,"protein":18,"carbs":6,"fat":27,"allergens":["Gluten","Sulphites"],"type":"Starters"},{"id":"fr-gougeres","name":"Gougeres au Gruyere","cuisineKey":"french","category":"Brasserie classics","role":"appetizer","course":"Starter","meal":"both","tier":"easy","inspiration":"","minutes":40,"serves":6,"level":"Weekend","idea":"Light Burgundian cheese puffs of choux pastry baked until golden, the perfect aperitif bite.","ingredients":[{"item":"120 ml water","note":""},{"item":"120 ml whole milk","note":"full-fat milk"},{"item":"100 g unsalted butter","note":""},{"item":"140 g plain flour","note":"all-purpose flour"},{"item":"4 eggs","note":""},{"item":"120 g Gruyere, grated","note":"firm, nutty Swiss-style cheese; Comte or a strong Cheddar substitutes"},{"item":"1 pinch grated nutmeg","note":"warm sweet spice; pre-ground is fine"},{"item":"Salt and black pepper","note":""}],"steps":["Heat the oven to 200 C and line two trays with baking paper.","Bring the water, milk, butter and salt to the boil, then beat in the flour off the heat until it forms a smooth ball.","Cook the dough for a minute to dry it slightly, then cool for 5 minutes.","Beat in the eggs one at a time until glossy, then fold in most of the Gruyere and the nutmeg.","Pipe or spoon walnut-sized mounds onto the trays and top with the remaining cheese.","Bake for 22 to 25 minutes until puffed, golden and crisp, and serve warm."],"pairing":"A glass of Champagne or cremant","tags":["choux","cheese","aperitif","party"],"vegetarian":true,"spicy":false,"calories":260,"protein":10,"carbs":15,"fat":18,"allergens":["Gluten","Milk","Egg"],"type":"Starters"},{"id":"fr-tartare-saumon","name":"Salmon Tartare with Creme Fraiche","cuisineKey":"french","category":"Brasserie classics","role":"appetizer","course":"Starter","meal":"both","tier":"easy","inspiration":"","minutes":20,"serves":4,"level":"Weeknight","idea":"Hand-cut fresh salmon dressed with shallot, chives, lemon and creme fraiche, served on toasts.","ingredients":[{"item":"400 g very fresh skinless salmon fillet (sushi or sashimi grade)","note":"must be very fresh as it is served raw; ask for sashimi-grade fish"},{"item":"1 small shallot, finely chopped","note":"small mild-sweet onion; use 1/4 regular onion"},{"item":"2 tbsp chopped fresh chives","note":"thin green herb with a mild oniony taste"},{"item":"2 tbsp creme fraiche","note":"thick, slightly tangy cream; sour cream works"},{"item":"1 tbsp lemon juice","note":""},{"item":"1 tsp Dijon mustard","note":"smooth, sharp French mustard; any plain mustard works"},{"item":"1 tbsp olive oil","note":""},{"item":"Toasted baguette or blinis, to serve","note":"blinis are small soft pancakes, sold near the smoked salmon"},{"item":"Salt and black pepper","note":""}],"steps":["Chill the salmon, then cut it into small even dice with a sharp knife.","Gently mix the salmon with the shallot, chives, lemon juice, mustard and olive oil.","Fold in the creme fraiche and season carefully with salt and pepper.","Taste and adjust the lemon and salt, keeping the mixture loose.","Spoon into ring moulds or simply mound onto plates and serve cold with toasts or blinis."],"pairing":"A cold glass of Chablis","tags":["salmon","raw","fresh","elegant"],"vegetarian":false,"spicy":false,"calories":240,"protein":21,"carbs":4,"fat":15,"allergens":["Fish","Milk","Mustard"],"type":"Starters"},{"id":"fr-blanquette-veau","name":"Blanquette de Veau","cuisineKey":"french","category":"Bistro mains","role":"main","course":"Main","meal":"dinner","tier":"signature","inspiration":"Joel Robuchon","minutes":120,"serves":4,"level":"Project","idea":"A gentle white veal stew in a velvety cream and egg-enriched sauce with mushrooms and pearl onions.","ingredients":[{"item":"1 kg veal shoulder, cut into 4 cm cubes","note":"meat from a young calf, mild and tender; turkey or pork shoulder can substitute"},{"item":"2 carrots, cut into chunks","note":""},{"item":"1 onion studded with 2 cloves","note":"whole cloves (the spice) pushed into the onion for flavour; remove before serving"},{"item":"1 leek, sliced","note":"long mild onion-family vegetable"},{"item":"250 g button mushrooms","note":"small white mushrooms"},{"item":"200 g pearl onions, peeled","note":"tiny round onions; frozen baby onions or quartered shallots work"},{"item":"40 g butter","note":""},{"item":"40 g plain flour","note":"all-purpose flour"},{"item":"2 egg yolks","note":""},{"item":"150 ml double cream","note":"heavy or thick pouring cream"},{"item":"1 tbsp lemon juice","note":""},{"item":"Bouquet garni of thyme, parsley and bay","note":"a small herb bundle tied with string; remove before serving"},{"item":"Salt and white pepper","note":"white pepper keeps the sauce pale; black pepper is fine"}],"steps":["Put the veal in a pot, cover with cold water, bring to the boil and skim off the foam.","Add the carrots, clove-studded onion, leek and bouquet garni, then simmer gently for 90 minutes until tender.","Meanwhile sweat the pearl onions and mushrooms in a little butter until soft.","Strain the veal, reserving 600 ml of the broth, and discard the aromatics.","Make a roux with the butter and flour, whisk in the hot broth and simmer to a smooth veloute.","Beat the egg yolks with the cream and lemon, temper in some hot sauce, then return off the heat.","Fold the veal, mushrooms and pearl onions into the sauce, warm through without boiling and serve with rice."],"pairing":"Steamed white rice and a white Burgundy","tags":["veal","stew","creamy","classic"],"vegetarian":false,"spicy":false,"calories":620,"protein":48,"carbs":18,"fat":40,"allergens":["Milk","Egg","Gluten","Sulphites"],"type":"Mains"},{"id":"fr-croque-madame","name":"Croque Madame","cuisineKey":"french","category":"Brasserie classics","role":"main","course":"Main","meal":"both","tier":"easy","inspiration":"","minutes":25,"serves":2,"level":"Weeknight","idea":"The croque monsieur crowned with a fried egg, a satisfying brasserie lunch in its own right.","ingredients":[{"item":"4 thick slices good white bread (sourdough or pain de mie)","note":"pain de mie is a soft white sandwich loaf; any sturdy white bread works"},{"item":"150 g cooked ham, sliced","note":""},{"item":"120 g Gruyere, grated","note":"firm, nutty Swiss-style melting cheese; Emmental or Cheddar substitutes"},{"item":"2 eggs","note":"fried, to sit on top (this is what makes it a madame)"},{"item":"250 ml whole milk","note":"full-fat milk"},{"item":"25 g butter, plus extra for frying","note":""},{"item":"25 g plain flour","note":"all-purpose flour"},{"item":"1 tsp Dijon mustard","note":"smooth, sharp French mustard; any plain mustard works"},{"item":"1 pinch grated nutmeg","note":"warm sweet spice; pre-ground is fine"},{"item":"Salt and white pepper","note":"milder-looking ground pepper; black pepper is fine"}],"steps":["Make a thick bechamel by melting the butter, stirring in the flour and whisking in the milk until smooth and glossy.","Season the sauce with mustard, nutmeg, salt and pepper and stir in half the Gruyere.","Butter the bread, layer with ham and a little sauce, then close into sandwiches.","Top each with sauce and the rest of the Gruyere and grill until bubbling and golden.","Fry the eggs in a little butter until the whites are set, then sit one on each sandwich and serve hot."],"pairing":"A green salad and a glass of cider","tags":["sandwich","ham","cheese","egg"],"vegetarian":false,"spicy":false,"calories":640,"protein":33,"carbs":40,"fat":38,"allergens":["Gluten","Milk","Egg","Mustard"],"type":"Mains"},{"id":"fr-ratatouille","name":"Ratatouille Nicoise","cuisineKey":"french","category":"Bistro mains","role":"main","course":"Main","meal":"both","tier":"easy","inspiration":"","minutes":60,"serves":4,"level":"Weeknight","idea":"A Provencal stew of aubergine, courgette and peppers slow-cooked in tomato and herbs, hearty enough as a vegetarian main.","ingredients":[{"item":"1 large aubergine, cubed","note":"also called eggplant"},{"item":"2 courgettes, sliced","note":"also called zucchini"},{"item":"1 red pepper, chopped","note":"red bell pepper (capsicum)"},{"item":"1 yellow pepper, chopped","note":"yellow bell pepper (capsicum)"},{"item":"1 onion, chopped","note":""},{"item":"3 cloves garlic, sliced","note":""},{"item":"400 g tin chopped tomatoes","note":""},{"item":"2 tbsp tomato paste","note":"concentrated tomato puree from a tube or small tin"},{"item":"5 tbsp olive oil","note":""},{"item":"1 sprig fresh rosemary","note":"woody, pine-scented herb; use 1/2 tsp dried"},{"item":"2 sprigs fresh thyme","note":"small woody herb; use 1/2 tsp dried"},{"item":"1 handful fresh basil, torn","note":""},{"item":"Salt and black pepper","note":""}],"steps":["Fry the aubergine in olive oil until golden, then set aside.","Brown the courgettes and peppers in batches and add to the aubergine.","Soften the onion and garlic in the same pan, then stir in the tomato paste.","Add the chopped tomatoes, rosemary and thyme and simmer for 10 minutes.","Return all the vegetables, season and cook gently for 25 minutes until thick and tender.","Stir through the basil and serve warm with crusty bread or rice."],"pairing":"Crusty baguette and a Provence rose","tags":["provencal","vegetable","stew"],"vegetarian":true,"spicy":false,"calories":260,"protein":5,"carbs":24,"fat":17,"allergens":["Sulphites"],"type":"Mains"}]};
  var DISHES = GM.dishes, CUISINES = GM.cuisines, TYPES = GM.types;
  var DAYS = ["Monday","Tuesday","Wednesday","Thursday","Friday","Saturday","Sunday"];

  var CZ = {}; CUISINES.forEach(function(c){ CZ[c.key]=c; });
  function czName(key){ var c=CZ[key]; return c?c.short:key; }
  function czHue(key){ var c=CZ[key]; return (c&&c.hue)||"#cda85f"; }
  function esc(s){ return String(s==null?"":s).replace(/&/g,"&amp;").replace(/</g,"&lt;").replace(/>/g,"&gt;"); }
  function pad(n){ return n<10?("0"+n):(""+n); }

  /* ---------------- allergens ---------------- */
  var ALLERGENS=["Gluten","Milk","Egg","Fish","Shellfish","Soy","Sesame","Peanut","Tree nuts","Mustard","Sulphites"];
  var PRESENT_ALLERGENS=(function(){ var s={}; DISHES.forEach(function(d){ (d.allergens||[]).forEach(function(a){ s[a]=1; }); }); return ALLERGENS.filter(function(a){ return s[a]; }); })();

  // ingredients may be plain strings or { item, note } (note = a plain-English explanation shown under the item)
  function ingText(x){ return (x&&typeof x==="object")?(x.item||""):(""+x); }
  function ingNote(x){ return (x&&typeof x==="object"&&x.note)?x.note:""; }
  function ingLi(x){ var n=ingNote(x); return '<li><span class="ing-it">'+esc(ingText(x))+'</span>'+(n?'<span class="ing-note">'+esc(n)+'</span>':"")+'</li>'; }

  /* ---------------- preferences (localStorage) ---------------- */
  var PKEY="chloe_grownmeals_v1";
  function defaults(){ return { cuisine:"all", category:"all", veg:false, quick:false, avoid:[], favorites:[] }; }
  function loadPrefs(){ try{ var p=JSON.parse(localStorage.getItem(PKEY)); var d=defaults(); for(var k in p){ d[k]=p[k]; } return d; }catch(e){ return defaults(); } }
  function savePrefs(){ try{ localStorage.setItem(PKEY, JSON.stringify(prefs)); }catch(e){} }
  var prefs = loadPrefs();

  /* ---------------- icons ---------------- */
  var IC_ARROW='<svg viewBox="0 0 24 24" aria-hidden="true"><path d="M4 11h13.2l-4.6-4.6L14 5l7 7-7 7-1.4-1.4 4.6-4.6H4z"/></svg>';
  var IC_BASKET='<svg viewBox="0 0 24 24" aria-hidden="true"><path d="M7 4 5.2 8H2v2h1.1l1.6 9h14.6l1.6-9H22V8h-3.2L17 4h-2.2l1.6 4H7.6L9.2 4zM6 12h12l-1 5H7z"/></svg>';
  var IC_HEART='<svg viewBox="0 0 24 24" aria-hidden="true"><path d="M12 21s-8-5.3-8-11a4.5 4.5 0 0 1 8-2.8A4.5 4.5 0 0 1 20 10c0 5.7-8 11-8 11z"/></svg>';
  var IC_GLASS='<svg viewBox="0 0 24 24" aria-hidden="true"><path d="M6 3h12l-1.2 6.6A5 5 0 0 1 13 13.4V19h3v2H8v-2h3v-5.6A5 5 0 0 1 7.2 9.6L6 3z"/></svg>';

  /* ---------------- filtering ---------------- */
  function categoriesFor(){
    if(prefs.cuisine==="all") return TYPES;
    var c=CZ[prefs.cuisine]; return c?c.cats:[];
  }
  // base filters (cuisine, diet, allergies) that apply to EVERY course, including starters
  function passesBase(d){
    if(prefs.cuisine!=="all" && d.cuisineKey!==prefs.cuisine) return false;
    if(prefs.veg && !d.vegetarian) return false;
    if(prefs.quick && d.minutes>30) return false;
    if(prefs.avoid && prefs.avoid.length){    // allergens removed first, so an allergy never slips through
      var al=d.allergens||[];
      for(var i=0;i<prefs.avoid.length;i++){ if(al.indexOf(prefs.avoid[i])>-1) return false; }
    }
    return true;
  }
  // the cuisine/type chip filters the MAINS by dish type; it does not touch starters
  function passesCategory(d){
    if(prefs.category==="all") return true;
    if(prefs.cuisine==="all") return d.type===prefs.category;
    return d.category===prefs.category;
  }
  function dishMatches(d){ return passesBase(d) && passesCategory(d); }   // used by the full-menu grid
  function pool(){ return DISHES.filter(dishMatches); }
  function rot(arr,n,start){ var out=[]; for(var i=0;i<n && arr.length;i++){ out.push(arr[((start+i)%arr.length+arr.length)%arr.length]); } return out; }
  function uniq(arr){ var seen={}, out=[]; arr.forEach(function(m){ if(m&&!seen[m.id]){ seen[m.id]=1; out.push(m); } }); return out; }
  function tierOf(d){ return d.tier==="signature"?"signature":"easy"; }   // default missing tier to easy
  function mealOf(d){ return (d.meal==="lunch"||d.meal==="dinner")?d.meal:"both"; }
  function roleOf(d){ var r=d.role; return (r==="appetizer"||r==="salad"||r==="dessert")?r:"main"; }

  // MAINS for a slot: proper main courses only, two easy then one signature, rotated by day.
  // A per-slot seed shifts dinner off lunch so the two trios differ.
  function mainsTrio(slot, dayIdx){
    function mains(catFilter){ return DISHES.filter(function(d){ return roleOf(d)==="main" && passesBase(d) && (!catFilter||passesCategory(d)) && (mealOf(d)===slot||mealOf(d)==="both"); }); }
    var p=mains(true); if(p.length<3) p=mains(false);   // ease the type filter if it thins the slot
    var seed=(slot==="dinner")?1:0;
    var easy=p.filter(function(d){ return tierOf(d)==="easy"; });
    var sig =p.filter(function(d){ return tierOf(d)==="signature"; });
    var picks=uniq(rot(easy,2,dayIdx*2+seed*5).concat(rot(sig,1,dayIdx+seed*2)));
    if(picks.length<3) picks=uniq(picks.concat(rot(p,3,dayIdx*3+seed)));
    return picks.slice(0,3);
  }
  // STARTERS for a slot: one appetizer + one salad from the cuisine (the type chip never applies here)
  function startersFor(slot, dayIdx){
    var seed=(slot==="dinner")?3:0;
    var app=DISHES.filter(function(d){ return roleOf(d)==="appetizer" && passesBase(d); });
    var sal=DISHES.filter(function(d){ return roleOf(d)==="salad" && passesBase(d); });
    return uniq(rot(app,1,dayIdx+seed).concat(rot(sal,1,dayIdx+seed)));
  }

  /* ---------------- favourites ---------------- */
  function isFav(id){ return prefs.favorites.indexOf(id)>-1; }
  function toggleFav(id){ var i=prefs.favorites.indexOf(id); if(i>-1) prefs.favorites.splice(i,1); else prefs.favorites.push(id); savePrefs(); }

  /* ---------------- shared bits ---------------- */
  function tagsHtml(d){
    var out=[], shown={};
    if(d.tags.indexOf("Vegan")>-1){ out.push('<span class="gm-tag veg">Vegan</span>'); shown.Vegan=shown.Vegetarian=1; }
    else if(d.vegetarian){ out.push('<span class="gm-tag veg">Vegetarian</span>'); shown.Vegetarian=1; }
    if(d.spicy){ out.push('<span class="gm-tag spicy">Spicy</span>'); shown.Spicy=1; }
    d.tags.forEach(function(t){ if(out.length>=4) return; if(shown[t]||t==="Vegetarian"||t==="Vegan"||t==="Spicy") return; shown[t]=1; out.push('<span class="gm-tag">'+esc(t)+'</span>'); });
    return out.join("");
  }
  function metaRow(d){
    return '<div class="gm-meta">'+
      '<span class="cz"><span class="cdot"></span>'+esc(czName(d.cuisineKey))+'</span>'+
      '<span class="sep"></span><span>'+esc(d.category)+'</span>'+
      '<span class="sep"></span><span>'+d.minutes+' min</span>'+
      '<span class="sep"></span><span>Serves '+d.serves+'</span>'+
      (typeof d.calories==="number"?'<span class="sep"></span><span>'+d.calories+' kcal</span>':'')+
      '<span class="sep"></span><span>'+esc(d.level)+'</span>'+
    '</div>';
  }
  // calories + macros block and the allergen line, shown in the recipe (only when data is present)
  function nutriBlock(d){
    if(typeof d.calories!=="number") return "";
    function macro(v,l){ return '<div class="gm-macro"><span class="mv">'+v+'<i>g</i></span><span class="ml">'+l+'</span></div>'; }
    return '<div class="gm-nutri">'+
      '<div class="gm-kcal"><span class="kv">'+d.calories+'</span><span class="kl">kcal<br>per serving</span></div>'+
      '<div class="gm-macros">'+macro(d.protein,"Protein")+macro(d.carbs,"Carbs")+macro(d.fat,"Fat")+'</div>'+
    '</div>';
  }
  function allergenLine(d){
    if(!d.allergens) return "";
    if(!d.allergens.length) return '<div class="gm-allerg none"><span class="al-k">Allergens</span> none of the common 11</div>';
    return '<div class="gm-allerg"><span class="al-k">Contains</span>'+d.allergens.map(function(a){ return '<span class="gm-alg">'+esc(a)+'</span>'; }).join("")+'</div>';
  }

  /* ---------------- overlay (dark, focus-trapped) ---------------- */
  function overlay(kicker, heading, innerHtml){
    var opener=document.activeElement;
    var ov=el('<div class="gm-ov" role="dialog" aria-modal="true" aria-label="'+esc(heading)+'">'+
      '<div class="gm-panel"><button class="x" aria-label="Close">&times;</button>'+
      (kicker?'<span class="gm-kick">'+esc(kicker)+'</span>':'')+
      '<h3 class="gm-display">'+esc(heading)+'</h3>'+innerHtml+'</div></div>');
    function close(){ document.removeEventListener("keydown",onKey); window.removeEventListener("hashchange",close); ov.remove(); try{ opener&&opener.focus&&opener.focus(); }catch(e){} }
    function onKey(e){
      if(e.key==="Escape"||e.key==="Esc"){ close(); return; }
      if(e.key==="Tab"){
        var f=[].slice.call(ov.querySelectorAll("button")); if(!f.length) return;
        e.preventDefault(); var ci=f.indexOf(document.activeElement);
        var ni=e.shiftKey?(ci<=0?f.length-1:ci-1):((ci<0||ci>=f.length-1)?0:ci+1); try{ f[ni].focus(); }catch(_e){}
      }
    }
    ov.querySelector(".x").addEventListener("click",close);
    ov.addEventListener("click",function(e){ if(e.target===ov) close(); });
    document.addEventListener("keydown",onKey); window.addEventListener("hashchange",close);
    document.body.appendChild(ov); try{ ov.querySelector(".x").focus(); }catch(e){}
    return { ov:ov, close:close };
  }

  // the full recipe: idea, ingredients with quantities, method, pairing, then the shopping list
  function recipeDetail(d){
    var ing=d.ingredients.map(ingLi).join("");
    var steps=d.steps.map(function(x){ return '<li>'+esc(x)+'</li>'; }).join("");
    var html=
      '<div class="gm-tierline">'+roleBadge(d)+tierBadge(d)+inspLine(d)+'</div>'+
      metaRow(d)+
      '<p class="gm-pidea">'+esc(d.idea)+'</p>'+
      nutriBlock(d)+
      allergenLine(d)+
      '<div class="gm-sec"><h4>Ingredients · serves '+d.serves+'</h4><ul class="gm-ing">'+ing+'</ul></div>'+
      '<div class="gm-sec"><h4>Method</h4><ol class="gm-steps">'+steps+'</ol></div>'+
      '<div class="gm-pair"><span class="pic">'+IC_GLASS+'</span><span><span class="pt">Pairing</span><span class="pv">'+esc(d.pairing)+'</span></span></div>'+
      '<div class="gm-tags">'+tagsHtml(d)+'</div>'+
      '<div class="gm-panel-acts">'+
        '<button class="gm-btn gm-shop-btn">'+IC_BASKET+' Shopping list</button>'+
        '<button class="gm-btn ghost gm-fav-btn'+(isFav(d.id)?" on":"")+'">'+IC_HEART+' '+(isFav(d.id)?"Saved":"Save it")+'</button>'+
      '</div>';
    var o=overlay(czName(d.cuisineKey)+" · "+d.category, d.name, html);
    o.ov.querySelector(".gm-panel").style.setProperty("--cz", czHue(d.cuisineKey));
    o.ov.querySelector(".gm-shop-btn").addEventListener("click",function(){ o.close(); shoppingFor(d.name, [d]); });
    var fb=o.ov.querySelector(".gm-fav-btn");
    fb.addEventListener("click",function(){ toggleFav(d.id); var on=isFav(d.id); fb.classList.toggle("on",on); fb.innerHTML=IC_HEART+" "+(on?"Saved":"Save it"); });
  }

  /* ---------------- shopping list (by aisle) ---------------- */
  var AISLES=[
    {k:"Pantry & dry goods", w:["flour","tipo 00","rice","arborio","carnaroli","pasta","spaghetti","tonnarelli","penne","linguine","noodle","udon","ramen","soba","vermicelli","tortilla","taco","bread","brioche","bun","panko","breadcrumb","oil","vinegar","soy","tamari","mirin","sake","dashi","miso","stock","broth","wine","passata","tinned","canned","coconut milk","chickpea","lentil","sugar","honey","maple","syrup","chocolate","vanilla","yeast","semolina","polenta","cornflour","cornstarch","baking","gelatin","fish sauce","oyster sauce","hoisin","tahini","tamarind","curry paste","nori","sesame oil","tomato puree","tomato paste","sun-dried","jaggery","palm sugar","ketchup","mustard","mayonnaise","worcestershire","stock cube","capers","olives"]},
    {k:"Meat, fish & deli", w:["chicken","beef","pork","lamb","veal","mince","guanciale","pancetta","bacon","sausage","chorizo","prosciutto","salami","steak","brisket","short rib","salmon","tuna","prawn","shrimp","squid","calamari","cod","haddock","sea bass","seabass","fish fillet","anchov","sardine","mackerel","scallop","mussel","clam","duck","turkey","ham"]},
    {k:"Dairy & eggs", w:["whole milk","milk","double cream","single cream","cream","butter","cheese","parmigiano","parmesan","pecorino","mozzarella","fior di latte","ricotta","mascarpone","burrata","yogurt","yoghurt","egg","ghee","paneer","feta","halloumi","creme fraiche","crème fraîche","buttermilk","gruyere","cheddar"]},
    {k:"Herbs, spices & aromatics", w:["garlic","ginger","chilli","chili","jalapeno","jalapeño","serrano","chipotle","cumin","coriander seed","ground coriander","turmeric","paprika","oregano","basil","thyme","rosemary","parsley","cilantro","fresh coriander","mint","bay leaf","cinnamon","cardamom","clove","saffron","peppercorn","black pepper","white pepper","nutmeg","lemongrass","kaffir","lime leaf","star anise","fennel seed","fenugreek","mustard seed","garam masala","curry powder","sesame seed","za'atar","sumac","dukkah","spring onion","scallion","shallot","galangal","dried","salt","sea salt","seasoning"]},
    {k:"Fresh produce", w:["tomato","onion","potato","carrot","celery","pepper","capsicum","bell pepper","mushroom","spinach","lettuce","cucumber","courgette","zucchini","aubergine","eggplant","lemon","lime","apple","pear","avocado","cabbage","broccoli","cauliflower","leek","corn","sweetcorn","bean sprout","beansprout","pea","edamame","radish","beetroot","squash","pumpkin","kale","rocket","arugula","watercress","coriander","fennel","asparagus","green bean","okra","plantain","banana","berries","strawberr","mango","herbs"]}
  ];
  function aisleOf(line){
    var s=line.toLowerCase();
    for(var a=0;a<AISLES.length;a++){ for(var i=0;i<AISLES[a].w.length;i++){ if(s.indexOf(AISLES[a].w[i])>-1) return AISLES[a].k; } }
    return "Other";
  }
  function shoppingFor(title, dishes){
    var by={}, seen={};
    dishes.forEach(function(d){ d.ingredients.forEach(function(ingRaw){
      var ing=ingText(ingRaw);
      var key=ing.toLowerCase().trim(); if(seen[key]) return; seen[key]=1;
      var a=aisleOf(ing); (by[a]=by[a]||[]).push(ing);
    }); });
    var order=["Fresh produce","Meat, fish & deli","Dairy & eggs","Pantry & dry goods","Herbs, spices & aromatics","Other"];
    var body="";
    order.forEach(function(a){ if(!by[a]) return;
      body+='<div class="gm-aisle"><h5>'+a+'</h5><ul>'+by[a].sort().map(function(x){ return '<li>'+esc(x)+'</li>'; }).join("")+'</ul></div>';
    });
    overlay("Your basket", "Shopping list",
      '<p class="gm-shop-for">'+esc(title)+'</p><div class="gm-shop-cols">'+body+'</div>'+
      '<p class="gm-shop-note">Quantities follow each recipe’s serving size. Buy the best you can of the few hero ingredients; the rest is forgiving.</p>');
  }

  /* ---------------- surprise ---------------- */
  function surprise(){
    var p=pool(); if(!p.length) p=DISHES;
    var pick=p[Math.floor(Math.random()*p.length)];
    if(pick) recipeDetail(pick);
  }

  /* ---------------- cards ---------------- */
  function favBtn(d){
    return '<button class="gm-fav'+(isFav(d.id)?" on":"")+'" aria-label="Save '+esc(d.name)+' to favourites" aria-pressed="'+isFav(d.id)+'">'+IC_HEART+'</button>';
  }
  function wireFav(card, d){
    var b=card.querySelector(".gm-fav"); if(!b) return;
    b.addEventListener("click",function(ev){ ev.stopPropagation(); toggleFav(d.id); var on=isFav(d.id); b.classList.toggle("on",on); b.setAttribute("aria-pressed",on); });
  }
  function openable(card, d){
    function open(){ recipeDetail(d); }
    card.addEventListener("click",open);
    card.addEventListener("keydown",function(e){ if(e.key==="Enter"||e.key===" "){ e.preventDefault(); open(); } });
  }

  function tierBadge(d){
    return tierOf(d)==="signature"
      ? '<span class="gm-tier sig">✦ Signature</span>'
      : '<span class="gm-tier easy">Easy &middot; everyday</span>';
  }
  function inspLine(d){
    return (tierOf(d)==="signature" && d.inspiration) ? '<p class="gm-insp">In the spirit of '+esc(d.inspiration)+'</p>' : "";
  }
  function roleBadge(d){
    var r=roleOf(d);
    if(r==="appetizer") return '<span class="gm-role app">Appetizer</span>';
    if(r==="salad") return '<span class="gm-role sal">Salad</span>';
    if(r==="dessert") return '<span class="gm-role des">Dessert</span>';
    return "";
  }

  // the big editorial slot feature (lunch / dinner picks)
  function featureCard(d, i){
    var c=el(
      '<article class="gm-feature '+(tierOf(d)==="signature"?"tier-sig":"tier-easy")+'" tabindex="0" role="button" data-gm="rise-s" style="--cz:'+czHue(d.cuisineKey)+'; --gm-delay:'+(i*100)+'ms" aria-label="'+esc(d.name)+', open the recipe">'+
        '<div class="idx gm-display">'+pad(i+1)+'</div>'+
        '<div class="fbody">'+
          tierBadge(d)+
          '<h3 class="gm-fname">'+esc(d.name)+'</h3>'+
          '<p class="gm-fidea">'+esc(d.idea)+'</p>'+
          inspLine(d)+
          metaRow(d)+
          '<div class="gm-tags">'+tagsHtml(d)+'</div>'+
        '</div>'+
        '<div class="gm-fside">'+favBtn(d)+'<span class="gm-open">View recipe '+IC_ARROW+'</span></div>'+
      '</article>');
    wireFav(c,d); openable(c,d);
    return c;
  }

  // the compact menu card
  function gridCard(d, i){
    var c=el(
      '<article class="gm-card '+(tierOf(d)==="signature"?"tier-sig":"tier-easy")+'" tabindex="0" role="button" data-gm="rise" style="--cz:'+czHue(d.cuisineKey)+'; --gm-delay:'+(Math.min(i,7)*60)+'ms" aria-label="'+esc(d.name)+', open the recipe">'+
        '<div class="gm-ctop"><span class="gm-czlabel"><span class="cdot"></span>'+esc(czName(d.cuisineKey))+'</span><span class="gm-ctop-r">'+tierBadge(d)+favBtn(d)+'</span></div>'+
        '<h3 class="gm-cname">'+esc(d.name)+'</h3>'+
        '<p class="gm-cidea">'+esc(d.idea)+'</p>'+
        '<div class="gm-tags">'+tagsHtml(d)+'</div>'+
        '<div class="gm-cfoot"><span class="m" style="color:var(--gm-muted);font-weight:700;font-size:.8rem">'+esc(d.category)+' &middot; '+d.minutes+' min'+(typeof d.calories==="number"?' &middot; '+d.calories+' kcal':'')+'</span><span class="gm-open">Recipe '+IC_ARROW+'</span></div>'+
      '</article>');
    wireFav(c,d); openable(c,d);
    return c;
  }

  // compact "to start" card (appetizer / salad) shown above the mains in each meal
  function starterCard(d, i){
    var c=el(
      '<article class="gm-card gm-starter" tabindex="0" role="button" data-gm="rise" style="--cz:'+czHue(d.cuisineKey)+'; --gm-delay:'+(i*70)+'ms" aria-label="'+esc(d.name)+', open the recipe">'+
        '<div class="gm-ctop"><span class="gm-czlabel"><span class="cdot"></span>'+esc(czName(d.cuisineKey))+'</span><span class="gm-ctop-r">'+roleBadge(d)+favBtn(d)+'</span></div>'+
        '<h3 class="gm-cname">'+esc(d.name)+'</h3>'+
        '<p class="gm-cidea">'+esc(d.idea)+'</p>'+
        '<div class="gm-cfoot"><span class="m" style="color:var(--gm-muted);font-weight:700;font-size:.8rem">'+(typeof d.calories==="number"?d.calories+' kcal &middot; ':'')+d.minutes+' min</span><span class="gm-open">Recipe '+IC_ARROW+'</span></div>'+
      '</article>');
    wireFav(c,d); openable(c,d);
    return c;
  }

  /* ---------------- filter studio ---------------- */
  function mk(html, fn){ var b=el(html); b.addEventListener("click",fn); return b; }
  function chip(label, on, cls, hue){
    return '<button class="gm-chip'+(cls?(" "+cls):"")+(on?" on":"")+'" aria-pressed="'+(on?"true":"false")+'"'+(hue?(' style="--cz:'+hue+'"'):"")+'>'+(hue?'<span class="cdot"></span>':"")+esc(label)+'</button>';
  }
  function filterStudio(){
    var box=el('<section class="gm-filter" data-gm="rise"></section>');

    var r1=el('<div class="gm-frow"><span class="gm-flabel">Choose your kitchen</span></div>');
    var cr=el('<div class="gm-chiprow scroll"></div>');
    cr.appendChild(mk(chip("All cuisines", prefs.cuisine==="all", "cz-cuisine", "#cda85f"), function(){ prefs.cuisine="all"; prefs.category="all"; savePrefs(); remount(); }));
    CUISINES.forEach(function(c){ cr.appendChild(mk(chip(c.short, prefs.cuisine===c.key, "cz-cuisine", c.hue), function(){ prefs.cuisine=c.key; prefs.category="all"; savePrefs(); remount(); })); });
    r1.appendChild(cr); box.appendChild(r1);

    var r2=el('<div class="gm-frow"><span class="gm-flabel">'+(prefs.cuisine==="all"?"What are you in the mood for":("Pick a "+esc(czName(prefs.cuisine))+" style"))+'</span></div>');
    var cgr=el('<div class="gm-chiprow scroll"></div>');
    cgr.appendChild(mk(chip("Everything", prefs.category==="all", "mini"), function(){ prefs.category="all"; savePrefs(); remount(); }));
    categoriesFor().forEach(function(cat){ cgr.appendChild(mk(chip(cat, prefs.category===cat, "mini"), function(){ prefs.category=cat; savePrefs(); remount(); })); });
    r2.appendChild(cgr); box.appendChild(r2);

    var r3=el('<div class="gm-frow"><span class="gm-flabel">Tonight’s mood</span></div>');
    var mr=el('<div class="gm-chiprow"></div>');
    mr.appendChild(mk(chip("Vegetarian", prefs.veg, "mini"), function(){ prefs.veg=!prefs.veg; savePrefs(); remount(); }));
    mr.appendChild(mk(chip("Quick · 30 min or less", prefs.quick, "mini"), function(){ prefs.quick=!prefs.quick; savePrefs(); remount(); }));
    r3.appendChild(mr); box.appendChild(r3);

    if(PRESENT_ALLERGENS.length){
      var r5=el('<div class="gm-frow"><span class="gm-flabel">Allergies to avoid</span><span class="gm-fhelp">Any dish containing a selected allergen is removed first, so it never shows in your picks or menu.</span></div>');
      var ar=el('<div class="gm-chiprow"></div>');
      PRESENT_ALLERGENS.forEach(function(a){
        ar.appendChild(mk(chip(a, prefs.avoid.indexOf(a)>-1, "mini avoid"), function(){
          var i=prefs.avoid.indexOf(a); if(i>-1) prefs.avoid.splice(i,1); else prefs.avoid.push(a);
          savePrefs(); remount();
        }));
      });
      r5.appendChild(ar); box.appendChild(r5);
    }

    var r4=el('<div class="gm-frow"><span class="gm-flabel">Which evening</span></div>');
    r4.appendChild(dayRail()); box.appendChild(r4);

    return box;
  }
  function dayRail(){
    var wrap=el('<div class="gm-day-rail" aria-label="Day of the week"></div>');
    var today=(new Date().getDay()+6)%7;
    DAYS.forEach(function(d,i){
      var b=el('<button class="gm-day'+(i===state.day?" on":"")+(i===today?" today":"")+'"'+(i===state.day?' aria-current="true"':"")+'><b>'+d.slice(0,3)+'</b>'+(i===today?'<small>tonight</small>':"")+'</button>');
      b.addEventListener("click",function(){ state.day=i; remount(); });
      wrap.appendChild(b);
    });
    return wrap;
  }

  /* ---------------- section title with a drawing rule ---------------- */
  function stitle(eyebrow, titleHtml, sub){
    return el('<div class="gm-stitle">'+
      '<span class="gm-kick eyebrow" data-gm="rise">'+esc(eyebrow)+'</span>'+
      '<h2 class="gm-display" data-gm="rise">'+titleHtml+'</h2>'+
      (sub?'<p class="sub" data-gm="rise">'+esc(sub)+'</p>':"")+
      '<div class="gm-rule" data-gm="rule"></div>'+
    '</div>');
  }

  /* ---------------- scroll reveal (transform/opacity, gated on motion) ---------------- */
  var _io=null;
  function gmReveal(scope, animate){
    var nodes=scope.querySelectorAll("[data-gm]");
    if(animate===false || !P.motionOK() || !("IntersectionObserver" in window)){
      [].forEach.call(nodes,function(n){ n.classList.add("gm-in"); }); return;
    }
    if(!_io){ _io=new IntersectionObserver(function(ents,obs){
      ents.forEach(function(e){ if(e.isIntersecting){ e.target.classList.add("gm-in"); obs.unobserve(e.target); } });
    },{ threshold:0.12, rootMargin:"0px 0px -6% 0px" }); }
    [].forEach.call(nodes,function(n){ _io.observe(n); });
  }

  /* ---------------- the view ---------------- */
  var rootEl, state={ day:(new Date().getDay()+6)%7 };
  function remount(){ var y=window.scrollY; render(rootEl, false); window.scrollTo(0,y); }

  function render(root, animate){
    rootEl=root; root.innerHTML="";
    var v=el('<div class="view gm-view"></div>');
    v.appendChild(P.topbar());
    v.appendChild(P.sectionNav("grownmeals"));

    var hero=el(
      '<header class="gm-hero">'+
        '<span class="gm-kick" data-gm="rise">For busy parents · lunch &amp; dinner, sorted</span>'+
        '<h1 class="gm-display" data-gm="rise-s">The Grown-Ups’ <span class="it">Table</span></h1>'+
        '<p class="gm-lede" data-gm="rise">Cooking around a little one is a juggle. Each day you get three lunch and three dinner ideas: two that are genuinely easy, built on common ingredients for a hectic day, and one world-class signature for when you want to treat yourself. Every dish comes with the method, the ingredients and a ready shopping list.</p>'+
        '<div class="gm-rule" data-gm="rule"></div>'+
        '<div class="gm-hero-meta" data-gm="rise">'+
          '<div class="gm-stats"><span><b>'+CUISINES.length+'</b> cuisines</span><span><b>'+DISHES.length+'</b> dishes</span><span><b>2&#8201;+&#8201;1</b> easy plus a signature</span></div>'+
          '<span class="gm-spacer"></span>'+
          '<button class="gm-surprise"><span class="ic">✦</span> Surprise me</button>'+
        '</div>'+
      '</header>');
    hero.querySelector(".gm-surprise").addEventListener("click",surprise);
    v.appendChild(hero);

    v.appendChild(filterStudio());

    var ctx=(prefs.cuisine==="all"?"Across every kitchen":czName(prefs.cuisine))+
      (prefs.category!=="all"?(" · "+prefs.category):"")+
      (prefs.veg?" · vegetarian":"")+(prefs.quick?" · under 30 min":"")+
      (prefs.avoid&&prefs.avoid.length?(" · no "+prefs.avoid.join(", ").toLowerCase()):"");

    function slotSection(slotKey, eyebrow, titleHtml){
      v.appendChild(stitle(eyebrow+" · "+DAYS[state.day], titleHtml, ctx+" · a starter and a salad, then two easy mains and a signature"));
      var starters=startersFor(slotKey, state.day);
      var trio=mainsTrio(slotKey, state.day);
      var bag=[];
      if(starters.length){
        v.appendChild(el('<div class="gm-substar" data-gm="rise">To start</div>'));
        var sg=el('<div class="gm-starters"></div>');
        starters.forEach(function(d,i){ sg.appendChild(starterCard(d,i)); bag.push(d); });
        v.appendChild(sg);
      }
      if(trio.length){
        v.appendChild(el('<div class="gm-substar mains" data-gm="rise">The mains</div>'));
        var tg=el('<div class="gm-three"></div>');
        trio.forEach(function(d,i){ tg.appendChild(featureCard(d,i)); bag.push(d); });
        v.appendChild(tg);
      }
      if(bag.length){
        var foot=el('<div class="gm-three-foot" data-gm="rise"></div>');
        var label=slotKey==="lunch"?"lunch":"dinner";
        var sb=el('<button class="gm-btn">'+IC_BASKET+' Shopping list for '+label+'</button>');
        sb.addEventListener("click",function(){ shoppingFor((slotKey==="lunch"?"Lunch":"Dinner")+" · "+DAYS[state.day], uniq(bag)); });
        foot.appendChild(sb); v.appendChild(foot);
      } else {
        v.appendChild(el('<div class="gm-empty" data-gm="rise">Nothing matches those choices. Ease the mood filters, or pick another kitchen.</div>'));
      }
    }
    slotSection("lunch", "Lunch", 'What’s for <span class="it">lunch</span>?');
    slotSection("dinner", "Dinner", 'What’s for <span class="it">dinner</span>?');

    var p=pool();
    if(p.length){
      var menuTitle=prefs.cuisine==="all" ? 'The full <span class="it">menu</span>' : ("The "+esc(czName(prefs.cuisine))+' <span class="it">menu</span>');
      v.appendChild(stitle("Browse everything", menuTitle, p.length+" dish"+(p.length>1?"es":"")+" to explore"));
      var mg=el('<div class="gm-grid"></div>');
      p.forEach(function(d,i){ mg.appendChild(gridCard(d,i)); });
      v.appendChild(mg);
    }

    var favs=DISHES.filter(function(d){ return isFav(d.id); });
    if(favs.length){
      v.appendChild(stitle("Saved", 'Your <span class="it">favourites</span>', favs.length+" saved for later"));
      var fg=el('<div class="gm-grid"></div>');
      favs.forEach(function(d,i){ fg.appendChild(gridCard(d,i)); });
      v.appendChild(fg);
    }

    v.appendChild(el(
      '<section class="gm-srcnote" data-gm="rise">'+
        '<h3 class="gm-display">From our kitchen to yours</h3>'+
        '<p>Every recipe here was developed and then cross-checked by a culinary panel for authenticity, sound quantities and correct method. Quantities serve two or four as noted; season to your own taste, and treat the times as a confident guide rather than a law. <b>Pour a glass of something nice, and enjoy the quiet.</b></p>'+
      '</section>'));

    root.appendChild(v);
    gmReveal(v, animate);
  }

  function renderHome(root){ render(root, true); }
  P.registerModule({ id:"grownmeals", title:"The Grown-Ups' Table", renderHome:renderHome });
})();
